window.IDW_ITEMS_TR=window.IDW_ITEMS_TR||{};window.IDW_ITEMS_TR["zh-Hans"]={"ICON-0001":{"nm":"脚印","de":"地板上留下的一枚土色印记。徘徊了许久，终究有人多迈出了一步啊。脚印铭刻的不是停留的时间，而是下定决心要离开的那一瞬。"},"ICON-0002":{"nm":"灯火","de":"火苗触到灯芯，黑暗便一寸寸悄悄退去。古人会把心愿写在那点暖意上放飞。点灯不是为了照亮，而是为了陪伴在身旁。"},"ICON-0003":{"nm":"丝带","de":"一个结，便把心意妥帖地包裹起来。系的人想让它好解，收的人却想慢慢拆开。丝带系住的不是盒子，而是递出前那阵怦然心动。"},"ICON-0004":{"nm":"信箱","de":"张着红红的口，立在巷子口。即便在手写信稀罕的年代，这小小的箱子也始终等着某人的问候。空空荡荡的那一刻，反而最明亮，是个温柔的容器。"},"ICON-0005":{"nm":"个人岛屿迷你地图","de":"折起来塞进口袋，摊开便是海与山脊并排躺着的一张纸。对初到的人而言，每一个转角都是尚未拆开的约定。展开的瞬间，小岛也成了辽阔的世界。"},"ICON-0006":{"nm":"麦克风","de":"发出第一个音前，调匀呼吸的半拍。一旦察觉台下的目光在等自己开口，指尖便会发颤。麦克风不是为了放大声音，而是把那阵颤抖一路护送到底。"},"ICON-0007":{"nm":"时钟","de":"秒针从不停歇，却没人催促你。离出道还有几夜，离登台还有几分——在表盘上，等待与悸动以相同的速度转动。看时间这件事，其实是在抚慰内心。"},"ICON-0008":{"nm":"笔记本","de":"空格最多的物件。舞蹈的走位、凌晨的决心、终究没能寄出的话，都堆积在这里。翻开的瞬间，昨天的我便静静地对今天的我开口。"},"ICON-0009":{"nm":"印章","de":"蘸饱红印泥，用力一按，约定便清晰地刻下。比字迹更重，比言语更分明的痕迹。在每份文书的末尾，人们以这枚小小的印章，替代名字托付了真心。"},"ICON-0010":{"nm":"底座","de":"把自己压得极低，去托起别的东西。为了上面摆放的不会摇晃，在最底下默默支撑。即使不闪耀，这里也藏着不让一切坍塌的温柔。"},"ICON-0011":{"nm":"邮票","de":"在一角舔上口水用力贴牢的小小图画。这是为送往远方的心意定下的，最诚实的价钱。一方小小的风景，牵着信的手，跨越大海。"},"ICON-0012":{"nm":"旗帜针","de":"在地图上轻轻一插，就成了\"我走到这里了\"。它不是征服，而是记录，是对后来人的鼓励。看到这面旗就再走一步吧——这是无声推着你后背的标记。"},"ICON-0013":{"nm":"树枝","de":"弯过一次的枝条，便忘了如何折断。每一处曾迎风弯下的地方都结出坚硬的节疤，真正的坚韧来自好好熬过的痕迹——古老的森林随风这样告诉你。"},"ICON-0014":{"nm":"纽扣","de":"松开又系上，反复间掩好衣襟。一个小小的圆圈，悄悄挡住凌晨的寒意，也挡住忽然涌起的羞怯。要等它啪地掉落，才惊觉那个位置原来那么重要。"},"ICON-0015":{"nm":"信封","de":"封口的那一刻，才终于成了秘密。里面装着什么，唯有收信人知道。一层薄纸搁在心与世间之间，是最薄也最温柔的一扇门。"},"ICON-0016":{"nm":"箱子","de":"四角端正，所以无论什么都宽厚地容纳。搬家时装回忆，过节时装礼物，平时装些杂物。合上的盖子内侧，总是塞满了某人的\"以后再说\"。"},"ICON-0017":{"nm":"门把手","de":"在门与人之间，最先伸出手的物件。要拉上一把，里与外才终于相连。所有进出的决心，都要先握一握这冰凉的手再走。"},"ICON-0018":{"nm":"汤匙","de":"用凹陷的口，轻轻舀起温热的汤。它记得母亲呼呼吹凉后先递来的那一勺暖意。是饭桌上最常碰到嘴边、最温柔的一只手。"},"ICON-0019":{"nm":"拖鞋","de":"跨过门槛的瞬间，脚先松了一口气。脱下咯噔作响的一天，换上窸窸窣窣慢走的傍晚之声。玄关里整齐摆着的一双，仿佛在说\"到家了\"。"},"ICON-0020":{"nm":"钥匙","de":"先学会开，再学会锁。在手心里被焐热，某天又静静停在陌生的新门前的一小块铁。它最持久地留存着离去之人的温度。"},"ICON-0021":{"nm":"酒杯","de":"空着时端庄，斟满时格外温暖。相对举起的两只杯叮地清脆相碰，盛着无言的约定。它生来就是为了两个人时比独自一人时更闪耀的器皿。"},"ICON-0022":{"nm":"碟子","de":"圆圆的边沿里，盛满一天的用心。清空、擦净、再盛满，循环一生——是最常闪耀、也最常被遗忘的器物。餐桌的舞台，总是摆在它之上。"},"ICON-0023":{"nm":"灯具","de":"一个开关，房间的表情便改变。明亮时是日常，柔和时是慰藉。为晚归的人始终亮着的那一点光，成了世上最温暖的迎接。"},"ICON-0024":{"nm":"茶匙","de":"在茶水上慢慢转一圈，叶与水便彼此交融。不急不躁的手法，是等香气弥漫开来的小小守候。一只银色的手，温柔地放慢了午后的节奏。"},"ICON-0025":{"nm":"书签","de":"在读到一半的地方静静夹下的约定。\"在这里停下了，一定会回来\"的承诺，沉睡在纸页之间。故事虽合上了，心却清楚地标在那一行上。"},"ICON-0026":{"nm":"靠垫","de":"对需要倚靠的后背和膝盖，无言地接纳。深深陷下又慢慢鼓起，吸走今天一整天的疲惫。是把最慵懒的姿态，最宽厚地允许下来的物件。"},"ICON-0027":{"nm":"相框","de":"方方的边框，把一幅风景捆进永恒。只要进入这里，无论时光流逝都不会褪色。比起装下什么，它更是\"决定留下什么\"的温柔抉择。"},"ICON-0028":{"nm":"地图","de":"每一道折痕里，都浸着迷路又重新找回的痕迹。摊开它，没去过的地方也能用指尖先走一遍。一切冒险，都始于展开这一张纸的小小勇气。"},"ICON-0029":{"nm":"明信片","de":"背面一半是照片，一半是空白。远行的人在\"我很好\"这几个字旁，附上那里的风景寄来。没有信封也不必羞于问候，是最坦诚的一张纸。"},"ICON-0030":{"nm":"出入证","de":"挂上脖子的瞬间，才终于踏入里面的世界。小小卡片上写着我的名字，静静地允许道\"这里，是你的位置\"。它不是通行的资格，而是归属于某处的凭证。"},"ICON-0031":{"nm":"字母B","de":"在单词正中最常被唤出的字母。要先抿一下嘴唇再啪地一弹，声音才发得出。它既非开头也非结尾，却是稳稳把住节拍的第二个位置。"},"ICON-0032":{"nm":"名片","de":"递出时双手奉上，接过时四目相对。一张纸上，静静压缩着一个人的日常与自豪。在名字与头衔之间窄窄的留白里，悄悄寄宿着那天的第一印象。"},"ICON-0033":{"nm":"封面","de":"在故事的最外层，率先承受风雨。为了守护里面的字，从自己的边角开始磨损。翻开前那一瞬的悸动，总是从这一页先开始。"},"ICON-0034":{"nm":"教材","de":"下划线与荧光笔，密密记录着一个人的奋斗。崭新时令人茫然，看完后却成了最可靠的朋友。把不懂变成懂了的痕迹，每一页都细细折好。"},"ICON-0035":{"nm":"舞蹈通行证","de":"这一张，把练习室的门敞开。镜子满墙的房间，跺脚声，初学的八拍。就算舞还跳得生疏也没关系——一张小纸，静静推着发颤的后背。"},"ICON-0036":{"nm":"文件夹","de":"散乱漂泊的纸张被齐齐穿在一根脊梁上，才终于有了次序。有了次序便成了故事，越厚就越是某人那般一点点活过的温柔证据。"},"ICON-0037":{"nm":"试卷","de":"空白行上微微发颤的指尖。比起正确答案，更可怕的是与不懂的东西正面相对。批改结束后，每一处错题旁，都静静留下日后会成长的空白。"},"ICON-0038":{"nm":"字母A","de":"要把嘴张大才终于发出的第一个音。常站在队列的最前、名字的最初。无论开始什么都从这个字母起步——所以它总是多了几分勇敢。"},"ICON-0039":{"nm":"字母D","de":"用柔和弯起的脊背，轻轻托住单词。圆鼓鼓的一侧，端正地挂在某人名字的末尾。虽不华丽，少了却觉空落——是字母中安静相伴的一个。"},"ICON-0040":{"nm":"练习纸","de":"错了也没关系的、世上独一无二的纸。它让你把同一个动作、同一句话，重写几十遍。揉皱丢掉的张数有多少，某人就确实地变得更好了一些。"},"ICON-0041":{"nm":"作曲谱","de":"凌晨两点，一段哼唱惊醒了睡意。铅笔在五线谱上犹豫迟疑，是因为旋律比手更快。每一处擦了又写的痕迹里，还没有名字的歌正一点点长大。"},"ICON-0042":{"nm":"出入通行证","de":"挂上脖子的瞬间，平凡的走廊便变成另一个世界。电缆如蛇般横穿黑暗，舞台那头开始了听不见的倒数。能踏进这里的资格，由这一张代为言说。"},"ICON-0043":{"nm":"接触印样","de":"每一个小格里，都停着不同的表情。笑着、回眸、闭眼。一格格指过去，按下快门那天的悸动便顺着指尖回流。光是挑一张，就已经是记录了。"},"ICON-0044":{"nm":"通告单","de":"明天几点、在哪里、做什么。一张纸预先画好一天的行程。在以分钟为单位密密排满的格子间，有人正循着这上面的次序，一步步走向梦想。"},"ICON-0045":{"nm":"吊牌","de":"价签背后，静静挂着制作者的时光。轻轻一撕的那个短短动作，它才终于成了我的，一张小纸。撕下的位置留下的，是新物的气味，和一把心动。"},"ICON-0046":{"nm":"作品集","de":"翻开封面，走过的路便一齐铺展开来。最自信的一页旁，是生涩的初次尝试羞涩地并排着。第一次把自己递给某人时，没有比这更坦诚的自我介绍。"},"ICON-0047":{"nm":"计划本","de":"写下今天，描绘下周，偶尔把一格涂得乌黑。即使从未按计划进行，填格子的手也不停下。是预先把未来活一遍的、像小小仪式一样的东西。"},"ICON-0048":{"nm":"播放列表","de":"在慢歌与快拍之间，配合那天心情的天气，把歌排成一列。一想到某人的一天恰好按这个顺序流淌，连歌曲之间的静默都变得温柔。"},"ICON-0049":{"nm":"学生证","de":"名字、照片，还有几个数字。证明那段往返于教室与练习室之间岁月的一张卡。被揣进口袋磨到边角发毛的卡上，嵌着再也回不去的青涩每一天。"},"ICON-0050":{"nm":"手环","de":"还记得把那天的颜色系在手腕上的瞬间吗？一起喊过的口号，一同被汗水浸湿的演唱会之夜。绳子磨损、颜色褪去也不解开，是想让那个夏天一直活在手腕上。"},"ICON-0051":{"nm":"袖标","de":"缠上手臂的瞬间，名为责任的重量悄悄加上。站在队列最前、最晚离开座位的人的标记。一片布，让某人多成长了一寸。"},"ICON-0052":{"nm":"环","de":"毫无断处、圆圆相连的一根线。始与终相接，所以人们从这里看见永恒的形状。两只手静静相搭，比言语更先地，约定便留下了形态。"},"ICON-0053":{"nm":"勋章","de":"别在胸前的小铁片上，铭刻着熬过的日子。闪耀的不是金属，而是它背后无数练习的夜。比起自豪，先涌上心头的，竟是一份感激。"},"ICON-0054":{"nm":"围裙","de":"把绳子在脖颈系好，双手便自由了。无论是面粉还是颜料，这是要全心投入某事的信号。污渍一点点增多，那天倾注的用心也随之愈发浓厚。"},"ICON-0055":{"nm":"护耳帽","de":"把耳朵裹得严严实实，外面的声音便退远一步。寒风刺骨的上学路上，悄悄躲进松软内里的小小避难所。冬日的温暖，有时就这样从耳尖开始。"},"ICON-0056":{"nm":"演出服","de":"幕布升起前，挂在衣架上屏息的一套。每一道接缝里都折着舞步。穿上袖子的瞬间，人便成了角色，舞台成了这衣服的第二层肌肤。"},"ICON-0057":{"nm":"王冠","de":"戴上头顶的瞬间，弯着的背便自然挺直。金色光芒先低语的是责任，而非权力。触到额头那冰凉的重量在说：越是闪耀的位置，越沉重。"},"ICON-0058":{"nm":"披风","de":"披在肩上，背后便有风猎猎作响。每次奔跑，一幅衣角都追在身后的那种感觉。与其说是英雄的标记，更接近只是想耍帅的那颗童心。"},"ICON-0059":{"nm":"面具","de":"遮住脸，反而更坦诚。就像在假面背后尽情哭笑的旧时庭院戏。隔着掩藏的表情，平日咽下的真实嗓音反而更大声地泄露出来。"},"ICON-0060":{"nm":"口红","de":"旋开盖子划上一笔，唇边便立起一个小小的决心。镜前最后的检视，在犹豫之上覆盖的一道红线。上色的那短短一瞬，畏惧便悄悄让出了位置。"},"ICON-0061":{"nm":"西装外套","de":"肩线恰好贴合时，人会变得稍许坚定。卷起袖子是干活的心，立起领子是出门的心。一套衣服，静静地定下那一天的姿态。"},"ICON-0062":{"nm":"跆拳道带","de":"颜色每升一级，下面积攒的汗水量也随之不同。勒紧腰带、行礼鞠躬的道馆清晨。随着系带的指尖，散乱的心神又重新聚拢。"},"ICON-0063":{"nm":"护目镜","de":"戴在眼前，世界便清晰一个色调。隔着挡住风与尘的圆圆盾牌，连每天走的平凡道路，也仿佛起跑线般闪闪发光。"},"ICON-0064":{"nm":"手套","de":"戴上手，便涌起紧紧抓住任何东西的勇气。曾怕掉落而蜷缩的手指，终于舒展开来。守护的是手，真正被守护的，却是接下来的挑战。"},"ICON-0065":{"nm":"口罩","de":"遮住嘴边，眼睛便说出更多的话。在人潮拥挤的街上，稍稍遮住所享受的小小匿名自由。所以全摘下后留在脸上的微笑，绽放得更加灿烂。"},"ICON-0066":{"nm":"帽子","de":"把帽檐微微压低，阳光与目光便偏开一寸。在头顶这小小屋檐下，今天就用轻松的表情走也无妨。最轻盈的变身，总是从这里开始。"},"ICON-0067":{"nm":"衬衫","de":"沙沙作响，刚熨好的衣领散着清晨的气息。从最上面依次扣好纽扣的过程中，凌乱的心也一格格端正起来。雪白的一件，开启一天的第一句话。"},"ICON-0068":{"nm":"围巾","de":"在脖子上绕一圈，风的去路便被挡住。末端在肩头轻轻摇曳之间，寒意再也触不到里面。是搁在时髦与温暖之间某处的一幅。"},"ICON-0069":{"nm":"手套","de":"连指尖都裹得严实，冰冷的东西也不再可怕。呵气暖手的双手悄悄变得温暖，是冬日小小的奢侈。脱下递出的一只，有时也能焐热某人的手。"},"ICON-0070":{"nm":"军牌","de":"薄薄两片牌，静静地彼此相望。三个字的名字和几个号码，便让人把某人记到最后。明明是冰冷的金属，却不知为何，最像最温暖的约定。"},"ICON-0071":{"nm":"手机指环","de":"套上手指，掉落的担忧便悄然消失。单手也能从容拿着挥动的小小安心。想拍张照而长长伸出手臂时，它静静托住手掌。"},"ICON-0072":{"nm":"花冠","de":"戴在头上，一捧春天便随之而来。在野地采来圆圆编成的花，轻轻环住额头。照片里灿烂的笑容上，淡淡的草香长久地留存。"},"ICON-0073":{"nm":"眼罩","de":"盖住眼睛，灯光与噪音便一齐远去。看不见了，听得见的只有自己的呼吸。暂且关掉世界、走进内里的宁静时，身后有一扇小门静静合上。"},"ICON-0074":{"nm":"长围巾","de":"一圈，两圈，每绕一下脖子，冬天便温顺一些。毛线之间某处，或许还掺着某人织进去的心意。埋到鼻尖时，世界便愈发暖融融。"},"ICON-0075":{"nm":"半月面具","de":"只遮住半张脸，舞会之夜便开始了。露出的嘴唇在笑，藏起的双眼怀着秘密。那似识非识的窄窄间隙，让午夜的空气怦然心动。"},"ICON-0076":{"nm":"贝雷帽","de":"斜斜一戴，平凡的一天便悄悄添了几分韵致。圆圆扁扁的一块布，在肩头静静披上艺术家的模样。连在镜前挑选角度的那一会儿都觉得快乐。"},"ICON-0077":{"nm":"颈链","de":"恰好贴合地绕在脖子上，目光便自然往上聚拢。一根细带，整个改变了氛围。虽小却分明，是为今天填满自信的、像锁扣一样的东西。"},"ICON-0078":{"nm":"派克大衣","de":"拉链拉到底，暴风雪也退后一步。把手深深插进厚实的内里，全世界的喧嚣便平静下来。在狂风中也终究温暖，是一座小小的房子。"},"ICON-0079":{"nm":"长裤","de":"套上脚、束好腰，出门的准备才算完成。每迈一步，布料便顺着纹理柔顺地动。在舒适与端正之间某处，一天就此开始。"},"ICON-0080":{"nm":"穿孔饰","de":"哪怕只添一个小点，也需要一点勇气。一颗闪亮的金属，在平凡的耳畔点上分明的句号。虽极小，却清楚地映照出今天有所不同的我的光。"},"ICON-0081":{"nm":"波形","de":"对工程师而言，歌不是听见的，而是看见的。从屏幕上起伏的山脊间，读出那天气息在哪里颤抖。看不见的嗓音如山脉般横卧，铺展出一首歌的地形。"},"ICON-0082":{"nm":"调音器","de":"演出前夕，依次抚过六根弦，把跑掉的音重新归位。哪怕只偏0.5度，台下也会神奇地察觉。精准到无人能觉，正是面向舞台的温柔。"},"ICON-0083":{"nm":"背带","de":"在手腕上缠一圈，掉落的担忧便松松解开。舞台上最可怕的是从手中失落什么，有了这一根小小的带子，心才终于安定下来。"},"ICON-0084":{"nm":"镲","de":"仅相碰一次的瞬间，便在曲子最后一句敲下分明的句号。金色圆盘懂得如何鸣响得最短、余韵留得最长。结尾就该这样明亮地合上。"},"ICON-0085":{"nm":"吉他","de":"手指在六根弦上一滑，狭小的房间便整个成了舞台。某人的第一段旋律，难眠凌晨的自言自语，都在这圆圆的木桶里最先获得了呼吸。"},"ICON-0086":{"nm":"声音云","de":"天空一隅，音符如棉花般聚拢，悠悠飘荡。风一扫而过，落下的便不是雨滴而是旋律——岛上的孩子们连伞都不带就出去迎接。"},"ICON-0087":{"nm":"舞步","de":"舞台走位是用脚尖解的算术。这里一步，那里半拍——错了也没关系，慢慢来。踩过几百遍刻进身体的格子聚在一起，一首歌的地图才终于完成。"},"ICON-0088":{"nm":"音箱","de":"把耳语变成呐喊的箱子。即便如此，把音量调高一格前总会停手。比起更大的声音，更准确的声音才能传到台下最后一排，这箱子懂得。"},"ICON-0089":{"nm":"音符棉","de":"豆芽脑袋们聚成棉团，像枕头一样松软。静静枕着躺下，便流淌出若有若无的摇篮曲——是岛上最温柔的一则传闻。"},"ICON-0090":{"nm":"磁带","de":"按下倒带键，咔吱一声，磁带慢慢转回那个夏天的第一首歌。整段时光被卷进的小箱子里，再也无法触碰的时间，完好地沉睡着。"},"ICON-0091":{"nm":"音叉","de":"轻敲两叉的金属，半空中便诞生一个基准音。所有乐器都向这微小的颤动静静地对齐。无论什么，起始都来自这般纤弱的振动。"},"ICON-0092":{"nm":"波形芯片","de":"把一截声音轻轻关进指甲盖大的芯片里。不曾刻意录下的应和声，以为消失了的某人的笑声，在这里面依旧温暖地活着、呼吸着。"},"ICON-0093":{"nm":"黑胶唱片","de":"唱针沿着纹槽迈出第一步，先传来沙沙的浅浅气息。连那细小的杂音都喜欢，所以有人始终舍不得放下这张黑色圆盘。"},"ICON-0094":{"nm":"口袋","de":"最珍视的，总放在离胸口最近的地方。一只巴掌大的布袋，某天是暖手宝，某天是护身符，又某天成了秘密的保管箱。"},"ICON-0095":{"nm":"创可贴","de":"练习拖长的夜里，脚后跟便一个个贴上小小的勋章。为了咽下喊疼的话而贴的一张——是明天也定要跳舞的、无人知晓的安静约定。"},"ICON-0096":{"nm":"枕头","de":"把一整天的舞台全部卸下的地方，终究是这松软的方方一片。轻轻把头放下，耳畔残留的掌声便慢慢平息，岛上也终于降下了夜。"},"ICON-0097":{"nm":"门铃","de":"叮铃，短短一声，便有人推门而入。是客人来了的信号，也是一天开启的问候。一块小铁片，整日只担着迎接的欢喜而鸣。"},"ICON-0098":{"nm":"盒套","de":"越珍贵的东西，越要另建一座坚固的家。每次开合的手都格外小心，是因为里面装的不只是物件，而是怎么也不愿失去的心意。"},"ICON-0099":{"nm":"刷子","de":"连一根毛都顺着纹理扫下去，角落里积压的灰尘便悄悄退去。有这样连看不见的地方都不嫌弃的手，房间才每天迎来新的清晨。"},"ICON-0100":{"nm":"素描","de":"完成前的线条，并不刻意藏起犹豫。每一处擦了又描的痕迹里，都毫不作假地留着\"曾想成为什么\"。越是生涩的开始，越是坦诚。"},"ICON-0101":{"nm":"玩偶","de":"有些存在，光是无言地抱进怀里就能成为慰藉。在舞台后手发颤的夜里，曾在枕边一同发颤的棉团朋友——谁的心里，都揣着这样一个吧。"},"ICON-0102":{"nm":"钟","de":"山寺的钟一响，便整个越过山谷。是想抵达远方、更远方的钟之心在长长地鸣，所以那声音会在听者的胸口慢慢沉淀。"},"ICON-0103":{"nm":"雨伞","de":"一起撑，总有一边的肩膀注定会淋湿。在悄悄倾斜的伞下，湿透的肩膀才是温柔最分明的证据。共一片屋檐的短短一程，长久地留在心里。"},"ICON-0104":{"nm":"垫子","de":"在光地板上铺开一张，那里立刻成了练习室。翻滚、跌倒都无言接住的位置——无数动作，都在它之上第一次让身体熟出了路。"},"ICON-0105":{"nm":"铃铛","de":"静静一摇，叮铃铃，清脆的声音便从手中滚落。旧时孩子们缀在彩袖衣角、在院子里奔跑的那份小小圆圆的欢乐，又在掌心上苏醒。"},"ICON-0106":{"nm":"玩具蛇","de":"细长耷拉的样子，调皮地把人吓一跳。被吓得逃跑、最终却咯咯笑出声——这样的玩闹，归根结底也是面向彼此温柔的一支。"},"ICON-0107":{"nm":"玩具","de":"谁都有一个长大成人后也舍不得丢的箱子。里面，最闪耀那段岁月的笑声，像没拧松的发条一样，至今仍紧紧地缠着。"},"ICON-0108":{"nm":"饭桌","de":"把折起的腿展开，哪里立刻都成了一家人的座位。围坐一圈勺子相碰的声音，那朴素的合奏，是一整天里最温暖鸣响的一首歌。"},"ICON-0109":{"nm":"肥皂","de":"在手中一点点变小，默默地把某人洗净。磨损自己去清洗他人——要等泡沫全消许久之后，那安静的心意才终于被看见。"},"ICON-0110":{"nm":"梳子","de":"就像把缠结的头发一缕缕梳开，凌乱的一天也渐渐变得齐整。镜前递出的短短一下，连头发那头内心的仪容，都悄悄替你整理好了。"},"ICON-0111":{"nm":"鸟笼","de":"即便门敞开着，也有不离去而歌唱的鸟。不是因被关着，而是因想留下才留下的心意——这细微的差别，这鸟笼比谁都先察觉。"},"ICON-0112":{"nm":"暖手宝","de":"冬日演出场的等候队列里，口袋中小小的暖意静静焐热冻僵的手指。是惦念着会受冻的你，某人预先摇热的、巴掌大的温柔。"},"ICON-0113":{"nm":"手帕","de":"眼泪也好汗水也好，都毫无怨言接住的一方布。角上小小绣着的图案，像先离去之人留下的、勿忘的最后问候，妥帖地停在那里。"},"ICON-0114":{"nm":"喷雾","de":"嗤地一喷，空气的纹理瞬间改变。漫上舞台的雾，清晨窗边的花草，都在这纤细的水珠里，暂时变成另一个世界闪闪发光。"},"ICON-0115":{"nm":"试香纸","de":"挑选香气这件事，竟与挑选记忆十分相似。细细纸端轻轻沾上的一缕气息，把以为忘却的某个季节，悄悄带到鼻尖。"},"ICON-0116":{"nm":"餐桌","de":"磨损的每一道木纹里，都静静刻着共同分享的餐数。喧闹的傍晚也好，独自度过的深夜也好——这方桌都无言地一并揽下，泛着光。"},"ICON-0117":{"nm":"线团","de":"轻轻拉住一端便顺顺地解开，一针便又重新接上。把断开的接续起来，总是这样从纤细的一根线，静静地开始。"},"ICON-0118":{"nm":"雨衣","de":"在倾盆的日子里也执意让人走出门去的，正是这一件。只有懂得在雨中扑哧扑哧行走之乐的人，才不会借雨为由留在家里。"},"ICON-0119":{"nm":"束口袋","de":"把袋口圆圆收拢，里面的东西才终于安全。一只手垢斑斑的小布袋里，硬币、某天的回忆、终究没说出口的话，一同装着摇晃。"},"ICON-0120":{"nm":"书架","de":"顺着插立的书脊慢慢抚过手指，走过的季节便摸在指尖。读完的书舍不得丢，是因为那时的我还活在那里。"},"ICON-0121":{"nm":"书塔","de":"读过的书横放一旁，没读的书往上垒高。\"总有一天读完\"的约定在天花板附近一点点摇晃，连那摇晃都喜欢，所以今天又添上一本。"},"ICON-0122":{"nm":"跑轮","de":"拼命奔跑却像在原地，可小小的脚正先熟悉脚尖的节奏。不曾停下的那些昨天聚在一起，某天便在真正的路上灿烂地闪光。"},"ICON-0123":{"nm":"罩布","de":"不让灰尘落下，不被阳光晒褪——遮盖这件事，也需要指尖的用心。越珍惜的东西，越在看不见的地方被更温柔地守护着。"},"ICON-0124":{"nm":"毛线","de":"曾在祖母膝上滴溜溜滚出来的一缕。看似缠乱，找到线头轻轻一拉，便准会乖乖跟来。冬夜就这样一针一针地变长了。"},"ICON-0125":{"nm":"收纳包","de":"润唇膏、发圈、细细折好的一封信——看着小，里面却装着一天的心意。随着拉链合上的声音，珍贵的杂物便整个安全起来。"},"ICON-0126":{"nm":"扶手","de":"读书读到睡着的午后，打电话踱来踱去的傍晚。在坐得越久手垢越深的位置上，手肘记得的所有歇息，悄悄汇聚了一寸的宁静。"},"ICON-0127":{"nm":"卡包","de":"拆开前，还不属于任何人。封好的一包里满是尚未开启的期待，捏住边角的指尖会轻轻发颤。那便是开封的悸动。"},"ICON-0128":{"nm":"包装纸","de":"比礼物先一步抵达的心意。对齐边角折好、用丝带系上的过程中，收礼人微笑的脸，已在手中提前灿烂地铺展开来。"},"ICON-0129":{"nm":"游戏手柄","de":"拇指比脑袋更先记住的那些按键。输了也\"再来一局\"——那一局终究熬到了通宵。恰好贴合手掌的重量，静静托起今夜的冒险。"},"ICON-0130":{"nm":"信号灯","de":"红灯请暂停，绿灯现在可以走。仅凭一个简单的约定，无数道路便不缠不乱地流淌。等待也有先后次序——闪烁的灯光温柔地告诉你。"},"ICON-0131":{"nm":"箭头","de":"对迷路的人而言最温柔的图形。不知该往何处去而茫然时，某人先划下的一个方向，让停滞的脚步重新坚定起来。"},"ICON-0132":{"nm":"坐标","de":"只要两个数字，世上哪里都能精准点出。约好相见的地方，埋藏宝物的沙滩。为了不让约定迷路，一个小小的点把它牢牢守到最后。"},"ICON-0133":{"nm":"瓷砖","de":"独自时只是方方的一块。与肩并肩躺下的瞬间，便成了地板、成了墙。小小的东西聚在一起，造出某人能安心落脚的位置。"},"ICON-0134":{"nm":"沙漏","de":"上格空了，下格便慢慢被填满。望着簌簌淌落的沙，我们相信时间在流逝。倒转过来又是开头——那是沙温柔的谎言。"},"ICON-0135":{"nm":"球","de":"扔出去会回来，踢一脚便滚走。正因圆，不知会弹向哪里才最有魅力。操场正中央，笑声总是从这小小的球体上圆圆地开始。"},"ICON-0136":{"nm":"开关","de":"咔哒，一下亮起，一下熄灭。走进昏暗房间时按下的那个小小声响，把散乱的一天的开始与结束，分成清晰的一条线。"},"ICON-0137":{"nm":"问号","de":"不知道答案并不羞耻。那是好奇心仍活着的可喜证据。当这个小小的钩子敲打头脑时，学习才终于迈出第一步。"},"ICON-0138":{"nm":"火柴","de":"划着自己来递出火的一根。短短地燃烧、静静地消失，可就在那一瞬，蜡烛被点亮、灶膛被焐热。小小的给予，成了暖意的第一颗纽扣。"},"ICON-0139":{"nm":"脚踏台","de":"只要踏上一只脚，够不到的架子也能伸手碰到。短暂地为某人增高一截。低低俯下身、悄悄把我们抬高的温柔位置，就在这里。"},"ICON-0140":{"nm":"手表","de":"下决心运动那天，最先戴在手腕上的东西。替你数心跳与步数的小小教练，今天会轻轻敲一敲，告诉你比昨天多走了一些。"},"ICON-0141":{"nm":"闹钟","de":"每天清晨被嫌弃的、最勤勉的朋友。多亏它每次替你和被窝里五分钟的诱惑作战，约定与梦想才不会迟到。那讨厌的响声，其实是加油。"},"ICON-0142":{"nm":"果核","de":"剥尽外层后留到最后的最内里。苹果的籽，内心的真心——无论什么，那正中央都装着最坚硬的东西。是摇晃后终究留下的一点。"},"ICON-0143":{"nm":"笔","de":"墨迹未干便蹭在手刀上的印子。写得顺也好不顺也好，在白纸前划下的第一笔，总需要一点小小的勇气。是想法渡到指尖的桥。"},"ICON-0144":{"nm":"毛笔","de":"蘸饱墨，行过宣纸时，连一丝犹豫的颤抖都原原本本留下。想求快便立刻露馅。毛笔最先知晓寄于指尖的诚实。"},"ICON-0145":{"nm":"对话气泡","de":"话还没来得及出口前，先在头顶圆圆浮起的地方。想说的一句，就盛在这里。空着的时候，是正在挑选要填进什么话。"},"ICON-0146":{"nm":"复选框","de":"在空方框里划上两道，心便轻松许多。是给完成的事自己颁发的小小勋章。一天结束时，望着填满的格子，我们又安心于今天也好好活过了。"},"ICON-0147":{"nm":"平板","de":"手指所到之处，图画晕开、文字流淌。静静放在膝上，一个世界便灿烂亮起。虽轻，里面装的可能性却绝不单薄。"},"ICON-0148":{"nm":"遥控器","de":"在钻进沙发缝里这件事上有着天赋。换台的权力，总属于握着它的人。家人之间最小也最亲切的争执，就在这一巴掌大的东西上展开。"},"ICON-0149":{"nm":"配重","de":"为了抓住摇晃的东西，自己降到最低处的重量。上面再怎么动荡，只要下面沉稳，终究不会倒。平衡，总在看不见的地方撑着。"},"ICON-0150":{"nm":"拼图","de":"为找最后一块而摸到沙发底下的夜。严丝合缝嵌进去那一刻无声的快感。散落的东西各归其位时，画面终于完成。"},"ICON-0151":{"nm":"尺子","de":"丈量长度，也是在守护一份约定。为了让每一拃对谁都一样，刻度诚实地排成一列。一道笔直的线，能把走偏的心也理得整整齐齐。"},"ICON-0152":{"nm":"画布","de":"空无一物的白面最让人害怕，却也最让人心动。在落下第一笔之前，它可以成为任何东西。空白不是终点，而是开始的另一个名字。"},"ICON-0153":{"nm":"魔方","de":"为了把六个面都拼好而通宵达旦的人，可不止一两个。指尖一遍遍转动的执着。当打乱的色块各归其位的那一刻，一个小小的宇宙便被整齐地安顿下来。"},"ICON-0154":{"nm":"游戏机","de":"放假时和表兄妹凑在一起盯着看的小小屏幕。掌心里那个小巧的冒险世界。哪怕只听一句开机的旋律，那年的整个夏天就会原封不动地回来。"},"ICON-0155":{"nm":"握把","de":"用力握紧时那股贴合手心的触感，悄悄递来一份自信。不打滑，不脱手。在最关键的时刻，把手和工具牢牢系成一体的连接点。"},"ICON-0156":{"nm":"钢笔","de":"在蘸墨书写的时候，连字迹也变得更端正了几分。伴着笔尖沙沙的声响平复心绪，慢慢落下手写信的第一行——它静静承袭着那份用心。"},"ICON-0157":{"nm":"调色板","de":"红的旁边是蓝，黄的上面是绿。在这块色彩整齐躺卧的小板上，画终于有了表情。调和与叠涂的所有冒险，都从这里迈出第一步。"},"ICON-0158":{"nm":"套组","de":"一件一件单看也许平凡，并排聚在一起便成了一个故事。一块不缺、配齐时的那份踏实。把散落之物聚拢一处，藏着一份小小完成的喜悦。"},"ICON-0159":{"nm":"羽毛球","de":"被球拍击中腾空而起时，羽毛划出的那阵柔软风声。看着轻得飞不远，可一旦认真打起来，它能笔直飞到球场尽头。轻盈，也是一种堂堂正正的力量。"},"ICON-0160":{"nm":"天线","de":"为了抓住看不见的信号，它静静朝天空伫立。把远方的声音也终究牵引过来的那份耐心。信号不好的日子，只要稍稍换个角度，就又清晰起来。"},"ICON-0161":{"nm":"听诊器","de":"凉凉贴上胸口的圆头，还有那一瞬屏住的呼吸。把耳朵凑近那一声小小的鼓点，便有一段最古老的、活着的节拍顺着指尖传来。这是一件以倾听为先的器物。"},"ICON-0162":{"nm":"棋子","de":"慢慢地、每次只走一格的小棋子。可一旦走到底线，它便能成为任何东西。它以迟钝的步伐翻转整盘棋的那一手，旧棋盘默默守望着。"},"ICON-0163":{"nm":"手柄","de":"用两根拇指畅游宇宙的那些夜晚，还记得吗？输了气得一摔，又讪讪捡回的那只满是手泽的握把。隔着屏幕与某人无言分享的、最漫长也最温暖的对话。"},"ICON-0164":{"nm":"主机","de":"一开电源，小小的启动音便像问候一样响起。整个假期都在被窝里开了又关的方盒子，童年的第一场冒险，总是从这块屏幕的光亮里开始。"},"ICON-0165":{"nm":"时间轴","de":"左端是最初，右端是尚未到来的日子。在两端之间随处拖放一个点，以为早已遗忘的瞬间便会再次展开。这是把时间横放成一条线的地方。"},"ICON-0166":{"nm":"棱镜","de":"原以为只是清澈的光，竟暗藏着七种色彩。穿过一片玻璃的瞬间，化作彩虹绽放的秘密。越是端整的东西，里头藏着的颜色越多。"},"ICON-0167":{"nm":"球座","de":"一个把球静静托起的小小托架。越想把球送得远，越需要有什么先稳稳地撑住它。草地上这枚小小的钉，托起了第一步。"},"ICON-0168":{"nm":"织针","de":"一针，又一针。漏掉一针，就得全部拆开从头来过。在膝头上整个冬天慢慢变长的围巾，正是指尖的耐心织成温暖的地方。"},"ICON-0169":{"nm":"旋律线","de":"在歌词落上之前，从嘴角哼哼唱出的那一小节。在那段还没填上字、朦胧的曲调里，藏着歌最坦诚的第一张脸。"},"ICON-0170":{"nm":"雷达","de":"朝着看不见的黑暗发出信号，静静等候那一个归来的光点。哪怕什么也看不见，仍相信那里有什么存在——这是一圈绿光的耐心。"},"ICON-0171":{"nm":"节奏垫","de":"轻轻一点，光与声便同时弹跳而起。让手比脑子更先记住节拍的地方。在掌心铺开的、最小也最温柔的舞台。"},"ICON-0172":{"nm":"颜料","de":"古时的画工把石头与泥土研磨取色。靛蓝出自草，赤红出自土。如今从指尖挤出的这一滴里，也流淌着把自然悉心收纳其中的古老用心。"},"ICON-0173":{"nm":"线条","de":"在下定决心连起点与点的那一刻，它才得以诞生。无论长短、曲直，都是“想往某处走走看”的心意，以最简单的方式留下的痕迹。一切画作的起点。"},"ICON-0174":{"nm":"快门","de":"咔嚓，那短短一次黑暗，便把一个画面永远定住。连眨眼间险些错过的一个表情，也被它把光轻轻切下，凝固成回忆——这是一把小小的刀刃。"},"ICON-0175":{"nm":"安全绳","de":"比攀高的人先一步牢牢系上的绳。替你揪紧那颗怕坠落的心，看不见地守在身边的承诺之绳。它总在你的背后。"},"ICON-0176":{"nm":"锁","de":"挂在仓房上那把沉甸甸的铁锁。它不是要把什么关起来，而是想安心地把珍贵之物搁好的心意。上锁的手势里也藏着用心，那是老宅的踏实。"},"ICON-0177":{"nm":"天平","de":"一边变重，另一边便自然变轻。在犹豫该放上什么、放多少的那一刻，人学会了公平。它用摇摆的两臂，教人何为均衡。"},"ICON-0178":{"nm":"劈开器","de":"再牢固黏合的东西，顺着纹理也终会裂开。一件能把任何东西一分为二、窥看其内的小工具。它是想把合在一起之物重新拆开看看的、好奇心满满的指尖。"},"ICON-0179":{"nm":"计数器","de":"一、二、三。代替手指、默默为你数数的小伙伴。把那颗怕漏数的忐忑心，咔哒咔哒换成安心——它是计数时温柔的同伴。"},"ICON-0180":{"nm":"光标","de":"在屏幕某处闪烁、等待下一道指令的小箭头。即便在你迟疑的时候，它也不离开那个位置，用一缕光的尖端静静招手：现在就开始吧。"},"ICON-0181":{"nm":"岩点","de":"在指尖的力气快要耗尽前，最后抓住的那一点。墙上这小小的凸起静静告诉你：有些时刻，全凭一颗“绝不松手”的心硬撑过去。"},"ICON-0182":{"nm":"鹅卵石","de":"在溪流里久久翻滚、把棱角悉数交出的石头。变圆，是被磨去的时光的另一个名字。轻轻握在掌心，便能摸到那流淌过的河水的耐心。"},"ICON-0183":{"nm":"纹章","de":"古时的家族在一面旗帜上刻下走兽与星辰，以此昭示自己。它是比言语更先递出心意的图画。把一个人的骄傲悉心压缩进小小一格的、古老的标记。"},"ICON-0184":{"nm":"盾牌","de":"挺身阻挡，向来都是为了身后的人。替人接下飞来的箭矢，守护某人平凡一天的、沉甸甸却又温柔的墙。"},"ICON-0185":{"nm":"复活","de":"有一种心，熄灭后又会重新点亮。唯有跌倒过一次，才终于懂得如何重新站起。在以为是终点的地方，悄然涨满的第二口气。"},"ICON-0186":{"nm":"弓","de":"想把箭送得远的手，会先把弦拉到极致。要送它远去，就得先把它揽得那样近——绷成弧形的弓身，静静无言地这样告诉你。"},"ICON-0187":{"nm":"爱心","de":"“喜欢”这句话，总爱缩成一个小小的形状。应援棒的顶端，相抵的指间，都会悄悄画出这个形。这是心意最常见、也最诚实的缩写。"},"ICON-0188":{"nm":"云","de":"顺着风向缓缓流去，每一次都变成不同的脸。一会儿是兔子，一会儿是棉絮，什么都不长久挽留、任其随风而去——这是天空最轻盈的心。"},"ICON-0189":{"nm":"迷宫","de":"这是在死胡同前学会折返的地方。即便在迷途之中，脚步也一点点朝着出口生长。人总要迷一次路，才能练出辨路的眼。"},"ICON-0190":{"nm":"牙齿","de":"曾有把掉落的牙扔上屋顶的风俗。那是盼新牙长得笔直的小小祈愿。它是童年那温柔的约定——成长途中总要失去一次，才能换来更坚固的东西。"},"ICON-0191":{"nm":"行星","de":"从未偏离过自己的轨道、绕星而行的圆润身躯。看似孤单，却总有一份引力让什么伴它一同旋转。默默守住自己的位置，本身便成了一个世界。"},"ICON-0192":{"nm":"星星","de":"迷路的夜里，人们会抬头仰望那最亮的一点。哪怕远得触不可及，它指引的方向却清晰分明。正因遥远，那份约定才愈发坚定。"},"ICON-0193":{"nm":"剪影","de":"背着光站立，人便只剩下轮廓。一个抹去了名字与表情的黑色形影。正因空着，反而让人想象出更多——这是一处未被填满的地方。"},"ICON-0194":{"nm":"耳朵","de":"想唱得好，得先听得好。节拍也好，心意也罢，归根结底都从倾听开始。这是世间种种声音最先抵达、停留的、圆圆敞开的小门。"},"ICON-0195":{"nm":"落叶","de":"有一种叶子，飘落的那一刻最是绚美。把一季的青翠尽染成红，再轻轻放下的那份轻盈。终结也能如此美丽——这是秋天给人的示范。"},"ICON-0196":{"nm":"月亮","de":"曾有在中秋圆光下双手合十许愿的夜晚。圆缺往复、从无一次相同的脸。它是变化着却总照亮原处的一盏灯。"},"ICON-0197":{"nm":"心脏","de":"即便在舞台上，最诚实的终究是这一下下的搏动。再颤抖也不停下，激动起来便跳得更响。它是那颗替你说不尽的应援而怦怦作响的、红色的小鼓。"},"ICON-0198":{"nm":"影子","de":"只要有光，便绝不分离的同行者。越亮越浓，越暗越淡，是陪我走得最久的另一个我。即使在孤单的日子，也有这一个人立在身旁。"},"ICON-0199":{"nm":"尾巴","de":"高兴时自然摇起，害怕时悄悄卷收。嘴再紧闭，也终究藏不住心意的诚实末梢。它是身体先一步泄露的心事。"},"ICON-0200":{"nm":"尾绳","de":"像发带一样系在末端收尾的小绳。怕它松开，便又多打了一道结的那份心意。把易散之物聚拢一处、轻轻安抚妥帖的温柔收束。"},"ICON-0201":{"nm":"瞳孔","de":"话可以斟酌，眼神却藏不住。被看穿的心意最先从这里泄露——那黑色圆圈的深处。哪怕把“喜欢”咽了回去，瞳孔也早已朝着你颤动。"},"ICON-0202":{"nm":"马蹄铁","de":"奔过远路、越磨越坚的一块铁。据说倒挂在门上，来往的福气便会聚在里头。它静静托起某人平安归家的那份期盼。"},"ICON-0203":{"nm":"纹章石","de":"风雨把字迹磨得模糊，可用指尖一点点摩挲，刻入的纹路便又清晰复活。那是某颗不愿被遗忘的心的重量。石头便这样长久地怀抱着一个名字。"},"ICON-0204":{"nm":"蹼","de":"凭脚趾间那一片薄膜，学会推开水的方法。这是大自然悄悄塞给不擅游泳者的一支小桨。哪怕慢，也终能让你抵达对岸——这是一份温柔的设计。"},"ICON-0205":{"nm":"亮片","de":"大家一边抱怨沾上手就要跟好几天，一边在喜庆的日子里头一个找出这些闪光的颗粒。撒上一把星星粉，平凡的纸也会闪一下，今天便变得特别。"},"ICON-0206":{"nm":"爪子","de":"森林里的野兽用爪子扒开泥土，留下自己的路。那不是威胁，而是痕迹——一声“我曾路过此处”的静静签名。锋利的尖端，于某人而言，有时也成了温柔的路标。"},"ICON-0207":{"nm":"闪电","de":"天空短暂摊开掌纹的刹那，光比雷声更先抵达。仿佛在说，趁巨响传来之前先喘口气吧。恐惧与惊叹，总在同一道光里一同诞生。"},"ICON-0208":{"nm":"符咒","de":"在红纸上用墨重重写下的一行祈愿。曾相信压在枕下，噩梦便会绕道而行。祈愿某人平安的那份心意，凭一张薄纸便能这样温暖。"},"ICON-0209":{"nm":"笔翼","de":"有那么一刻，笔尖化作了羽翼。落下一笔时，在纸上滑行的那份轻盈。书写本身即是飞翔——研墨的古人想必也隐约知晓。"},"ICON-0210":{"nm":"骨头","de":"血肉尽数消逝后，才留下来的东西。正因最坚硬，才撑到最后的白色骨架。哪怕时间把一切都带走，它终究只记得形状——这是一桩静默的证据。"},"ICON-0211":{"nm":"鼻子","de":"气味是通往记忆最快的捷径。节日厨房的油香，初雪清晨冰凉的空气——鼻尖先一步察觉，心才慢半拍跟上。"},"ICON-0212":{"nm":"吐司","de":"忙碌的清晨里，最快抓到手的一餐。咬下烤得金黄的那一面，一天份的勇气便酥脆碎开。不必多隆重，正是这些踏实的东西，让人重新振作。"},"ICON-0213":{"nm":"曲奇","de":"在烤箱前等得最久的人，才能尝到第一口。刚出炉的边缘那股暖意，还有片刻的甜。越是想着某人而烤的，不知为何就越甜。"},"ICON-0214":{"nm":"零食","de":"练习拖长的午后，从书包深处掏出的小小一袋。掰成两半，踏实感却神奇地翻了一倍。它是比填饱肚子更先填满心的、一把温柔。"},"ICON-0215":{"nm":"扭蛋","de":"在拧开之前，谁也无从知晓。圆圆的壳里装着的，永远是同一份心跳。它是买卖小小偶然的、世上最诚实的心动。"},"ICON-0216":{"nm":"门把手","de":"开门关门的无数只手，最先触到的地方。从冰凉开始，在掌心里被焐暖——这是家的第一句问候。手泽越积越多，那个房间便一点点成了某人的家。"},"ICON-0217":{"nm":"散步","de":"漫无目的地走，也自有它的理由。那是把缠成一团的思绪，随脚步一缕缕解开的时光。绕一圈回来，答案依旧，心却已轻盈了许多。"},"ICON-0218":{"nm":"滑板车","de":"穿行窄巷的两只轮子。虽不算快，却用全身迎接那阵风。走不远也没关系，只想今天痛痛快快地兜上一圈——总有这样的日子。"},"ICON-0219":{"nm":"安全压杆","de":"上车前，朝胸前牢牢压下的一道横杆。它是陪你撑过整段惊险路程的、踏实的承诺。它冰凉而无言地告诉你：紧紧抓住也没关系。"},"ICON-0220":{"nm":"台阶","de":"一级一级往上爬，不知不觉风景就变了。没有一步登顶的高度——脚掌先一步明白了这个道理。这上上下下本身，于某人而言，便是一天份的脚步。"},"ICON-0221":{"nm":"生态瓶","de":"这不是把森林关进玻璃里，而是悉心培育一个世界。青苔蔓延、水珠凝结的、掌心大小的宇宙。越是凝望，心便越被慢慢染成绿色。"},"ICON-0222":{"nm":"讲台","de":"登上高出一拃的位置，看到的风景便不同了。这是恐惧与自豪在同一高度相遇的地方。随着站上来的人不同，那一阶每一次都成为不一样的舞台。"},"ICON-0223":{"nm":"飞机","de":"云朵铺到脚下的那一刻，离开的地方才终于令人怀念。这不是渐行渐远，而是世界变得更宽广。在小岛上长大的梦，也这样越过了天空。"},"ICON-0224":{"nm":"滑板","de":"得先学会摔倒，才终于能驾驭的东西。每磨破一次膝盖，平衡便一点点刻进身体。摔得越漂亮，便滚得越远——这是诚实的四只轮子。"},"ICON-0225":{"nm":"护照","de":"翻开封面，满是空白的页。每一枚将要盖上的印章，都成了活过的证据。它是一本小书——承载的不是“到过哪里”，而是“能去往任何地方”的可能。"},"ICON-0226":{"nm":"手绘地图","de":"虽没有精确的距离与比例，却因是手绘的路，怎么也不必担心迷失。巷子与店名亲昵地缠在一起的纸。带着心意的指引，总比路本身先一步温暖。"},"ICON-0227":{"nm":"走位图","de":"舞台上的每一步都被画成线条的纸。在哪里停、在哪里转，箭头早已替你约定好。看似自由的舞蹈，其实都从这一张纸开始。"},"ICON-0228":{"nm":"座位指引单","de":"在陌生的空间里，最先摸索寻找的便是自己的座位。顺着排与号，终于抵达的那一格。一张纸，把成千的雀跃一一安顿到各自的位置。"},"ICON-0229":{"nm":"巷弄指引卡","de":"为了迷宫般巷弄里可能迷路的人，有人亲手写下的指引。“在第几个拐角转弯”的温柔字迹。整条街的人情，被工工整整地装进小小一张卡片。"},"ICON-0230":{"nm":"门禁卡","de":"把这张卡挂上脖子，里头世界的门才终于打开。它是准许出入的小小权限，也是“我属于此处”的静静凭证。只有懂得为得到它所付出时间的人，才知道它的分量。"},"ICON-0231":{"nm":"临时入场带","de":"在手腕上一戴，到取下为止便是那一天的一员。一条纸带划开了内与外，成了“共度同一天”的标记。即便扯断之后，那道勒痕也还会留好一阵。"},"ICON-0232":{"nm":"来宾贴标","de":"凭胸前贴上的一枚小小名牌，陌生之地便成了我的位置。当“欢迎”二字载着一张纸递来时，初来乍到的人也终于成了客人。"},"ICON-0233":{"nm":"海报筒","de":"把卷成一卷的海报毫无褶皱地守护好的坚固圆筒。越珍贵的画，越要笔直地舒展着寄出。里头虽看不见，它却怀着某人的用心踏上路途。"},"ICON-0234":{"nm":"资料集封面","de":"包裹厚厚一沓资料的第一页。它是比内容更先触到手的脸。封面端整，连里头的心态也显得端整起来——这是小小礼数的温柔开端。"},"ICON-0235":{"nm":"纪念邮卡","de":"在远方风景的一角写下问候寄出。等它抵达时，寄出的心意也一同微微旧了，反倒更显亲切。这是屏幕里的消息终究追不上的、手写信那缓慢的温度。"},"ICON-0236":{"nm":"礼物吊牌","de":"系在礼物上的小小一张纸。仅凭“给你”两个字，包装便已圆满。它写下的不是“送什么”，而是“想起了谁”——这是世上最短的一封信。"},"ICON-0237":{"nm":"包装贴纸卷","de":"每撕下一格来用，收尾便利落了几分。它是把欲松开的末端端整摁住的小小结扣。用心包好的包装，最后那一手，总出自这卷卷起的带子。"},"ICON-0238":{"nm":"透明信件套","de":"为了不让手写信被岁月褪色，而裹上的透明一层。让字迹照旧可见，只把手泽隔在外面。某人珍惜的心意，被一层看不见的膜静静守护着。"},"ICON-0239":{"nm":"彩色封缄贴","de":"封住信封的最后一点，颜色越鲜明，心意便越不会泄出。它是“拆开之前无人染指”的承诺。秘密，也需要这样一个漂亮的结扣。"},"ICON-0240":{"nm":"留言卡本","de":"把一张张短笺归拢在一起的小书。每一页都是要递给某人的一句话。把来不及说出口的话一一收好，总有一天，要传达的勇气便会长出来。"},"ICON-0241":{"nm":"折叠指引牌","de":"展开是“这边请”，收起便是“今天到此为止”。它在巷口岔开双腿伫立，为可能迷路的人，整整守上一天。被收拢的傍晚，于我而言是最温柔的歇息。"},"ICON-0242":{"nm":"邮件整理带","de":"把一摞明信片往腰间一圈拢住，险些散开的问候便终于成了一束心意。一条轻巧的带子，将要远行的话语端整地捆好，静静目送它启程的背影。"},"ICON-0243":{"nm":"感谢便笺束","de":"因为“谢谢”这句话总在嘴边打滑，便写在巴掌大的纸上，悄悄捆成一束。这束越积越厚，欠下某人的那份心意，也并肩长得越来越厚。"},"ICON-0244":{"nm":"应援口号样张","de":"写着“请这样喊”的一张样本。还没披上嗓音的应援，像一张等待第一个节拍的空白乐谱，静静含着满满的雀跃。"},"ICON-0245":{"nm":"预录申请便条","de":"写着“请安排预录”的便条，总停留在凌晨五点那一格。它仿佛全都懂得，默默替你记下那份宁愿少睡也要占位的心意。"},"ICON-0246":{"nm":"签售顺序券","de":"定下你第几个上前问候的一张券。排队不是在等候轮到自己，而是因为给喜欢的心意排不出号，只好暂且借来一个次序。"},"ICON-0247":{"nm":"等候号手环","de":"凭一个数字，今天排队的先后便分了开来。无论前排后排，把这条轻巧小带戴上手腕的人，终究是为看同一场舞台而聚来的、同心的同伴。"},"ICON-0248":{"nm":"小卡整理表","de":"明明是同一张脸，却说各有不同，一格一格分着记下来。表填得越满，心便越整齐，而空着的那一格，则化作今天想填满的雀跃，让胸口怦怦直跳。"},"ICON-0249":{"nm":"专辑核对单","de":"版本、小卡、是否封缄——用数字一行行写下的爱意清单。预先想象着填满那天的满足，今天也在某一行里，工整地画上一个圈。"},"ICON-0250":{"nm":"应援方法便笺","de":"手势、喊的节拍，连换气的位置都写明。为了让初来的人也能很快汇入同一道声音，这张小便笺便成了亲切的向导，从一只手传到另一只手。"},"ICON-0251":{"nm":"私密备忘本","de":"只把那些谁也不会给看的句子挑出来，写在这里。从未翻开过的那一页最为坦诚——这本本子合着封面，默默守护着这份真心。"},"ICON-0252":{"nm":"纪念日印章纸","de":"盖一下，又一天变得特别。在平凡的日期上“咚”地落下一枚小印，“今天”便悄悄把名字添进了想要记住的日子名单。"},"ICON-0253":{"nm":"记事板封套","de":"哪怕起风，哪怕飘雨，夹住的纸张也守到最后。我甘当记事板的铠甲，是那些写下文字的忠实保镖。"},"ICON-0254":{"nm":"文件索引","de":"为了在厚厚的资料里不迷路，它探出一小片“舌头”，提示着“这里”。一张张彩色的标，把上百页一眼掌管得井井有条。"},"ICON-0255":{"nm":"分类标签","de":"这个归这格，那个归那格。把世间的纷乱一行行理得整整齐齐，便是我的活儿。标签贴上的那一刻，乱作一团的东西才终于各归其位。"},"ICON-0256":{"nm":"迷你审批板","de":"“咚”地盖下印章的那一刻，不知怎的就觉得自己成了真正的大人。个头虽小，权威却利落，一枚通过印，便把堆积的活儿利索地了结。"},"ICON-0257":{"nm":"透明资料袋","de":"里头看得一清二楚，没什么可藏。它怀抱着要紧的纸，生怕淋了雨、皱了角，用透明的身躯将其裹住，护送到约定的地点。"},"ICON-0258":{"nm":"出勤打卡带","de":"来了，又填上一格。每天的脚印顺着带子排列堆叠，看不见的勤勉，便终于成了一眼可见的花纹。"},"ICON-0259":{"nm":"错题整理本","de":"把错的记下来，并不是在收集羞愧。为了不在同一处跌倒两次，把昨日的失误改写成今日的向导，便是它的用意。"},"ICON-0260":{"nm":"日程印章板","de":"在空白日程表上盖一枚章，“约定”便诞生了。手腕一抖、一天便定下来的魔法——那魔法其实是“早早打点”这份勤快的另一个名字。"},"ICON-0261":{"nm":"书脊标签","de":"在书架上背朝外站立的书们的名牌。窄窄书脊上那几个短字，能从数百本里一下子招手唤出你要找的那一本。"},"ICON-0262":{"nm":"照片保护膜","de":"谢绝赤手。连一枚指纹也别留下，它轻轻覆在珍贵的那一张上。喜欢的心意，便是这样以小心翼翼的手势，长长久久地走下去。"},"ICON-0263":{"nm":"胶片索引纸","de":"给胶片一格一格编上号，散落的瞬间便重新找回了故事的次序。它是把光写就的记忆悉心照看、不让弄混的小小向导。"},"ICON-0264":{"nm":"照片收纳袋","de":"把方方正正的幸福一张张供奉其中的透明小屋。不必担心边角被压，最珍爱的那张脸，在这里四季都端端整整地闪着光。"},"ICON-0265":{"nm":"迷你冲印信封","de":"趁刚冲出的照片余温未散，小信封便张开双臂接住它。从巴掌大的口子放进去的那一张，转眼便成了某人包里的宝贝。"},"ICON-0266":{"nm":"光栅卡封套","de":"把一倾斜表情就变的难伺候照片，毫发无伤地守好，便是我的使命。要把每个角度不同的脸全都护住，我也实在不能不勤快些。"},"ICON-0267":{"nm":"镜头分类标","de":"四格里哪一格最佳，标签替你指出来。把拍得好的和搞笑的并排分开的这件小事，正是让回忆再享受一遍的诀窍。"},"ICON-0268":{"nm":"四格收纳带","de":"把窄长的四格回忆整整齐齐地围拢捆好。将那天险些飘散的笑容牢牢抱成一束，平安护送到包的最深处。"},"ICON-0269":{"nm":"照片相角贴","de":"往相册里贴照片时，轻轻托住四个角的小小手。不必涂满胶水也不会掉落——细心，便是这样从边角开始的。"},"ICON-0270":{"nm":"冲印校色表","de":"再暖一点，再稍稍暗一点。一张为调出心仪色彩而反复摆弄数字的表，便把寻常的一张照片，悄悄变成了一件作品。"},"ICON-0271":{"nm":"票据夹","de":"把皱巴巴的票据端端整整地咬住，绝不松口。用小小的嘴麻利地收好一天份的开销，月末结算便轻松了许多。"},"ICON-0272":{"nm":"预约确认单","de":"凭“已预约”一行字，心便慢慢放下了。一张纸成了约定的凭证，把雀跃悉心保管到等候的那一天。"},"ICON-0273":{"nm":"归还确认证","de":"把借来之物放回原处的、虽小却坦荡的证据。这张纸落到手里的那一刻，搁在心头一角的一份“债”，便轻轻一笔勾销。"},"ICON-0274":{"nm":"寄存证夹","de":"为了不让你弄丢取回寄存物的票，由我替你紧紧攥着吧。因为一张小纸的去向，有时也左右着某人一天的收尾。"},"ICON-0275":{"nm":"租借票尾","de":"每件借出之物上轻轻摇曳的小尾标。顺着这条尾巴，谁拿走了什么便一目了然，连失物的谜团也很快迎刃而解。"},"ICON-0276":{"nm":"验收核对单","de":"一件一件用眼睛细细摸排，查有没有遗漏。当核对的勾排成一列填满时，看不见的细致，才终于获得“信赖”这个名字。"},"ICON-0277":{"nm":"结算备忘袋","de":"把进的钱与出的钱写在信封上，乱糟糟的数字便沉静地排起队来。结算的收尾，总由这张小小的备忘，稳稳地落下句点。"},"ICON-0278":{"nm":"配送标签纸","de":"把要去往哪里、抵达谁手中，写在自己身上便启程。这张标签贴上的那一刻，箱子就成了拥有目的地的旅人，雀跃地出发。"},"ICON-0279":{"nm":"签收确认带","de":"把“已平安收到”一句话，用一条带子捆起送回。收件人的安心与寄件人的放心，在这条小小的绳上静静地彼此握手。"},"ICON-0280":{"nm":"单词卡环","de":"把散成单张就会弄丢的单词，用一个小环一齐串住、抓牢。翻了又翻之间，陌生的词不知不觉就成了嘴边熟络的朋友。"},"ICON-0281":{"nm":"发音备注带","de":"在舌尖总打滑的地方，挂上一个小小的标。在口中迷路的陌生音，顺着这条备注走，也不知不觉找回了自己的发音。这是把生涩的声音一点点驯服的第一页。"},"ICON-0282":{"nm":"翻译便笺盒","de":"横跨于语与语之间的小桥，一座座工整地折叠收纳在里头。把好不容易选定的一句写下、悄悄递去，原本不通的心意，也隔着一张便笺渐渐靠近。"},"ICON-0283":{"nm":"句子摘抄纸","de":"正中心扉的句子，得用手抄下来才留得长久。把从书角剪下的一行贴在书桌前，那几个字便静静托起了往下沉的今天一日。"},"ICON-0284":{"nm":"笔记索引","de":"为了在厚书里不迷路而夹下的、五颜六色的小旗。要知道回返之处，才能漫游得更远——探头探脑的标签们，在书页间静静这样提醒。"},"ICON-0285":{"nm":"背诵核对贴","de":"在记下的东西旁“咚”地点上一枚标记。它是把那些在脑中匆匆停留、就要消失之物拴住的小小锚，于是每一格被涂黑的地方，都静静沾着昨夜流下的努力。"},"ICON-0286":{"nm":"测验信封包","de":"在拆封之前，谁也不知道会蹦出什么。用指尖摩挲封口的那几秒——一道题被工整地折叠收进里头，连同心跳一起被封存的雀跃包裹。"},"ICON-0287":{"nm":"语法标签本","de":"规则不是用脑子背，而是用手熟练起来的。从常翻那一面的彩色标签，到被磨得软软的本子，那磨损的边角，便成了你坚持过的时光的年轮。"},"ICON-0288":{"nm":"口语练习表","de":"为开口是世上最难之事的人，准备的一张表。用手指一格格往下点，喉中颤抖的第一句，也不知不觉找回了自己的声音。因为勇气，也是有次序的。"},"ICON-0289":{"nm":"彩色草稿纸","de":"尚未完成的色彩，粗粝地躺着喘息。这不是正确答案，而是仍处在可能之中的状态——在这张未经雕琢的纸上，盛着比什么都多的明天，荡漾着。"},"ICON-0290":{"nm":"情绪板碎片","de":"把零散的印象聚到一处贴起来，那总也抓不住的氛围便隐约显出了轮廓。一种尚无名字的感觉，由这些碎片彼此倚靠着、静静指了出来。"},"ICON-0291":{"nm":"图案样本册","de":"包袱布的格纹与窗棂的编织，在一册里一格格地整理妥当。同一花纹一直重复到底的地方，住着的不是懒惰，而是约定——一颗守住一道纹理的坚定的心。"},"ICON-0292":{"nm":"服装色样纸","de":"明明是同一种色，每块布料染上的肌理与阴影却各不相同。挑舞台服之前，用指尖反复抚过、踌躇不定的那个夜晚，原原本本地标本在一片小小的样张里。"},"ICON-0293":{"nm":"logo禁用示意纸","de":"把不可以做的事先工工整整写下来的纸。在画着红色叉号的轮廓里，自由反倒愈发分明，于是在以为是死路的地方，反而开出了新的路。"},"ICON-0294":{"nm":"色感参考片","de":"颜色实在没法用言语说清，便另做了一片样本。把晚霞最红的某个刹那囚进小小掌心，好对下一个人精准地递出一句：“就是这个颜色”。"},"ICON-0295":{"nm":"排版草稿卡","de":"把什么放在哪里轻轻勾画出的第一张图。定位置即是定心意，于是在生涩散落的线条之间，整体的均衡慢慢睁开了眼。"},"ICON-0296":{"nm":"材料备忘板","de":"木、土、石——可触之物的名字密密麻麻地写着。只有先用手读懂纹理再动工的人才知道的秘密：用什么来造，已经差不多半数决定了会成为什么。"},"ICON-0297":{"nm":"图样描摹纸","de":"在底稿上覆一张薄纸，静静顺着线条描。借用他人之路的同时，我的手熟悉了那条路，在描摹的线条之间，不知不觉便悄悄长出了只属于我的线。"},"ICON-0298":{"nm":"入场动线带","de":"顺着长长贴在地上的带子，人们排着队鱼贯而入。它是为了不让雀跃的脚步乱作一团而静静指引的一条线——是托住雀跃不致崩塌的、看不见的温柔的手。"},"ICON-0299":{"nm":"活动指引牌","de":"替人举着“这边请”一句话伫立的牌子。为了不让谁迷路而立在各个路口的小小亲切，像牵手一样，静静领着初来者陌生的一天往前走。"},"ICON-0300":{"nm":"展位号标","de":"给每个展位编上的一个号码，把那一格的主人分得清清楚楚。虽是小小的数字，却是“这里是你的位置”的约定，于是在陌生的会场里，有了可以归来的地方。"},"ICON-0301":{"nm":"工作人员同意书","de":"在决定携手共事的那一刻留下的一行签名。虽只是薄薄一纸，里面却承载着愿意彼此信任的分量，活动中的每一份心力都从这里开始。"},"ICON-0302":{"nm":"体验券一束","de":"刚好一手能握住、厚厚扎成一捆的体验券。它越发越多人收，不但不会减少，反而不断为别人增添一个个\"第一次\"，是越摸越暖的人情之束。"},"ICON-0303":{"nm":"排队指示牌","de":"请从这里开始等候，地面低声这样招呼。守序的心意聚在一起，再长的队伍也成了一道风景，一个小小的标识便把焦躁换成了从容。"},"ICON-0304":{"nm":"现场领取吊牌","de":"在亲手领取预订之物的地方轻轻挂上的小吊牌。握到手里的瞬间，肩头便缓缓松下那份轻盈的安心——久候的心终于有了形体的那个结。"},"ICON-0305":{"nm":"随机盒抽签","de":"在不知里面装着什么的情况下挑一个的乐趣。摇一摇，里面咯哒作响，心先一步跳起，开启前的那一刹那成了一天中最鼓胀的时光。"},"ICON-0306":{"nm":"交换完成贴纸","de":"宣告互换顺利结束的小小圆形印章。它是留在彼此手与手之间那个光滑的句号，轻轻一贴，这场交易才算温暖地圆满起来。"},"ICON-0307":{"nm":"记录封缄带","de":"用带子把珍贵的盒子绕上一圈静静封好。这既是请勿随意开启的嘱托，也是把里面之物视若珍宝的、最安静的礼数，全都凝在这一条带里。"},"ICON-0308":{"nm":"秘密便条胶囊","de":"把想说的那句话妥帖地关进小筒里收藏。像把未能寄出的心意埋藏起来般紧紧合上，直到某天重新打开的那日，掌心这座小金库为它守住时光。"},"ICON-0309":{"nm":"小巧剪贴卡","de":"剪下贴上的一片小角，隐隐沾着那天的心情。它比日记轻盈，又比照片更有手作的温度——容易从指缝间散落的一天，被这巴掌大的纸牢牢留住。"},"ICON-0310":{"nm":"初访记录纸","de":"初次踏上这座岛那天的悸动，化作短短一行留下。在陌生即将转为亲切的前一刻，纸替你怀抱那最清澈的初心，长久珍藏。"},"ICON-0311":{"nm":"回忆分类表","de":"依着纹理与脉络，把回忆一一分门别类记下的表。若把所有记忆胡乱堆进一个抽屉，连最珍惜的那一天也会被埋没，所以越珍贵的，越要妥帖地安放归位。"},"ICON-0312":{"nm":"话泡便签片","de":"想说的话像气球般圆圆地鼓起，浮在纸上。连说不出口的那一句，在圆圆的边框里也悄悄鼓起勇气——这是让心意溜出来的小小温暖通道。"},"ICON-0313":{"nm":"日期立座","de":"把今天是几号端端正正立起、与你相对的小底座。在一串串流逝的日子里挑出唯一的一天端坐于正前，平凡的日期也会染上值得纪念的暖意。"},"ICON-0314":{"nm":"收藏编号吊牌","de":"为每件珍爱之物逐一编上的专属号码。所谓收藏，就是承诺把那一件当作世上独一无二来呼唤，小吊牌上的数字清晰刻下了心意的分量。"},"ICON-0315":{"nm":"档案内页","de":"把要长久珍存的东西一张张夹进去的薄薄内页。让它与光与时间稍稍隔开一层——所谓爱一样东西，归根结底就是把它好好保存下来。"},"ICON-0316":{"nm":"小卡卡套挂绳","de":"让卡套能挂在脖上的细细挂绳。这是把本命揣在胸前、走过一整天的追星方式，整日温柔的相伴，都系在这一根细绳上。"},"ICON-0317":{"nm":"小卡支架别针","de":"仅凭一枚小别针，小卡便能在桌上端端正正立起。平放时只是一张纸，立起时才成了彼此相望的关系，悄悄为目光留出久久停驻的位置。"},"ICON-0318":{"nm":"镭射小卡膜","de":"随角度流泻出彩虹的一层薄膜。这层把光稍稍囚住的膜，给平凡的卡披上星光，每当手腕一晃，便有不同的神情闪着醒来，是个小小的魔法。"},"ICON-0319":{"nm":"小卡保护壳","de":"仿佛只要边角被压一下，连珍爱的心也跟着折了一下。它是把珍贵的一张紧紧拥住的透明铠甲，真心珍视的事，总伴着这样的小心翼翼。"},"ICON-0320":{"nm":"小卡整理托盘","de":"把几十张小卡顺着纹理整整齐齐躺好安睡的浅盘。散开时只是一堆，排好队躺下便成了收藏，整理的每一下手心，都层层刻下爱意的次序。"},"ICON-0321":{"nm":"小卡交换信封","de":"把一张小卡装进信封递出时，指尖会稍稍迟疑。这不是送走，而是托付它去成为某人的本命。封口折下的瞬间，一段小小的缘分悄然换了手。"},"ICON-0322":{"nm":"小卡装饰笔","de":"填满留白的不是字迹，而是心意。笔尖划过之处，长出小小的爱心与星星，平凡的一张纸醒来，成了世上独一无二的应援。装饰，正是告白的另一个名字。"},"ICON-0323":{"nm":"小卡夹环","de":"咔哒一声，夹子合拢的声响。就这小小一扣，险些散落的卡片便聚成一列。哪怕在包里晃荡一整天，也不让一个边角受伤。坚固原来这般无声。"},"ICON-0324":{"nm":"小卡随行收纳袋","de":"开合拉链的手不知不觉养成了习惯。遇上阵雨，挤进人潮，唯独里面始终干爽。把最珍爱的放在最深处，这份心意，正是名为携带的温柔劳动。"},"ICON-0325":{"nm":"粉丝见面会手环绳","de":"有位粉丝久久记得，那位为她在手腕系绳的工作人员，手是温热的。一个结便是今天属于此地的标记。怕松开而绕了两圈的那根绳，牢牢系住了这一天份的悸动。"},"ICON-0326":{"nm":"入场手环带","de":"正是穿过入口的那一刻，里与外才被清晰地分开。整日戴着戴着，不觉便贴合了肌肤，解下时还留着浅浅的印痕。仿佛曾在那个地方停留过的证据。"},"ICON-0327":{"nm":"谈话环节抽签片","de":"谈话环节一开始，一枚签子便咕噜噜滚出去。谁先开口、抽到哪个问题——那小小的偶然，便能把气氛整个翻转。比起排好的剧本，这一颗签子的任性更惹人喜爱。"},"ICON-0328":{"nm":"签售会等候券","de":"手里握着写有号码的纸排起队。142号。在数着前面141人的工夫，心已先一步数着轮次。等待虽长，多亏这一张，连那段时光也成了悸动的一部分。"},"ICON-0329":{"nm":"击掌手套","de":"手掌相触的刹那，手套替你接住那短短一瞬的暖意。为了0.5秒的相遇，整日捂热的手。即便隔着布，也挡不住那份颤动——人人都是到那时才明白。"},"ICON-0330":{"nm":"纪念拍照别针","de":"咔嚓一声，今天就这样被定格封存。用别针固定住的画面里，连尴尬的笑脸，日后也成了最令人怀念的一幕。记录，是把瞬间留住的、最温柔的贪心。"},"ICON-0331":{"nm":"座位丝带吊牌","de":"挂在座椅靠背上的小丝带，明明无风却轻轻摇曳。那是某人系下的标记，是这里曾有人在的痕迹。演出结束后的空座上，唯有丝带仿佛还记得那段节拍。"},"ICON-0332":{"nm":"礼物检收标签","de":"每一份礼物都贴上标签。寄出了没、确认了没、有没有遗漏。收下心意这件事也需要打理，这枚小贴纸把一份份诚意毫无遗漏地一一连起。"},"ICON-0333":{"nm":"纪念内页","de":"为了长久珍存而写下的一纸。那天的天气、座位号，连最后一首歌的歌名。记忆会模糊，唯有这张内页不曾模糊。保存回忆，原来也需要一份小小的格式。"},"ICON-0334":{"nm":"应援毛巾挂扣","de":"把挂扣套在毛巾一端，便不会从肩头滑落。擦汗、举过头顶挥舞、再挂回脖上的动作之间，一个小小的连接，让应援的姿态绵延不断。"},"ICON-0335":{"nm":"标语夹","de":"夹子把标语两端牢牢咬住。即便高举双臂，字也不会折皱或乱飘。在看不见的地方默默把讯息撑直的、最沉默的配角，就在这里。"},"ICON-0336":{"nm":"静音收纳袋","de":"拉链缓缓地、无声地滑动。在约定要安静的场合，为了不漏出一丝杂音而设计的沉默。所谓体贴，有时就是把声音变得听不见，这只袋子静静这样说。"},"ICON-0337":{"nm":"掌声节拍片","de":"每当双掌相击，片子便数着拍子。啪、啪、啪——散落的掌声不知何时聚成了同一个节奏。几千人的掌声化作同一口呼吸的那种魔法，小小的片子悄悄相助。"},"ICON-0338":{"nm":"应援法折页","de":"翻开来，应援法分步骤一一写着。哪一段举什么颜色，何时喊声。初来的人只要这一册折页，转眼便成了自家人。这是分享约定的小小指南。"},"ICON-0339":{"nm":"座位扇子挂绳","de":"把挂绳系在扇柄上，即便脱手也不会掉落。炎热天里挥着扇，欢呼时双手得空，它便在手腕上晃晃悠悠。一根挂绳，把暑气与兴奋一并消解。"},"ICON-0340":{"nm":"闪亮膜碎片","de":"受光时，每一片都以不同的角度碎裂开来。放在掌心，便有小小的彩虹晃动，每一晃，颜色都活起来流转。所谓闪亮，或许就是把光细细分着拥有。"},"ICON-0341":{"nm":"小型横幅杆","de":"撑开小杆，布料便迎风绷得笔直。双手高举，字便能越过看台直抵远处，一折又能塞进包的一角。心的大小，可不是用杆的长短来量的。"},"ICON-0342":{"nm":"应援贴纸包","de":"每一张贴纸上都印着应援字句。贴在日记本上、手机上、笔记本电脑的边角——贴到哪里，日常就被应援染到哪里。喜欢的心意，就这样四处留下痕迹。"},"ICON-0343":{"nm":"专辑保护套","de":"用套子裹住专辑的手格外小心。不让边角磨损，不被阳光晒褪。音乐用耳朵听，这一张却由手记住。它是想把珍爱之物长久留在身边的、心的铠甲。"},"ICON-0344":{"nm":"碟片内袋环","de":"把碟片装进内袋，再用环扣起，便成了一本唱片册。一张张翻动时那沙沙的声响真好听。把散落的音乐在手中整整齐齐聚拢，正是收藏者安静的幸福。"},"ICON-0345":{"nm":"周边收纳隔板","de":"一块隔板，让险些混在一起的周边各归其位。这里是小卡，那里是钥匙扣，旁边是应援棒。整理，就是为物件盖起一座家。隔出格子的瞬间，杂乱便化作了秩序。"},"ICON-0346":{"nm":"随机包封缄绳","de":"用绳子把随机包的口扎紧，谁的命运都还未定。开封之前，人人都是期待的主角。解开封缄时指尖的那份颤动，正是这根绳守护的乐趣。"},"ICON-0347":{"nm":"特典整理盒","de":"特典们在盒子里按种类排起队。明信片归明信片，书签归书签。看着越攒越满的格子，这一路攒下的时光便一目了然。整理，就是一份回忆的清单。"},"ICON-0348":{"nm":"版本区分标签","de":"有些东西看似相同，其实并不一样。一枚标签，把A版与B版、初版与再版分了开来。多亏这小小标识，混淆消失，收藏的世界又添了一枚清晰的名牌。"},"ICON-0349":{"nm":"首周销量记录便条","de":"发售头一周，一个数字便能让心起伏。便签上一笔一画记下的勾选符。几天的记录聚起来，便成了一份小小的应援成绩单。这是把喜欢的心意翻译成数字的、用心的习惯。"},"ICON-0350":{"nm":"海报固定盖","de":"给卷成一卷的海报两端套上盖子，它便乖乖摊平着待着。在犹豫要挂上墙还是装进框的工夫，也不让它皱起。是把最喜欢的画面平平整整守护好的小塞盖。"},"ICON-0351":{"nm":"立式照片底座","de":"照片在底座上斜斜地立起。摆在桌角，正好与视线齐平的角度。这发明，让你每次经过都与它对上眼。把喜欢的脸纳入每日风景里，最简单的方法。"},"ICON-0352":{"nm":"彩排胶带卷","de":"把胶带贴在地上，标出该站的位置。一格、两格，正正好就在这里。把同一道印痕踩上几十遍，走位便刻进了身体。华丽舞台的脚下，铺着这诚实的胶带印。"},"ICON-0353":{"nm":"舞台走位别针","de":"钉在舞台地面的一枚别针，告知下一步该往哪迈。即便在黑暗中，脚尖也会先一步找到那个位置。看不见却精准的路，是无数次练习画下的、看不见的地图。"},"ICON-0354":{"nm":"工作人员耳塞帽","de":"塞上耳塞帽，看台的欢呼便低下一层，唯有传递提示的嗓音变得清晰。后台工作人员的耳朵，总在同时听着两个世界。它是在喧闹中挑出信号的小工具。"},"ICON-0355":{"nm":"休息室衣架标牌","de":"每个衣架上都挂着名牌。1号服装、2号服装、安可服装。看着那张写满换装顺序的标牌，一天的舞台便先以衣服的次序勾勒出来。是驯服忙乱的安静秩序。"},"ICON-0356":{"nm":"道具检收标签","de":"登台之前，每一件道具都被扣上标签。有没有遗漏、是否完好。看台并不知晓，可这小小的检查防住了事故。看似完美的舞台背后，总有一双细致的手。"},"ICON-0357":{"nm":"提示信号片","de":"提示信号片从一只手传到另一只手。现在，上场。一句话都不必说，时机便已传到的那一刻。在舞台旁的黑暗中，这小小的信号牢牢守住所有人的节拍，不让错过。"},"ICON-0358":{"nm":"后台通行徽章","de":"有一扇门，只有戴着这枚徽章的人才能通过。舞台之后，欢呼隔着墙传来的地方。一小片布，分开了华丽的台前与忙碌的幕后。它是撑起舞台之人的标记。"},"ICON-0359":{"nm":"提词器遮光板","de":"遮光板拦住提词器的光，不让它漏向看台。只让台上的人看见，看的人却浑然不知。它静静遮住那一份不可被察觉的帮助，是舞台斯文的守密人。"},"ICON-0360":{"nm":"休息室镜罩","de":"演出结束的休息室，用布盖住镜子。整日映过无数表情的玻璃，暂且阖上了眼。卸去妆容的素颜最后面对的，不是镜子，而是静谧的黑暗。"},"ICON-0361":{"nm":"预录入场手环","de":"一旦扣上，不剪断便解不开的小小带子。为了进入预录看台那唯一的一份资格，有人在漆黑的凌晨搭上了首班车。手腕的分量，便成了那一天份的悸动。"},"ICON-0362":{"nm":"录制等候标签","de":"红灯亮起前的一刻，把众人的呼吸拢成一条线，是我的活儿。在等候提示信号的寂静里，我默默坚持到最后。被揭下的瞬间，正式开播的帷幕才缓缓拉开。"},"ICON-0363":{"nm":"摄像机位置片","de":"印在地上的一个小标记，麻利地定下六台摄像机的走位。在哪儿被拍到最明亮，导演彩排前便已了然。是在画面之外，预先勾画画面之内的手。"},"ICON-0364":{"nm":"音响检测吊签","de":"对着空荡的看台，把麦克风轻轻敲一敲。回响过长，便在天花板再添一层吸音材料。在观众不知不觉间打磨声音纹理的那份用心，便从这小小的吊签悄然开始。"},"ICON-0365":{"nm":"现场盖章册","de":"每经过一处现场，便集一格印章。每一处晕开的墨痕里，都一并印着那天的天气与心跳。集满的那一页，会成为谁也仿不来的、只属于我的足迹地图。"},"ICON-0366":{"nm":"电视台访客证挂绳","de":"没有这根绳，大厅的闸门便不会开。挂在脖上一步步走过走廊的工夫，昨日还只在屏幕里见过的世界，慢慢近到了伸手可及。"},"ICON-0367":{"nm":"录影棚鞋套包","de":"录影棚的地板总是又凉又滑。脱下鞋穿上薄薄的鞋套，脚步声便悄然消失。镜头要拍的是舞蹈而非脚步声，抹去声响，也是对舞台的一份礼数。"},"ICON-0368":{"nm":"休息室零食吊牌","de":"彩排与正式录制之间，饥饿来得最是诚实。休息室一角，每份零食上都写着是谁的份的小名牌。这份事先备好的温柔，让漫长的一天能撑到最后。"},"ICON-0369":{"nm":"复盘笔记带","de":"回看画面边看边记。这里调整视线，那里慢半拍。密密麻麻的字，是写给明天的我的秘密信。末尾系上的这条带，是要比昨天进步一寸的、安静的约定。"},"ICON-0370":{"nm":"展示会邀请内页","de":"一纸文书，于某人或许便是整整一年的等待。\"诚邀您出席展示会\"这短短一句，连同拆封时指尖的颤动，化作了世上最小的请柬。"},"ICON-0371":{"nm":"媒体证挂绳","de":"挂在记者的脖上，穿行于快门声的正中央。为寻最佳角度而奔忙的脚步，那份速度便成了把舞台的热度传向外界的通道。"},"ICON-0372":{"nm":"谢幕顺序表","de":"为了即便在掌声如潮涌来的瞬间也不慌乱，谁先谁后，都一行行写好。最后一次谢幕的排序，往往与初次登场一样用心编排。"},"ICON-0373":{"nm":"拍照墙地面标记","de":"拍照墙前的地面，早已刻好该放脚尖的位置。只要偏一步，背景的标志就会被切掉。被拍得最明亮的那个位置的秘密，悄悄标在了脚下。"},"ICON-0374":{"nm":"首映会手环","de":"影院灯光熄灭前一刻扣在手腕上的小带子。帷幕一拉开，所有人便在同样的黑暗里，平生第一次相遇同一个画面。它是那第一瞬曾共在一处的、小小的入场标记。"},"ICON-0375":{"nm":"纪念幕布碎片","de":"末场那天，最后一次谢幕之后，幕布缓缓落下。把那一幅剪下、装进相框的碎片。布上还微微残留着灯光的热度与掌声的震颤，尚未冷却。"},"ICON-0376":{"nm":"首次公开印章","de":"向世界初次露面的那天，为那唯一一次而刻的印章。第二次的\"首次公开\"并不存在，所以连墨迹风干的那短短一瞬，也是再不会回头的时光。"},"ICON-0377":{"nm":"舞台片段卡","de":"把一场舞台中最闪耀的一帧剪下，收进卡里。音乐与灯光都已停下，可握到手里的瞬间，那天的欢呼又在耳畔鼓胀起来。是让定格的画面复活的小小魔法。"},"ICON-0378":{"nm":"结尾pose便条","de":"最后一个音落下的刹那，把该停住的指尖与视线角度画下来的便条。唯有深知结尾一帧能左右几日的人，才会把这张小图珍重地折好。"},"ICON-0379":{"nm":"巡演城市别针","de":"地图上，每去过一座城市便钉上一枚别针。釜山的海风、光州的正午，都钉在这小小的钉尖上。把这些点静静连起，便看见一条横贯一整季的漫长旅程之线。"},"ICON-0380":{"nm":"座位区域夹","de":"把数万个座位分成区域来指引方向。不让人迷路，不让人相撞。跟着我，谁都能抵达自己的位置。所谓秩序，归根结底是为所有人着想的小小善意。"},"ICON-0381":{"nm":"入场闸口吊牌","de":"在闸口前，一个人一个人依次接受确认。这是把握着票的手与怦怦跳的心引入内场的最后一道关。经过我的瞬间，漫长的等待便结束，今日的舞台正式开始。"},"ICON-0382":{"nm":"手环保存胶囊","de":"纵使颜色褪去，那天的欢呼依旧被原样封存。舍不得丢掉手腕上的带子，便妥帖地卷进小胶囊里。我想，珍贵的回忆也该有一格能安放自身的地方。"},"ICON-0383":{"nm":"现场交接杆","de":"粉丝与舞台之间，有什么从一只手传到另一只手。或许是信，或许是小礼物。我为那份心意能平安抵达而开出一条路，是现场最忙碌的桥。"},"ICON-0384":{"nm":"演出日期封印章","de":"那天的日期被印进圆圆的封印章里，永远停住。日历会翻过去，唯有这小小的圆停留在那一天。但凡是不想忘却的日子，人们总会把什么封存起来。"},"ICON-0385":{"nm":"巡演包补丁","de":"一同走过巡演的包，每到一座城市便多一片补丁。缝在布上的地名不知不觉成了一份履历。连磨损起毛的边角，也作为\"哪里都一同去过\"的证据留了下来。"},"ICON-0386":{"nm":"票务展示牌挂绳","de":"在入场队伍末端晃动的展示牌，把它一端牢牢系住的一根绳。在高举着票的双手长长排开的风景里，我静静标出这列悸动行列的最前端。"},"ICON-0387":{"nm":"安可丝带碎片","de":"高喊安可的声音最响亮的那一夜，装点舞台的丝带掉下一片。就像因不舍结束而唱得更长的歌，这一片碎片上，也打着舍不得离去的心结。"},"ICON-0388":{"nm":"讯息胶囊瓶","de":"妥帖折好、放进玻璃瓶里的一句话。像盼着有朝一日抵达而放出的小船，我怀抱着心意，在时间之上慢慢漂流。直到被打开的那日，约定在瓶里静静沉睡。"},"ICON-0389":{"nm":"小小告白吊牌","de":"把说不出口的话写在小吊牌上，悄悄夹了进去。字迹虽颤抖，真心却分明。有时候，最小的一纸，怀抱着最大的勇气。"},"ICON-0390":{"nm":"匿名应援纸条箱","de":"不写名字，心意也能传达。投进箱里的每张纸条，都匿名地一层层堆起某人的应援。不知是谁写的，温暖却分明，是一本没有面孔的温柔合集。"},"ICON-0391":{"nm":"心愿折纸","de":"方方的纸顺着指尖变成了纸鹤，变成了星星。每折一次，所盼的心也叠上一层。在用心折出的形状里，栖着比言语更长久的真心。"},"ICON-0392":{"nm":"封缄丝带火漆","de":"滴下烛蜡，再用印章使劲一按，信便终于封好。一如那把心意稳稳凝固的古老方式。在渐渐冷却的红蜡上，一个秘密静静锁住。"},"ICON-0393":{"nm":"礼物缓冲纸","de":"怕礼物受损，便柔柔地把它一圈圈裹住。每一道揉皱的纹理里，都渗着\"别碎啊\"的叮咛。收礼的人或许浑然不觉，那是看不见处的、小心翼翼的一层心意。"},"ICON-0394":{"nm":"彩色信件绳","de":"捆信的绳也有颜色。黄色是应援，蓝色是思念。把言语道不尽的情感，挑成色彩打成结。还没解开，心的温度便先一步传到指尖。"},"ICON-0395":{"nm":"手写遮挡带","de":"递出之前一直把字遮住的一条带。它把怕被发现而忐忑的告白守护到最后一刻。轻轻一掀便显露的真心，那份颤动的分量，我在最近处懂得。"},"ICON-0396":{"nm":"应援句子片","de":"应援棒如波浪起伏的夜晚，要齐声高喊的一句话刻在片中。它是把散落的心拢成一行的约定之言。当大家一同呼喊，那句话便闪得最为耀眼。"},"ICON-0397":{"nm":"旧练习室钥匙扣","de":"把练习室的门开关了数百次的钥匙扣。漆已剥落，环已松动，可那里以手泽的形式，留着最青涩岁月的汗水。所谓旧，意味着曾在那里停留得够久。"},"ICON-0398":{"nm":"舞台妆笔碎片","de":"舞台用妆容唯有在灯光下才算完成。那浓重色彩的一片。汗水也晕不开、牢牢上好的痕迹里，原原本本渗着想把表情传到远处看台的那份用心。"},"ICON-0399":{"nm":"耳塞收纳盒","de":"在舞台上让人听见自己声音的小小入耳塞。演出结束后，便把它妥帖地躺进盒里。越是在最近处传递音乐的东西，越想更用心地保存它。"},"ICON-0400":{"nm":"私人储物柜标签","de":"宿舍走廊尽头，每个储物柜上贴着的名牌。告知这是谁的位置的小字，把陌生的空间变成了家。有了属于自己的一格，便是\"留在这里也没关系\"的温柔许可。"},"ICON-0401":{"nm":"便携护嗓壶","de":"彩排间隙，把温温的水一口口慢慢咽下。嗓子是歌手借来用的乐器，所以趁它没凉前补满的这只小壶，预先守护着明天的第一个音。珍惜的心意，总是这般安静。"},"ICON-0402":{"nm":"日程提醒别针","de":"在以分钟塞得满满的一天上，一枚别针指向下一格。在那密密的排列之间，最叫人欢喜的，是空着的那一格。能稍稍望一眼窗外的时间，就小小地藏在那里。"},"ICON-0403":{"nm":"休息室毯子夹","de":"妆已上完、靠在椅上打盹的午后，有人轻轻为我披上了毯子。怕它滑落而咬住的这枚夹子，把那只手的暖意一直牢牢留到登台的时刻。"},"ICON-0404":{"nm":"小小香水试管","de":"在手腕内侧轻轻拍一下，香气便只在这一掌的范围内绽开。飘不远也没关系。正因是只有走近的人才能察觉的痕迹，才更隐秘，也才更像我自己。"},"ICON-0405":{"nm":"练习服洗涤吊牌","de":"无论洗多少遍，深深浸进布料里的汗味终究除不尽。把晒得蓬松干爽的练习服重新叠起时，我想——那除不去的印痕，其实才是最诚实的痕迹。"},"ICON-0406":{"nm":"灯光色片","de":"嵌进一张薄薄的色片，白光便晕成晚霞色，再叠一张，黎明便降临。要把舞台染成怎样的季节，给光也披上衣裳的手，正在幕后屏息以待。"},"ICON-0407":{"nm":"聚光灯镜头盖","de":"即便相机关着，也有人打开这小小的盖子擦拭镜头。为了那尚未拍下的下一个画面。在不被收进屏幕的时间里，最忙碌的手预先对好了焦。"},"ICON-0408":{"nm":"舞台反光板","de":"有一种板，自身并不发光，却把接到的光返照向阴影里的脸庞。舞台正中之所以那般明亮，是因为边缘有谁默默调着角度照射的那条手臂在那里。"},"ICON-0409":{"nm":"彩色滤镜套","de":"在透明的套里嵌入蓝光，看台便整个变成海，换成红光，那里便落下晚霞。同一座舞台仅凭一种颜色就化作不同季节的魔法，便从这薄薄一层开始。"},"ICON-0410":{"nm":"灯具编号别针","de":"无数盏灯上都贴着小小的编号。哪一号亮起、哪一号沉睡，今夜演出的流走，便以这些数字的次序预先编好。耀眼帷幕的背后，总铺展着一份细致的清单。"},"ICON-0411":{"nm":"灯光胶带标记","de":"暗场的舞台地面，荧光胶带静静照亮该停步的位置。看台上看不见，可演出者的脚尖会摸索着这微光找到自己的方位。黑暗中也有温柔的引路人。"},"ICON-0412":{"nm":"遮影板","de":"挡住漏进来的光、让影子清晰落下的板。驾驭黑暗归根结底也是驾驭光，要展示什么，先取决于要静静遮住什么。"},"ICON-0413":{"nm":"照度检测片","de":"测量空间明暗的小片，在掌心读出数字。太亮、太暗，眼睛都会不适。人停留得最舒适的那条看不见的合适线，由这枚片悄悄守护着。"},"ICON-0414":{"nm":"聚光灯遮罩","de":"为防聚光灯漏向别处而加上的遮罩。把光只汇聚到一个人身上，是一种温柔的专注。踏入那圈圆圆光晕的瞬间，世界便暂且只凝望唯一一人。"},"ICON-0415":{"nm":"耳塞套组","de":"与耳朵严丝合缝咬住的一对耳塞。尺寸只要稍有偏差声音便会漏出，一漏，便错了拍。舞台上分毫不晃的歌声，有时其实就始于这一小只橡胶。"},"ICON-0416":{"nm":"线缆魔术贴","de":"把缠乱的线整整齐齐扎成一束的魔术贴绳。越是无人看见的幕后，整洁越显光彩。一束线缆的整饬，静静撑起了台前毫不动摇地流淌的声音。"},"ICON-0417":{"nm":"线路检查标签","de":"几十根线上，用手写标着是哪件乐器的名牌。那一个个歪歪扭扭的字各守其位，原本各自为政的声音，才终于汇流成一首曲子。"},"ICON-0418":{"nm":"静音垫","de":"把脚步声与震颤都静静吞下的一张静音垫。它铺在非要静谧不可的地方。最澄澈的声音，有时正是在这片不漏一丝杂音的安静地面上，才得以诞生。"},"ICON-0419":{"nm":"音响检测代币","de":"演出前调试声音的工夫里，在手中渐渐捂热的代币。每检查完一支麦克风、一台音箱，便换个位置握着。正场的完美，便在这安静的预演里一步步雕琢成形。"},"ICON-0420":{"nm":"麦克风保护帽","de":"正因是无数嗓音触碰过的地方，才更用心地擦拭裹住麦克风顶端的这只帽。它是盛纳歌声的器皿，于歌手而言无异于又一只手。擦拭的工夫，预先描摹明天的第一句歌词。"},"ICON-0421":{"nm":"防喷罩夹","de":"垂在唇与麦克风之间的薄薄一层网。多亏那把网撑住的小夹子，原本粗粗漏出的气息，不知不觉被打磨成圆润柔和的嗓音流淌而出。"},"ICON-0422":{"nm":"音响机架标签","de":"漆黑的幕后，为了不在层层堆叠的器材架间迷路而挂上的小标签。填满看台的华丽之声，其源头总是这般在幽暗处一一收拾整齐。"},"ICON-0423":{"nm":"音箱网罩别针","de":"把音箱网罩牢牢固定住的别针。声音透出的窗口是最先沾上灰尘的地方，便用薄薄一层网守住音色。凡是触及耳朵的一切，都被一层看不见的保护悄悄罩上。"},"ICON-0424":{"nm":"走位标记贴纸","de":"在地上一点点贴好的走位贴纸。群舞如刀般整齐划一的秘密，其实就藏在脚下。在几十人踩着同一个点散开又重聚、约定了无数次的印痕之上。"},"ICON-0425":{"nm":"转圈练习圆盘","de":"在原地一圈圈转动的练习用圆盘。要战胜眩晕，得先从把视线钉在一个点上学起。无论转得多快也不松开那一点，是慢慢刻进身体的平衡。"},"ICON-0426":{"nm":"护膝胶带卷","de":"把膝盖牢牢缠好的一卷胶带。跳过、落地过数千次的关节终究沉默不语，而这一层静静把那份沉默托住。坚持到最后的身体背后，总有谁的悉心照料。"},"ICON-0427":{"nm":"脚尖对齐板","de":"把脚尖的角度整齐定住的板。人们都说，舞蹈是在脚尖而非指尖处完成的。朝同一方向伸出的几十只脚尖聚在一起，便造出众人宛如一人的魔法。"},"ICON-0428":{"nm":"练习室防滑垫","de":"铺在练习室地面的防滑垫。要尽情跳，得先安全。在不必担心摔倒、能放心翻滚的地面上，最大胆无畏的动作才得以绽放。"},"ICON-0429":{"nm":"动作分解卡","de":"把编舞一拍一拍细细拆开画下的卡。再难的动作，分成一格格便不知不觉跟上了。舞台上行云流水般顺滑的流走，正是这些拆开背熟的图聚在一起造就的。"},"ICON-0430":{"nm":"镜面遮帘别针","de":"把暂且遮住练习室镜子的帘子别住的别针。没有映出的身影、单凭身体的感觉去跳的时光，也是需要的。盖上镜子的瞬间，音乐才终于渗进肌肤——我懂得这一点。"},"ICON-0431":{"nm":"节拍计数珠","de":"咕噜，每一拍便用指尖拨过一颗珠子来数拍。像古老的算法那样，握得到、摸得着。音乐的骨架——节拍，正要这样用摸得到的东西去练，才终于牢牢附进身体。"},"ICON-0432":{"nm":"热身确认绳","de":"标记身体是否已完全舒展开的确认绳。正式练习之前，总有沉稳的准备先行。比起受伤后追悔，系上一根绳慢慢唤醒身体，反而能让人跳得更久。"},"ICON-0433":{"nm":"服装编号夹","de":"为不让多套服装混淆而夹上编号的夹子。在气喘吁吁的换装之间，哪怕只弄混一套也是大事，所以每件衣服上都清晰写着各自的次序。忙乱，也要有秩序托着才优雅。"},"ICON-0434":{"nm":"缝补室针插","de":"放在缝补室一角的针插。绽开的接缝、掉落的纽扣，那双默默补缀的手在此停留。舞台上一丝不乱的衣着背后，藏着一针一线、从未见过舞台的用心。"},"ICON-0435":{"nm":"布料碎片环","de":"把多余布料碎片穿成一串的环。为防正装受损，预先留下一模一样的布。盼着别出事而备下的这点小准备，偏在大事临头的瞬间救下舞台服装。"},"ICON-0436":{"nm":"速钉纽扣包","de":"急用时能立刻钉上的一包纽扣。演出前一刻若一颗纽扣咔地掉落，整间化妆室便一时骚动起来。它是把那短短一阵惊险一举平息的、小却无比可靠的急救箱。"},"ICON-0437":{"nm":"舞台腰带扣","de":"把舞台服装的腰带牢牢扣住的扣具。剧烈跳跃旋转，衣服也不凌乱。舞台上尽情享受的那份自由，正来自把看不见处麻利收紧。"},"ICON-0438":{"nm":"羽毛掸子","de":"灯光之下连一粒小棉絮都格外醒目，便用羽毛掸子在服装上轻轻拂过。即将迈向舞台的前一刻，最后整理衣装的那份温柔手势，总是这柔软羽毛的份内事。"},"ICON-0439":{"nm":"休息室拖鞋吊牌","de":"休息室每双拖鞋上贴着的名牌吊牌。在写着是谁的小标里，悄悄盛着\"我们是同一队\"的安心。脱了鞋伸展双脚的那个房间，成了幕后最安适的家。"},"ICON-0440":{"nm":"造型固定夹板","de":"整理头发时把发缕固定住的夹板。一缕一缕梳理之间，手指把险些散开的头发暂且托付给这枚夹。所谓整洁，归根结底是这些小小的停顿聚在一起造就的。"},"ICON-0441":{"nm":"别针整理胶囊","de":"接缝绽开的凌晨，打开胶囊盖，小小冰凉的银光整整齐齐躺在里面。在看不见的内侧把服装绑得最牢的手——别针，总在舞台幕后静静工作。"},"ICON-0442":{"nm":"镜头清洁布","de":"呵，吹一口气，画着圈擦拭，朦胧的世界便清晰起来。就喜欢那短短一刹那，便老想擦镜头。它是替谁把视野重新拭得明朗的小小一片春日暖阳。"},"ICON-0443":{"nm":"三脚架胶皮脚","de":"在三只脚尖套上胶皮，地板便不再发出尖叫。小小一点吞下晃动的同时，画面里的风景便如撒谎般静下来。安定，总是在脚下悄悄开始。"},"ICON-0444":{"nm":"相机防雨罩","de":"纵使雨珠滴滴滑落，镜头也干爽地收纳着世界。户外拍摄阴沉的午后，相机上轻轻罩起一件透明的雨衣。珍贵的东西，要趁淋湿前先裹起来。"},"ICON-0445":{"nm":"拍摄标记胶带","de":"站这里，转那边——五颜六色的短短印痕，一言不发地一笔一画指明该走的路。舞台一结束便毫不留恋地揭下，可习惯了的脚尖，会把那个位置久久记得。"},"ICON-0446":{"nm":"分镜分隔夹","de":"一口咬住险些散开的纸张的小夹子。咔嗒，清脆一声，便把昨天与今天整整齐齐地夹在一起。整理，是把险些丢失之物静静托住的、温柔的小习惯。"},"ICON-0447":{"nm":"白平衡板","de":"把白板对着画面一照，颜色便悄悄各归其位。泛黄的晚霞、发蓝的黎明，都毫不失真。一块懂得真正白光的板，让其余的色彩诚实地开口说话。"},"ICON-0448":{"nm":"记忆收纳罐","de":"小小的铁皮罐里，回忆的存储卡安然沉睡。打开盖子咔嚓一声，逝去季节的画面便倾泻进掌心。记忆，就这样妥帖盛进一只坚实的罐里安住。"},"ICON-0449":{"nm":"监视器遮光罩","de":"在监视器四周围上黑色遮檐，光的反射便戛然而止。即便在阳光倾泻的窗边，画面也不失本色。要看清，得先把杂光遮住，遮罩静静这样提醒。"},"ICON-0450":{"nm":"片场隔音别针","de":"塞进门缝的一枚小别针，悄悄裁掉了外面的杂音。走廊的脚步声、隔壁房的笑声，到这里都触不到。要收进澄澈的声音，得先筑起一片沉默。"},"ICON-0451":{"nm":"化妆海绵套装","de":"柔软的海绵层层叠放成一束。用指尖轻轻拍打散粉，脸庞便亮起一个色调。舞台上灿烂笑容的背后，总藏着这些温柔的指尖触碰。"},"ICON-0452":{"nm":"发夹收纳盒","de":"容易弄丢的小夹子们的整齐之家。掀开盖子，银光便排成一列相迎。散开时看不见，聚拢时却令人安心——再小的东西也需要自己的家。"},"ICON-0453":{"nm":"刷具消毒筒","de":"整日含着色彩的刷子们在筒里享受紫外线沐浴。看不见的光洗去陈旧的同时，明日的刷尖又如初般清爽。整洁也是用心的一层纹理。"},"ICON-0454":{"nm":"粉扑晾干网","de":"圆滚滚的粉扑在网袋里静静调息。风从网眼间穿梭，蓬松便能长久。一颗晾干的粉扑里，已预先盛着明早的明媚。"},"ICON-0455":{"nm":"定型喷雾盖","de":"嘶——喷一次，便任风吹也不凌乱。一个小小的盖子，整夜守住精心打理的发型。在牢牢固定的发丝上，明亮的灯光如碎裂般倾泻而下。"},"ICON-0456":{"nm":"唇刷保护套","de":"轻轻包住纤细刷尖的小盖子。即便在包里左摇右晃，刷子也被守护得笔直洁净。珍惜一支小刷的心意，成就了唇上一笔的色彩。"},"ICON-0457":{"nm":"候场号码镜","de":"告知我出场顺序的数字旁，悄悄贴着一面小镜子。登台前最后一刻，在此整理凌乱的刘海。紧张照一照镜子，也会轻松几分。"},"ICON-0458":{"nm":"腕带毛巾","de":"用手腕一抹，便擦去额头汗水的柔软束带。舞步越激烈，手往这儿伸得越频繁。每个喘不过气的瞬间，它都是腕上一缕小小的慰藉。"},"ICON-0459":{"nm":"道具包标签","de":"化妆室里十个一模一样的包排成一列，也不会弄混。因为每个包上的名牌都清晰地标明主人。写下“我的”二字，虽小却是温柔的标记。"},"ICON-0460":{"nm":"练习室预约夹","de":"今天谁会用这间练习室呢。门前白板上插着的小夹子，无声地分配着时间。等待下一轮的心情，都在这一枚夹子上静静排起队。"},"ICON-0461":{"nm":"挂钟防尘罩","de":"透明的罩子轻轻落在挂钟上，挡住灰尘。滴答的指针不再模糊，时间清澈地流淌。珍贵之物上，总需要一层看不见的守护。"},"ICON-0462":{"nm":"地板保护垫","de":"贴在椅腿下的薄垫，预先挡住木地板的伤痕。拖也不划，移也不留一丝痕迹。看不见地爱护地板的心意，正是长久使用的秘诀。"},"ICON-0463":{"nm":"禁带饮料标识贴","de":"在这里先把饮料放下吧——小小的贴片温柔地请求着。乐谱也好装备也好，弄湿了都麻烦。“禁止”二字这样递出来，不知不觉便成了温暖的体贴。"},"ICON-0464":{"nm":"换气按钮标签","de":"想换换沉闷的空气时，就按这里——按钮旁的小标签为你指路。畅快呼吸这件事，意外地常从这样一个不起眼的标记静静开始。"},"ICON-0465":{"nm":"音箱防震脚垫","de":"垫在音箱底下的橡胶脚垫，悄悄吞下沉闷的震动。低音不再沿地板蔓延，声音便愈发清晰。好的回响，唯有在坚实的底座上才得以澄澈。"},"ICON-0466":{"nm":"储物柜号码磁贴","de":"啪地贴上柜门的小数字磁贴。今天我的行李在第几格安睡呢。即便每天位置变换，一枚磁贴便能立刻拥有我的格子。归属感，便来自这样轻巧的标记。"},"ICON-0467":{"nm":"镜面刮水器","de":"在镜面上轻轻一划，雾气便干净退去。模糊的脸庞清晰浮现的瞬间。想要看清自己，得先静静擦去那层朦胧。"},"ICON-0468":{"nm":"门缝缓冲垫","de":"夹在猛关的门缝里的松软缓冲垫。砰的声响也好，夹手也好，都被它柔和地接住。在粗暴的碰撞之间，悄悄塞进一层温柔的小小安全。"},"ICON-0469":{"nm":"线缆防护盖块","de":"横穿地面的线缆上，坚固的盖子稳稳架起一座桥。既不会绊脚，也不会踩到电线。不挡路却守护路的，是这一块的默默无言。"},"ICON-0470":{"nm":"防滑警示锥","de":"湿滑的地面上，黄色的圆锥独自伫立着静静警示。小心些，慢慢踩。灿烂舞台的背后，就这样站着一位默默守护脚步的小小哨兵。"},"ICON-0471":{"nm":"应急照明棒","de":"停电的走廊里啪地亮起的一束光。即便身处黑暗也别迷路——应急的光被握在手心。这世上确有一些东西，在最黑暗的时刻最为明亮。"},"ICON-0472":{"nm":"扶手保护帽","de":"套在楼梯扶手末端的圆帽，柔和地包住尖锐的棱角。即便无意间手掠过，也不会受伤。静静盖住锋利这件事，也是朝向某人的体贴。"},"ICON-0473":{"nm":"舞台边角软垫","de":"舞台边缘的棱角围上松软的软垫。即便激烈舞步中脚尖触到，也不会淤青。每一个闪耀动作的背后，都有看不见的守护一同起舞。"},"ICON-0474":{"nm":"地面标记圆盘","de":"放在地上的圆盘安静地说着“请站这里”。排队的人也好，找位置的人也好，看着这一点便静静停下。秩序，从小小的标记中生长。"},"ICON-0475":{"nm":"手电筒挂绳","de":"把手电筒末端垂下的绳子在手腕上绕一圈，即便身处黑暗也不会丢失光亮。无需担心掉落，双手便得以自由——这是小却可靠的一圈束缚。"},"ICON-0476":{"nm":"动线隔离绳","de":"请别越过这里——一根绳子柔和地划出界线。静静分开危险与安全之处的温柔边界。阻拦，也是守护某人的一种方式。"},"ICON-0477":{"nm":"安全确认夹","de":"每个检查完毕的地方，小夹子都留下“已确认”。如同毫无遗漏地巡视过的心之印章。安全并非什么宏大之事，而是这样一处处确认过的痕迹之和。"},"ICON-0478":{"nm":"迷你场记板","de":"啪地切断第一拍的轻快声响中，现场所有人的呼吸瞬间合拍。尺寸虽小，每个场景的起跑线却总是这一拍。拍摄那令人雀跃的开始，就从这里揭幕。"},"ICON-0479":{"nm":"桌面麦克风套","de":"桌上的麦克风轻轻套上柔软的套子。即便呼吸声粗重地迸出，也无杂音地温柔传递。最温暖地包裹声音的，正是这小而柔软的一层。"},"ICON-0480":{"nm":"吸音板片","de":"嵌在墙上的一片吸音板，安静地收走回声。声音不再碰撞四散，歌声便愈发清澈地沉淀。好的回响，源自精心打磨寂静这件事。"},"ICON-0481":{"nm":"耳机挂钩帽","de":"把耳机挂在这里是个小小的约定。为了让下一个人能立刻取用，要解开线整齐挂好。一枚挂钩，为忙碌的录音棚带来安静的秩序。"},"ICON-0482":{"nm":"录音中提示灯","de":"红灯亮起的瞬间，棚里所有的呼吸都停住了。连门外的脚步声也停下的那个信号。录制声音这件事，始于守护这份深深的寂静。"},"ICON-0483":{"nm":"拨片收纳筒","de":"按颜色分格插放的拨片们。厚度与重量造就了指尖的习惯。登台前一刻，不看也能一把准确取出的那份精准，便从这里生长。"},"ICON-0484":{"nm":"线缆标签器","de":"在数十根缠绕的地面线缆中也不迷路，就得在两端写上名字。唯有写下从何而来、往何而去的人，才能在黑暗中让手不致迷乱。"},"ICON-0485":{"nm":"小型调音台旋钮","de":"拧动一指节的距离，声音的纹理便不同。调高便粗糙，调低便埋没，在这之间摸索唯一一点。最细微的触碰，雕琢出最大的变化。"},"ICON-0486":{"nm":"支架固定垫圈","de":"支撑舞台的不是华丽的灯光，而是这枚小小的圆环。把晃动牢牢系住，谁的目光也不留意它，只在自己的位置默默坚守。"},"ICON-0487":{"nm":"拆台标签","de":"把搭起的一切再次小心放倒，也有明确的顺序。写着从哪里拆、往哪里搬的一张纸。搭建的手与收拾的手，一样利落。"},"ICON-0488":{"nm":"失物招领袋贴","de":"某人遗落的物件，各自寄寓着一段缘由。装进小袋等待主人的名字，是连失主的心也暂且替他保管的温柔。"},"ICON-0489":{"nm":"清扫动线标记","de":"顺着画在地上的箭头走，便能毫无遗漏地擦净。扫帚也得有路才不空转。最闪亮的地方，就在画得最好的脚步尽头。"},"ICON-0490":{"nm":"退场引导杆","de":"最后的掌声平息后，这根杆子便开出一条路。为了不伤到仍兴奋的心情，缓缓送行的手。引导结尾这件事里，也满含温暖的体贴。"},"ICON-0491":{"nm":"剩余胶带球","de":"把用剩的边角圆圆地团起来，便又生出一份用处。如同险些被丢弃的尾端聚成坚实的球，珍惜之心从小小的指尖生长。"},"ICON-0492":{"nm":"座椅号码帽","de":"观众席每张椅子上都得嵌着数字，谁才不会迷茫。一顶为人定座的小帽子，把初来者的忐忑换成安心的踏实。"},"ICON-0493":{"nm":"垃圾分类夹","de":"把纸和塑料分开插放的小夹子。混在一起便只是垃圾，分开来便成了可再用的资源。分类，是归还事物第二段生命的温柔之事。"},"ICON-0494":{"nm":"装备归还吊牌","de":"借来的东西必须物归原位。挂上吊牌归还的每个指尖，信任便一层层累积。善于归还的人，下次也能安心地借。"},"ICON-0495":{"nm":"化妆间退场钥匙","de":"卸下今天的妆容与服装，最后归还这把钥匙。把进来时领的，在离开时放回。一天的开始与结束，盛在同一只手中。"},"ICON-0496":{"nm":"气垫粉扑盒","de":"蓬松的粉扑被压便失了纹理。把它好好躺进一个圆圆的家，缘由便在此。想长久守住柔软，得先从温柔地对待开始。"},"ICON-0497":{"nm":"眼影盘","de":"敷在眼睑上的一点色彩，便整个改变了神情。沉睡在小盘里的颜色，唯有在灯光下才苏醒，为朝向舞台的眼神添上深邃。"},"ICON-0498":{"nm":"腮红刷帽","de":"刷尖损坏，显色也随之崩塌。套上小帽守护那份纹理，是想把好工具长久留在身边之人的安静习惯。"},"ICON-0499":{"nm":"纤薄唇彩盘","de":"厚实的彩盘在包里占尽位置。懂得一条薄薄削过的就够的手。舍去，正是收纳的瞬间。"},"ICON-0500":{"nm":"睫毛膏防护套","de":"为了不让一根根竖起的睫毛晕开，小小的防护套轻轻守护那道弧线。精心刷上的，就得精心守护——镜前的时光这样告诉你。"},"ICON-0501":{"nm":"棉签盒","de":"为了不让白色棉签四处散落，便盛进这个小小的家。为了最后一次修整，总放在手边的触碰。细碎的准备，填补大舞台的缝隙。"},"ICON-0502":{"nm":"睫毛夹橡皮替换装","de":"橡皮硬了，夹睫毛时会刺痛。预先备好替换的心意，源自连小小疼痛都体察的温柔。"},"ICON-0503":{"nm":"遮瑕刷","de":"用纤细的刷尖轻轻抹去阴影。在光照不到的地方引入明亮。比起遮盖瑕疵，添上光亮的手收尾得更为细腻。"},"ICON-0504":{"nm":"散粉筛","de":"把细粉过滤一遍，便无结块地细腻附着。多过一道筛的那份费心。所谓用心，终究渗透在多走一步的指尖。"},"ICON-0505":{"nm":"刘海卷夹","de":"把刘海卷圆暂时夹住的夹子。等待之间，形状便沉静定型。在不慌不忙、懂得等待的地方，端庄绽放。"},"ICON-0506":{"nm":"发蜡勺","de":"发蜡在沾上手之前，先用这小勺挖出。只取恰好所需的那份节制。懂得不过量使用的手，造就最自然的纹理。"},"ICON-0507":{"nm":"卷发棒隔热垫","de":"烧得滚烫的卷发棒可不能随意放下。一张垫子守护书桌也守护手。处理热度的地方，总需要一处安全的歇脚。"},"ICON-0508":{"nm":"护发油小样","de":"一滴便足够的光泽，盛进小小的样品瓶，悄悄塞进包的一角。比起大瓶，小小的一瓶反而更常触到手边。"},"ICON-0509":{"nm":"刷具清洁耙","de":"用耙子慢慢梳下缠在刷上的头发。打理工具的时间，是收工后安静的仪式。打理妥当的刷子，细腻地雕琢明日的纹理。"},"ICON-0510":{"nm":"发圈绕线轴","de":"只是缠在线轴上，便一眼了然。这圆圆整理好的小卷，是献给橡皮圈四处骨碌滚动的忙乱清晨的一份温柔从容。"},"ICON-0511":{"nm":"染发手套包","de":"为了不让上色的手被染，套上的薄手套。想在收工后也以干净的手迎接下一刻的心意。保护，正是这份准备的另一个名字。"},"ICON-0512":{"nm":"发网收纳袋","de":"把守护发型的网细细折好收进的小袋。越是没有体积的东西越易失去位置，为它定下自己的家的体贴之手令人感激。"},"ICON-0513":{"nm":"碎发定型笔","de":"把翘出的碎发轻轻一压理顺的笔。大功告成后的最后一下。所谓收尾，总是抚平最小之处的事。"},"ICON-0514":{"nm":"香水试香盖","de":"挑选香气时不直接凑到鼻尖。要沾在小盖上撒入空气中，真正的纹理才显露。香气也唯有退后一步去闻，才终于诚实。"},"ICON-0515":{"nm":"滚珠香水瓶","de":"圆圆的珠子骨碌滚动，在手腕上描出香气。与轻点涂抹的旧香水瓶不同，是如滑行般晕开的一道。香气在每种触碰方式里，都留下不同的故事。"},"ICON-0516":{"nm":"身体喷雾盖","de":"关住如雾般散开的香气的小盖子。把打开便飘散的关上守护。稍加珍惜的心意，让那香气更长久地停留身边。"},"ICON-0517":{"nm":"护手霜钥匙圈","de":"给涂手的小霜装上环，便能随处同行。挂在包外晃晃悠悠的同伴，成了递给干涩指尖的温柔问候。"},"ICON-0518":{"nm":"沐浴球挂钩","de":"搓出咕嘟咕嘟的泡沫后，要好好晾干。挂在浴室一角钩子上的网球，骨碌甩落水珠，清爽地等待下一个清晨。"},"ICON-0519":{"nm":"按摩球收纳袋","de":"把放松僵硬肩膀的坚实球装进小袋。舞台后短暂的休息，安静抚慰僵硬身体的时光。照料，总是从自己开始。"},"ICON-0520":{"nm":"降温贴筒","de":"把贴上便凉爽降温的贴片收拢的筒。火热舞台落幕的夜晚，慢慢平息发烫身心的小小慰藉，就沉睡在其中。"},"ICON-0521":{"nm":"指缘油笔","de":"按一按，揉一揉，亮晶晶。干涩的指尖只需一滴便足够。无需华丽的处方，从小笔尖晕开的淡雅光泽，在指甲上细腻萦绕。照料，便从这样小小的一滴开始。"},"ICON-0522":{"nm":"香囊夹","de":"把香气系在纸上的小结。每次拉开抽屉，淡淡的一缕便抢在手前先来问候。看不见却伴在身边的温柔——一枚夹子静静怀着一天份的慰藉。"},"ICON-0523":{"nm":"甲片托盘","de":"预先铺开十指色彩的小舞台。哪个色调与今天相配呢，托盘上正开着一场安静的试镜。挑选的那片刻不知为何令人雀跃，指尖的一天便从这里开始。"},"ICON-0524":{"nm":"死皮推帽","de":"推开这件事里也有温柔。用圆圆的头慢慢、不慌不忙地处理一根倒刺。匆忙的手总会漏掉些什么，所谓整理，更近于慢慢端详的心。"},"ICON-0525":{"nm":"迷你抛光锉","de":"粗面与细面，两副面孔握在一手。把棱角慢慢磨平的事虽琐碎，完成却总来自这样琐碎的触碰。最后，终究归于柔和的那一份。"},"ICON-0526":{"nm":"指甲贴纸板","de":"星星、花朵、爱心——挑一张正合今天心情的轻轻贴上便好。在排列着指甲大小图案的板上，一枚贴纸如指尖留下的温柔签名般闪烁。"},"ICON-0527":{"nm":"光疗灯遮光板","de":"把光暂时关住的薄膜。固化期间眼睛歇息，唯有指尖安静变得坚实。等待也需要一缕阴影——在不慌不忙的时光里，今天的指尖得以完成。"},"ICON-0528":{"nm":"美甲配件筒","de":"闪亮的碎片一格格沉睡着。立方钻、珍珠、星粉——以打开无名宝石盒的雀跃揭开盖子。把哪种光放上指甲呢，挑选的那一刻最为闪烁。"},"ICON-0529":{"nm":"护手手套包","de":"睡眠期间手所享的短暂假期。在手套里，干燥的肌肤整夜慢慢变得滋润。所谓照料，终究是在看不见之处发生的事——到了清晨，指尖最先知晓那份温柔。"},"ICON-0530":{"nm":"卸甲水泵瓶","de":"按一次，恰是所需的量。沁入棉花晕开的清凉香气，干净擦去指甲上的昨日。清空也有节奏，一次按压便静静腾出重新涂抹的位置。"},"ICON-0531":{"nm":"钻饰镊子","de":"要夹起比指尖更细的宝石，便需要更细的手。毫无颤抖地移动一点的镊尖——细致既是心的事，也是工具的事。一束小小的光找到了归位。"},"ICON-0532":{"nm":"耳环收纳板","de":"为了不让失伴的耳环再在抽屉里成为迷儿。一对对插回原位，忙乱清晨挑选的时间便轻松许多。整理，是递给未来的我的小小善意。"},"ICON-0533":{"nm":"戒指量圈","de":"把手指周长换成数字的一串小圈。一个个试戴合适的格子，与慢慢了解恰好适合自己之物的过程相似。如同恰好合适时的那份安心。"},"ICON-0534":{"nm":"表带销钉","de":"表带松动时，这枚小小的销钉把时间重新留在手腕上。藏得最深的零件坚守得最久——戴了许久的表，无言地知晓。"},"ICON-0535":{"nm":"项链防缠板","de":"为了不让细链相互缠绕而分格摆放。不缠结的清晨，始于昨夜预先分开的小格子。所谓从容，终究是手触之前已整理好的心。"},"ICON-0536":{"nm":"胸针后扣","de":"正面越华丽，背面越沉默。把别在衣襟上的胸针稳稳托住的小扣子——显露的光辉背后，总有无名坚守的手。正因看不见，更显可靠。"},"ICON-0537":{"nm":"墨镜收纳袋","de":"把挡住夏日光线的镜片，用柔软的布静静包裹。守护一副视野免于包中碰撞的小袋。珍惜某物的心意，总是这样以柔软的一层降临。"},"ICON-0538":{"nm":"皮带打孔器","de":"腰围少了一格也好，季节多了一格也好。只需再打一个孔，皮带便重新合身。变的总是我，默默配合的，是这小小工具的事。"},"ICON-0539":{"nm":"丝巾固定夹","de":"把滑落的丝巾聚于一点夹住的夹子。被风吹散的风度终于安定。优雅有时也倚靠这小小的夹子，把险些凌乱的一天端庄收拢。"},"ICON-0540":{"nm":"挂饰扣套装","de":"挂在包一侧的小扣子一套到来。把喜欢之物带在身边的心意——在一枚挂饰上挂起当天的心情，是只有自己知晓的小小仪式，不知为何令人愉悦。"},"ICON-0541":{"nm":"去毛球器筒","de":"毛衣一夜间像老去般起了毛球，就静静滚动这个筒，重回新品的神情。去除陈旧的轻轻嗡嗡声不知为何令人安心。珍惜的衣服，便这样再活一次。"},"ICON-0542":{"nm":"衣物香氛卡","de":"塞进衣柜深处，便用香气静静填满数日。以香代字写就的信——不展开也能读懂的一张。每个取衣的清晨，昨日写下的温柔先一步晕开。"},"ICON-0543":{"nm":"防静电夹","de":"裙摆贴住腿的冬日清晨，一枚夹子悄悄解开那份黏贴。连看不见的摩擦都安抚的小小平和——一桩琐碎的烦躁消失，一天便顺滑许多。"},"ICON-0544":{"nm":"便携衣刷","de":"出门前一刻，肩上轻轻落下的一道灰尘。展开折好的刷子一刷，第一印象便重归端庄。收尾总在门前发生，端庄由那一下的触碰完成。"},"ICON-0545":{"nm":"洗衣袋标签","de":"把不能混在一起的东西关进网袋，标签静静写上名字。洗衣也有位置，位置便伴着小小的标记。易乱一天的秩序，从这小小的名牌生长。"},"ICON-0546":{"nm":"去渍笔","de":"咖啡一滴在衬衫上留下的痕迹，轻轻点拍也会悄然退去。不是遮盖失误，而是静静抹去的笔。谁都需要把一天重新干净开始的那一次。"},"ICON-0547":{"nm":"擦鞋布","de":"用布轻轻一拭，皮革便重拾本色。穿得越久的鞋，光泽越深。光亮是一同走过岁月的回报——鞋子把那段时光，静静刻在脚背上。"},"ICON-0548":{"nm":"鞋带头帽","de":"扣在松开鞋带末端的小帽子。为了直到终点都不分神，把末端牢牢封住。一根系好的鞋带，把一步送得更远——细小的约束，成了跑到最后的勇气。"},"ICON-0549":{"nm":"衣架名牌片","de":"在相似的衣架之间，这一枚小片静静标明“我的位置”。减少忙乱清晨混乱的安静向导——寻找的辛劳少了，一天的开始也轻快许多。"},"ICON-0550":{"nm":"镜片镊子筒","de":"有时需要比指尖更精确的尖端。能毫无颤抖夹起小镜片的镊子，在筒里等待轮到自己。精密总是安静地准备着沉睡，一呼便立刻苏醒。"},"ICON-0551":{"nm":"化妆棉迷你包","de":"只装恰好用一次份量的小束。既减小包中体积，又保留柔软如初。少带些也是一种温柔——舍去的位置，腾出轻盈的一天。"},"ICON-0552":{"nm":"吸油纸盒","de":"正午晕在鼻梁上的油光，用薄薄一张静静按拭。整齐沉睡在盒中的纸张——取出一张的瞬间，谁都会暂且在镜前，温柔地端详自己。"},"ICON-0553":{"nm":"折叠梳镜","de":"折起是手掌大小，展开是镜子与梳子。在包的一角负责急忙整理仪容的小小万能。端庄并非什么宏大之事，而更近于随处展开整理一下的心。"},"ICON-0554":{"nm":"便携剃须刀盖","de":"把旅行箱中锋利的刀刃安全地睡好。多亏这看似钝实则坚固的盖子，忙乱清晨摸索的指尖也不受伤。所谓照料，总是先一步盖住危险的事。"},"ICON-0555":{"nm":"唇膏挂环","de":"晃在包带上的小小保护壳。无需担心在口袋里滚动碎裂，把干燥的唇总放在手能触及之处。所谓照料，终究是把所需之物放在最近距离的心。"},"ICON-0556":{"nm":"免洗洗手凝胶挂架","de":"单手一按，便落下一掌的洁净。门前、桌上，随处一挂，洗手的心意也随之亲近。好习惯并非宏大，而是从手能触及的地方开始。"},"ICON-0557":{"nm":"纸巾纤薄包","de":"纤巧的身躯怀着一把纸巾。既不让口袋鼓起，又总为突然的鼻涕或泪水静静备着。悄悄递给某人的一张——准备越纤薄越帅气。"},"ICON-0558":{"nm":"迷你漱口水瓶","de":"吃了辣泡面又要见人的日子，这小瓶悄悄负责清新口气。一口的清爽有时成了大大的自信，让犹豫的问候轻松许多。"},"ICON-0559":{"nm":"闪粉片","de":"用指尖蘸一点敷在脸颊上，便如灯光下星粉飞散般晕开。平凡的脸颊一瞬闪烁，是这小小一片的魔法。光总是这样，借指尖沾上的粉而来。"},"ICON-0560":{"nm":"遮闪粉贴纸","de":"太过闪耀而显累赘的地方，这贴纸便悄悄压一压光。减去一层华丽也是装扮的一部分——舍去后留下的淡雅，有时成了另一种感觉。"},"ICON-0561":{"nm":"拾石笔","de":"走路时绊在脚尖的一颗小石子。是特地俯身拾起的笔。把本可径直走过的东西用指尖静静拾起的心意——温柔，总是从停下脚步开始。"},"ICON-0562":{"nm":"假睫毛收纳板","de":"把一根根整齐躺好的小板。即便取下后，那道美丽的弧线也不凌乱。暂且放下的东西也记得自己的位置——那是安静端庄的收纳之慰藉。"},"ICON-0563":{"nm":"双面胶切割器盖","de":"两刃咬合，一下切断结扣。切口越干净，下一个结便越端庄。在善结善断的指尖，新的开始也愈发轻快地解开。"},"ICON-0564":{"nm":"脸部轮廓胶带","de":"沿着下颌线一道，屏息小心地贴下去。所谓轮廓，并非画出本无的线，而是点明本就秀美之处。是温柔顺着原本就在那里的纹理描绘的触碰。"},"ICON-0565":{"nm":"灯光反射粉","de":"尽情含住光又细腻返还的粉。即便自身不发光，也把受到的光细细撒开而明亮。如同把得来的温柔再传给某人，闪烁越分享越大。"},"ICON-0566":{"nm":"妆容定型风扇","de":"把精心妆容守到一天结束的风扇之风。别崩塌、别滑落地静静吹凉固定。让用心整理的脸庞，直到舞台落幕都清晰分明。"},"ICON-0567":{"nm":"校色盘片","de":"把偏差的色彩一格格安抚校正的小碎片。独自时显得格格不入的色，身旁置上相配之色便终于明亮。色与色携手，才终成一幅清澈。"},"ICON-0568":{"nm":"颈部围巾包","de":"围在颈上，凌晨练习室的寒气便缓和许多。如同奶奶为孙儿围在颈上的那份手心般温暖。寒冷总从最细之处来，所以从脖颈先环抱起。"},"ICON-0569":{"nm":"热敷眼罩袋","de":"盛放加热眼罩的小袋。打开袋口的瞬间，困倦的暖意便缓缓晕上眼睑。把疲惫的一天暂且封存再解开，是入睡前温柔的仪式。"},"ICON-0570":{"nm":"便携加湿器滤芯","de":"为干透的房间归还水汽的小小滤膜。在看不见的内里默默滤去浑浊。满室的滋润，是某人看不见的辛劳守护的澄澈。"},"ICON-0571":{"nm":"维生素整理盒","de":"把一天份药片分格盛放的盒子。一丝不苟地按时服用，便是明天也要登台的决心。每个小格里，爱惜自己的心意都工整地整理着。"},"ICON-0572":{"nm":"睡眠耳塞盒","de":"暂且关上世界声响的耳塞之家。寂静也需要照料，便细细躺进盒中。唯有酣睡的夜晚，次日的嗓音才清澈苏醒——歇息，懂得这一点。"},"ICON-0573":{"nm":"凉感毛巾夹","de":"为了不让冰镇的毛巾滑落，把它牢牢咬在肩上的夹子。酷热日里触到颈背的一缕清凉，撑过漫长的午后。再小的清爽，留住了也能长久停留。"},"ICON-0574":{"nm":"拉伸球收纳袋","de":"把放松身体的球重新装回的袋子。尽情伸展再缩小收回，与吸气和呼气相似。在伸展与收拢之间，身与心都慢慢变得坚实。"},"ICON-0575":{"nm":"弹性绷带卷","de":"一圈圈包住扭伤脚踝的带子。不是勒紧，而是静静托住的事。越是勉强之处，越需要身旁默默支撑的手——它一圈圈缠绕着低语。"},"ICON-0576":{"nm":"状态记录吊牌","de":"把今天的状态写成一行挂起的标牌。坦白挂出好与坏，是小小的勇气。不再强装没事，写下今天的我，便有人会留意那一行静静关照。"},"ICON-0577":{"nm":"鞋内香氛胶囊","de":"啪地放进鞋里的香气胶囊。是献给整日奔走舞台的脚的小而淡雅的慰藉。把最好的香气给最辛苦的地方——温柔无遗漏地触到脚尖。"},"ICON-0578":{"nm":"鞋垫尺码标","de":"连一只鞋垫上都清晰刻着脚码的标。一双合脚的鞋，让舞台上的步伐轻盈。体察各不相同步幅的事——所谓合身，终究是深深端详对方的心。"},"ICON-0579":{"nm":"鞋拔钥匙圈","de":"把鞋拔缩成手掌大小挂起的钥匙圈。在穿鞋那片刻顺滑相助的小小体贴。启程的脚上，总静静一同挂着某人温柔的搀扶。"},"ICON-0580":{"nm":"包袋防尘罩","de":"把珍爱的包从灰尘中轻轻盖住的布。即便闲置不用，也细细安睡守护其纹理。即便不常触手却心系之物，都寄寓着这样静静的照料。"},"ICON-0581":{"nm":"肩带调节夹","de":"把松弛的带子调到正合身的夹子。太松肩便滑落，太紧便喘不过气。在寻找恰好的一格调节里，舞台服装与心都终于安适。"},"ICON-0582":{"nm":"拉链润滑笔","de":"在生涩的拉链上一划，便重又顺滑滑动。堵住之物哧溜松开的那声响，何其畅快。让停滞之处重新流动的，是一缕顺滑。"},"ICON-0583":{"nm":"运动鞋清洁刷头","de":"把沾满尘土的运动鞋一点一点擦净的刷尖。在舞台之外，精心抹去看不见的练习痕迹。看着重又雪白的鞋头，便觉得明天又能以新的心情奔跑。"},"ICON-0584":{"nm":"防水喷雾盖","de":"把雨珠滚圆滑落的防水之盖。在淋湿前预先多披一层，是放眼长远的温柔。因知晓雨天，才在晴朗的今天围上一层膜。"},"ICON-0585":{"nm":"皮革保护布","de":"静静覆在皮革上防止起皱的布。如同用韩纸包裹屏风的旧日手心般守护纹理。越是长久相伴之物越要慢慢——驯养，是照料时光的另一个名字。"},"ICON-0586":{"nm":"行李箱名牌带","de":"在众多行李中让人一眼认出我的名字带。在转盘上打转的行李里，以一个字举手示意。无论走得多远，一个名字便能重逢的安心。"},"ICON-0587":{"nm":"压缩袋夹","de":"把鼓胀的行李压扁锁住的夹子。与其说是清空，不如说是层层叠好。在整洁地精简家当的指尖，贪念也一同变小——压得紧实的行李静静告诉你。"},"ICON-0588":{"nm":"旅行洗涤剂片","de":"一张便能在洗手台洗衣的洗涤剂片。与远途上手洗衣物穿着的客旅智慧相似。轻装出行，却也带上端庄——路上旅人由来已久的心态。"},"ICON-0589":{"nm":"颈枕套","de":"为托住脖颈的枕头新换上的洁净罩子。倚靠之处总要干净，心才安。把位置松软地空出来让人安心倚靠——款待便从那里开始。"},"ICON-0590":{"nm":"行李秤带","de":"把包猛地提起掂量重量的带子。出发前，用手预先抱一抱行李的重量。在该带与该留之间，连心的重量也一同静静称量的瞬间。"},"ICON-0591":{"nm":"鞋袋一对","de":"左只右只，把两双鞋并排装入的一对鞋袋。分开放易丢的东西，成对放便安心。总是结伴同行之物，自有相互静静守护的力量。"},"ICON-0592":{"nm":"辅助包挂钩","de":"少一只手的日子，把包悄悄挂起的小挂钩。是为行李多到怎么也拿不完的日子准备的一格从容。仅是有处可暂挂，肩便轻松许多。"},"ICON-0593":{"nm":"旅行行程片","de":"把一天的动线工整刻在一片上。在哪里见面、往哪里流转，为路盲的脚步预先划下的指引线。一同启程的路，分格记下便不易迷失。"},"ICON-0594":{"nm":"多功能转换头盖","de":"在陌生国度的插座上也能恰好咬合插入的盖子。即便模样不同，终究连成一体。连接来自不同位置之物的事——所谓契合，从小小一个转换静静开始。"},"ICON-0595":{"nm":"交通卡套","de":"每次掠过闸机时守护卡片的透明一张。每日的通勤，连那刷得磨损的痕迹都细细包裹。平凡的路珍藏起来便成回忆——这薄薄的一层证明着。"},"ICON-0596":{"nm":"车票夹","de":"把转眼就皱的一张票端庄咬住的夹子。路上丢了票，连心都会动摇。越是小小的纸越要牢牢握住——旅途的安心，正来自那一格。"},"ICON-0597":{"nm":"换乘备忘片","de":"把在哪里换乘写成一行的小片。每个易混的岔路口，预先写下的一句便豁然开路。备忘，是悄悄递给将迷路的未来之我的温柔提点。"},"ICON-0598":{"nm":"闸门通行牌","de":"过门时静静被识别的通行之牌。看似堵塞的路，只要持有资格便哧溜打开。坦然通过，便是毫不犹豫地轻快迈向下一格。"},"ICON-0599":{"nm":"出租车票据夹","de":"每一张小纸上都清晰印着那天去过的路的痕迹。把四处滚动的票据整齐夹拢一处，原本不起眼的一天也层层累积，成了像样的旅程。"},"ICON-0600":{"nm":"自行车反光带","de":"在昏暗路上承接经过灯光而静静闪烁的带子。即便自身不发光，也借某人的光而明亮。让自己被看见，是夜路上盼你平安归来的温柔叮咛。"},"ICON-0601":{"nm":"行李箱轮盖","de":"在机场传送带上滚过千万次，边角依然完好，全靠这个包住轮子的小小护盖。它走在最崎岖的路上，最先触地——默默守护别人的事，总是这样藏在不起眼的地方。"},"ICON-0602":{"nm":"座椅头枕套","de":"长途巴士上，给头枕套上一张，靠着车窗。前座的气味、昨日的疲惫，都被挡在这里之外。能有个干净的依靠之处，是陌生旅途上意外珍贵的慰藉。"},"ICON-0603":{"nm":"停车定位针","de":"\"刚才是几层几号来着。\"在空荡荡的停车场里转悠过半天的人，才懂这枚定位针有多让人安心。与其指望会模糊的记忆，不如插上一个标记，提前定好回来的位置。"},"ICON-0604":{"nm":"房卡挂绳","de":"客房钥匙怎么那么容易不见。穿在绳上挂到手腕，今晚要回的那间房就绝不会忘。即便在陌生的城市，也有个属于我的去处——这份小小的安心，就挂在手腕上。"},"ICON-0605":{"nm":"门挂提示牌","de":"彩排一开始，就在门上挂个小牌。请勿打扰——意思是此刻要全心专注。后台那份深深的宁静，正是被这些小小的信号默默守护着。"},"ICON-0606":{"nm":"洗漱收纳包","de":"牙刷、洁面、巴掌大的毛巾。无论去哪儿，只要带上这个包，一天的结束与开始都由同样的手势打理妥当。一小把家什，悄悄把陌生的睡处变得熟悉起来。"},"ICON-0607":{"nm":"备用毛巾夹","de":"洗手台旁，那条总没处放、老是湿漉漉的备用毛巾。用夹子一夹挂起来，它才算找到了自己的位置。给它腾出晾干的地方——温柔，大多就是这么大小的模样。"},"ICON-0608":{"nm":"排插收纳包","de":"每次打开包，充电器都缠成一团。把排插整个卷起来收进去，里头便清爽了许多。线缆理顺，也意味着出发前那一缕心绪也悄悄松开了。"},"ICON-0609":{"nm":"床位编号牌","de":"集体宿舍的上下铺，每张床都贴着号码。一张标明哪个位置是我的标签，就让初来乍到的陌生房间，当晚便成了我们的家。开始总是这样微小。"},"ICON-0610":{"nm":"迷你晾衣绳","de":"把两端挂在窗框之间，那就是晾衣绳了。阳光好的日子，几只手洗的袜子在风里晒得蓬松摇曳。即便在远离家乡的地方，日常也这样在绳上晾干。"},"ICON-0611":{"nm":"拖鞋区分牌","de":"玄关堆满拖鞋时，根本分不清谁是谁的。挂上一个小牌，鞋子也能认出自己的主人。许多人挤在一起生活，正需要这些贴心的小标记。"},"ICON-0612":{"nm":"早餐券夹","de":"夹着早餐券的小夹子。饥肠辘辘的清晨，有这一张，就等于约定好了一碗冒着热气的汤。旅途中的一天，总是从一顿温热的饭里慢慢开启。"},"ICON-0613":{"nm":"脚踝反光带","de":"绕在脚踝上，在黑暗中把光反射回去。夜里散步时，它向远处驶来的车默默挥手说\"这里有人哦\"。安全，就这样朴素地闪着光。"},"ICON-0614":{"nm":"湿巾盖","de":"正好卡在湿巾开口上的盖子。一张张顺滑抽出，剩下的也不会变干。看着不起眼，可每天都要用到的东西，背后都藏着它该有的理由。"},"ICON-0615":{"nm":"野餐垫束绳","de":"把野餐垫卷成一圈，用绳子捆好。汉江边、樱花荫下，无论在哪儿铺开的那一刻，那里就成了我们的位置。一根绳，把草地上巴掌大的领地整个带在身边。"},"ICON-0616":{"nm":"驱蚊贴盒","de":"夏夜必备的驱蚊贴收纳盒。在痒起来之前就先备好的那份心意，都装在这一格里。户外舞台的后台，总是被这些小小的预备打点得稳稳当当。"},"ICON-0617":{"nm":"散步水壶挂钩","de":"出门散步时把水壶挂在包上的钩子。口渴时伸手就能拿到水，也就意味着能走得更远些。一个让行走的人不必停下的小小连接。"},"ICON-0618":{"nm":"折叠购物篮","de":"展开是购物篮，折起来只有巴掌大。逛市场巷子时，装上看中的一捆青菜正合适。生活的智慧，总是朝着更省空间、更便于携带的方向生长。"},"ICON-0619":{"nm":"防风夹","de":"刮风的日子，夹住翻飞的篷布一角，把它牢牢固定。一个夹子，就把总在晃动的东西按回原位。户外最靠得住的，往往就是这样手指般大的小物件。"},"ICON-0620":{"nm":"遮阳针","de":"插在窗上、斜斜挡住阳光的针。正午的光太烈时，它悄悄垂下一小片阴凉。减轻刺眼的光，对某些人来说，也是再温柔不过的一只手。"},"ICON-0621":{"nm":"应急哨盖","de":"盖住应急哨口的盖子。挡住灰尘，好让真正需要的瞬间能一吹即响。有些东西，明明盼着永远用不上，可光是在身边，就让人安心。"},"ICON-0622":{"nm":"伞尖盖","de":"套在伞尖上的小盖子。尖锐的末端钝下来，旁人不会被戳到，我的包也不会被划破。雨天的礼貌，就这样从把锐利的尖端圆圆包起开始，悄然开启。"},"ICON-0623":{"nm":"雨衣收纳袋","de":"把叠好的雨衣卷起来收进袋里。它在包的一角静静等着，直到下一场骤雨落下。所谓未雨绸缪，归根结底，是预先备好那也许终究用不上之物的一片心。"},"ICON-0624":{"nm":"防水鞋套","de":"套在鞋上，雨水便再也渗不进来。梅雨倾盆的上学路上，袜子也依旧干爽。脚尖没被淋湿的一天，比想象中更能改变人的心情。"},"ICON-0625":{"nm":"雪地防滑垫","de":"贴在鞋底，冰面也没那么可怕了。雪积满的小巷里小步快走的那个冬天，是它悄悄拉住我不让滑倒。小心翼翼的脚步下，藏着踏实的依靠。"},"ICON-0626":{"nm":"降温颈圈","de":"戴在脖子上，一丝清凉便悄悄萦绕。即便在闷热的三伏天，也能把一缕清爽挂在颈间——这是夏天的智慧。熬过酷暑的法子，年复一年也越发周到。"},"ICON-0627":{"nm":"手持风扇支架","de":"立起手持风扇的支架。双手一空闲，就能翻翻书页，不用扇风，还能写写字。一缕小小的风，让伏案的漫长夏天变得勉强能熬过去。"},"ICON-0628":{"nm":"暖宝宝收纳包","de":"装暖宝宝随身带的小包。想暖一暖冻凉的指尖，把手伸进口袋，那里早有一小团暖意先来等着。冬天的出门，就靠这一捧温热撑过去。"},"ICON-0629":{"nm":"护耳套收纳盒","de":"收纳护耳套的盒子。把它好好供着，直到下一场寒冬来临。即便季节更替也舍不得丢的东西里，藏着对重逢之冬的一份静静的笃信。"},"ICON-0630":{"nm":"紫外线测量芯片","de":"轻轻对着光，就用颜色告诉你今天紫外线强度的芯片。把看不见的日照强度，终于变得肉眼可见。等于在手腕上轻轻系上一只读天的小眼睛。"},"ICON-0631":{"nm":"巷弄集章板","de":"在巷口每家店盖章、一格格填满的板子。每盖上一格，街区地图就在心里愈发清晰。用双脚走出来的回忆，就这样以印章的痕迹留存下来。"},"ICON-0632":{"nm":"到访地图钉板","de":"每去过一处就插上一枚钉的小板。一点点变多的同时，我世界的边界也随之拓宽。每一枚钉，都像在轻声搭话\"我，曾经来过这里\"，是这样的痕迹。"},"ICON-0633":{"nm":"小指南针挂绳","de":"兜转半天找不到路，唯有北方始终在那个位置纹丝不动。挂在胸前的小指南针，在彻底不知该往哪儿走时，会先把那颗摇摆的心轻轻安抚下来。"},"ICON-0634":{"nm":"找路便签环","de":"把找路时记下的纸条穿在环上。\"红色邮筒处左转。\"某人笨拙的手写字，静静指引着陌生的巷弄。留在纸上的路，不大容易变得模糊。"},"ICON-0635":{"nm":"地标贴纸册","de":"用每处旅行地买的一张贴纸填满的册子。塔、桥、古老的城墙，一页页堆叠起来。收集去过的地方，就像用指尖重新触摸走过的时光。"},"ICON-0636":{"nm":"地铁换乘芯片","de":"在线路分岔的换乘站紧紧攥在手里的芯片。决定往哪儿换乘的那短短一瞬，有时会把一整天的方向彻底改变。一个小小的选择，城市便露出另一副面孔。"},"ICON-0637":{"nm":"街区探险卡","de":"\"今天就走到这街区的面包店为止吧。\"抽出一张卡，今天的探险目的地就定下了。总是路过的熟悉巷子，一旦有了任务，也成了新的路。这一张卡告诉你：冒险并不遥远。"},"ICON-0638":{"nm":"店铺名片夹","de":"插放常去店铺名片的夹子。味道好的店、招呼亲切的老板，一格格慢慢攒了起来。对一座城市生出感情，往往就是从这些小小的纸片开始的。"},"ICON-0639":{"nm":"路线完成徽章板","de":"把散步路线走到底，就会填上一枚徽章的板子。走完全程的成就，化作一枚圆圆的金属留在手中。只有走到最后的人才懂的那份满足，在这里清晰地嵌着。"},"ICON-0640":{"nm":"包锁钥匙环","de":"扣在包拉链上、兼作锁的小钥匙环。既牢牢守护着珍贵之物，又在包角叮当晃动。安全与装饰合为一体，是旅人相当机灵的同伴。"},"ICON-0641":{"nm":"防丢标签","de":"蜷在包最深处的黑暗里，在所有人都放弃的那一刻悄悄闪光。\"我在这里哦。\"那是以为弄丢了的心，回到指尖的声音。虽小，却始终守在主人身旁。"},"ICON-0642":{"nm":"拉链锁扣","de":"咔嗒一声扣上，寻常的手就再难打开。急切的指甲，悄悄凑近的手指，它一视同仁地挡下。安全有时就算紧一点也没关系——它用沉甸甸的分量这样告诉你。"},"ICON-0643":{"nm":"防盗铃带","de":"在结账之前，守着货架上的东西不许擅自\"外出\"，是一位看不见的门卫。诚实的手拂过时，它始终缄默。不响的铃，才是最平和的铃。"},"ICON-0644":{"nm":"联系方式遮挡标签","de":"在快递箱上写着的姓名和号码上，悄悄覆上一层。谁住在那儿、要送去哪里，只有收件人知道就够了。遮挡好，也是温柔的一种——它静静守着自己的位置。"},"ICON-0645":{"nm":"护照封套束带","de":"陌生的机场，几十个一模一样的封皮在传送带上转圈的清晨。它在那堆里用只有我认得的颜色招手\"在这边哦\"。给远行的证件披上的小外套。封皮磨旧了，旅程依旧明亮。"},"ICON-0646":{"nm":"现金分装包","de":"纸币在左，硬币在右，应急钱放在谁也不知道的那一格。逛完市场的手，最先摸的就是这里。再凌乱的一天，在这里头也整整齐齐、叮当作响地各归其位。"},"ICON-0647":{"nm":"安全贴封","de":"一旦撕开就会留下痕迹。\"有人打开过哦\"——这份小小而诚实的良心，到最后也藏不住。封好后平安抵达的箱子底下，都铺着这位朋友始终如一的沉默。"},"ICON-0648":{"nm":"应急联系芯片","de":"走丢孩子的口袋里、笔记本电脑包的内侧、狗绳的末端。哪怕到了说不出话的时刻，它也替你一字一句念出号码。一枚小小的芯片里，整整装着\"请送我回家\"这句话。"},"ICON-0649":{"nm":"自拍杆遥控盖","de":"手臂不够长，合影里总有人被切掉。如今只需在末端轻按一下按钮，全家就都进了同一个画面。大家一起笑的那一瞬，我悄悄按下快门，跳进画面里去。"},"ICON-0650":{"nm":"镜头收纳包挂绳","de":"用绳子把备用镜头紧紧抱住，免得它在包里磕碰。一枚玻璃镜片就是一片风景，所以不会随意晃动它的分量。拍照之人的那份小心，系在每一个绳结上。"},"ICON-0651":{"nm":"滤镜盒环","de":"薄薄一片，就把同一片天空染成不同的光。把那些小小的魔法整整齐齐供在圆圆的窝里。每次打开盒子，今天要拍下怎样的晚霞呢——指尖便雀跃片刻。"},"ICON-0652":{"nm":"三脚架收纳包","de":"折起来一拃长，展开就是稳稳的三条腿。把那位能替颤抖的手稳住风景的朋友，好好卷起来收进去。越是沉重的器材，越该让它躺在更柔软的布上，这才是道理。"},"ICON-0653":{"nm":"相机背带垫","de":"走上一整天，总会到相机压得肩膀生疼的时候。那时一块垫子，悄悄替它分担那份重量。为了一张好照片而走过远路的肩膀上，搭上一小团柔软的慰藉。"},"ICON-0654":{"nm":"存储卡分类卡","de":"数百张回忆睡在哪张卡里，让人犯迷糊的夜晚。五颜六色的标记替你指路。春日之旅是蓝，初登舞台是黄。给记忆也分好格的，是一位小小而贴心的图书管理员。"},"ICON-0655":{"nm":"充电线收纳卷","de":"趁线缆在包里上演打结秀之前，把它卷成圆圈、规规矩矩地哄睡。理顺一根线，心里那一根线竟也跟着松开了。盘成一圈的模样，看着便让人心静。"},"ICON-0656":{"nm":"照片备份标签","de":"\"这些照片，备份过没？\"对深夜忽然涌上的那份不安，预先写好答案的小便签。越珍贵的瞬间，越该在两处以上活着——标签一笔一划地记下。"},"ICON-0657":{"nm":"构图取景板","de":"透过方形的窗看世界，要装下什么、舍去什么，一眼便分明。好照片不是多塞，而是善减——这道理，空空的取景框最先教会你。"},"ICON-0658":{"nm":"零钱包挂饰","de":"晃晃悠悠挂在包角，揣着几枚零钱。在自动贩卖机前、在冒着热气的鲷鱼烧摊前，最先打开的小小宝库。它叮当作响的声音，就是细碎幸福的配乐。"},"ICON-0659":{"nm":"票据收集签","de":"本想丢却没丢的纸片，一张张被穿了起来。今天吃了什么、买了什么，票据是比账本更诚实的日记。攒上一个月，便成了厚厚一叠生活的记录。"},"ICON-0660":{"nm":"市场购物篮牌","de":"挂在去买菜的手腕上，一起穿梭市场街。一块豆腐、一捆大葱，还有顺手添上的那份人情，所有的重量它都毫无怨言地接下。比起腾空，它装满时反倒更起劲。"},"ICON-0661":{"nm":"纪念磁贴板","de":"每处旅行地挑一个贴在冰箱门上，厨房就成了一张小小的世界地图。去过的城市一个个并排挂着，悄声说\"再去吧\"。平凡的铁板，也有挽留回忆的力量。"},"ICON-0662":{"nm":"地区集章册","de":"一页一个章，走过的巷子以墨迹重新活了过来。走遍全国攒下的红色印记，便是足迹的地图。空格越来越少，下一段旅程就静静向你招手。"},"ICON-0663":{"nm":"包装绳卷","de":"为捆一个礼盒，无穷无尽抽出来的，是长长的耐心。只对懂得适时剪断的手，才肯许下利落的结。盘成一圈，静静等着下一回轮到自己。"},"ICON-0664":{"nm":"礼品缓冲包","de":"把易碎的心意软软地裹住抱在怀里。即便在颠簸的快递格中，也松松软软地撑着说\"没事，有我接着\"。连开箱人那灿烂的笑容，都预先替你守护好了。"},"ICON-0665":{"nm":"价签遮挡封","de":"悄悄盖住送礼物品价格的，是一张贴心的善意谎言。\"多少钱不必知道，收下心意就好\"——它轻轻落在价签上。这不是遮掩，而是让那份心意更显光彩。"},"ICON-0666":{"nm":"迷你购物车芯片","de":"推不动真的购物车，可指尖晃悠的这位小朋友，装满了逛超市的雀跃。虽小，可那\"今天买点啥\"的怦然心动，丝毫不输给真货那般沉甸甸。"},"ICON-0667":{"nm":"夜光鞋扣","de":"夜里散步的运动鞋尖一闪，向驶过的车发出\"这里有人哦\"的信号。在漆黑的巷子里最先出来相迎的小小光。安全，总是从脚尖悄悄开始。"},"ICON-0668":{"nm":"小手电盖","de":"套在手电头上，光便照得更远、晕得更柔。它是在漆黑帐篷顶上画出星群的小魔术师。夜里有点怕黑时，再没有比它更好的朋友了。"},"ICON-0669":{"nm":"到家提醒按钮","de":"用力一按，\"平安到家了\"这一行字便飞向远方的家人。深夜里，不必听玄关门响，一个小按钮就替你传了平安。有人正等着这个信号才安心入睡。"},"ICON-0670":{"nm":"反光贴卷","de":"裁下一格贴到包上、自行车上、伞上，夜路便安全许多。一遇车灯就明亮苏醒的瞌睡虫。它盘成一卷，等着下一场黑暗到来。"},"ICON-0671":{"nm":"应急出租车卡","de":"插在钱包一格里，深夜空荡的车站也没那么无措。一个号码、一行地址，像\"会送你到家\"的承诺般写着。应急这个词，竟能让人这般安心。"},"ICON-0672":{"nm":"夜路地图带","de":"把它绕在手腕上，走过路灯稀疏的路。哪条巷子明亮、哪里漆黑，它悄悄告诉你只有夜晚才知道的近路。是一条在黑暗中也不丢方向、把陪伴系在身边的带子。"},"ICON-0673":{"nm":"安心铃收纳包","de":"危急时一拉，便大声呼喊，喊得整条巷子都吓一跳。平日里它乖乖藏在包中，为那唯一的一瞬省着嗓子。这是装在小包里的、最响亮的呼喊。"},"ICON-0674":{"nm":"门前照明钥匙环","de":"漆黑走廊尽头，摸索着找锁孔的夜晚，从此再见。它挂在门前，用一圈圆圆的光迎接回家的手。\"辛苦了，到家了\"——钥匙环先一步打了招呼。"},"ICON-0675":{"nm":"归宿提醒便条","de":"\"带上伞，关灯再出门。\"贴在冰箱上的一句短短叮咛，守着空荡的住处。一张写给要回来之人的小纸条。一纸温柔，一路静静相随到玄关。"},"ICON-0676":{"nm":"理线梳","de":"像梳头发一样，把缠在一起的电线轻轻梳得整整齐齐。桌后那片丛林般的线缆，几下梳理就利落起来。乱的不只是头发——梳子静静这样告诉你。"},"ICON-0677":{"nm":"笔筒隔板","de":"铅笔放这边，荧光笔放那边，剪刀放末格。在一只筒里分出一个小村庄，给笔们各自定下位置。有了格子，手也不再乱翻。这是桌上小小秩序的开端。"},"ICON-0678":{"nm":"显示器便签夹","de":"挂在显示器侧边，把\"今日待办\"端到正好的视线高度。一块正对眼前、容不得遗忘的小提示板。一个夹子，悄悄按住那颗总想拖延的心。"},"ICON-0679":{"nm":"抽屉分类托盘","de":"回形针和橡皮筋，图钉和橡皮。给抽屉里这些小部族，各自分一间屋子。手伸向一格格分好的位置，找东西的时间少了，心里某个角落也轻松了。"},"ICON-0680":{"nm":"除尘刷筒","de":"落在镜头上的一粒灰，在照片里也会成为巨大的污点。所以刷子总在筒里干干净净地待命等候。守护那肉眼难见的洁净，是一双勤快的手。"},"ICON-0681":{"nm":"桌垫护角","de":"铺在桌子一角的一拃柔软。笔不会滚落，冰凉的玻璃换成了温暖的纹理托住手腕。为了长夜里的字迹不晃动，它最先腾出位置——是一片贴心的桌面。"},"ICON-0682":{"nm":"鼠标线夹","de":"线一缠，心也跟着哪里乱了起来。预先抓住那将要散开的一缕，规规矩矩地放好。它并不起眼，却静静理顺着桌面的纹理——是一份小小而勤快的修整。"},"ICON-0683":{"nm":"充电座托架","de":"把躺着的设备斜斜立起来，屏幕这才与人对上了眼。连充电时的等待，也变得整齐起来。所谓托住，就是连短暂歇息的东西，也替它整好姿态。"},"ICON-0684":{"nm":"迷你垃圾桶标签","de":"再小的桶也贴上自己的名字。\"扔这里\"一行字，在杂乱的桌面上唤来一份安静的秩序。所谓标签，归根结底是告诉物件：你的用处在这里——一句小小的问候。"},"ICON-0685":{"nm":"隔板软木钉","de":"把一张纸往板上轻轻一按。是把不想忘的心意，暂时托付给墙壁。挂在钉尖的今日誓言，随风微微摇晃，每次路过都把你拽住。"},"ICON-0686":{"nm":"标签边框芯片","de":"一道方形的边，就把寻常的字变成清晰的一句话。给容易散落的便签围上端正的格调。这不是囚禁，而是把要紧的话好好包住，不让它丢失。"},"ICON-0687":{"nm":"透明抽屉拉手","de":"给透明的抽屉装上拉手，既能看清里头装着什么，又不至于随手拉开。看得见却不靠近的一拃距离。透明也需要分寸——抽屉这样悄声说。"},"ICON-0688":{"nm":"盖子锁夹","de":"敞着放，香气也好、颜色也好，都会悄悄溜走。一个小夹子把盖子咬紧，昨天的颜色就原原本本留到明天。锁起来，其实是守护所珍惜之物。"},"ICON-0689":{"nm":"干燥剂支架","de":"厌恶潮湿、默默守在原处的小小哨兵。把干燥的空气留在身旁，是长久保存的第一要诀——这道理，由这端正的支架静静告诉你。干爽，就这样被守护着。"},"ICON-0690":{"nm":"整理篮标牌","de":"每只篮子配一枚小名牌。定好哪格里住着什么，找东西所费的时间，便径直变成了休息的时间。整理，是预先递给未来的我的一张贴心便条。"},"ICON-0691":{"nm":"迷你隔断板","de":"在桌上三两下立起一间小小屋的小隔板。有了这一块板，便有了一个稍稍背对世界的安静角落。一处适合专注降临、全然属于我的温馨小天地。"},"ICON-0692":{"nm":"收纳袋支架","de":"把一个个东倒西歪的袋子背脊轻轻撑立起来的支架。光是整整齐齐立着，挑选取用就轻松许多。把它立得端正，是为下一只手预先着想。"},"ICON-0693":{"nm":"空位标记芯片","de":"特意标出\"此处为空\"的芯片。留出该填补的位置，也是堂堂正正的计划。空格不是懒惰，而是为即将到来之物郑重留出的一拃留白。"},"ICON-0694":{"nm":"牙刷护套盖","de":"对要碰到嘴的刷头，总会用上更挑剔的心思。一顶连一粒灰也挡住的小帽子。照看那看不见的洁净，正是把每个清晨开得清爽的一份小小用心。"},"ICON-0695":{"nm":"肥皂托网","de":"轻轻把肥皂托起、免得它泡在水里变软的网。沥掉水分便能更久地陪在身边——这道理，它每天在浴室最低最小的角落里静静证明。"},"ICON-0696":{"nm":"洗发水泵夹","de":"轻轻夹住泵头，按一下就只流出恰好的量。省着用的手上习惯，是细水长流持家的根基。一个小夹子，温柔地管住了浪费。"},"ICON-0697":{"nm":"剃须刀挂盖","de":"锋利之物，要另给它一间小屋。把剃须刀套进盖里挂起来，水汽和危险便一同流走。小心对待锋利的方法，也正是爱惜自己的方法。"},"ICON-0698":{"nm":"沐浴巾环","de":"长长垂下的浴巾绕成一环，把够不着的后背也带到了手边。顺着泡沫滑过的那一道纹理，独自搓背的那份温情，也在浴室里暖暖地漫开。"},"ICON-0699":{"nm":"地漏滤网包","de":"放水流走、把残渣留住的一张小网。在看不见的地方，静静挡下堵塞。在最低处干活的东西守护着家的流动——地漏默默这样告诉你。"},"ICON-0700":{"nm":"吸盘挂钩板","de":"一颗钉也不钉，就能在墙上造出新位置。用力按上去，揭下来时连痕迹都不留。不留印记、暂歇片刻便离去的法子——吸盘板深谙这份轻盈的礼数。"},"ICON-0701":{"nm":"浴室拖鞋牌","de":"门槛前整整齐齐摆着的一双。脱鞋而入的那份家的讲究，一路细心延续到浴室门前。给冰凉脚尖暖意的小小款待，由名牌悄悄替它指定了位置。"},"ICON-0702":{"nm":"迷你漱口杯","de":"盛一口漱口水的小小圆杯。用漱口那短短一瞬，静静接住一天的开始与结束。不华丽却天天陪在身旁——朴素，才是最长久的家什。"},"ICON-0703":{"nm":"掸子套","de":"像爱抚般轻轻拂去灰尘的刷子，给那一身羽毛套上套子。像不用时把翅膀好好收起的鸟一样，懂得歇处的工具，才能长久地留在身边。"},"ICON-0704":{"nm":"粘毛器替芯","de":"撕下一层，下面便冒出一面崭新的清爽。收拢绒毛和发丝的那一层层黏黏的内里。用完又能续上的圆圆替芯里，卷着勤恳重复的美德。"},"ICON-0705":{"nm":"抹布夹","de":"替手稳稳咬住抹布的夹子。在冰凉的地板和手指之间，留出一拃距离。一个替你接下脏活的把手，让繁重的打扫变得轻快了不少。"},"ICON-0706":{"nm":"缝隙刷盖","de":"瞄准狭窄缝隙钻进去的细刷，给它纤弱的尖端配一顶小帽。是一份连手够不着的角落也要照看到的心。擦那看不见之处的人，把家的胸怀扩大了一拃。"},"ICON-0707":{"nm":"喷雾瓶标签环","de":"轻轻贴在喷雾瓶肩上的小名牌。里头装的是清水还是清洁剂，只一行字便分明告知。预先消除混淆的标签，是手脚麻利的持家人由来已久的习惯。"},"ICON-0708":{"nm":"卷纸替换带","de":"在用完的位置塞上新的一卷、牢牢系好的带子。是把断掉之物重新接上的、最简单的一只手。在用尽之前预先补上的那份心意，圆圆地缠在这小小一环上。"},"ICON-0709":{"nm":"清洁手套挂钩","de":"把刚做完水活的湿手套挂起晾干的钩子。给辛劳的手腾出片刻歇息的地方。水分慢慢晾干的同时，也是为下一份活计静静喘口气的短暂休憩。"},"ICON-0710":{"nm":"扫帚挂钉","de":"把扫帚倒过来挂起，刷毛便不会弯折、笔直地立着。倒挂着等待下一片庭院的姿态。这是一处小小却利落的位置，帮它在用尽之后仍守住自己的模样。"},"ICON-0711":{"nm":"垃圾袋夹","de":"牢牢咬住袋口，不让一点东西漏出，封得严严实实。把末端仔细收口的这一下，便让收尾干净许多。所谓收尾，归根结底是从好好封口开始的。"},"ICON-0712":{"nm":"晾衣夹收纳筒","de":"散开就容易丢的晾衣夹，聚在一起住的筒。给这些小东西腾出一个共住的家。把指尖的小兵们收拢在一处，需要时一眼便能找到。"},"ICON-0713":{"nm":"袜子分类环","de":"落了单的袜子，总会悄悄不知去向。洗之前用环把一双双扣好，蓬松晾干后两只也不会分开。分类，是预先防住走失的一个小小约定。"},"ICON-0714":{"nm":"洗衣球收纳袋","de":"在洗衣机里咕噜咕噜滚动，把衣服里的污渍轻轻拍醒。用圆圆的身子爱抚衣物的节奏。在湍急的水流间，把拍打这一洗衣的古老本能，装进袋里滚动起来。"},"ICON-0715":{"nm":"羊毛洗液量盖","de":"细致的衣物，用与之相称的细致分量。把羊毛洗剂恰好量上一盖的量盖。小小一道刻度里，盛着处理毛料的小心翼翼。减去过量，也是一份用心。"},"ICON-0716":{"nm":"布料修护贴","de":"在磨破处悄悄补上的小补丁。磨损的地方不随意丢弃，而是静静照看的指尖之心。每一道缝补的痕迹，都细细留下了与那件衣裳共度的岁月纹路。"},"ICON-0717":{"nm":"晾衣架固定针","de":"为了不让衣物被风吹跑、把晾衣架轻轻摁住的针。即便在衣物随风摇曳的日子，也帮它在晃动中守住原位。这是小小却踏实的一枚配重之责。"},"ICON-0718":{"nm":"内衣洗衣袋牌","de":"娇嫩的内衣，单独放进网袋里洗。把柔软之物从湍急水流中整个包住的网。一只贴着名牌的小袋告诉你：小心守护脆弱之物，也是持家。"},"ICON-0719":{"nm":"洗剂勺挂架","de":"把舀粉状洗剂的勺子整整齐齐挂在墙上。免去掉进桶里、弄湿手的麻烦。总把同一件工具放在同一处的端正习惯，利落地装在这小小挂架里。"},"ICON-0720":{"nm":"晾衣绳止扣","de":"牢牢咬住晾衣绳末端，即便挂上沉重衣物，也不会滑松。撑到最后、不让绷紧的一根松垂下来的最后一结。利落的收尾，就系在这里。"},"ICON-0721":{"nm":"枕套标签","de":"每夜脸颊最先贴上的地方，那内侧缝着一枚指甲大的标签。写着洗涤温度的蝇头小字，有谁会全读呢。可它依旧守在熟睡的脸庞旁，是最贴身的一份说明。"},"ICON-0722":{"nm":"被子夹","de":"开着窗的夜里，即便风吹进来，被子也不会跑掉。因为闭紧双唇的夹子正咬着边角。它替熟睡的人抓住被角，是一只无声的手。"},"ICON-0723":{"nm":"睡眠灯遮光板","de":"\"灯光照到眼睛，睡意就远了。\"有人悄悄立起的一块遮光板，让光退到后头，只朦胧润着脚边。是一块借给你一拃黑暗的小隔板。"},"ICON-0724":{"nm":"床缝口袋","de":"想想床垫和墙之间那道手够不着的缝吧。滚落的遥控器也好、眼镜也好，如今都汇到这里来。是床悄悄张开的一只口袋，接住那些险些弄丢的东西。"},"ICON-0725":{"nm":"眼镜收纳托盘","de":"摘下镜片，世界便柔柔地晕开，那短暂的毫无防备，由一只浅浅的碟子接住。到了早晨，不必伸手摸索，眼镜总在同一个位置等着。"},"ICON-0726":{"nm":"闹钟底座","de":"清晨六点，最招人恨的声响响起的坚实底座之上。它纹丝不动地托着钟，最终开启某人的一天。把醒来这冷硬的约定，默默扛在肩上。"},"ICON-0727":{"nm":"床头线缆夹","de":"顺着床头滑落的充电线，再也不会掉到地上。因为小小的夹子静静抓住了线的末端。伸手就够得到的距离，是为夜里的动线理好的一只手。"},"ICON-0728":{"nm":"睡衣收纳带","de":"把叠好的睡衣绕一圈系起来的带子。再柔软、易乱的东西，也需要一份整齐。为明晚的我，今天的我端端正正地卷好——是一份小小的准备。"},"ICON-0729":{"nm":"香氛卡夹","de":"把沾了香气的卡片斜斜立起，便像翻页一样，用鼻尖翻过一个季节。从薰衣草到柑橘——它成了用气味写下的那一天的日记本。"},"ICON-0730":{"nm":"钥匙碟垫","de":"玄关一隅，钥匙曾叮当掉落的地方。铺了柔软垫子的碟子，把那刺耳的声响吞了下去。归来之人的第一个动作，由小小的托垫静静接住。"},"ICON-0731":{"nm":"雨伞接水盖","de":"拿进屋的伞尖上，雨水滴滴答答落下。一个盖子利落地接住那滴落的水，于是地板上险些悄悄漫开的小水洼，便有人预先替你想到、拦下了。"},"ICON-0732":{"nm":"口罩挂芯片","de":"贴在玄关旁墙上、指甲般大的芯片。像出门最后的仪式一样，口罩挂在这里。为了不忘记该带的东西，它守在门前的视线高度，是个小小的记忆装置。"},"ICON-0733":{"nm":"快递刀刃护套","de":"套在划开快递箱的刀刃上的保护套。把藏在开箱雀跃背后的割伤风险，悄悄遮住。安全地开启等待的尽头，是一份不起眼的体贴。"},"ICON-0734":{"nm":"鞋刷托座","de":"刷完鞋的鞋刷湿漉漉搁置的地方。即便它含着水分，底座也干干爽爽。制造洁净的工具也需要歇处——小小的托座这样告诉你。"},"ICON-0735":{"nm":"访客留言板","de":"\"顺路来了一趟就走啦。\"留在玄关留言板上的短短一行字。是错过彼此的人们隔着时间分享的小小广场。一格纸上，问候、嘱托和一颗爱心层层叠起。"},"ICON-0736":{"nm":"门缝挡条卷","de":"曾从门下手指般宽的缝里渗进来的穿堂风。卷成一圈的挡条，静静拦住那条通路。把悄悄漏走的暖意，在屋里多挽留了一层。"},"ICON-0737":{"nm":"门挡挂饰","de":"为了不让敞开的门重新合上、托住门脚的小挂饰。为来往的风和脚步声，沉甸甸地守着位置。是延续\"敞开\"的一份贴心固执。"},"ICON-0738":{"nm":"玄关灯开关盖","de":"深夜摸索着找的玄关开关。夜光盖在黑暗中隐隐指出它的位置。为了让手不再乱摸，它在灯亮起之前先一步发光——是个小小的引路人。"},"ICON-0739":{"nm":"杯垫","de":"放到餐桌上的杯子险些咕噜滑走的瞬间，一张垫子静静托住了它的脚。即便凝出水珠也不留一点印记，是一只沉稳守着位置的托垫。"},"ICON-0740":{"nm":"车用香氛夹","de":"挂在车内的小小香氛夹。乘着出风口的风，淡淡的香气慢慢盈满这狭小的空间。连等红灯的无聊，也用香气温暖起来——是驾驶座上贴心的慰藉。"},"ICON-0741":{"nm":"安全带套","de":"套在横过肩膀的安全带上的柔软套子。蹭着颈侧的那份粗糙感，便悄然消失。为安全而设的带子也能添上温柔——一拃布这样说。"},"ICON-0742":{"nm":"停车号遮挡板","de":"把地下停车场里告诉我位置的车位号，在拍照前悄悄遮住的板子。不想留下的信息，谁都有那么一些。在日常的一幕里小心翼翼抹去的一层。"},"ICON-0743":{"nm":"自行车铃盖","de":"叮铃铃。巷子拐角，自行车递来的清脆问候。套在铃上的盖子，让这声音在雨中也得以守住。一声小小的铃响，人们便笑着退开一步。"},"ICON-0744":{"nm":"车把握环","de":"把触到掌心的车把手感柔柔包住的环。握久了奔驰也不发麻。路越远，握处的舒适，越能把那段距离缩短。"},"ICON-0745":{"nm":"头盔标签贴","de":"贴在头盔内侧的姓名贴。在一模一样的安全帽之间，小声喊着\"这是我的\"。在守护头部的坚硬之上刻下的、最私人的一枚标记。"},"ICON-0746":{"nm":"车轮反光盖","de":"太阳一落，才开始干活的盖子。接住路过的灯光，把车轮清晰地映回去。在黑暗中用光递出\"这里有人哦\"的一个小小信号。"},"ICON-0747":{"nm":"车钥匙保护包","de":"在口袋里与别的钥匙磕碰、被划伤的车钥匙。柔软的包把它的表面整个裹住。越是天天攥着的东西，越盼它无伤无痕、长久陪伴——那份心意都装在里头。"},"ICON-0748":{"nm":"吸附搁板钉","de":"一颗钉也不钉、往墙上轻轻一按就贴住的吸附搁板钉。在不想留印记的墙上，也多出一格收纳。把家什挂进暂住的房间，是一手不留痕迹的好手艺。"},"ICON-0749":{"nm":"免打孔挂钩板","de":"竟能不在墙上打孔就挂东西。免打孔挂钩板悄悄接下轻巧的物件。不愿弄伤所借空间的那份心意，细细装在一个小钩里。"},"ICON-0750":{"nm":"磁吸整理条","de":"铁器啪嗒一声归位的声响。把散落四处的小工具用磁铁唰地一收，乱糟糟的工作台便排成整整齐齐的一列——一份小小的爽快随之而来。"},"ICON-0751":{"nm":"缝隙收纳杆","de":"想想冰箱和墙壁之间那道被遗忘的狭窄缝隙吧。细细的杆子把那道空隙变成了收纳空间。从被认为无用的角落里挖出收纳之地，多么精打细算的巧思。"},"ICON-0752":{"nm":"粘贴垫片","de":"贴上一次，再重的东西也能稳稳托住的粘贴垫片。揭下来时却神奇地不留一丝痕迹。在看不见的地方默默承重，安静而坚韧的力量。"},"ICON-0753":{"nm":"门挂钩帽","de":"只需轻轻挂在门板上方的挂钩帽。包也好毛巾也好，都垂在伸手可及的高度。无需一颗钉子便凭空生出的挂钩，为狭小的房间多添了一处余裕。"},"ICON-0754":{"nm":"理线墙夹","de":"把顺着墙壁垂落的电线收成一条的夹子。书桌后纠缠的乱线被理成利落的一道。看不见的整理，连房间里的空气都变得轻盈几分。"},"ICON-0755":{"nm":"台灯底座垫","de":"悄悄垫在台灯底脚下的垫子。不在桌面留下划痕，连细微的颤动也一并安抚。要让灯光立稳，先得有一方不晃的底面。"},"ICON-0756":{"nm":"防滑粘贴板","de":"脚下总是悄悄滑动的垫子，终于停在了原处。因为粘贴板把地面牢牢咬住了。提前收走差点摔倒的瞬间，一张不起眼的安全网。"},"ICON-0757":{"nm":"精密螺丝刀帽","de":"“这颗小螺丝怎么拧不动呢。”套在精密螺丝刀尖上的帽子守护着刀刃。打开手掌大小机器里的世界，最纤细的指尖工具。"},"ICON-0758":{"nm":"内六角扳手环","de":"把好几支内六角扳手穿进一个环里系住。按尺寸排好的金属像折扇般哗啦展开。要哪一支便一下挑出来，整齐手感的节奏。"},"ICON-0759":{"nm":"迷你卷尺扣","de":"正好握进手掌的迷你卷尺上挂着的小扣。系在钥匙圈上，去哪都跟着。把忽然好奇的长度当场量出答案，一个小小的伙伴。"},"ICON-0760":{"nm":"螺丝分类盒","de":"形状各异的螺丝在一格格里找到各自归处的分类盒。原本混杂乱滚的小零件也有了秩序。在动手修理之前，先学会整理的双手。"},"ICON-0761":{"nm":"胶水喷嘴帽","de":"盖着便不会干，敞着却又会干——我活在这两者之间。每滴落下时，某处破碎的东西正被重新连接。一个小小的盖子，静静守护着停滞与流动的边界。"},"ICON-0762":{"nm":"水平仪钥匙扣","de":"在钥匙串末端晃荡的、手掌大小的诚实。最先察觉架子歪斜的，总是这个小小的气泡。我把这个悄悄告诉我世界微微倾斜的伙伴揣在口袋里带着走。"},"ICON-0763":{"nm":"镊子保护帽","de":"越是尖锐的东西，越需要一件能安抚它的外衣。轻轻包住尖端，手和零件便都不会受伤。对待锋利之物的第一份礼貌，便是悄悄盖住它的尖端——小小的帽子担起了这份温柔。"},"ICON-0764":{"nm":"小切割垫","de":"刀刃划过千百次，伤痕也会自行愈合的板子。划痕处又叠上下一次的工作，又再次愈合。舍出自身让别物被细细切割，沉默底板的一天。"},"ICON-0765":{"nm":"维修零件袋","de":"为了不让一颗螺丝、一根弹簧永远消失而收拢袋口的小袋。修完后剩下的小零件，在这里静静等待下一次轮到自己。防止遗失的，总是这样不起眼的小格子。"},"ICON-0766":{"nm":"零食袋夹","de":"守护开过封的袋子里那份酥脆，终究靠的是一次果断的夹合。不给受潮留一丝空隙的小小约定。把袋口紧紧咬住的手上习惯，救活了明天的零食。"},"ICON-0767":{"nm":"果冻分装杯","de":"要把一袋分给几个人，先得公平地分开。往每个小杯里舀进同样分量的那份心意。所谓分享，便相信是从谁也不委屈的、恰好相同的分量开始。"},"ICON-0768":{"nm":"巧克力锡纸片","de":"曾包裹甜蜜的那抹银光，在指尖轻易便皱起。摊开时短暂闪烁，叠起时便成回忆。吃完之后才最漂亮的一片光——丢弃前再多看它一眼。"},"ICON-0769":{"nm":"零食标签带","de":"里面装了什么、能放到什么时候——我替沉默的袋子说出来。贴上一条带子的瞬间，零食也有了名字和约定。分类其实是，最温柔的一种记忆法。"},"ICON-0770":{"nm":"糖果分类盒","de":"不把酸的和甜的放进同一格。为了让手不犹豫而提前分好。当小盒子们排成一列站好，挑选的乐趣便悄悄翻了一倍。"},"ICON-0771":{"nm":"饼干缓冲纸","de":"为了不让饼干在路上磕碰，一片片夹在中间的薄纸。越是易碎的东西，越需要更柔软的同行。比起坚硬，柔软有时更能守护。"},"ICON-0772":{"nm":"甜甜圈盒绳","de":"一个十字打的结，担起盒中蛋糕的平安。它成了提手，成了封印，也成了令人雀跃的等待的标记。这根绳被解开的那一刻，便是某人的生日。"},"ICON-0773":{"nm":"面包袋夹","de":"拧一下折起，再把我夹上，面包的松软便能封存到明天清晨。挡住空气的、小而固执的坚持。把柔软之物守护得长久，总是某件坚硬之物的本分。"},"ICON-0774":{"nm":"零食交换牌","de":"你的那份给我，我的那份给你。在小小的牌子上写下名字交换零食的那天的雀跃，还记得吗？贴在分享之心上的纸片，总是工整地写着朋友的名字。"},"ICON-0775":{"nm":"吸管封盖","de":"歇一口的时候，我便把自己盖上。不让洒出，不让凉掉，在原处静静等待。为了再次贴上嘴唇的那一刻而守住入口，小小封盖的工作。"},"ICON-0776":{"nm":"随行杯名字环","de":"在并排站着的众多随行杯中，告诉你“这是我的”的小环。一个颜色，混淆便悄然解开。表明这是我的，有这一个环就足够清晰。"},"ICON-0777":{"nm":"杯套","de":"悄悄塞进滚烫的杯子与手掌之间的一层瓦楞纸。为了不烫到、不打滑而夹进去的体贴。守住其间的距离，便成全了平安无事的一杯。"},"ICON-0778":{"nm":"冰格标签","de":"有人会在每块冰上写下制作的日期。怀着连冰冷也有顺序的信念。一张小小的标签，让冷冻室里的时间诚实地、依次流淌。"},"ICON-0779":{"nm":"茶包夹","de":"守望着泡开的时间，在恰好的瞬间捞起。懂得在太浓之前停下的手感。茶的深浅，由取出的时机决定，而非浸泡的时长。"},"ICON-0780":{"nm":"滤杯托","de":"为了让热水缓缓滴落而托住滤纸，默默站立。它很清楚，急了香气便会变浅。承托等待这件事，也需要不晃动的姿态。"},"ICON-0781":{"nm":"水瓶背带","de":"把水瓶挂在手腕、挂在肩上一同行走的带子。不必特意去拿，也总能伴在身边的同行方式。要不忘记，轻轻系上有时是最温柔的办法。"},"ICON-0782":{"nm":"罐口盖","de":"盖住喝了一半的罐口，挡住灰尘与跑气。负责把新鲜留到下一口的小帽子。把暂时开着的东西静静盖上，这件事里也藏着用心。"},"ICON-0783":{"nm":"饮品优惠券夹","de":"为了不弄丢第十杯免费那个约定，揣着集章卡。让一格格填满的日子不被揉皱。这个夹子里，堆着熟客勤快往来的脚步。"},"ICON-0784":{"nm":"便当束带","de":"为了不让盖子打开，把便当紧紧抱住一圈的带子。是包里汤汁不会渗漏的一份小小安心。担起到午餐前平安无事的，便是这扎实的一圈。"},"ICON-0785":{"nm":"小菜杯套装","de":"给每样小菜一个自己的位置，味道便不会互相串。泡菜归泡菜，凉拌归凉拌，各自分明。小杯子分出的格子，是便当的秩序，也是手艺之上的温情。"},"ICON-0786":{"nm":"筷子盒","de":"把陪伴一日三餐的筷子干净地收进来随身携带的小屋。在书包里也守着端正的安静同行。随身带着的那份心，终究造就了整洁的一餐。"},"ICON-0787":{"nm":"酱料瓶标签","de":"是酱油还是醋，给曾让人分不清的瓶子贴上分明。贴上一条的瞬间，指尖的犹豫便消失了。忙碌厨房的速度，正是由这些小小的标记悄悄成就的。"},"ICON-0788":{"nm":"紫菜包饭卷帘","de":"把米饭和馅料卷成一体的薄薄一张海苔。要卷得紧实，切的时候才不会散开。郊游清晨的雀跃，正是从这一层里圆圆地卷出来的。"},"ICON-0789":{"nm":"竹签筒","de":"把串签和牙签立在一处，需要的瞬间手便不会乱找。给尖锐之物也辟出固定的家。整理，终究是为下一次伸手而准备的小小善意。"},"ICON-0790":{"nm":"保冷袋套","de":"为了多留住一丝冰凉，给保冷袋再裹上一层。也一并挡住结露把包弄湿。把清凉守到最后的，总是这厚厚的一层。"},"ICON-0791":{"nm":"便当隔板","de":"为了让米饭和小菜不侵犯彼此的位置而立起的小小围墙。是汤汁不会越界的一格平和。分成一格格的便当里，盛满了制作者细致的心意。"},"ICON-0792":{"nm":"用餐顺序卡","de":"是先喝汤还是先吃饭，悄悄告诉你今日吃法的卡片。是按顺序吃会更美味的温柔指引。它静静告诉你，连一餐饭也像故事一样有它的流向。"},"ICON-0793":{"nm":"量杯贴纸","de":"贴在刻度旁的小贴纸，明确地点出“到这里”。把每次都搞混的分量一下子对准的标记。所谓准确，便始于这样一条小小的指引线。"},"ICON-0794":{"nm":"硅胶锅盖把手","de":"让烫手的锅盖能不烫到手指便提起的小把手。悄悄借给你打开冒着热气的锅的勇气。安全，总是来自提前备好可抓之处。"},"ICON-0795":{"nm":"迷你夹挂","de":"抹布也好袋子也好，给无处可挂之物辟出位置的小夹子。把杂乱的一面墙变成整齐的风景。一个挂起来的习惯，让厨房轻盈许多。"},"ICON-0796":{"nm":"油刷帽","de":"盖住刷油刷子的尖端，灰尘与凝固便都绕道而行。把那份柔软守到下一次烹饪的帽子。爱惜工具的一点小心思，终究把味道守得长久。"},"ICON-0797":{"nm":"盐勺筒","de":"深深插在盐筒里生活的小勺。每次都用心舀起一撮的精准。所谓调味的手感，便是这把小勺所记住的那么多心意。"},"ICON-0798":{"nm":"计时器磁吸板","de":"贴在冰箱门上数着泡面的3分钟，量着运动的30秒。一块磁铁，便让流逝的时间停在眼前。把流过之物暂时按在墙上的、勤快的圆盘。"},"ICON-0799":{"nm":"锅柄套","de":"为了不让人空手抓烧热的把手而包住的一层。挡在滚烫与手掌之间的小盾牌。平安地端起来这件事，总是从这柔软的一裹开始。"},"ICON-0800":{"nm":"砧板防滑垫","de":"我铺在底下，砧板便不再打滑。每当切菜晃动时在下面撑住的一片橡胶。所谓稳定，便是在看不见的地方牢牢咬住。"},"ICON-0801":{"nm":"厨房手套夹","de":"在炉火前不停忙碌的手，短暂停歇的地方。把翻飞的一只手套别在墙上，到下一餐前的短暂喘息便开始了。整理，终究是温柔的别名。"},"ICON-0802":{"nm":"咖啡搅拌棒架","de":"柜台旁，细细的小棒肩并肩、整整齐齐倚立的地方。备好了要在某人的清晨杯里画个圈，排队站立的模样，活像开口前的合唱团。"},"ICON-0803":{"nm":"杯垫套装带","de":"把杯子触到餐桌那细微“嗒”声轻轻接住咬住的带子。把圆圆的杯垫扎成一束，迎客的准备便妥当了。款待，总是从这般细小的角落里先开始。"},"ICON-0804":{"nm":"糖浆标签片","de":"贴在瓶上的一行名字。甜，浓——那短短一个词，便把忙碌的清晨抚得整齐许多。标签是把小小约定提前写下的纸。"},"ICON-0805":{"nm":"甜点叉筒","de":"把要扎起一块水果的尖尖小棒聚在一起生活的筒。在像旗子般插上甜点盘之前，在这里静静等待轮到自己。甜味也是有顺序的。"},"ICON-0806":{"nm":"搅拌棒套","de":"把一把搅拌棒整个包住的纸衣。替冷饮淌下的水珠先含住，让握杯的指尖保持干爽。看不见的体贴总是来自边缘。"},"ICON-0807":{"nm":"外带提手牌","de":"在两手不够用的瞬间，替你拎起杯子的小提手。把打包的暖意一滴不洒地托住，一路相送到某人巷口的那份温暖。"},"ICON-0808":{"nm":"咖啡取餐器套","de":"静静包住直到震动响起前那段等待的衣裳。守着咖啡馆一隅闪光的号码牌，连同“马上就要叫到我了”的那份雀跃也一并怀抱。"},"ICON-0809":{"nm":"集章券环","de":"集满十格便白送一杯的纸。每多盖一枚章，熟客这个名字也一点点长大。穿在小环上的、再朴素不过的乐趣。"},"ICON-0810":{"nm":"咖啡豆样品袋","de":"装上一把咖啡豆、先递上香气的袋子。掠过鼻尖的酸味与甜香，那第一印象决定了一杯的命运。香气比任何说明都更快抵达。"},"ICON-0811":{"nm":"冷藏标签磁铁","de":"啪地贴在冰箱门上的小磁铁名牌。写下什么东西何时放进来，差点被遗忘的小菜也能找回自己的轮次。持家，便是把流逝的记忆系住。"},"ICON-0812":{"nm":"保存日期片","de":"把装入的那天清楚刻下的一小片。即便过了几天，也悄悄告诉你这还没坏的小小见证者。新鲜，靠记住日期的指尖来守护。"},"ICON-0813":{"nm":"分装盒束带","de":"绕着分装好的盒子腰身抱住一圈的束带。把蠢蠢欲动的盖子牢牢拥住，守住冰箱里的小小秩序。捆住某物这件事，与整理心绪很相似。"},"ICON-0814":{"nm":"密封夹色带","de":"把袋口扎实咬住的五颜六色的夹子。红的是辣的，黄的是甜的——只看颜色，手便先知道了。厨房的红绿灯就这样无声地指引着路。"},"ICON-0815":{"nm":"冷冻袋名牌","de":"轻轻搁在冷冻之物上的名牌。让它在结霜的袋子里也不忘自己曾是什么，给它安抚。是递给进入冬眠的食材的一句小小问候。"},"ICON-0816":{"nm":"蔬菜保存网","de":"宽厚地接纳沾着泥土的蔬菜的疏网。要给点透气的空隙才能久放，奶奶的厨房早就懂了。通风是施予蔬菜的温柔留白。"},"ICON-0817":{"nm":"瓶盖分类帽","de":"把各种尺寸的盖子一一配对的分类帽。重新找回丢失的另一半，比想象中更温柔。配好相称的一对，厨房也整齐许多。"},"ICON-0818":{"nm":"鸡蛋托标签","de":"在十个小巢上工整标记的记号。提醒你先用放了几天的蛋的持家智慧。连一张早餐煎蛋里，也藏着讲究先后的心意。"},"ICON-0819":{"nm":"剩菜贴纸","de":"“这是我的！”写上一行贴好，冰箱里也暂得片刻和平。提前定下宵夜主人的可爱宣战。一家人，便靠这般细小的协定，今天也照常运转。"},"ICON-0820":{"nm":"筷勺托片","de":"让勺子和筷子不直接触到餐桌而轻轻托住的一小片。这点小小的端整，悄悄抬高了一餐的格调。餐桌礼仪便在这样的角落里静静长成。"},"ICON-0821":{"nm":"餐巾固定环","de":"把会被风吹散的餐巾轻轻夹住的环。把等待展开的白纸端整地拢起，在餐桌上工整地刻下一份小小秩序。"},"ICON-0822":{"nm":"餐垫角夹","de":"轻轻按住安抚餐垫翘起一角的小片。一端被压住，整体才得以平整，餐桌每天都在如此教导。连边角也有它那份的责任。"},"ICON-0823":{"nm":"小调料盘","de":"把一碟酱油、一撮盐并排托住的小托盘。连一样佐料也给它一个位置的餐桌宽广胸怀。韩餐因照顾配菜的心意而愈发深厚。"},"ICON-0824":{"nm":"餐桌号码片","de":"在忙碌的餐厅里被喊“几号客人！”的那个数字。给等待编上号，为所有人守住公平。一块号码片里盛着小小的约定，和即将端上的一碗热饭。"},"ICON-0825":{"nm":"水杯标识带","de":"绕在水杯上悄悄告知是谁的带子。在相似的杯子之间标出我位置的小旗。围坐一桌时，这般体贴能免去无谓的误会。"},"ICON-0826":{"nm":"分食盘标识针","de":"用颜色把分食用的小盘分开的针。温柔地划出我的和你的边界，让分食的乐趣更显利落。情谊照样分，卫生也扎实地守。"},"ICON-0827":{"nm":"菜单遮挡板","de":"在摊开的菜单后悄悄被遮住的纠结时光。选什么吃的那短暂犹豫，其实也是用餐的一部分。今天吃点什么呢——它静静遮住那份雀跃。"},"ICON-0828":{"nm":"席位牌座","de":"把名牌笔直立住的小底座。无论会场座位还是宴席，都清楚告知这里有你的位置。款待，要在呼唤名字的那一刻才算完成。"},"ICON-0829":{"nm":"玛芬杯套","de":"把刚烤好的玛芬丰腴的腰身整个包住的纸衣。托住温热的身子不从手中滑落，把暖意妥妥守到咬下一口的那一刻。甜点也需要一件衣裳。"},"ICON-0830":{"nm":"裱花袋帽","de":"让挤奶油的袋子尖端紧紧闭合的封盖。歇着的时候，把袋口扎实堵住，不漏出一滴。蛋糕上小小一朵花，正是从这份克制中绽放。"},"ICON-0831":{"nm":"饼干模具环","de":"把面团切成星形、熊形的圆形模具。同样的面粉经指尖醒来成数十种表情。无论烤什么，最先触到面团的，永远是用心。"},"ICON-0832":{"nm":"面团刮板挂饰","de":"把面团利落刮拢、干净切分的扁平之手。连黏在盆上的那一把也要收起的勤快，决定了一块面包的体积。烘焙是珍惜之手的活计。"},"ICON-0833":{"nm":"量勺板","de":"一小勺、半大勺——稳稳把量勺整齐摆放的板。精准的一勺把味道的平衡立得端正。手感这个词背后，其实藏着细致的称量。"},"ICON-0834":{"nm":"烤箱手套钩","de":"把守在滚烫烤箱前的手套挂起来的钩子。挡住烫伤的厚厚之手，歇息时也静静待在伸手可及处。安全，总是从待在原处的东西开始。"},"ICON-0835":{"nm":"晾架夹","de":"把刚烤好的点心冷却的晾架端整咬住的夹子。在散热时夹住不让走样，一同等待酥脆完成。冷却也需要一把耐心。"},"ICON-0836":{"nm":"蛋糕装饰插","de":"把“生日快乐”几个字轻轻插立在蛋糕上的插饰。烛火熄灭前的一刻，这面小旗把一个人的一天照得最明亮。祝福要立得高才显眼。"},"ICON-0837":{"nm":"糖粉罐","de":"盛着最后那轻轻一撒的罐子。像白雪般簌簌落在刚烤好的甜点上，把寻常的一块变成小小的礼物。收尾，来自最轻的一抹手势。"},"ICON-0838":{"nm":"三角饭团标签","de":"按1、2、3的顺序撕开塑料膜，海苔便酥脆复活的那个三角形。让人一眼认出便利店凌晨那个可靠伙伴的一行字。晚自习后嘴馋的夜晚就贴在这里。"},"ICON-0839":{"nm":"杯面盖夹","de":"在3分钟的等待里静静压住不让盖子掀起的托。替代了从前为防跑气而搁在上面的筷子。面泡熟的那短短时光，是宵夜最让人雀跃的一刻。"},"ICON-0840":{"nm":"热狗串帽","de":"把串签的尖端扎实包握住的小帽。让你方便一口咬下，又不让酱料沾上手一滴。小吃店前零嘴的乐趣，总在这般细小处成全。"},"ICON-0841":{"nm":"塑料袋提手","de":"勾在手指上，塑料便沙沙地轻轻作响。买的东西的重量偏向一侧，走到家的路在手掌留下红印。轻巧的声响里，沉甸甸地晃着今天一天的生计。"},"ICON-0842":{"nm":"收据收纳夹","de":"把长长吐出的收据对折咔地夹住，今天花的钱便成了乖巧的一叠。沾着墨味的纸一张张堆起的同时，细碎的持家记忆也被整理得井然。"},"ICON-0843":{"nm":"微波炉标签","de":"叮——一声响起前，标签静静掂量着加热的时间。几分几秒，写下要加热之物名字的小指示牌。等待变暖的心里，也有这样的刻度。"},"ICON-0844":{"nm":"折扣贴纸卷","de":"每撕下一格，便有黏黏的“嘶”声逗着指尖。红色数字成排展开时，某人的购物篮便轻了几分。圆圆卷着等待的小小善意一卷。"},"ICON-0845":{"nm":"酱料包环","de":"酸味啪地一下在嘴边漾开，寻常的一天也微微甜了起来。挂在圆环上的酱包随走路晃荡时，一点小小的甜味便整天在口袋里跟着我。"},"ICON-0846":{"nm":"便利店购物篮片","de":"握在手里，塑料轻盈地一颤。灯火通明的深夜小店里，正好装得下两三个三角饭团和一瓶饮料的深度。一个人也不孤单，刚好一顿饭那么大的温柔容器。"},"ICON-0847":{"nm":"马卡龙盒带","de":"为了不让五彩马卡龙散乱，一条带子静静抱住盒子。解开缎带前的那份雀跃其实最甜，收过礼物的人用指尖便懂。"},"ICON-0848":{"nm":"水果网夹","de":"把网口拢起轻轻一夹，苹果香便从网眼间悄悄溢出。一只防止滚落的小手。是“趁没软掉快吃吧”那句无声的温柔叮咛。"},"ICON-0849":{"nm":"果酱瓶盖布","de":"用圆布盖在盖上、再用橡皮筋扎住，外婆的夏日厨房便浮现眼前。一块格纹布里，连同果酱熟成的甜蜜时光与心意一并封住。手艺便这样被盖着保存。"},"ICON-0850":{"nm":"饼干扎丝丝带","de":"把刚烤好的饼干装进玻璃纸、拧上扎丝系好，黄油香便渗到丝带末端。把亲手做的递给某人的手，总会微微发颤。连心意也一并系进结里。"},"ICON-0851":{"nm":"巧克力隔板","de":"一格一格，为巧克力定好彼此不相触的位置。怕它化掉，怕它碎掉。小小隔板守到最后的，终究是要递给某人那一颗完整的心意。"},"ICON-0852":{"nm":"茶礼标签","de":"绕在茶包上的标签上，手写工整的名字。小纸片提前透露，泡开时草叶香会随热气升起。还没喝，手便先暖起来的一杯。"},"ICON-0853":{"nm":"糖果瓶项链","de":"在装着五彩糖果的瓶颈绕上绳子做成的项链。每走一步，里面便咕噜噜滚出小珠子般的声响。把甜蜜挂在脖子上的童年那份骄傲的宝物。"},"ICON-0854":{"nm":"礼品勺挂饰","de":"凭着手柄末端挂着的一个小挂饰，平凡的勺子转眼成了礼物。每次舀起时叮当轻碰的清脆声响。为递出的心意添上一点雅致的小巧装饰。"},"ICON-0855":{"nm":"零食回礼牌","de":"想把收到的多少也回赠一点的心意。轻轻挂在零食袋上的回礼牌一张。替还没说尽的“谢谢”，一句小小的问候从手到手静静传递。"},"ICON-0856":{"nm":"和纸胶带样品环","de":"一拃一拃剪下贴好的花纹排成一条小带。用指尖慢慢挑着哪个颜色好的同时，单是想着装饰，一天便染得五彩斑斓。连纠结都快乐的样本一条。"},"ICON-0857":{"nm":"贴纸镊子帽","de":"给尖尖的镊子尖端套上帽子，连指甲盖大小的贴纸也不会受伤。轻轻夹起手指够不到的边角的精密之手。摆弄喜爱之物，总要带着小心。"},"ICON-0858":{"nm":"手账角贴","de":"在手账四角贴上角贴，翻飞的书页便像谎言般安分下来。纸张微微被压住的触感，是把今天细细封存的一个小仪式。记录从边角开始变得牢固。"},"ICON-0859":{"nm":"打孔导引板","de":"提前指明打孔位置的板子。沿着虚线静静对准便不会错位。不慌不忙再掂量一次的心，准确总是从那一拍的小小余裕里悄然降临。"},"ICON-0860":{"nm":"纸屑托盘","de":"剪裁后剩下的纸屑簌簌聚进托盘里。为了不弄乱书桌，小碎片暂时栖身的居所。手工的收尾便这样无声地被整理妥当。"},"ICON-0861":{"nm":"彩色印泥","de":"轻轻按下印泥再抬起，指尖便润润地染上颜色。红黄蓝，一枚印章上沾起的小彩虹。在白纸上点点种下色彩的、软软的一方天地。"},"ICON-0862":{"nm":"装饰胶带卷","de":"嘟噜——抽出的花纹无尽延续。撕下一格贴上，平淡的地方便开出花来。随手便越来越漂亮的、圆圆卷着等待的小魔法一卷。"},"ICON-0863":{"nm":"主题印章帽","de":"为了不让墨水干掉而把印章头整个包住的小帽。让下次要盖的花纹清晰留存而静静守护。妥善收好的颜色，在下一张纸上也照样鲜明地绽放。"},"ICON-0864":{"nm":"装饰冲压片","de":"冲子咔地落下的小碎片。剪成星星、爱心、花瓣的彩纸屑簌簌聚在掌心。漂亮得舍不得扔、又会贴到某处去的小小宝石。"},"ICON-0865":{"nm":"线轴标签环","de":"每个线轴上写着彩线名字贴好的小标签一张。在缠乱之前便指明归处的温柔标记。纠缠的线也好、心也好，有一张名牌便理起来轻松许多。"},"ICON-0866":{"nm":"针书封套","de":"盖住密密插着针的毛毡书页的柔软封套。翻开时缝纫工具整齐躺着迎接我。为了不让指尖受伤，把尖锐之物温柔安睡的一小册。"},"ICON-0867":{"nm":"布料样品环","de":"粗糙也好柔软也好，用指尖一一摩挲挑选布纹的缓慢时光。在按颜色层层聚拢的布片之中，成衣之前，布先静静等着被触摸。"},"ICON-0868":{"nm":"刺绣绷环","de":"把布料嵌进圆绷拧紧，便像鼓面般绷得紧紧的。一针一线刺绣的准备就绪的小小信号。绷子牢牢抓住的不是布，而是专注的心。"},"ICON-0869":{"nm":"纽扣分类胶囊","de":"曾咕噜乱滚的纽扣按颜色乖乖坐进胶囊的每一格。为了不丢失而细细分装的持家智慧。把散落之物聚起来，也要费这般用心。"},"ICON-0870":{"nm":"缝纫划粉夹","de":"把在布料上划线的划粉夹得便于握持的夹具。把易折之物稳稳托住。第一行要划直，衣服才会正——那是拿起剪刀前沉静的初心。"},"ICON-0871":{"nm":"珠针瓶","de":"透明瓶里珠针相碰发出叮当声。对着阳光，每根针尖都凝着一点小小的光。把散开便危险的东西聚在一处细细安睡的、扎实的一只器皿。"},"ICON-0872":{"nm":"修补胶带卷","de":"对着破洞贴上熨一熨便悄悄黏住的魔法之带。不用一针，破衣便静静愈合。不丢弃而缝补着穿的心意，圆圆地卷进这一卷里。"},"ICON-0873":{"nm":"补丁图样纸","de":"提前画好补丁形状的图样纸一张。虚线温柔指引剪刀将走的路。先描出想做之物的轮廓，雀跃总是从这淡淡的底稿开始。"},"ICON-0874":{"nm":"水彩水桶盖","de":"盖在水桶口上，彩色水再怎么晃荡也不漏一滴。连洗笔后浑浊的水会洇上书桌的担忧也一并盖住。默默守住画画那方天地的安静封盖一只。"},"ICON-0875":{"nm":"粉彩保护带","de":"给簌簌掉粉的粉彩绕上一条带，手指便不那么脏。把娇嫩的颜色不碎裂地轻轻包住的纸。越软越要轻巧拿，在纸上才涂得漂亮。"},"ICON-0876":{"nm":"彩铅延长帽","de":"把帽子插在用秃的彩铅尾端，一支便又变长了。不因短了就轻易丢弃的心。在用到最后的指尖下，画的颜色到最后一格也更浓地完成。"},"ICON-0877":{"nm":"洗笔杯钩","de":"把洗笔杯挂在钩上，笔上滴落的水珠便咕噜噜流下。涂下一个颜色前，洗笔那短暂而清澈的静默。变干净的那声响里，也流淌着安静的节奏。"},"ICON-0878":{"nm":"调色刀帽","de":"套在铺开刮拢颜料的刀刃上的小帽。守护着锋利的尖端不变钝。厚厚抹上的颜色质感，正诞生于这一把照料得当的刀刃。"},"ICON-0879":{"nm":"画布夹","de":"把画布用力绷在框上固定的扎实夹子。一夹紧，作画的面便绷得平展。要有不晃动的底子，在其上奔驰的笔触才能尽情自由。"},"ICON-0880":{"nm":"画板带","de":"把带子往肩上一挎，画板便跟到了背后。随处坐定，那里便成了我专属的工作室。为寻想画的风景而轻装出发的、背在背上的小画室一间。"},"ICON-0881":{"nm":"丙烯颜料钥匙","de":"多加一滴水便是黎明，少一滴便成午夜。明明是同一种蓝，在指尖每次都开出不同的天空。挤出一支的瞬间，今日心绪的色彩便在纸上洇染开来。"},"ICON-0882":{"nm":"渐变样品纸","de":"晚霞不会一下子变红，这张纸最先懂了。从浅向深过渡的小小阶梯。眼睛在其间缓缓行走，静静追随色彩熟成的时光。"},"ICON-0883":{"nm":"钩针帽","de":"在线勒进手指之前套上的、像顶针般小小的护套。织得久的手越是明白。唯有不受伤，才能把最后一针也温柔地带到。"},"ICON-0884":{"nm":"编织记号环","de":"织到哪里了，有一个标记便重新清晰起来。不必把同一针数两遍的安心。心也一样，轻轻指一指走过的地方，才不会迷路。"},"ICON-0885":{"nm":"行数计数挂饰","de":"织完一行的安静证据一格格累积。看似无尽的活计，一个个数下来，转眼已过了一半。小小的计数让今日的心坚持到最后。"},"ICON-0886":{"nm":"线头整理针","de":"解开的线头若就这么留着，不知下一个结会在哪儿缠住。提前整理看不见之处的手。温柔大多便是这样，先在不起眼的角落里动起来。"},"ICON-0887":{"nm":"打结练习绳","de":"死结、蝴蝶结、戒指结。直到手记住形状，便把同一根绳系了又解。生疏的指尖在某个夜晚忽然变得顺滑时，那一根绳最先知道。"},"ICON-0888":{"nm":"毛线标签带","de":"在每个线团上写下是什么粗细、什么颜色的小带。曾因用完后买不到同款线而辗转的夜，才生出这习惯。记录是写给未来的我的温柔便笺。"},"ICON-0889":{"nm":"密度尺片","de":"10厘米里能容下几针——那个小小的数字决定一件衣服的尺寸。手掌大小的一片握着整体的尺度，掂起来其实分量不轻。"},"ICON-0890":{"nm":"扣眼标记","de":"钉纽扣之前，先点一个点标出要在哪儿打孔。多亏那转眼便会消失的标记，衣襟才不歪。用心大多终究悄悄留在看不见的角落。"},"ICON-0891":{"nm":"小流苏环","de":"像佩饰末端的流苏，一个小环造出摇曳。垂挂着静静晃动之物，总能引来人的目光停留。每当风吹过便悄悄活动起来的纹理。"},"ICON-0892":{"nm":"迷你涂料瓶","de":"不是省着用，而是精确地用，才是正确对待涂料之道。一滴便够的颜色，放在小瓶边掂量的手。节制来自把贪心放下一回。"},"ICON-0893":{"nm":"小型砂纸棒","de":"从粗面开始，渐渐移向细面。世上没有一下子就变光滑的表面。在一级级降低纹路的指尖下，粗糙之处慢慢变得柔顺。"},"ICON-0894":{"nm":"模型夹托","de":"用手攥着上了胶的零件便会留下指纹。轻轻夹在夹子上，手便自由了，干燥独自悄悄完成。等待，也在有人撑着时变得轻松。"},"ICON-0895":{"nm":"胶水垫板","de":"一滴胶水落在书桌上，痕迹便久久不去。先铺一张垫板的习惯。作业的一半，或许便始于那不想弄脏台面的心。"},"ICON-0896":{"nm":"零件分类格","de":"数十个同样形状的零件混在一起，组装转眼便成迷宫。在每格分开装的手，便提前省下了将要迷茫的时间。整理是递给未来的我的善意。"},"ICON-0897":{"nm":"组装顺序片","de":"写着从几号零件先装起的小片一张。守住顺序便不易垮掉。模型也好，一步步累起的某一天也好，都在那安静的约定上变得牢固。"},"ICON-0898":{"nm":"迷你画笔挂","de":"把用过的笔放平，笔毛便压弯了。倒挂起来沥水的位置。把工具长久留在身边的人，活计结束之后反倒更忙碌、更温柔。"},"ICON-0899":{"nm":"塑料碎片筒","de":"从模具上剪下的边角料静静聚集的筒。看似被丢弃，却总有一天会变成一处小细节回来。剩下的也有它的轮次，筒默默等着、明白着。"},"ICON-0900":{"nm":"封面喷漆帽","de":"最后一层若喷得太近，便会就那样淌下来。隔着一拃的距离，轻轻地，轻轻地。上光这件事，或许也是把心中贪念放下一回的练习。"},"ICON-0901":{"nm":"自动铅笔芯盒","de":"细细的铅笔芯在口袋里总是轻易折断。把它们整齐地横放在小盒里，一根都不会浪费。所谓整理，归根结底是预先珍惜明天的自己的一份静默心意。"},"ICON-0902":{"nm":"橡皮纸套","de":"给橡皮披上的小小纸衣。被手垢染得越黑，修改重写的痕迹就积得越多。所谓擦去，也是一种温柔的允许——告诉你回到最初也没关系。"},"ICON-0903":{"nm":"笔尖收纳筒","de":"笔尖干了会开裂，磕碰了会弯折。一只单独横放收纳的小筒，能长久守护字迹的纹理。被细心对待的工具，终会以顺滑的笔触作为回报。"},"ICON-0904":{"nm":"钢笔墨水试色","de":"一滴一滴试着蘸取的墨水。以为是青绿的颜色，落在纸上却成了深沉的大海。颜色总要亲自相遇才知道——心里想象的色彩，往往会有偏差。"},"ICON-0905":{"nm":"便签旗收纳筒","de":"在读到一半的地方轻轻夹上的小旗子。下次翻开书，昨天的自己就招着手在等待。连暂停的位置都成了约定，这是小小标记温柔的功劳。"},"ICON-0906":{"nm":"便签旗补充包","de":"撕下一张贴上，故事就从那里重新开始。小小的旗子在书页侧边排成一列，散乱的思绪便像一张地图般层层汇聚成册。"},"ICON-0907":{"nm":"回形针分类磁铁","de":"能一次收拢散落回形针的小磁铁。越小的东西越容易丢失，一份聚拢的力量便悄悄拯救了凌乱的书桌。连吸引之中，也藏着温柔。"},"ICON-0908":{"nm":"铅笔帽套装","de":"包住铅笔尖、守护书包内部的小帽子。尖锐的东西总会刺到什么，所以需要一只静静覆盖它的手。既不让它变钝，也不让它伤人。"},"ICON-0909":{"nm":"桌牌贴纸","de":"写上名字贴在桌前的那一刻，那个位置才终于成了某人的所属。哪怕只是一掌大的空间，一旦有了主人，安放心情的姿态都会变得不同。"},"ICON-0910":{"nm":"跳绳手柄帽","de":"在手柄末端磨损开裂前套上的帽子。摇过上千次的绳子的节奏，手掌比脑子更先记住。刻进身体里的拍子，是很难忘记的。"},"ICON-0911":{"nm":"瑜伽环拉带","de":"握住环慢慢舒展身体。带子越绷紧，僵硬的肩膀便一层层松开。所谓拉伸，不是硬扯，而更接近于静静等待身体自己打开。"},"ICON-0912":{"nm":"乒乓球盒","de":"因为轻所以滚得远，被踩到就直接瘪掉的白色小球。一只小盒便守护着这最脆弱的球直到下一场比赛。坚固，常常来自柔软的包裹。"},"ICON-0913":{"nm":"羽毛球握把胶带","de":"把被汗水打滑的手柄细细缠上一层。在缠得漂亮的握把上，球拍便成了手的一部分。不靠力气、靠手感击球的诀窍，就藏在这薄薄一层里。"},"ICON-0914":{"nm":"迷你计分筹码","de":"一分，又一分。移动着小小的筹码，把分数一点点累积起来。当计数变得可见，比赛就更加清晰，追平一分之差的勇气也悄然涌起。"},"ICON-0915":{"nm":"球鞋朝向夹","de":"整齐摆放的鞋尖总朝着同一个方向。脱鞋时轻轻转一下的那只手。一个微不足道的整理，便让明早的脚步轻快了许多。"},"ICON-0916":{"nm":"哨子挂绳","de":"把哨子挂在脖子上，就有了说\"停\"的权力。短短一声，整个操场齐齐停下的景象。信任那一声小小哨音的心汇聚起来，便成了约定。"},"ICON-0917":{"nm":"打气针收纳筒","de":"瘪了气的球，只需一根细针就能重新鼓胀起来。被小心供在小筒里的那根针，一旦弄丢，整个打气筒就成了废物。最小的东西，往往最关键。"},"ICON-0918":{"nm":"迷你标志锥","de":"从这里到那里，小小的锥筒画出了看不见的边界。即使没有线，人们也会自然地沿着标记排队。秩序，正是从这样微小的信号里悄悄生长。"},"ICON-0919":{"nm":"代币小袋","de":"把叮当作响的代币聚到一处的小袋。把袋口收紧，就不会散落。再小再不起眼的东西，也得有个容身之处才能各尽其用——小袋无声地这样诉说。"},"ICON-0920":{"nm":"纸牌洗牌垫","de":"光滑的桌面上，牌总是不好拿。一张垫子，洗牌和抓牌都顺手了许多。哪怕只是玩乐，也有先铺好桌底的那份温柔准备。"},"ICON-0921":{"nm":"棋盘护角","de":"桌游之夜结束后，总有人默默先收拾棋盘的四个角。因为知道折痕一深，下一局就会歪斜。在抚平边角的指尖里，藏着明天再一起玩的心意。"},"ICON-0922":{"nm":"骰盅盖","de":"摇、掷，然后大家一起屏住呼吸的那短短一刻。这是不让骰子蹦出去的小小天顶。在盖子里，今日的运气先稍稍喘口气，再咯啦地滚出来。"},"ICON-0923":{"nm":"牌片整理板","de":"越是因手气而兴奋的人，排得越歪。当牌片倾斜时悄悄推一推、对齐它的活儿。所谓对齐，是温柔接住某人雀跃急切的那只手。"},"ICON-0924":{"nm":"筹码收纳筒","de":"筹码在筒里堆得越满，牌局也越发火热。圆圆的分数在掌心咯啦碰撞时，比起输赢，那声音先一步令人愉悦。"},"ICON-0925":{"nm":"回合标记环","de":"告诉你\"轮到你了\"的小戒指。挪一格套上去的那一刻，所有人的目光便静静聚到我身上。这是在等待与雀跃之间缓缓转动的环。"},"ICON-0926":{"nm":"棋子底座","de":"越容易倒的棋子，脚下越要稳。一个底座，能在微微晃动的棋盘上稳住它的位置。小的撑得住，上面的大物才能挺立。"},"ICON-0927":{"nm":"说明书夹","de":"说明书总是摊开着却又悄悄翻了页。在书页被风吹跑前，静静咬住一页的夹子。把规则固定住，游戏才能一直玩到最后。"},"ICON-0928":{"nm":"拨片盒挂绳","de":"吉他拨片偏偏在最尽兴的段落从指间溜走。挂在盒上的一根绳子，便阻止了这场小小的离家出走。只有经历过音乐戛然而止之夜的人，才会感激这根绳。"},"ICON-0929":{"nm":"簧片保湿筒","de":"簧片一干就会失去自己的声音。在湿润的筒里，一片细细的芦苇等待着下一次演奏。这是在吹入气息之前，先让气息安睡的地方。"},"ICON-0930":{"nm":"换弦上弦器","de":"弦一松，音也悄悄低垂。慢慢转动手柄找回张力——用心总是来自手腕末端。端正的声音，正是从这样细小的整理开始。"},"ICON-0931":{"nm":"乐器擦拭布","de":"演奏结束后，乐器上也留下淡淡的汗。用柔软的布轻轻一拭，光泽与今日的音符便一同沉静下来。珍惜之心，总在收尾时显现。"},"ICON-0932":{"nm":"调音钉护套","de":"调音钉裸露着放着，不知不觉就会生锈。一个小护套，把金属的季节延缓了一拍。先照料看不见角落的人，才能长久演奏。"},"ICON-0933":{"nm":"谱架夹灯","de":"昏暗的后台，有些时刻只需照亮乐谱。这是夹在谱架上、把光轻轻洒下的小灯。为不让音符迷路而照亮脚下的一捧光。"},"ICON-0934":{"nm":"练习消音帽","de":"凌晨的练习总与邻人的睡眠悄悄相争。套上一个帽子，洪亮的声音便缩成了细语。也有这样守护着别人安眠而成长起来的音乐。"},"ICON-0935":{"nm":"鼓垫贴纸","de":"贴在鼓垫上的小小标记。敲哪里会发出什么声音，在手记住之前，眼睛先认了路。节拍，就这样慢慢刻进身体。"},"ICON-0936":{"nm":"旋律速记筹码","de":"哼着的旋律，不抓住转眼就消失。匆匆记在筹码上的几小节，日后也可能长成一整首歌。灵感，总会再来寻找那只勤于记录的手。"},"ICON-0937":{"nm":"书衣束带","de":"读到一半的书在包里随意翻开就麻烦了。用一根束带把书页静静捆住，纸页就乖巧了。这是为下一页而端正合上的约定。"},"ICON-0938":{"nm":"翻页指环","de":"想单手撑开书、一边喝热咖啡的日子。套在手指上的指环替你按住书页。小小的悠闲，正是从这样微不足道的发明开始。"},"ICON-0939":{"nm":"阅读计时筹码","de":"想着\"就读一章\"坐下，不知不觉夜已深。按下筹码定好时间，阅读也有了逗号。越是喜欢的事，越需要懂得停下的温柔勇气。"},"ICON-0940":{"nm":"书角保护帽","de":"越珍爱的书，越是从书角悄悄磨损。套上一个帽子，封面的边角就被圆润地护住了。这是把想长久相伴的心意悄悄夹上的小铠甲。"},"ICON-0941":{"nm":"感想便签带","de":"有那么一刻，一句话便让心猛地一沉。誊抄在带子上的感想，像书签般停留在那一页。那是只有读过的人才懂的、批注的温度。"},"ICON-0942":{"nm":"图书馆归还吊牌","de":"还书日总是早一天逼近。吊牌上的日期静静推着你的背，借来的书也有了收尾的礼数。为了下一个人的手，图书馆便这样等待着。"},"ICON-0943":{"nm":"阅读灯夹","de":"在熟睡的家人旁独自醒着读书的夜。书页一端夹上的一束小光便已足够。不必驱尽黑暗，一页之光便已充裕的宁静时光。"},"ICON-0944":{"nm":"书香卡","de":"旧书会散发阳光与纸张混合的气味。据说把那香气封进了一张卡里，翻开时，旧书店的小巷便在鼻尖短暂复苏。记忆，也会用气味夹上书签。"},"ICON-0945":{"nm":"阅读进度别针","de":"\"读到哪儿了\"——这枚小别针能抹去那茫然的疑问。别在最后一句上，明天的我便不再迷路。这是替你记住停下之处的温柔标记。"},"ICON-0946":{"nm":"手机挂绳扣","de":"手机绳上挂的一个小扣，人就显得有点不一样了。喜欢的颜色，喜欢的形状。握在手里的小小喜好，悄悄拨动了那天的心情。"},"ICON-0947":{"nm":"相机镜头保护盖","de":"旅行照片的命运，系于一片镜头之上。摘下保护盖的那一刻，便是按下快门的心理准备。这是收纳风景前，最先睁开眼的小小仪式。"},"ICON-0948":{"nm":"充电口防尘塞","de":"包里的灰尘总是先盯上充电孔。用一个塞子堵住这小小入口，接口便能长久干净。这里藏着连看不见的缝隙都要照料的勤勉。"},"ICON-0949":{"nm":"手机支架气环","de":"想舒服地看一段视频而把手机斜着立起的事。展开背后的气环，手和屏幕都从容了许多。一个小小立起的支撑，把傍晚时光悠然拉长。"},"ICON-0950":{"nm":"屏幕清洁贴","de":"满是指纹的屏幕，连心情都莫名变得模糊。用清洁贴一擦，世界便重新清晰起来。所谓干净，有时只是手指一抹的短暂工夫。"},"ICON-0951":{"nm":"取卡针收纳盒","de":"取卡针偏偏在最需要的时候销声匿迹，像个精灵。放进盒子的一格，就再也不必为找发夹而翻遍整个家。小小的整理，悄悄解救了那匆忙的一刻。"},"ICON-0952":{"nm":"无线充电板贴纸","de":"静静放上去就自动充满的夜。贴着的贴纸，悄悄标出手机该躺下的位置。看不见的电流无声地补满一天份的元气。"},"ICON-0953":{"nm":"通知遮挡贴","de":"不想看的通知，遮起来反倒心安。一张贴纸便安抚了凌晨的那点小亮光。有时，不去看也是守护自己的一种温柔方式。"},"ICON-0954":{"nm":"镜头保护环","de":"相机镜头触地的那一瞬，心猛地一沉。围上的一个环，便悄悄挡住了这场小小的坠落。这是最先包裹住那双收纳回忆之眼的边框。"},"ICON-0955":{"nm":"线缆标签","de":"从缠成一团的线堆里硬是辨出自己那根的活儿。一个标签，充电线也终于有了自己的名字。这是在凌乱线间为你指路的小旗子。"},"ICON-0956":{"nm":"充电器收纳袋","de":"旅行箱里的充电器们总是互相缠斗。整齐地聚到袋子的一格里，它们才终于和解。收纳的诀窍，就在于把散落之物温柔地唤回一处。"},"ICON-0957":{"nm":"插排标签","de":"排插的孔个个长得一模一样，每次都让人犯迷糊。贴上标签定好谁的位置，忙碌的早晨便顺畅许多。一个小小名牌，减少了日常里的琐碎纷争。"},"ICON-0958":{"nm":"电线收线轮","de":"解开来用，再卷回去——这是线缆端正的一天。在一个轮上层层卷起，缠结便干净消失。用完归位的那只手，让明天变得轻盈。"},"ICON-0959":{"nm":"磁吸接口帽","de":"磁吸接口不知不觉就会聚拢细小的铁屑。盖上帽子，黏腻的灰尘便不再附着。多一份照料的手所触及的设备，会更长久地陪在身边。"},"ICON-0960":{"nm":"充电宝束带","de":"充电宝和线分开放，总会少了一样。用束带捆在一起，两者才终于成了一对。出门前，悄悄系上一个小结，让它们结伴同行。"},"ICON-0961":{"nm":"插头防尘帽","de":"空着的插座孔，没几天灰尘就悄悄安了家。这个小帽子替你守着那位置，下一个插上的充电器便能吸入干净的第一口气。这是细心守护空置时光的门卫。"},"ICON-0962":{"nm":"线缆色彩环","de":"在缠乱的线里摸索自己那根的夜里，是谁说给它们上点色吧。蓝色是你，黄色是我。一个小环，我们便再也不会把彼此弄混。这是合奏室一角留下的、温柔约定的痕迹。"},"ICON-0963":{"nm":"转接头分类筹码","de":"圆脚与扁脚，110和220。这枚筹码静静记下了各国插座不同的面孔。第一次跨海登台的行李箱一角，总塞着这张小小的分类表。"},"ICON-0964":{"nm":"耳塞套分类板","de":"据说每个人耳道的深浅宽窄都不同。把大、中、小三对并排横放，挑出最合自己耳朵的一对。这是在听声之前，先把身体调合好的温柔程序。"},"ICON-0965":{"nm":"手机壳硅胶环","de":"舞台服连一针线缝都精心打理，偏偏手机壳的边角总是裸着相撞。这薄薄的硅胶圈轻轻包住一圈，即使在从手中滑落的凌晨，屏幕也能完好地迎来清晨。"},"ICON-0966":{"nm":"降噪贴","de":"总有想暂时关掉世间声响的日子。贴在头戴耳机耳罩上的这枚小贴纸，是开启寂静的标记。无论台下的呐喊还是地铁的喧嚣，都只在一首歌结束前被远远带开的护符。"},"ICON-0967":{"nm":"耳挂套装","de":"一跳起舞来，耳机总有一只先跑掉。挂上这个轻轻搂住耳廓的环，即使在激烈的编舞中，音乐也能始终留在耳边。这是练习室里大家相互交流出的小发现。"},"ICON-0968":{"nm":"清洁刷帽","de":"为了不让刷尖沾的灰尘再次飞扬而套上的小帽子。打扫的工具也需要打扫——扫完地把扫帚倒立靠放的那只手，很久以前就懂得这道理。"},"ICON-0969":{"nm":"充电座底垫","de":"充电座在桌上总打滑，是因为没有脚。铺在底部的这一张薄垫代替了脚，设备便能稳稳停在原处，整夜安静地补充元气。"},"ICON-0970":{"nm":"左右区分标记","de":"左L，右R。为了在黑暗中摸索也能分辨，多点上一个点。绝不想把舞台的左脚右脚弄错哪怕一次的心意，原原本本地嵌在这小小标记上。"},"ICON-0971":{"nm":"音频分配口帽","de":"那个让众人分享一路声音的插口，休息时也得堵上末端。免得灰尘渗进电路。这是为了下次也能把一同听过的歌清澈传送，而小心翼翼的手。"},"ICON-0972":{"nm":"耳机线收线器","de":"像从前缠线团的手法一样，耳机线在这里绕成圆圈也变得整齐。曾缠着乱滚在包里的音乐，被收拾得井然有序的瞬间。明天解开时也轻快许多。"},"ICON-0973":{"nm":"镜头盖挂绳","de":"每次打开镜头，盖子总不知该去哪儿。系在绳上拴在相机旁，就再也不必白白摸口袋了。不想弄丢，拴在身边就好——这道理手先学会了。"},"ICON-0974":{"nm":"热靴盖挂饰","de":"在相机顶端空着的热靴位，悄悄插上一个小装饰。那个毫无功能的挂饰，竟让笨重又冷漠的器材，不知不觉显得像自己心爱的物件般亲切。这是给工具注入情意的事。"},"ICON-0975":{"nm":"背带调节扣","de":"每当包带勒进肩膀，就把这个扣稍稍松一松、紧一紧。用手指挑出合自己身体的长度。背负行李，归根结底也是照顾自己——扣子静静地这样提醒。"},"ICON-0976":{"nm":"滤镜收纳盒","de":"把分割光线的玻璃片一层层横放收纳的小家。朦胧与晴朗，晚霞与黑夜。它像一个预先盛好天气的抽屉，摄影师出门前总要先打开这只盒子。"},"ICON-0977":{"nm":"气吹防尘帽","de":"喷出气流驱赶灰尘的橡胶球，它的口对灰尘也同样脆弱。休息时便套上这个帽子。替别人除尘的工具先静静堵住自己的口，那模样不知怎的格外温柔。"},"ICON-0978":{"nm":"快门键护盖","de":"在包里快门被乱按、空拍下上百张天空的事，大家都遇过一两回。套在按键上的这个小盖便阻止了那番徒劳。这是只为留下真正想留下的瞬间的、小小的锁。"},"ICON-0979":{"nm":"电池区分贴","de":"用完的和充满的混在同一个口袋里，总是糟糕。贴在每块电池上的彩色贴纸，悄悄理清了那份混乱。红色是空的，绿色是满满的。这是拍摄现场亮起的无言红绿灯。"},"ICON-0980":{"nm":"相机包隔板","de":"为了让镜头、机身和备用电池互不碰撞，在包里分出格子。在一份行李中辟出好几个小房间。每个位置都有定好的主人，再怎么摇晃也不会失了原位。"},"ICON-0981":{"nm":"拍摄手套垫","de":"冬日户外拍摄，唯独按快门的指尖不能冻着。手掌处是厚实的垫，指尖留着触感的手套。想把温暖与精准一同握在手中的、现场温柔的折中之策。"},"ICON-0982":{"nm":"平板笔尖筒","de":"笔尖也像铅笔芯一样会磨损——长久握着平板的人都懂。把备用笔尖咕噜噜聚在一起的这只小筒，是预先备好不可中断之线的、指尖的应急金。"},"ICON-0983":{"nm":"键帽托盘","de":"把键帽一个个拔下来洗净再装回去的那天，这只托盘成了一片小小的滩涂。辅音与元音格格分明地躺着晾干水汽的景象。也有些用心，要拆开一次才终于看得见。"},"ICON-0984":{"nm":"鼠标脚贴包","de":"鼠标能在桌面上滑行般飞驰的秘诀，就在底部贴着的这些小脚。磨损了就更换的一捆。这是在看不见的位置默默撑起顺滑的、那些东西的辛劳。"},"ICON-0985":{"nm":"笔记本支撑垫","de":"它形似笔记本，实则是撑起笔记本电脑的橡胶垫。把屏幕稍稍抬到与视线齐平，舒展弯曲的脖颈。这是为长久书写、长久注视的人，端正姿态的体贴。"},"ICON-0986":{"nm":"摄像头遮挡滑块","de":"用手指推着遮住镜头，再推开。只在想被看见时才被看见的心意。这一个小小滑块里，寄托着\"隐私\"这份大大的安心。合上的声音，不知怎的格外可靠。"},"ICON-0987":{"nm":"USB分类标签","de":"五根相似的黑色小棒，根本分不清哪根装了什么。贴上小标签起个名字，它们这才成了自家人。有名字可叫，找起来才容易。"},"ICON-0988":{"nm":"桌垫压角","de":"桌垫边角总往上卷，连手写字都跟着歪斜。轻轻压住四个角的这个小部件，守护着桌面上平整的安宁。底面安静，指尖才沉着。"},"ICON-0989":{"nm":"集线器支架夹","de":"把众线汇聚的集线器斜立在桌边的夹子。凌乱的线缆汇成一点被理顺的模样。把缠乱之物归拢成一束的手感，在这里也鲜活地存在着。"},"ICON-0990":{"nm":"屏幕清洁喷雾盖","de":"擦去屏幕上手印的喷雾，这是堵住它口的小盖。为防液体渗漏或干涸，总要拧紧盖好。想看得清，就得先珍惜擦拭这件事——这是过日子朴素的次序。"},"ICON-0991":{"nm":"存储卡夹","de":"好几天的舞台影像，静静沉睡在指甲盖大小的一张卡里。一旦弄丢，那一整天就会整个消失，所以珍重地聚在小夹里揣着。这是收纳最小却也最大记忆的家。"},"ICON-0992":{"nm":"移动硬盘标签环","de":"五个黑色移动硬盘在抽屉里以同一张面孔沉睡着。贴上标签，命名为\"那年夏天\"\"未公开片段\"的活儿。这是给模糊的记忆挂上清晰索引的工作。"},"ICON-0993":{"nm":"备份确认筹码","de":"备份完了没有，就这一线之差让人心揪。在完成处轻轻夹上的这枚小筹码，告诉你\"到这里都安全了\"。安心，来自留下标记。"},"ICON-0994":{"nm":"云端备忘令牌","de":"把一行备忘飘送往天空某处储藏库的令牌。无论在哪开机，那段文字都会出来相迎的小小魔法。曾在夜空放风筝写下愿望的夜，如今仿佛轻轻降落到了掌心。"},"ICON-0995":{"nm":"USB保护帽套装","de":"接口裸露着在包里乱滚，触点难免受损。给每个末端套上小帽，凑成一套收好。把不用的时光好好安睡。这是为下一次连接所做的、最安静的准备。"},"ICON-0996":{"nm":"数据盒束带","de":"把装着珍贵数据的设备整个包裹束紧的带子。为了在摇晃的包里不互相磕碰，缠上一圈牢牢系住。曾用心打结裹包袱的那只手，在数字世界里也原样鲜活。"},"ICON-0997":{"nm":"文件整理标签","de":"数百个文件无名无姓地堆着，找东西便成了迷路。挂上五彩标签理出脉络的瞬间，凌乱的堆里便开出了路。所谓整理，归根结底就是开辟道路。"},"ICON-0998":{"nm":"密码提示卡","de":"把密码整个写下来很危险，干脆不写又会忘。于是只悄悄留下唯我自知的线索，比如\"初次登台的那座城\"。记下的不是答案而是路——这是聪明又温柔的记忆法。"},"ICON-0999":{"nm":"存放日期贴","de":"不记下存入的日子，保管很快就成了遗忘。贴在每个箱子上的日期贴纸，清晰刻下\"从何时起\"。从前老仓房里记下酿酱之日的那份心意，延续到了这张小纸上。"},"ICON-1000":{"nm":"迷你环形灯帽","de":"发出圆圈光的小灯，这是盖住它出光孔的帽子。为防镜片在包里被刮花，暂时让光安睡。把点亮前的黑暗好好珍藏，也是珍惜光明的一种方式。"},"ICON-1001":{"nm":"支架紧固螺丝","de":"再拧一圈。松动的缝隙消失，掌心之下一份沉甸甸的安心落定。不晃动的舞台背后，总藏着某人利落的一记手腕。小小螺丝撑起的，是看不见的稳固。"},"ICON-1002":{"nm":"直播中标记筹码","de":"红灯亮起的那一刻，走廊里的脚步声悄悄踮起了脚尖。\"直播中\"——这一句话前，所有人都屏住了呼吸。连门那头的寂静都是向着某人的心意，这枚小筹码静静地宣告着。"},"ICON-1003":{"nm":"弹幕速记本","de":"用指尖抓住那些将从屏幕掠过的应援。本会流走的一句一句，在纸上工整停留的时光。所谓记录，是哪怕迟一些也想要抵达的温柔停驻之处。"},"ICON-1004":{"nm":"静音键盘膜","de":"凌晨两点，敲键盘的声音像谎言一般消失了。为了不惊扰熟睡室友的呼吸声而蒙上的一层薄膜。最安静的体贴，总从无声之处开始。"},"ICON-1005":{"nm":"麦克风臂夹","de":"唇与麦克风之间，恰好能让歌声不晃动的那点距离。这个小夹子替你守住那个约定。舞台背后，总有这样牢牢撑住的手先一步在那里。"},"ICON-1006":{"nm":"背景布夹","de":"即使起风，背景布也纹丝不动。因为有一个紧咬着边角的小颚撑住了整个画面。不晃动的风景背后，总有人在看不见的地方咬紧了牙。"},"ICON-1007":{"nm":"流媒体控制台标签","de":"数十个按键之上，多亏小小的名牌，手才不会迷路。一行标签，便预先抹去了直播中的一个失误。所谓沉着，来自在颤抖之前写下的字。"},"ICON-1008":{"nm":"时间戳按钮","de":"用力一按，流逝的时间上便插下一面小旗。给再也不会回来的此刻盖一个印。许久之后回望，那标记已成了通往回忆的门。"},"ICON-1009":{"nm":"标签读取钥匙环","de":"凑上去，\"嘀\"地一声，信息便苏醒。挂在钥匙环上、在口袋里叮当作响的小同伴。平凡的一天，靠这样细小的提示音平安延续。"},"ICON-1010":{"nm":"智能插座标签","de":"给每个插座贴上名字，就再也不必为哪根线是什么而迷糊。把名字递给连看不见的电的心意。所谓整理，是温柔暂时借穿的另一张脸。"},"ICON-1011":{"nm":"温湿度传感器支架","de":"默默注视着房间温度与湿气的、巴掌大的守望者。舒适不会开口，但这支架每时每刻都静静照看着你的状态。安好，就这样悄悄被守护着。"},"ICON-1012":{"nm":"门磁传感器帽","de":"不放过门轻轻打开那一瞬的小小之眼。无声地传递有人归来的信号。守护空屋的，总是这样无言的东西。"},"ICON-1013":{"nm":"遥控器收纳座","de":"到处乱滚的遥控器们，终于各自找到了归处。静静收住差点弄丢之物的小小位置，是预先刻下\"再见面\"约定的那只手。"},"ICON-1014":{"nm":"睡眠App令牌","de":"每个睡得香的夜晚，都咕噜噜累积一份圆圆的成就。睡眠也像练习一样层层积攒——App温柔地这样告诉你。这是递给好好休息的你的、世上最小的奖。"},"ICON-1015":{"nm":"计时方块底座","de":"三分钟工整流逝期间，方块毫不动摇地数着自己的时间。静静撑住它底部的一处巴掌大的位置。连等待，也需要可以安心踏上的底面。"},"ICON-1016":{"nm":"提示灯罩","de":"为了不太刺眼，把光柔柔地裹住一层。提示再急切，也要让眼睛舒适。所谓体贴，是连光的强弱都静静体谅的心意。"},"ICON-1017":{"nm":"电池更换卡","de":"看见这张卡，就意味着该给设备里的小小心脏换新了。这是在停下前提前备好的温柔提醒。长久相伴的秘诀，总在于快一拍的照看。"},"ICON-1018":{"nm":"摇杆帽套装","de":"为了让拇指不打滑而轻轻套上的小帽子们。指尖的触感更清晰了。这一个小小的帽，有时甚至能左右手心冒汗的一局胜负。"},"ICON-1019":{"nm":"游戏机底座盖","de":"把主机休息的位置悄悄从灰尘中盖住。哪怕是暂时入睡的设备，也需要一床被子。珍惜之心，反而在不使用时更清晰地显现。"},"ICON-1020":{"nm":"掌机收纳袋","de":"移动时一律放进这里面。把掌上主机软软包住的袋子。为了在包里东碰西撞也安然无恙，珍贵的东西最好多包一层。"},"ICON-1021":{"nm":"按键贴纸环","de":"在平平无奇的按键上只叠一个小图案，那一刻它便全然成了我的。在相同的设备上留下唯我独有的标记。个性，总在这样微不足道的地方静静绽放。"},"ICON-1022":{"nm":"游戏卡盒","de":"通宵沉迷的一局游戏，在这只小盒里香甜地沉睡。再次掀开盖子，那一夜便原原本本地苏醒。回忆，往往出人意料地盛在巴掌大的盒里。"},"ICON-1023":{"nm":"散热风扇支架","de":"在风冷却热气的同时，稍稍倾斜撑住设备的位置。给发烫的身躯造出一个喘息的间隙。想跑得远，就得懂得暂时停下散散热。"},"ICON-1024":{"nm":"手腕带插销","de":"缠在手腕上扣好插销，无论动作多激烈，手柄都不会离开身边。这看似累赘的带子，实则是让你放心尽情玩耍的安心。"},"ICON-1025":{"nm":"摇杆握帽","de":"给握久了变得光滑的摇杆披上新衣。手熟的触感原样保留，只让表面焕然一新。熟悉与雀跃在一只手中并肩共处的瞬间。"},"ICON-1026":{"nm":"存档槽标签","de":"在每个存档格里工整写下是谁的冒险。一行标签，默默守护着过去几天的旅程。珍贵的记忆，最好刻上名字，免得被覆盖。"},"ICON-1027":{"nm":"录音机收纳袋","de":"收纳声音的机器，因里面所装之物而更显珍贵。装进能护它免受冲击的软软袋子细心携带。说不定有谁的声音正沉睡其中，所以更要小心。"},"ICON-1028":{"nm":"防风罩帽","de":"拂去风声，只留下声音。户外录音时静静套在麦克风上的毛绒罩。这是在杂乱噪音中只挑出真心来收的小小滤网。"},"ICON-1029":{"nm":"语音备忘标签","de":"这是想到的歌词，这是哼出的旋律。给每条语音备忘贴上五彩名牌。散落四处的灵感碎片，这才各归其位排成一列。"},"ICON-1030":{"nm":"采样按钮筹码","de":"用力一按，预先存好的一段声音便\"咚\"地蹦出来。雨滴、掌声、某人的笑——世界的片段在指尖苏醒。音乐，正是这些小小筹码温柔的合唱。"},"ICON-1031":{"nm":"声音收集袋","de":"走在路上偶然拾起的声音，悄悄装进这只袋子。风的纹理，乃至凌晨小巷的寂静。终将成为歌的素材，总是这样朴素地聚拢起来。"},"ICON-1032":{"nm":"迷你三脚架脚","de":"三条腿在桌上铺开一座小小舞台。代替晃动的手稳稳站立，撑住画面。一张清晰的照片，正是从默默静立的三只脚中诞生。"},"ICON-1033":{"nm":"录音文件标签","de":"给数百个录音文件一一挂上短短的吊牌。让人一眼便知是哪天初次流出的第一句。这是为散落的嗓音重新指路的、一个小小路标。"},"ICON-1034":{"nm":"波形贴纸带","de":"原样仿照声音形状的波纹带。围在笔记本或盒子上，仿佛音乐就在眼前可见。这是把听见之物变得可见的、温柔的障眼法。"},"ICON-1035":{"nm":"耳机挂钩","de":"练习结束后，为疲惫的耳机静静备好歇息之处。嵌在桌角的一个小钩。整洁的书桌，是预先挂好明日干劲的地方。"},"ICON-1036":{"nm":"迷你礼盒束带","de":"围在礼盒腰间的最后一圈。仅凭这一根带子，心意才终于完整。诚意，往往比起盒内之物，先从抚弄其上的手中传递出来。"},"ICON-1037":{"nm":"丝带尾帽","de":"为了不让丝带末梢散开而轻轻包住收尾。一个不太起眼的细节，悄悄改变了礼物的第一印象。收尾若漂亮，心意也会美美地抵达。"},"ICON-1038":{"nm":"包装火漆封蜡","de":"滴上滚烫的一滴，封住信封。像旧时书信一般，是\"莫要随意拆开\"的沉甸甸的约定。礼数，有时便这样怀着温暖的分量。"},"ICON-1039":{"nm":"感谢卡支架","de":"为了不让承载谢意的卡片皱折，端正地撑住它。让心意笔直地站着传递出去。感谢，连模样都端庄时，才会更长久地留在心里。"},"ICON-1040":{"nm":"缓冲星星纸","de":"剪成星形的纸片软软填满盒中的空隙。是\"哪怕摇晃也千万别受伤\"的心意之棉。包装里的黑暗中，也算升起了一颗小星星。"},"ICON-1041":{"nm":"礼物清单吊牌","de":"在收礼人那一栏前，笔停了好一阵。写下名字三个字的工夫里浮现的面孔，一同度过的季节。系上的那一刻，这张小纸便成了拆开前谁也读不到的秘密。"},"ICON-1042":{"nm":"祝贺印章环","de":"用力一按，圆圆的祝贺便清晰印出。等墨水晾干的片刻里，想着要递给谁的那份心意最是温暖。若说有什么缺点，那就是会让人想再多印一个。"},"ICON-1043":{"nm":"包装绳线轴","de":"用心缠绕着，又在某人雀跃的指尖下欢快地解开。在缠与解的那短短片刻间，被线捆住的一份心意，终于成了礼物。"},"ICON-1044":{"nm":"非花结饰挂坠","de":"它不是模仿花，而是一缕线多次拥抱自己、自行绽放出的形状。整夜挑选打结的指尖那份耐心，化作了这样一个小小花苞留存下来。"},"ICON-1045":{"nm":"幸运硬币袋","de":"在远行之人的口袋里悄悄塞几枚硬币的心意。填进去的不是重量，而是温柔。每一步叮当作响的声音，替代了\"一路平安\"的叮嘱。"},"ICON-1046":{"nm":"愿望胶囊挂坠","de":"圆圆的壳里，一个折好的愿望正酣酣沉睡。\"打开就会实现\"是假话，但\"不打开珍藏着，那愿望便永远活着\"却是真的。"},"ICON-1047":{"nm":"护身结绳","de":"用五色线牢牢编织，把邪气挡到身后的绳。像幼时奶奶在手腕系结的那只手一般，每一处系结都细细嵌着某人的祈祷。"},"ICON-1048":{"nm":"迷你纸鹤盒","de":"据说要折满千只才成愿的纸鹤，唯独这一只被毫发无损地供在这小小的家里。哪怕一边翅膀皱了，那夜倾注的心意也会簌簌散去。"},"ICON-1049":{"nm":"亮片小袋","de":"从舞台服上掉落的小小光粒，舍不得丢而扫起来收好的地方。一旦沾上便会跟随一整周的亮片，在这里也像在掌心般乖乖安睡。"},"ICON-1050":{"nm":"吉兆印章筹码","de":"挑选好日子时悄悄添上的一枚小牌。不在算命铺的门槛，而在我自己的书桌上，只为今天一天悄悄盖下\"愿只有好事发生\"的、温柔的一点小迷信。"},"ICON-1051":{"nm":"祈愿手链卡","de":"印成手链模样的一张纸，承载着某人无声的祈愿。即便戴不到手腕上，把它深深放进钱包里，那份心意便始终系在身旁，与你同行。"},"ICON-1052":{"nm":"门前盐瓶","de":"把粗盐装进小瓶，静静摆在门前。这是把坏运气送走、只迎进可喜客人的古老算法。每一粒咸盐，都是守护我们家的小小门卫。"},"ICON-1053":{"nm":"幸运号码遮盖签","de":"刮开之前，每个人都暂且是头奖。这枚轻轻遮住幸运数字的标签，守护着期待最为膨胀的最后一秒。即便刮的指尖在颤抖，它也会装作没看见，替你闭上眼。"},"ICON-1054":{"nm":"生日蜡烛收纳帽","de":"连点过一次火的蜡烛，也要好好供到下一个生日的那份周到心思。若去年许的愿还没实现，今年就在原地接着许便好——这是一种温柔的算法。"},"ICON-1055":{"nm":"纪念日倒数戒","de":"把倒数日子套进手指的淘气小物。剩余天数每往回转一格，心跳也随之向前提一分。它独自坚持说，归零的那天它会自己发光。"},"ICON-1056":{"nm":"派对尖帽绳","de":"把尖帽稳稳固定在头上的细细一根绳。虽然主角嫌闷，转眼就摘掉了，但在照片里那一帧却永远戴着。它的使命，那一刻便已足够。"},"ICON-1057":{"nm":"小蛋糕插签","de":"插在仅两指节大的小蛋糕上的小小标记。即便在一口就消失的甜味之上，祝福也挺直自己的身高。再小，生日也是生日，今天的主角就是你。"},"ICON-1058":{"nm":"庆祝彩炮标签","de":"虽不发出砰的声响，看上去却最华丽的纸彩炮。贴上信封的瞬间，平凡的邮件就变身成来自喜宴的来信。舍不得撕下、就这么留着的人很多。"},"ICON-1059":{"nm":"照片挂夹","de":"生怕弄丢挂在绳上的回忆，我总是把嘴抿得紧紧的。只要还各夹着一张张照片，纵使有风从窗缝吹进，那些日子也不会掉落。"},"ICON-1060":{"nm":"日期气球贴片","de":"写着数字的气球形贴片。贴在衣服上，全村人都会知道今天是第几天的特别日子。撕下会留印记，连那淡淡的痕迹也成了又一个纪念。"},"ICON-1061":{"nm":"礼物交换标记","de":"让收到的手和递出的手稍稍分不清的调皮标记。比起记得谁送的，更要记得交换了什么——这是赠礼场合上小小而温柔的规矩。"},"ICON-1062":{"nm":"纪念餐桌号","de":"每张喜宴桌上都立着的一格小号码。事先定好谁坐哪个位子，彼此就不会尴尬——这里藏着办过多次喜宴的人那份温柔的智慧。"},"ICON-1063":{"nm":"门把礼物袋","de":"不按门铃也能传递心意的方法。悄悄挂在门把上，再像逃跑一样消失，那么发现它的人那张惊讶的脸，便成了回赠给寄出者最大的礼物。"},"ICON-1064":{"nm":"秘密配送标签","de":"外面什么都没写。把寄件人藏到最后，是这枚标签小小的自尊。收件人歪着头琢磨、笑得越久，那项神秘的任务就越完美。"},"ICON-1065":{"nm":"门铃便条贴","de":"鼓不起勇气敲门时，代为贴上的小纸条。「顺道来看看就走啦」这样短短一行，比门铃声留得更久。因为歪歪扭扭的手写字，是有表情的。"},"ICON-1066":{"nm":"快递刀安全帽","de":"当快递刀刃不经意瞄向手指时，悄然挡在前面的小英雄。对新物品的雀跃让指尖变急时，它把你一直护到最后一格安然无恙。"},"ICON-1067":{"nm":"缓冲气泡膜片","de":"我生来就是给人捏的。咔的一声爆开，一天的紧张不知怎的就缓缓松开了。比起里头护着的物品，我被爱得更久的日子，也时常有呢。"},"ICON-1068":{"nm":"收件时间针","de":"把几点送达精准插定的针。再茫然的等待，只要多出一个坐标，也会变得好熬许多。在那个时刻之前要往玄关张望多少回，就全凭本人了。"},"ICON-1069":{"nm":"自助寄存柜钥匙圈","de":"为总忘记快递柜密码的人准备的小小同伴。挂在钥匙圈上晃啊晃，在关键时刻引出一句「啊对了」，是这位朋友隐隐的拿手好戏。"},"ICON-1070":{"nm":"玄关篮子签","de":"贴在玄关一角篮子上的名牌。写着「请放这里再走」这样无声的约定。即便空着，等待某人心意的位置，也绝不孤单。"},"ICON-1071":{"nm":"地址遮盖贴","de":"要丢弃的箱子上，留下名字，只把地址刷地抹去。可以被知道的只到名字为止，住处是只属于我的秘密。揭下一层贴上的瞬间，便生出一点安心。"},"ICON-1072":{"nm":"零食罐标签","de":"一眼就告诉你罐里装了什么的标签。可写上「零食」，竟连盖子都不用开就莫名觉得踏实，这便是它的陷阱。标签可不为食欲负责哦。"},"ICON-1073":{"nm":"小项链吊坠","de":"在衣服里静静分享体温的一颗小小内核。它总贴在谁的眼睛都看不到的位置，反倒更令人怜惜。是与你一同走在胸口、最亲近的伙伴。"},"ICON-1074":{"nm":"脚印印章垫","de":"在脚掌上一按，小小的脚印就一排排留下。谁走向了哪里，工工整整记在纸上的一日份散步日记。沾了墨的第一步，总是最清晰。"},"ICON-1075":{"nm":"理毛刷帽","de":"把缠在梳子上的毛干净利落地包办的小盖子。一梳就聚一把的换季时节，没有这顶帽子，全家就会变成毛茸茸的雪原。是不露痕迹却勤快的清洁工。"},"ICON-1076":{"nm":"散步袋收纳盒","de":"把散步路上要带的袋子端端正正揣着同行的小屋。只有事先备好的人才能从容地走，这盒子每天都在悄悄证明这一点。那一张忘了可就麻烦。"},"ICON-1077":{"nm":"名字遮盖牌","de":"悄悄遮住真名、只留下昵称的牌子。世上也有不愿随便给谁看的温柔。只有熟人才知道的那声呼唤，正轻轻藏在这里。"},"ICON-1078":{"nm":"水碗托垫","de":"垫在水碗下面的我，总是湿漉漉的。我替它接住四处溅开的水珠，守护着地板干爽。虽然没人夸我，但我也从无怨言。"},"ICON-1079":{"nm":"玩具修补线","de":"线脚裂开的玩偶不是用来扔的，而是用来重新缝的。每一针补上的地方，与那孩子共度的时光都再次变得结实。所谓修补，到头来就是静静地推迟告别。"},"ICON-1080":{"nm":"纪念照项链","de":"把笑得最灿烂的那一帧戴在脖子上的心意。照片里的那一天不被制成标本，而是随每一步一同晃动，延续到今天。美好的那个瞬间不会停下。"},"ICON-1081":{"nm":"心情色彩片","de":"若心也有颜色，今天你的色彩是什么呢？挑一枚色片放在桌上的瞬间，言语说不尽的心情便悄悄晕染开来。晚霞色也好黎明色也好——它是静静映照那日之我的小小镜子。"},"ICON-1082":{"nm":"今日记录珠","de":"一天落幕，今天便在珠子里圆圆地凝成。做得好的事、笨拙的事都骨碌碌地收拢滚动。托在掌心，昨日的我有些温热，轻拍着背说今天也活得很好。"},"ICON-1083":{"nm":"称赞纸条瓶","de":"好话太容易飘散，便一张张折起装进这瓶里。当称赞像香气一样积满，在心里空落落的夜晚就打开盖子。再读一遍谁递来的一句温柔，那天的暖意便复苏。"},"ICON-1084":{"nm":"和解丝带绳","de":"纠结的心像打了结，解时也要费心。两人各执绳的一端慢慢拉，转眼便成一只漂亮的蝴蝶结。和解不是剪断，而是重新系上——这根绳静静地这样告诉你。"},"ICON-1085":{"nm":"感谢代币","de":"在「谢谢」难以出口的日子，便代替它悄悄递上一枚代币。接过的手，凭那小小的重量便读懂了全部心意。比言语先抵达的真心——圆圆一颗里盛着情谊渡过来。"},"ICON-1086":{"nm":"休息时间标记","de":"整日奔忙的练习室，也需要一拍喘息。把这标记挂在门上，时间便暂且放慢。歌要有了休止符才能喘气——经历过气喘吁吁一天的人都懂。"},"ICON-1087":{"nm":"秘密情感抽屉","de":"有些日子，没法把心里话全掏出来给人看。那时就把悲伤也好雀跃也好，静静放进心里的一格小抽屉，关上。眼下放着也没关系——总有一天会有慢慢打开整理的时候。"},"ICON-1088":{"nm":"笑脸贴纸卷","de":"一格格撕下，一个笑脸符就沾上指尖。悄悄贴在笔记本的角落、朋友的储物柜上的小小开朗。当纸上升起一个小太阳，发现它的某人那一天就明亮了一点。"},"ICON-1089":{"nm":"问候铃挂饰","de":"想触及远方的你，那份心意凝成了一颗铃铛。摇一摇，清亮的声音便替你捎去问候。在说不出「过得好吗」的日子——这小小的回响乘着风先抵达你身旁。"},"ICON-1090":{"nm":"春雨遮盖夹","de":"下春雨的日子，越珍惜的东西越容易被淋湿。用这枚夹子把封面合拢，雨滴便斜斜地滑落。把珍贵的一本揽进怀里的那份心意——小小一枚夹子替你做到了。"},"ICON-1091":{"nm":"夏日清凉贴","de":"在被盛夏暑气累坏的手背上贴一张。沁凉如薄荷般散开，汗意消退一层。躺在堂屋地板上摇着扇子的那份清凉，巴掌大的一张纸细心地模仿了出来。"},"ICON-1092":{"nm":"秋日格纹布片","de":"宛如秋日田野的一块格纹布。是有人精心在磨破处补缀过的痕迹。不丢弃而缝补着用的心意——小布片聚在一起，把磨损之物重新温暖地救活。"},"ICON-1093":{"nm":"冬季手套夹","de":"冬天的手套不知怎的总爱一只只逃跑。用这枚夹子把两只连起来，发冷的手便不会迷路。不愿弄丢的心意寄托在小小金属上，把两只并排守护。"},"ICON-1094":{"nm":"梅雨防水签","de":"梅雨时节连名牌都会被雨水晕开。这枚镀了防水层的标签，在倾盆大雨里也守住字迹。雨过天晴后依旧清晰留下的一行——为了到最后都不忘记这是谁的。"},"ICON-1095":{"nm":"初雪收藏瓶","de":"初雪一触到手便消失了，便至少把那份雀跃装进瓶里。被关进玻璃里的不是雪，而是那天怦怦跳动的心。摇一摇，一个冬天再次纷飞，把你带回那个清晨。"},"ICON-1096":{"nm":"节日红包带","de":"缠在节日红包上的一条红带。比起里头装的，递出之手的情谊更大，这点大家都知道。把「过得好」的祝福与福气一同包起的心意，正端端地系在这条细带里。"},"ICON-1097":{"nm":"野餐餐具束带","de":"铺开野餐垫打开便当，风总爱掀盖。用这条束带把餐具稳稳合拢，野餐便不会散乱。想把带来的一餐守到最后的心意，盛在小小一条带子里。"},"ICON-1098":{"nm":"季节香气样品卡","de":"为了不打开也能知道季节，便把那个时令的香气装进一张卡里。春天是花香，秋天是干叶味。掠过鼻尖的瞬间整个季节就浮现——「这就是四月的空气」。"},"ICON-1099":{"nm":"价签写字夹板","de":"价签总爱飞走的地摊烦恼，被这一块写字夹板平息了。它稳稳咬住数字，笔直地递到客人面前。买卖的第一声招呼，始于不曾凌乱的诚实一行。"},"ICON-1100":{"nm":"营业中翻转牌","de":"把这块牌子翻过来挂在门前，店铺这才苏醒。从「准备中」翻到「欢迎光临」。宣告一天开始的小小信号——是店主之手每天清晨最先触及的地方。"},"ICON-1101":{"nm":"优惠券印章垫","de":"把十格全集满，不知怎的就会有好事发生。每一个印章都是熟客的脚步，是积攒下来的情谊。垫上墨干处的每一道印记里，都活着「还会再来」的小小约定。"},"ICON-1102":{"nm":"纸袋提手帽","de":"纸袋的提手在重量面前总是脆弱。套上这顶帽子，眼看要断的提绳便变得牢靠。想把所装之物平安带到家的心意——小小一个配件，把这条路一直撑到最后。"},"ICON-1103":{"nm":"收银台硬币碟","de":"找零从手递到手时的那份迟疑，被这只碟子静静化解。硬币叮当作响、各归其位的声音。给与受变得更温暖一些，正多亏了这般圆圆的体贴。"},"ICON-1104":{"nm":"积分累积片","de":"今天迈出的脚步化作一枚枚片子层层堆积。积得越多心越轻，是种奇妙的算法。一点点填满的乐趣，与看着空缸不知不觉满起来的喜悦很像。"},"ICON-1105":{"nm":"陈列架号码针","de":"每个陈列架上都温柔地插着一个小号码。是默默告诉你哪里有什么的向导。为了不让人迷路而事先指明位置的心意——秩序里也这样栖着暖意。"},"ICON-1106":{"nm":"试吃签杯","de":"把一口试吃插出来递过去的小杯子。犹豫的客人也会因这一口悄悄敞开心。劝你「来尝一个吧」的人情挂在签头，留住初来者的脚步。"},"ICON-1107":{"nm":"预约名单夹","de":"今天要来的客人名字，在这只夹子里整整齐齐地立着。是连等待也有先后的温柔约定。把一张纸笔直立着这件事，成了用心迎接某人一天的第一道准备。"},"ICON-1108":{"nm":"墙面照片绳夹","de":"在墙上拉一根绳，用夹子把照片一张张挂起。欢笑的瞬间像晾衣一样并排挂着晾干。把回忆晾在洒进阳光的地方，每次经过那天的笑就再次翻飞。"},"ICON-1109":{"nm":"迷你地毯角","de":"铺在房间边角的一小块地毯。是率先把暖意铺到冰冷地板上的位置。赤脚最先触到的一掌之地——回到家的脚尖，在这里才终于安心地懒洋洋起来。"},"ICON-1110":{"nm":"门牌遮帘布","de":"轻轻遮住门牌的一幅布。把名字暂且藏起来，也是一种过日子的雅致。把内与外的边界优美地垂下的一片——「今天想安静歇着」的心意柔柔地挂在那里。"},"ICON-1111":{"nm":"灯线夹","de":"把垂下的灯线由这枚夹子端正地理好。为了让光不凌乱，是替它把路捋直的手。傍晚降临时分理一理那一根杂乱的线，房里的光与心都随之沉静许多。"},"ICON-1112":{"nm":"海报磁帽","de":"把海报贴上墙的小小磁帽。不戳一个图钉的孔，纸也能守住原位。对待珍爱之物的手总是柔和的——不让它受损的心意盛在这里。"},"ICON-1113":{"nm":"窗帘流苏绳","de":"把窗帘的一角束向一侧的流苏绳。优美地为晨光打开进来的路。带穗的绳子一拉，明亮的一天便大步涌进房里驻留。"},"ICON-1114":{"nm":"香薰托标签","de":"贴在香薰托上的小小一张标签。烧的是什么香、什么时候第一次点的，都工工整整记下来。给喜欢的气味起个名字这件事——那份齐整让房里的空气更添几分温柔。"},"ICON-1115":{"nm":"装饰架橡胶脚","de":"撑着架子不晃动的四只橡胶脚。在看不见的地方默默承受重量。又小又矮不起眼，但在最底下撑着的东西，到头来撑得最久。"},"ICON-1116":{"nm":"方向标箭头挂饰","de":"为犹豫着该往哪走的人，一支箭头静静指明方向。是「别迷路」的温柔手势。多亏每个岔路口都有人先立好这份心意，今天也不迷茫地往前走。"},"ICON-1117":{"nm":"岛屿邀请钥匙绳","de":"交到邀你上岛之人手中的钥匙绳。接过它，从此你也是这里的一家人。把陌生客人迎进温暖之内的款待，牢牢盛在绳头那个小小的约定里。"},"ICON-1118":{"nm":"关系温度片","de":"两人之间的温度，由一枚片子悄悄告诉你。是还生疏的蓝光，还是不知不觉已暖成绯红。情谊加深的速度难以测量，但手掌会先一步察觉那份暖意。"},"ICON-1119":{"nm":"喜好样品盒","de":"还不知道喜欢什么时，就把小小的样品装进一盒递过去。在挑选的乐趣里，喜好慢慢生长。哪个会成为你的呢——盒子里满是令人雀跃的可能。"},"ICON-1120":{"nm":"照护预约针","de":"要照护某人的约定，清清楚楚插在这一枚针上。写下名字与时间，心便不会迷路。轮流替彼此看孩子的那份温柔互助，在这里活着、呼吸着。"},"ICON-1121":{"nm":"成长记录胶囊","de":"就像门框上量身高的刻痕一道道累积，这枚胶囊把昨日的你静静封存。遥远的某天打开盖子你就会明白——曾经小小的脚步，走了多远。"},"ICON-1122":{"nm":"初遇收藏带","de":"初次十指相握时的那份悸动，轻轻系进一条带子里。这结不是为解开而在，而是为了让那天的暖意继续活在手腕上，才停留在那里。"},"ICON-1123":{"nm":"我的房间小物标签","de":"「这里是我的位置。」小小一张标签贴上书桌一角的瞬间，陌生的房间这才舒了一口气，成为我的房间。名牌，是心第一次落脚的地方。"},"ICON-1124":{"nm":"亲密度珠筒","de":"一摇便骨碌碌，两人之间靠近一格的声音滚动起来。等筒子满起来的时候，光是喊名字，笑就先迎出来候着了吧。"},"ICON-1125":{"nm":"出道准备封缄印","de":"封住信封的最后一张。到这里是准备，翻过下一页便是舞台。指尖用力一按，练习生调匀呼吸。终于，要开始了啊。"},"ICON-1126":{"nm":"水","de":"因为最常见，所以最珍贵。熄了灯的凌晨练习室里，仅仅一口便把瘫坐下的人重新扶起。没有自己的形状，却渗入任何容器的那份温柔。"},"ICON-1127":{"nm":"清水","de":"连底下的小石子都映得透亮的清澈。山间小泉从不炫耀自己的清澈。无所隐藏的心，总是这样一眼看到底。"},"ICON-1128":{"nm":"海水","de":"触到舌尖的瞬间，远处的浪潮便涌来。一口咸味里，地平线与海鸥、离开的港口整个化在其中。大海总是咸咸地留作记忆。"},"ICON-1129":{"nm":"冰","de":"在掌心里渐渐变小，握多少便消失多少。看似坚硬，终究懂得回归为水。冰，是暂且屏住呼吸的河。"},"ICON-1130":{"nm":"雪球","de":"紧紧攥成的一团，划开巷子白白地飞去。咯咯的笑声与冻得通红的脸颊。是冬天悄悄塞给孩子们的、最雪白的玩具。"},"ICON-1131":{"nm":"泥土","de":"孕育种子，饮下雨水，无言地接住路过的脚印。是拥抱一切的黑色肌肤。所有生长之物的最初之地，都有这一捧。"},"ICON-1132":{"nm":"肥沃泥土","de":"把手指深深插进去，黑色的油润便松软地缠上来。奶奶的菜园年年葱郁的秘密，正在这里。养熟的土，用堆肥的气味低语着丰年。"},"ICON-1133":{"nm":"黏土","de":"含上水分的瞬间，便顺从地接受任何形状。随手而成鸟、成器的温柔之肉。陶轮转动之间，一捧泥土这才做起梦来。"},"ICON-1134":{"nm":"沙","de":"从指缝间簌簌漏走的细小颗粒。越想抓住越快流泻，越发像极了时间。海滩一捧里，沉睡着无数个昨日。"},"ICON-1135":{"nm":"鹅卵石","de":"在溪边被磨得圆圆的石头。是水长久长久地抚摸、磨去棱角的痕迹。越是滚到过远方的，越是乖巧地落进掌心。"},"ICON-1136":{"nm":"石头","de":"随意搁在路旁的一块。有人一脚踢开走过，有人静静捡起垒成塔。同一块石头，随心意既可成负担，也可成心愿。"},"ICON-1137":{"nm":"石板","de":"横贯古宫庭院的扁平石头。几百年的鞋子踩踏而过，中间凹陷下去。每个一步步踏过的人，都在那里添上一层时间。"},"ICON-1138":{"nm":"石灰石","de":"曾是海洋时代的贝壳层层凝固，化作白石。入窑便化为石灰，把围墙刷得雪白。看似宁静，却是整个怀着一个时代的石头。"},"ICON-1139":{"nm":"煤","de":"黑黑地睡去的远古森林。是数亿年前的蕨类在地底深处坚实地凝结而成。一旦点火，长久埋藏的阳光便熊熊重新苏醒。"},"ICON-1140":{"nm":"木炭","de":"含住火，却静静咽下烟。在窑中被黑黑压实的木头，在火炉上无言地红红绽放。越是沉默的，越能长久温暖。"},"ICON-1141":{"nm":"树枝","de":"为不被折断而默默弯曲过来的枝条，懂得弯折之道。熬过狂风的每一处都嵌着节疤，真正的坚韧，到头来是善于弯折留下的痕迹。"},"ICON-1142":{"nm":"原木","de":"切开的年轮里，一百个春与冬圆圆地叠在一起。一棵树活过的岁月整个横卧着，如今静静等候着成为房屋柱梁的轮次。"},"ICON-1143":{"nm":"木材","de":"刨子每划过一次，芬芳的纹理便露出一层。粗糙的木头渐渐光滑之间，刨花像黄色的雪般堆在地上。打磨之手，唤醒了用处。"},"ICON-1144":{"nm":"木板","de":"铺地板、搭凉床、围墙篱。把笔直锯出的一张张聚在一起，人住的地方这才立起。平凡之物层层堆叠，便成了安身的窝。"},"ICON-1145":{"nm":"竹","de":"内里虽空，临风却挺直。每一节都断了又重新冒出的那份气节，古时的士人都想效仿。因为空，反而更加挺拔的，正在这里。"},"ICON-1146":{"nm":"软木","de":"用力一按再松开，又鼓回原本的厚度。看着这又轻又坚韧的纹理，便明白柔软绝非软弱。从瓶塞到布告板，它静静地撑托着。"},"ICON-1147":{"nm":"草","de":"被踩踏了，下一场雨来便又站起来。无名无姓却把田野整个覆盖过去的那份绿色的坚韧。莫因它小而轻视，最先报知春天的，总是这低处。"},"ICON-1148":{"nm":"稻草","de":"秋收过后田里黄黄留下的东西。编起来成屋顶，铺下去成温暖的卧铺。把谷粒全部交出后，仍到最后为人遮盖的那份心。"},"ICON-1149":{"nm":"芦苇","de":"风一掠过便沙沙作响，整片江边都在歌唱。因内里空，才哭得更远的茎。摇曳的那副模样便是自己的歌——芦苇丝毫不以为羞。"},"ICON-1150":{"nm":"棉花","de":"成熟的荚啪地裂开，便绽放出一朵小小的云。又轻又柔的这团棉成了线、成了衣，在寒冷冬夜静静温暖某人的肩头。"},"ICON-1151":{"nm":"羊毛","de":"沾到手上便泛起油润，静静留下暖意。是羊为熬过寒山而披在身上的外套。剪下的那份温暖，如今移到了人的冬天。"},"ICON-1152":{"nm":"线","de":"细得若有若无，可把断开的两端重新接上的，总是它。一缕虽弱，编起来便成一幅布。在连接这件事上，粗细并不重要。"},"ICON-1153":{"nm":"布","de":"纬线与经线无数次交错，织成一幅。是独自便要散开的线彼此紧紧抓住的结果。越细密越温暖，这点人与人之间也一模一样。"},"ICON-1154":{"nm":"皮革","de":"越用越浸上手泽，一点点地变得像它的主人。最初的僵硬被驯服之间，色泽愈深，纹理愈柔。时间刻下的那份润泽，是什么都模仿不来的。"},"ICON-1155":{"nm":"羽毛","de":"轻得托在掌心都感觉不到重量。是飞过天空的记忆原封栖着的一缕。最轻的东西飞得最高——这点，请千万别忘了。"},"ICON-1156":{"nm":"贝壳","de":"奶奶说「贴到耳边试试」的话忽然浮上心头。内侧的虹彩里整个刻着离开的大海，因此从空壳里也能听见一个时代的荡漾。"},"ICON-1157":{"nm":"珊瑚","de":"虽像石头般凝固，曾经却分明是呼吸过的群落。在缓慢的海底花上数百年伸展枝条。最坚硬的枝，是等待最久之后才长成的。"},"ICON-1158":{"nm":"珍珠","de":"忍不住一粒沙的硌痛，贝便把它用光静静地包了起来。把伤痛圆圆地揽住，便会这般晶莹——这是大海递来的小小安慰。"},"ICON-1159":{"nm":"海藻","de":"退潮的礁岩上滑溜溜垂着的绿色带子。握在手里，一股腥腥的海味便扑来。无根地把身子交给水流，大海静静打理着自己的庭园。"},"ICON-1160":{"nm":"海苔","de":"把黑黑的一张在火上稍稍一烤，便泛青散出香气。卷在刚煮好的米饭上的那个清晨。薄薄一片，却足以把一餐的幸福整个包住。"},"ICON-1161":{"nm":"盐","de":"我是大海留在阳光下的白色结晶。一小撮便能让清淡的汤变深，手一滑便盖住所有的味。只有懂得分寸的指尖，才能好好驾驭我。"},"ICON-1162":{"nm":"玻璃碎片","de":"正是在破碎的那处，它才折射光芒、绽出彩虹。完好时不曾知晓的本领。即便碎了，也还留有分一点阳光的份额——躺在窗边的碎片静静告诉你。"},"ICON-1163":{"nm":"玻璃","de":"透明并不只意味着无可隐藏。是为了让光原封透过，而抹去了自己的模样。在不被看见地停留在那里这件事上，手一触，也有一份清凉的端整。"},"ICON-1164":{"nm":"玻璃瓶","de":"唯有内里空着才能盛装什么。是果酱，是一捧野花，是折好放进的信，随进来之物改换名字。不畏惧空的容器，才最宽容。"},"ICON-1165":{"nm":"空瓶","de":"我喜欢喝完之后到来的宁静。有人把我丢弃，有人冲洗干净放上窗台盛满阳光。在结束之处重获用处，那便是空物的第二段人生。"},"ICON-1166":{"nm":"纸","de":"我白白地铺开，备好承接任何书写。最久凝视着迟疑落下第一行之人的心的，总是我。白纸的耐心，比墨水还深一掌。"},"ICON-1167":{"nm":"旧纸","de":"泛黄不是衰老，而是熬过。每一道折痕里，都浸着摊开来读的手的暖意。旧纸为了不被遗忘，用自己的色泽记下了流逝的时光。"},"ICON-1168":{"nm":"墨水","de":"从一滴起始成句，干了便如约定般留下。晕开便照晕开的模样，是那天的痕迹。让一切无法挽回是我的活计，所以人们落我一笔时会更加慎重。"},"ICON-1169":{"nm":"铁矿石","de":"是在地底睡着红色之梦的石头。要过一遍火，才终于交出体内的铁。坚硬不是一开始就坚硬，而是通过炽热之后才得到的名字。"},"ICON-1170":{"nm":"铁锭","de":"矿石熬过火之后，才凝成一块冷却下来。这冰冷沉重的形状，可成桥、成刀、成锄。正因用处尚未定下，我便能成为任何东西。"},"ICON-1171":{"nm":"铜矿石","de":"披着青苹果色的锈从泥土里钻出。熔了便钟声回荡、铜像耸立、电线流淌。在漆黑地底沉睡时，我也总在等着被唤作什么的那一刻。"},"ICON-1172":{"nm":"铜锭","de":"长久搁在身旁，它便亲手织出青色的衣裳穿上。有人把那光泽叫作瑕疵，也有人当作岁月的花纹去抚摸。不羞于自己渐变之色的金属，被爱得最久。"},"ICON-1173":{"nm":"金矿石","de":"是淘了又淘江沙才遇上的一点。不是因稀有而珍贵，而是因不变而珍贵。古人把它握进手里作信物，盼你效仿那不生锈的心。"},"ICON-1174":{"nm":"金锭","de":"不黯淡也不生锈地凝成一块横卧着。它听过的人的贪欲最多，自己却什么都不觊觎。只忠于发光这一件事的，沉甸甸的沉默。"},"ICON-1175":{"nm":"废铁","de":"不是用尽了用处，而是正等着下一次用处。折断的钉与瘪了的罐聚在一处，再次遇上炽热的火。「被丢弃」这句话于我，意思是正暂且歇着。"},"ICON-1176":{"nm":"螺丝","de":"独自什么也做不成。唯有旋进去、把两块板紧紧咬合时，才终于尽到本分。以小小身躯撑住大物的本领，那拧紧的力里也栖着用心。"},"ICON-1177":{"nm":"钉子","de":"一旦钉进去便轻易不肯退。锤子每敲一下，加深的不是伤口而是约定。只要是把什么牢牢相连的事，我甘愿献出自己的头。"},"ICON-1178":{"nm":"齿轮","de":"推着邻旁的齿，一同转动。不独自抢快，而懂得配合身边的速度。如同唯有咬合才流动时间的钟，我相信合拍即是运转。"},"ICON-1179":{"nm":"弹簧","de":"越被压，越向内攒起回弹的力。弯曲不是放弃，而是为重新挺直的备战。承受多少冲击便弹回多少——柔韧即坚硬的小小螺旋。"},"ICON-1180":{"nm":"电线","de":"外是温顺的外皮，内是片刻不停流动的路。在看不见的地方运送着光与声。如同默默连结舞台幕后的手，不显露反而更令人信赖的通道。"},"ICON-1181":{"nm":"电池","de":"把半日的明亮在小小身躯里一点点收拢。它说用完再充便是，绝不把空当作终结。它怀着照亮某人漫漫长夜的一个小小傍晚。"},"ICON-1182":{"nm":"灯泡","de":"细细一根丝红红地烧热起来，推开黑暗。它不是烧自己来烘暖房间，而是照亮房间。点亮时最烫，因此也最明亮的一瞬之小太阳。"},"ICON-1183":{"nm":"镜片","de":"把散开的光聚到一点、清晰立起。远方的星，掌上小小的字，都静静唤来。为了助人看见，反倒藏起自己的模样，清澈圆润的媒人。"},"ICON-1184":{"nm":"橡胶","de":"压也好拉也好，终究回到原位。嫌它软的人，下雨天也会挑我来穿。把猛烈的冲击柔柔接住这件事，这份软里也住着坚韧。"},"ICON-1185":{"nm":"塑料碎片","de":"是从本体上脱落的小小一片。险些被丢弃，但聚成一群便又成新物。不是因小而轻，而是因轻才能走到远方的、某物的一部分。"},"ICON-1186":{"nm":"绳索","de":"要把好几股拧在一起，才终于成一根。独自易解，编起来便能拖船、捆货。一同被拧多少便结实多少，掌心里粗糙的、协作的古老结。"},"ICON-1187":{"nm":"帆布","de":"不憎恨风，满胸怀地把它揽进。要绷得鼓鼓才能把船送远，连逆风于我也是力气。不违逆强劲而拥抱着前行的法子，我从大海学来。"},"ICON-1188":{"nm":"锚片","de":"虽只是锚的一角，却完整记得那份重量。记得它紧抓深底、把船停住的岁月。如今脱落了，也仍是懂得停留之重的、沉甸甸的一片。"},"ICON-1189":{"nm":"船钉","de":"是把随浪起伏的甲板一点一点钉牢的钉子。即便被盐分锈得通红，也到最后不曾松开自己的位置。把漂荡之物牢牢抓住，也是要有韧劲的。"},"ICON-1190":{"nm":"防水布","de":"在挡雨这件事上从无怨言。默默接住从上头倾下的，守护下面的东西干爽。虽不华丽，却把某人的货物遮得不湿的、可靠的一层。"},"ICON-1191":{"nm":"染料","de":"静静渗进白布，才终于成为色彩。无论是靛蓝还是茜红，旧时的母亲们都染着指尖，给布上色。在沉淀渗入这件事里，也有着轻易褪不去的深度。"},"ICON-1192":{"nm":"香精油","de":"仅一滴，房间里便大步铺开一片辽阔的原野。即便看不见也最先抵达的客人。悄悄牵起沉睡记忆的衣襟、先一步触到鼻尖的风景。"},"ICON-1193":{"nm":"蜡","de":"受热便流，冷却便凝，守住那形状。在柔软与坚硬之间往来，把什么都静静拓印下来。封、缄、抛光，随温度变换表情的温柔材料。"},"ICON-1194":{"nm":"蜡烛","de":"慢慢融化自己的身躯，点亮黑暗的一格。烧尽后只剩下变短的身高，但温暖过某人夜晚的那段时间不会消失。是懂得变小着发光的、笔直的灯芯。"},"ICON-1195":{"nm":"堆肥","de":"腐烂的东西聚在一处，便成最肥沃的土。被丢弃的果皮与干枯的落叶，成了春日新芽的饭。在以为已结束的那处，下一个生命静静调匀着第一口呼吸。"},"ICON-1196":{"nm":"米","de":"把一粒攥进手里，要经八十八道工。从插秧到打谷，农夫的一整年都原封盛在这小小颗粒里。冒着热气的一碗饭，便是某人的四季。"},"ICON-1197":{"nm":"糙米","de":"只稍稍褪去外壳，原封守住了本来的色泽。越嚼越香，是不慌不忙那份诚实的味道。它谢绝被细细削磨、留下粗糙的纹理，是谷粒坚硬的执拗。"},"ICON-1198":{"nm":"小麦","de":"记得在风中一齐低头的金色田野。成面包、成面条、成面片，温暖着世界各处的餐桌。因常见反而更深地，渗进人间烟火里的谷物。"},"ICON-1199":{"nm":"面粉","de":"成了细细的白粉之后，才终于备好成为任何东西。遇水便发，遇火便熟。因没有定好的形体，便随手所揉而得形，是温顺的底子。"},"ICON-1200":{"nm":"面团","de":"粉与水在掌下融成一块。揉得越多越筋道，等得越久越鼓胀。急了便变硬，唯有发酵的时间催不得——老面包坊这样说。"},"ICON-1201":{"nm":"面包屑","de":"拍落指尖沾着的白色粉末时，不知不觉连衣袖都白了一片。裹上它便成了酥脆的炸衣，轻轻堆起又像初雪。这是一块面包烤过后留下的最轻盈的痕迹，可即便再微小，用处也会慢慢长大。"},"ICON-1202":{"nm":"意面","de":"把一把面条像折扇般在沸水中铺开的那一刻，远方的阳光仿佛也跨进了厨房。长长的面条是手腕的功夫，弹牙的口感则是懂得稍欠火候、静静等待的心。看那叉子上卷起的那份光泽吧。"},"ICON-1203":{"nm":"方便面","de":"卸下舞台妆容的凌晨，偷偷下的一包面。等面泡软的三分钟，是一天里最私密的时光。呼呼吹气间，紧张也跟着一起冷却，隔着雾蒙蒙的眼镜，今天悄然落幕。"},"ICON-1204":{"nm":"年糕","de":"稻米熬过石臼的捶打，才终于成了年糕。可做白糕、黄豆糕、松饼——同一种谷物随着手艺，得了上百个名字。一上喜宴的桌，比起嘴，先唤起的是情意，是要分着吃才地道的食物。"},"ICON-1205":{"nm":"年糕汤年糕","de":"把长条年糕斜切开，便圆得像一枚枚小铜钱。漂在乳白汤里的，是年糕，还是一个个圆圆的心愿呢？新年头一个清晨喝下一碗，便添上一岁——这是这个国度多情的算法。"},"ICON-1206":{"nm":"土豆","de":"拍掉泥土，圆圆的脸便露了出来。在江原道山坡的风里也默默长粗的块根，蒸来绵软，煎来喷香。即便是囊中羞涩的日子，它也老老实实地把一家人的肚子填得饱饱的。"},"ICON-1207":{"nm":"红薯","de":"巷口支起烤红薯的炉子，那便是冬天的开端。剥开锡纸，金黄的热气先暖了指尖，那份甜，是熬过寒冬的根回赠的礼物。呼呼吹凉，掰成两半分着吃，正好暖身。"},"ICON-1208":{"nm":"胡萝卜","de":"在泥土里笔直扎下的一根橙色。本以为只有兔子爱吃，可一炒，藏着的甜味便醒了，放进汤里还能添上一抹色彩。老人们说它对眼睛好，这话大抵是对的。"},"ICON-1209":{"nm":"白萝卜","de":"有这么一根又白又沉的根，冬天的饭桌就踏实了。做成水萝卜泡菜清凉爽口，煮成萝卜汤鲜美开胃，腌成块泡菜爽脆可口。它没有一处可丢，连青绿的萝卜缨也挂在屋檐下晾成干菜——是节俭人家的好蔬菜。"},"ICON-1210":{"nm":"洋葱","de":"剥着皮，一行泪珠便扑簌簌滚落。又辣又呛的内里，一遇上烧热的油，竟骗人似的变甜了。它的名字写在几乎所有韩餐的第一行，默默铺垫着香气的底色，是低调的主角。"},"ICON-1211":{"nm":"大葱","de":"把切碎的白色葱白与青绿葱叶撒在汤面上，这一碗才仿佛终于大功告成。吃剩的葱根插进水杯里，又会蹭蹭往上长——这是会过日子的人在窗边的小菜园。"},"ICON-1212":{"nm":"蒜","de":"六瓣圆圆地聚在一起，凑成一整头。就是那把熊变成人的辛辣之根。用刀背咚咚一拍，香气便轰地醒来，泡菜也好炖锅也罢，少了这一把，怎么都说不过去。"},"ICON-1213":{"nm":"生姜","de":"长得疙疙瘩瘩、像打了结的小根。只放一片，便能压住腥味，从身体内里暖热冰凉的躯体。感冒难受的夜里，与蜂蜜一同泡来喝下的那杯暖意，正是从这份辛辣里开始的。"},"ICON-1214":{"nm":"白菜","de":"把包得严实的菜叶用盐腌过，泡菜的第一章这才翻开。深秋时节，家家院子里像小山般堆起的，正是它。一家人围坐着腌上一整缸，是要一同熬过漫长寒冬的约定。"},"ICON-1215":{"nm":"卷心菜","de":"把一层层圆圆卷起的叶子一片片剥下来，竟剥不到头，不知不觉心也悠闲了下来。焯一焯软嫩，炒一炒清甜。在憨厚的外表下，它藏着一份意想不到的温柔。"},"ICON-1216":{"nm":"生菜","de":"在凹凹的叶子上稳稳放一块肉，再抹上酱，满满塞进嘴里。围坐成一圈包着吃的场合，谁都会悄悄卸下拘谨——这正是一份绿色的款待。"},"ICON-1217":{"nm":"韩式生菜","de":"在菜园一角最先冒出头的叶子。摘了又长，整个夏天都填满餐桌。用凉水冲一冲，用手随手一包就吃下的那股清新草香，对某些人来说，整个儿就是故乡的味道。"},"ICON-1218":{"nm":"菠菜","de":"吃光一罐就力气大增的，正是动画里那抹绿。焯过后缩成小小一把，香气与劲头却丝毫不减。搓拌也好，撒一把进大酱汤里也好——绝不是因为常见就能小看的蔬菜。"},"ICON-1219":{"nm":"蕨菜","de":"采下春山赠予的嫩芽，煮了又晒。要经过这番漫长的辛劳，才终于能上祭桌、入拌饭。费工夫多，心意便层层浸入其中，是山头养育一季的珍贵山菜。"},"ICON-1220":{"nm":"山野菜","de":"看似无名，却各自怀着不同香气的春日礼物。奶奶的手在山路上一眼便能认出哪片叶子能吃。一篮野菜里，那个季节连香气一起，整个儿被装了进来。"},"ICON-1221":{"nm":"艾草","de":"最先顶破冻土冒出头来的，那带点苦却清香的草。揉进年糕里，春光便原封不动地入了口。正月里人们相信用它煮汤能挡一年的厄运，所以春天总是从这股香气里来的。"},"ICON-1222":{"nm":"紫苏叶","de":"仅仅一片，就能把满口染得浓烈的香气。配上烤得焦黄的五花肉，或是用酱油层层腌好，一碗白饭转眼就见了底。这股独特的香味，唯有在这片土地的饭桌上才显得亲切。"},"ICON-1223":{"nm":"青椒","de":"中间空心、咬下去爽脆碎裂的绿色果实。微微的一丝苦味唤醒迟钝的胃口，下油一炒，颜色便愈发鲜亮。哪怕只是切碎撒上一把，任何菜都能瞬间变得清爽。"},"ICON-1224":{"nm":"彩椒","de":"红的黄的橙的，像红绿灯般的色彩满满一筐。生着咬一口，甜汁便汩汩流淌，单凭颜色就能让餐桌亮堂起来。说好看的蔬菜也开胃，用在这里正合适。"},"ICON-1225":{"nm":"番茄","de":"总惹人争论究竟是水果还是蔬菜的圆红。煮得久了味道便更深厚，生着吃又再清爽不过。它是把盛夏阳光最诚实地攒起来的果实，咬一口，整个晌午都在嘴里炸开。"},"ICON-1226":{"nm":"黄瓜","de":"把夏日暑气消解得最清凉的那抹绿。在凉汤里浮上几片，满口便凉飕飕；腌成酿黄瓜泡菜，脆爽便活了过来。酷热的日子薄薄切片敷在眼上也好——是里里外外都清凉的蔬菜。"},"ICON-1227":{"nm":"南瓜","de":"圆圆地挂在藤蔓尽头，一直到深秋慢慢攒足甜味。熬烂了成了黄澄澄的粥，暖人脾胃；煎一煎便是焦黄的饼。挂在屋檐下，整个冬天都能当作殷实的粮仓。"},"ICON-1228":{"nm":"嫩南瓜","de":"夏日菜园里一天比一天长粗的嫩绿。切大块下进大酱汤，或煎得焦黄成饼——绵软得连小孩子的嘴也吃得顺口。正因常见才更让人感激，是盛夏饭桌上的常客。"},"ICON-1229":{"nm":"茄子","de":"泛着紫色油亮光泽的长条果实。一吸饱油便绵软得没边，蒸得透了，纹理细滑如绸。看似平凡，却和什么搭配都合得来，是饭桌上多情的配角。"},"ICON-1230":{"nm":"玉米","de":"一粒一粒整齐排成行的金黄颗粒。下锅蒸熟，呼呼吹着啃下去的夏日零食，也是田野熟透了的可喜信号。在一束毛茸茸的须里，藏满了甜味。"},"ICON-1231":{"nm":"黄豆","de":"又小又硬的颗粒泡了一夜的水，胀得圆滚滚。磨细成了豆浆，发酵透了成了酱——这片土地餐桌上的蛋白质，大多从这里起步。往土里埋下一粒，又能长回一株。"},"ICON-1232":{"nm":"豆腐","de":"黄豆吸饱水、磨开、凝固，便成了棱角端正的白块。柔软而温吞，进了哪锅汤都不固执己见。用勺一舀就酥酥碎开——淡然便是它的美德。"},"ICON-1233":{"nm":"红豆","de":"把红红的小颗粒煮得透烂，深红的甜味便浓浓渗出。在最长的那一夜，用一碗热腾腾的红豆粥同时驱走寒冷与邪祟，这份心意便栖息于此。甑糕里层层叠叠的那抹红，正是一片诚心。"},"ICON-1234":{"nm":"红豆沙","de":"把煮熟的红豆细细碾碎，熬了又熬做成的绵软馅料。夹进面包，包入年糕，浇上刨冰——一勺甜意能暖到旧日的记忆。过滤、熬煮的那段漫长时光，原封不动地变成了甜味。"},"ICON-1235":{"nm":"蘑菇","de":"雨过天晴后，在幽暗的林荫里无声地探出头来。没有一丝阳光，也能养出自己香气的泥土的手艺。只放一把进汤里，没有肉也能煮出醇厚的鲜——是森林藏起来的秘密。"},"ICON-1236":{"nm":"香菇","de":"撑开菌盖的褐色小伞。在阳光下晒得干透，香气便浓上数倍，干干一朵就足以撑起一锅汤的味道。它是素食餐桌坚实的顶梁柱，也是懂得深味之人多年的老相识。"},"ICON-1237":{"nm":"松茸","de":"秋日松林深处，只在松树旁悄悄抬起头来。它无法人工培育，唯有靠双脚跋涉去寻，因而愈发珍贵。稍微烤一烤，只蘸点盐，一片森林便入了口。"},"ICON-1238":{"nm":"杏鲍菇","de":"把厚实的菌柄顺着纹理一缕缕撕开，那份嚼劲便握在了手里。它四季都长得殷实，从不曾远离餐桌。或烤或炒——在那丰腴的肉身里，满是毫无负担的踏实。"},"ICON-1239":{"nm":"草莓","de":"在熬过寒冬的大棚尽头，它最先红透。咬上一口，酸酸甜甜，恰似早春的第一声问候。在蛋糕上圆圆地放上一颗，平淡无奇的今天也立刻成了纪念日。"},"ICON-1240":{"nm":"蓝莓","de":"啵地一爆开，满口便明亮地漾起酸味。把紫色的小珠子一颗颗捏着吃，不知不觉一盒就空了；撒在洁白的牛奶上，眼前便铺开了一小片夜空。"},"ICON-1241":{"nm":"苹果","de":"咬上一口，咔嚓一声，秋天便碎裂开来。果园奶奶用抹布擦了擦递来的那抹红，是要久久怀抱阳光才能染上的色。越是结实，越懂得甜到最后的道理。"},"ICON-1242":{"nm":"梨","de":"削起皮来，指尖先觉一阵清凉。中秋祭桌的最前排，冰凉甜汁满溢口中的那一刻，秋夜的一缕晚风便悄悄过来，坐到了身旁。"},"ICON-1243":{"nm":"桃子","de":"桃花谢去的地方，便结出毛茸茸的夏天。轻轻一按，香气先漫开来，咬下一口的瞬间，整个季节都跟着进了嘴里。"},"ICON-1244":{"nm":"葡萄","de":"紫色的果粒一颗颗挂成一串，彼此倚着肩。啵地爆开，酸味先来，甜味慢上半拍——像夏末时节唱起的一支端庄的合唱。"},"ICON-1245":{"nm":"青葡萄","de":"嫩绿任阳光原样穿过，每一粒都点起了灯。无籽而干净的清爽，像刚唱出的第一个音节，是不带一丝多余的甜。"},"ICON-1246":{"nm":"柠檬","de":"用指甲刮一下黄色的皮，香气便咚地一下，唤醒鼻尖。哪怕一滴酸得嘴角不由自主皱起，那酸味的尽头，却奇妙地藏着让一整天都明亮起来的角落。"},"ICON-1247":{"nm":"青柠","de":"比柠檬更小、更深绿的这颗果，先以呛人的香气前来问候。只一片，便能让温吞的水瞬间醒来——虽小却精干的一捧清凉。"},"ICON-1248":{"nm":"橙子","de":"剥皮的瞬间，手指便沾上了阳光的气味。一瓣瓣放进嘴里，啵、啵，小小的甜汁气泡接连爆开——圆圆的东西，连心情都给滚得圆了起来。"},"ICON-1249":{"nm":"橘子","de":"冬天暖炕上，把脚埋进被窝里剥来吃的那个味道，你还记得吗？指甲缝间漫开的香气，把整个房间都染成了黄色。一袋橘子，便成了一家人围坐的借口。"},"ICON-1250":{"nm":"香蕉","de":"饥肠辘辘的凌晨，在练习室角落里，曾有过用从包里滚出的一根黄色充饥的日子。绵软、香甜又顶饱——是最温情的临时救急。"},"ICON-1251":{"nm":"菠萝","de":"要先过带刺的外皮那一层，金黄的果肉才露出来。一片含进嘴里，酸酸甜甜地刺一下舌头，嘴边不知不觉便萦绕起南方海洋的气味。"},"ICON-1252":{"nm":"芒果","de":"用手掰开熟透的果肉，黏黏的甜香便沾湿了指头。浓郁的金黄在口中酥酥融化、消散时，掠过一场如夏日午睡般短暂的甜梦。"},"ICON-1253":{"nm":"椰子","de":"晃一晃坚硬的壳，里头便荡起咣当的水声。敲开后是雪白的果肉与清凉的汁——是把远方大海整个装进、晃晃悠悠的一只小坛子。"},"ICON-1254":{"nm":"火龙果","de":"粉色鳞片般的外表起初让人一怔，可剖开一看，雪白果肉里点点黑籽。味道朴素，妆扮华丽，是表里截然相反的滑稽角色。"},"ICON-1255":{"nm":"猕猴桃","de":"把裹着绒毛的褐色对半剖开，绿色宝石便露了出来。黑籽如星星般嵌在切面上，舀一勺送进嘴里，一口酸便把睡意摇醒。"},"ICON-1256":{"nm":"鸡肉","de":"放进抹了油的锅里，滋啦一声，焦黄的声响先熟了。清淡而柔软，无论谁的餐桌都能随和地凑上一席——是温和一餐里的常客。"},"ICON-1257":{"nm":"猪肉","de":"在烤盘上滋滋作响，油花啪啪溅着，焦黄地熟了过去。在一片生菜上抹点酱，满口塞进去的聚餐之夜，那股喷香暖了整个场子。"},"ICON-1258":{"nm":"牛肉","de":"每一道红色的纹理里都细细嵌着油花，泛着光。放上烧热的石板，香气便先占满了座席，一片送进嘴里的瞬间，一天的疲惫便悄然松开。"},"ICON-1259":{"nm":"培根","de":"清晨的平底锅上，咔嚓作响，油花跳起了舞。仅凭那股咸香，赖床的家人也会揉着眼睛聚到厨房来——是气味先唤来的一餐。"},"ICON-1260":{"nm":"香肠","de":"划了刀口的地方咧开来，啵地爆出汁水。撑起便当一格的那只红色章鱼模样，是儿时午餐时间享受的一点小小奢侈。"},"ICON-1261":{"nm":"意式香肠","de":"圆圆又微辣的一片，在滚烫的奶酪上从边缘开始卷起。稍稍渗出一点油，那便是一整张披萨的高潮——虽小，存在感却又圆又浓。"},"ICON-1262":{"nm":"肉饼","de":"捏得厚厚的，放上烤盘，从边缘开始变成褐色熟透。把蔬菜夹进压烤过的一片之间，一手便能稳稳握住的踏实就此完成。"},"ICON-1263":{"nm":"鸡蛋","de":"啵地敲开，蛋黄便像圆圆的太阳般滑了出来。拌进刚煮好的饭里好，成了紫菜包饭里的那道黄线也好——是最常见因而也最多情的蛋白质。"},"ICON-1264":{"nm":"牛奶","de":"凌晨放在门口的冰凉一瓶，掌心触到的那份清凉，常常开启一天。加热便冒出热气，冷却则香醇——是随时守在身旁的白。"},"ICON-1265":{"nm":"奶酪","de":"黄澄澄的一片，在温热的面包上慢慢塌陷开来。等待它拉出长丝的那一瞬的心情——越是融化，那份香醇便越深越浓。"},"ICON-1266":{"nm":"切达奶酪","de":"浓郁的橙色一眼便预告了那咸鲜的味道。薄薄切片夹进吐司，鲜味便满口散开——颜色多分明，风味便多分明。"},"ICON-1267":{"nm":"黄油","de":"往烧热的锅里丢一块，便酥酥融化，升起喷香的热气。抹在面包上、拌进饭里，碰到什么都能让它更添柔润的黄色魔法。"},"ICON-1268":{"nm":"鲜奶油","de":"打蛋器越转，稀稀的白便渐渐鼓成结实的云朵。在蛋糕上舀一勺的瞬间，平凡的午后也像个小小的生日般明亮起来。"},"ICON-1269":{"nm":"酸奶","de":"勺子探进去便顺滑舀起的酸味白色。拌一块水果，早晨便轻盈起来；一杯下肚，肠胃便安稳地归于整齐——是柔和开端的味道。"},"ICON-1270":{"nm":"鲭鱼","de":"放上烤架，油花啪啪溅着，带着腥又喷香的烟气弥漫了厨房。剔了刺放到饭上递来的那双手——是寻常饭桌里藏着的最深的诚心。"},"ICON-1271":{"nm":"三文鱼","de":"粉色的纹理一层层叠着躺着。生着切片吃，在口中柔柔化开；烤一烤，油脂渗出，香喷喷的——是逆着远方大海游来的结实滋味。"},"ICON-1272":{"nm":"金枪鱼","de":"拧开罐头盖，咸鲜的香气便扑地涌上来。拌进饭里、用紫菜裹着吃的独居岁月，曾有过一罐就能成为踏实一餐的日子。"},"ICON-1273":{"nm":"鳕鱼","de":"清亮的肉质清淡，一煮，汤头便先鲜美地熬了出来。这熬过冬日港口刀刃般寒风的白鱼，热腾腾一碗汤下肚，冰凉的手也会慢慢暖开。"},"ICON-1274":{"nm":"虾","de":"把背圆圆地蜷起来，一熟，灰色便染上了红晕。啵地爆开的弹嫩与那股喷香，一只只剥着吃，不知不觉盘子就空了。"},"ICON-1275":{"nm":"螃蟹","de":"从坚硬的壳里剔出雪白的肉，是一段小小的耐心时光。那番辛苦尽头送进嘴里的一口，鲜甜满溢，秋天的海整个儿入了口。"},"ICON-1276":{"nm":"鱿鱼","de":"在烤盘上圆圆地蜷缩起来，升起喷香的气味。咬起来弹牙的一片，蘸点醋辣酱送进嘴里，咸鲜的大海便跟了进来。"},"ICON-1277":{"nm":"蛤蜊","de":"在清亮的汤里张开口，悄悄献出自己的香气。咕嘟咕嘟煮沸的声响中，海的气息漫开，呼噜一口下肚，冰凉的肠胃便暖暖地舒展开来。"},"ICON-1278":{"nm":"鱼糕","de":"连签子一起浸进热腾腾的汤里，热气便袅袅升起。寒冷的日子里，路边摊前用纸杯接着汤、呼呼吹凉的那双手——是巷子递来的一点小小慰藉。"},"ICON-1279":{"nm":"泡菜","de":"在缸里慢慢熟成，养出又酸又深的香气。用手撕开一条，放上刚煮好的饭就极好，家家不同的味道，正是那户人家的家世。"},"ICON-1280":{"nm":"黄萝卜","de":"黄黄的一片，咔嚓一声，在口中轻快地碎开。它是守在一卷紫菜包饭、一盘小吃旁边的好搭档——酸酸甜甜，把油腻的口腔清爽地涮净。"},"ICON-1281":{"nm":"腌黄瓜","de":"黄瓜在盐里短暂地敛了气息，又在醋里睁开了眼。生怕错过爽脆回归的那一刻，玻璃瓶便一直守在洒满阳光的窗边。慢慢腌渍的时光，把味道带了来。"},"ICON-1282":{"nm":"辣椒酱","de":"在缸里熬过一年的红。辣味的尽头悄悄藏着黄豆的甜，化进汤里一勺，炖锅这才有了自家的面孔。是院里酱缸台用阳光养出的深度。"},"ICON-1283":{"nm":"大酱","de":"酱饼拥着霉菌过了一整个冬天。那股醇香，是熟与过熟之间惊险的走钢丝——奶奶单凭指尖一缕气味便能拿捏那道分界。等得越久，味道便越深。"},"ICON-1284":{"nm":"酱油","de":"黄豆越黑，内里便越深。一滴便能让野菜活过来、让炖菜得了光泽，所以厨房里所有的色彩，归根结底都从这温暖的褐色起步。是咸味之外的那份鲜。"},"ICON-1285":{"nm":"春酱","de":"同是黑色，纹理却不同。再用焦糖多炒一道的那股咸甜余味，拌进面里，那乌黑的光泽便把胃口摇醒。是中华锅气开启的第一颗纽扣。"},"ICON-1286":{"nm":"咖喱粉","de":"多种香料在一勺之中和睦交融的黄色粉末。化进水里咕嘟咕嘟沸腾，暖了整间屋子，便成了下雨傍晚最踏实的那一碗饭的预告片。"},"ICON-1287":{"nm":"胡椒","de":"整粒现磨香气才活，预先磨好香气便悄悄溜走。最后那一圈，总在关火前的那一刻——是下厨的手珍惜地点上的一个小小句号。"},"ICON-1288":{"nm":"辣椒粉","de":"秋阳下晒干的太阳椒，这才把红补得圆满。磨得细还是磨得粗，决定了泡菜的性格，所以所谓手艺，归根结底来自挑选这粉末的颗粒。"},"ICON-1289":{"nm":"盐","de":"所谓调味，是朝着不足那一边一撮撮靠近。盐味一旦放进去便收不回，所以老练的手总在最后少放一点，尝过味道再说。留出的那一分，便是余地。"},"ICON-1290":{"nm":"糖","de":"它抚平苦味，磨圆酸味的棱角。可甜味不该被人察觉，所以越是好的调料，糖越会在最后悄悄隐去踪影。是懂得藏身的甜。"},"ICON-1291":{"nm":"蜂蜜","de":"蜜蜂在花田间往返千百回攒下的一瓶。凝固了就隔温水化开复活，化进茶里，便柔柔包裹住喉咙。是把一整季节整个熬浓的金黄一勺。"},"ICON-1292":{"nm":"食用油","de":"在烧热的锅里转一圈，食材便忘了粘锅。倒得太早会糊，太晚会黏，所以烟气刚升起的那半拍，正是煎制的正道。靠声音来掐时机。"},"ICON-1293":{"nm":"橄榄油","de":"初榨的那抹绿里，住着草香与一丝微辣。比起上火，更该在最后浇上，那香气才能存活到底，所以不加热才是它最诚实的用法。"},"ICON-1294":{"nm":"香油","de":"最后滴上一滴，野菜这才宣告了完成。那股香醇生性容易在火上溜走，所以总在所有烹饪结束后悄悄添上，成为一个句号。"},"ICON-1295":{"nm":"香草荚","de":"剖开一根荚，刮出黑色的籽，甜点便换上了香气做的衣裳。用完的荚也舍不得丢，埋进糖里——这是糕点师傅传承下来的古老节俭。"},"ICON-1296":{"nm":"可可","de":"果实里雪白的果肉与苦涩的籽。要经过发酵与日晒风干，才终于被翻译成我们熟知的甜蜜。在变成巧克力之前，它有着最接近野生的第一张脸。"},"ICON-1297":{"nm":"巧克力","de":"单凭掌心的温度便酥酥融化的难缠脾性。要在28度上下凝固，那啪一声折断的光泽才活得了，所以甜蜜背后，竟藏着一套挑剔的温度规则。"},"ICON-1298":{"nm":"咖啡豆","de":"磨开之前的一粒，近乎一种坚硬的沉默。可一遇上热水便鼓鼓膨起、吐出香气，所以唤醒早晨的第一声信号，总是从这颗小小的豆子开始。"},"ICON-1299":{"nm":"茶叶","de":"在热水里待得太久便涩，太短便寡淡。静静掂量叶子慢慢舒展的时间——所谓泡茶，便是用指尖来量度等待。"},"ICON-1300":{"nm":"薄荷","de":"一揉碎便沁出苦味，所以总要轻轻对待的娇嫩叶子。轻轻一拍唤醒沉睡的香气，酷热的日子里浮进玻璃杯，盛夏便沉降下一个调子般凉爽。"},"ICON-1301":{"nm":"香草","de":"连茎一起放，香气便深；只用叶子，则清。晒干会更浓，生用则清新，一束香气有多宽，厨房的表情便随之拓得多宽。"},"ICON-1302":{"nm":"栗子","de":"带刺的壳里藏着泛光的果肉。划个口子烤一烤，便啵地咧开，散出甜香，冷风吹过的巷子里那袋烤栗子的暖意，仿佛触手可及。"},"ICON-1303":{"nm":"花生","de":"那股香醇，在炒制的火里完成。一颗颗剥着吃，便会不知时光流逝的小颗粒——围坐在地板上分着吃，连故事也一同絮絮地剥了出来。"},"ICON-1304":{"nm":"杏仁","de":"稍微焯一下剥去皮，内里便更白更柔。碾碎磨开像牛奶，整颗烤一烤又酥脆——一颗所藏的变身幅度，把糕点师的想象拓得宽宽。"},"ICON-1305":{"nm":"芝麻","de":"用小火轻轻晃着，晃着，某一刻便噼噼啪啪地跳起来。那声响快停的前一刻最香——炒芝麻这件事，归根结底成了用耳朵来听的事。"},"ICON-1306":{"nm":"甘蔗","de":"嚼一节，草香伴着甜汁便渗了出来。要熬了又熬才能成为我们熟知的甜味的茎——糖的开端，竟是这般青翠而高挑。"},"ICON-1307":{"nm":"原糖","de":"少经提炼、原样保留自己颜色的粗犷甜味。隐隐残留着泥土气般的深度，所以偏爱精雕细琢之前那份坦率的手，会特意把它寻出来。"},"ICON-1308":{"nm":"可可豆","de":"刚从荚里取出的籽又苦又涩。要默默熬过发酵的几日，香气才会绽放，所以所谓甜蜜，是这颗豆长久忍耐到头后领到的一份小小奖赏。"},"ICON-1309":{"nm":"可可碎粒","de":"把炒过的豆细细碎开的碎块里，没有一丁点糖。送进嘴里，苦涩先来，香醇随后迟迟跟上，所以这是最诚实地遇见甜味之前的可可。"},"ICON-1310":{"nm":"咖啡生豆","de":"还泛着青气的绿色颗粒。就这样香气仍熟睡着，在接受火的洗礼之前，它静静留存为一份连自己也不知将成为什么的可能。"},"ICON-1311":{"nm":"烘焙咖啡豆","de":"微微渗出油脂的褐色表面，蓄满了香气。要趁没凉透就磨，那香气才完整，所以一杯的命运，会在烘焙后的几天内悄然定下。"},"ICON-1312":{"nm":"香草豆荚","de":"一根的香气，便能把一整锅牛奶通通染上味道。连用完的荚也插进糖罐里，几天后整罐糖都香起来，所以它是没有一处可丢的奢侈。"},"ICON-1313":{"nm":"黑胡椒","de":"一粒整胡椒的香气，从被磨开的那一刻起便开始减损。所以才整粒摆在餐桌上，需要时随手碾碎——所谓新鲜，从不拖延的心里绽放。"},"ICON-1314":{"nm":"白胡椒","de":"剥了皮、更显光滑的颗粒，与其说辣，不如说隐约。它生于一份不愿在白酱里留下一个黑点的体贴，是隐于无形之处的细腻。"},"ICON-1315":{"nm":"肉桂","de":"泡上一片，温暖的辛辣便在茶里慢慢漫开。比起粉末，整片放进去香气才持久，所以冬日饮品的深度，来自这片干皮的韧劲。"},"ICON-1316":{"nm":"丁香","de":"长得像小钉子的一个花苞里，浓缩满了香气。放得太多便会把食物整个吞没，所以仅一粒的克制，悄悄守护着风味的平衡。"},"ICON-1317":{"nm":"肉豆蔻","de":"把整颗籽留着，需要时随手稍稍磨一磨。预先磨好香气便很快散去，所以最后呼地刮下的那一手，让牛奶的香气更添一层深。"},"ICON-1318":{"nm":"小豆蔻","de":"啵地捏开绿色的荚，里头便倾泻出清凉的香气。只往茶里碾进一两粒，平淡的一杯便忽然得了遥远国度的香气。"},"ICON-1319":{"nm":"藏红花","de":"一朵花只能采下三根的红丝。化进温水里，黄色便慢慢漫开，所以所谓珍贵，也是用手一根根挑出的时间的重量。"},"ICON-1320":{"nm":"姜黄","de":"把泥土里的根一磨，连指尖都染成了黄。要下油稍稍炒过香气才醒的性子，所以咖喱的金黄，正是这小小的根在火上绽出的色。"},"ICON-1321":{"nm":"月桂叶","de":"据说曾戴在胜利者额头上的叶子。往沸水里浮上一片，热气间便短暂升起昔日竞技场的呐喊。哪怕在不曾获胜的日子里吸一口它的香气，也会成为静静拥抱今日之你的、青绿的慰藉。"},"ICON-1322":{"nm":"椰浆","de":"要敲开坚硬的壳，才终于流出的白汁。在炎热国度市场的一角，插上一根吸管啜一口，晌午的干渴便整个儿凉了下来。满口漾开的清凉甜香，带来热带的阴凉。"},"ICON-1323":{"nm":"椰子油","de":"凝固时洁白如初雪，在掌心一暖香气便缓缓漫开。说一罐就足够从头用到脚而递来的，海岛奶奶那多情的持家智慧，原原本本盛在了圆圆的罐里。"},"ICON-1324":{"nm":"香蕉干","de":"在阳光下晾上几日，黄色的果肉便变得有嚼劲。一片片省着咬下去，下雨收获季那黏黏的甜香，便在口中悄悄复活。慢慢熟成的甜，就这样怀抱住了季节。"},"ICON-1325":{"nm":"芒果干","de":"绵软的果肉在阳光下浓缩，重生为琥珀色的果冻。酸、甜、有嚼劲，三种味道全在一片里，在口中慢慢打着转，一袋便拉长了一个下午。"},"ICON-1326":{"nm":"菠萝干","de":"与带刺的外表不同，内里果肉再黄再亮不过。在阳光下晾着，酸味便浓缩起来，只咬一片嘴角也会自己扬起。一片尽头残留的那份清爽余韵，久久停驻。"},"ICON-1327":{"nm":"热带水果篮","de":"刚摘来的色彩在一篮里相映成趣。芒果的橙、香蕉的黄、菠萝的金——还没伸手去挑，夏天便先从鼻尖涌了过来。是光看着心情就明亮起来的满满一抱。"},"ICON-1328":{"nm":"海藻束","de":"退潮的礁石上收来的大海的头发。咸鲜的海腥里缠着浪声，用凉水静静泡发，腥腥的海香便慢慢漫到厨房。一把便在餐桌上铺开一小片滩涂。"},"ICON-1329":{"nm":"海产干货","de":"把干得韧韧的大海抓上一把。顺着纹理用手撕开，咸味伴着旧日港口咸涩的风便松了开来。是会让人不由想起一碗马格利酒、守在情深饭桌旁的老朋友。"},"ICON-1330":{"nm":"鱿鱼干","de":"把十条腿整整齐齐铺开在阳光下晒干。用火稍稍一烤，喷香升起，便顺着纹理一缕缕撕开。凭着那弹韧的嚼劲，深夜一盘宵夜的格调便上了一个台阶。"},"ICON-1331":{"nm":"腌咸鱼","de":"埋进粗盐里，鱼便学会了熬过时间的法子。一片咸味深透的肉，便能让一碗饭转眼见底，是海边奶奶用指尖传下的、多情的秘诀。"},"ICON-1332":{"nm":"虾酱","de":"小小的虾在盐里慢慢熟成，重生为鲜味。腌泡菜时往白菜心里放一勺的瞬间，整个院子便漫开咸鲜的气味。那一勺，决定了一年泡菜的味道。"},"ICON-1333":{"nm":"鳀鱼","de":"手指般大的身躯，撑起一锅汤的深度。摘头去肠时絮絮叨叨聊天的儿时厨房——虽小，却稳稳立在持家正中央的可贵小鱼。"},"ICON-1334":{"nm":"海带","de":"在海底长长生出的黑带。下凉水煮，将沸未沸之际轻轻捞起，是熬汤的手代代相守的约定。深厚的鲜味，从不知何为急躁。"},"ICON-1335":{"nm":"羊栖菜","de":"疙疙瘩瘩的口感在口中啵啵爆开。春天里把礁石染成绿色的海藻，搓拌一番，餐桌一角便铺开一小片清新的海。是嚼着春天的味道。"},"ICON-1336":{"nm":"珍珠贝","de":"在坚硬的两扇之间久久怀抱、孕育出的圆圆之光。从一粒沙的不适化作宝石，海一次也不曾催促。捧在掌心，那段漫长忍耐的重量便一同搁了上来。"},"ICON-1337":{"nm":"珊瑚饰品","de":"海浪打磨了数百年的大海的树枝。阳光一照便漾开粉色与橙色，只静静摆在架上，便能把一间屋子染成温暖的海岛。连触到指尖那粗糙的纹理也透着亲切。"},"ICON-1338":{"nm":"贝壳纽扣","de":"贝肉离去的地方，把莹润的内侧圆圆地剜了下来。缝在衣襟上，每扣一次，指尖便闪起一道小小的彩虹。是把所有都给了出去、离去时大海留下的最后一份多情的礼物。"},"ICON-1339":{"nm":"玻璃珠","de":"在掌心一滚，困在里头的光便骨碌碌跟着一起来。蹲在巷子里玩弹珠玩到忘了日落的那段岁月，多赢一颗的孩子，口袋格外沉甸甸、满是得意。"},"ICON-1340":{"nm":"香木雕片","de":"削过的每一道纹理里都沁着隐隐的香气。古人燃这木头，理顺纷乱的心绪。静静攥着一片，从指尖起，沉静便慢慢漫了上来。"},"ICON-1341":{"nm":"香","de":"细细的一缕慢慢燃着，向上开出一条路。眼睛追着烟描出的曲线，整日匆忙的心也不知不觉放慢了脚步，停在了那里。"},"ICON-1342":{"nm":"染料花","de":"把藏在花瓣里的色彩化进沸腾的锅，洁白的布便渐渐染上那个颜色。借来自然预先涂好的色用一阵——染色，本就是向花儿递去的一声多情的问候。"},"ICON-1343":{"nm":"靛蓝染料","de":"把蓝草发酵了又发酵才得来的、深沉幽远的蓝。每浸一次再取出，布便从天色慢慢移向海色。是要放下急躁，才终于绽放的、等待的颜色。"},"ICON-1344":{"nm":"红色染料","de":"把茜草根熬开，沉睡在泥土里的晚霞便在锅中醒来。它曾把喜宴上新娘的裙摆染得娇美，是村里最喜庆、最明亮的颜色。"},"ICON-1345":{"nm":"金线","de":"把比头发还细的金抽出来，一缕缕用心捻成。绣过的每一处都含着光，即便在灯火熄灭的暗房里，唯有那纹样仍自顾自隐隐地明亮浮现。"},"ICON-1346":{"nm":"绸缎","de":"把蚕吐出的丝织了又织，才勉强成得了一幅。拂过手背，便如春水般滑过的触感，是古人用一整个季节怀抱、慢慢养出的纹理细腻的布。"},"ICON-1347":{"nm":"珍珠纽扣","de":"只挑出珍珠内侧的光，圆圆地打磨而成。一颗颗扣进上衣衣襟时，指尖便一时优雅了起来。虽小，却悄悄抬升一身穿着的格调，是端庄的一颗。"},"ICON-1348":{"nm":"航海图碎片","de":"撕裂的边缘之外，未知的海岸线戛然而断。据说唯有集齐其余碎片的人才能触到宝藏旁——可或许，随风去寻它的那段旅程本身，早已是宝藏。"},"ICON-1349":{"nm":"陈旧海图","de":"被海水洇开的航线与褪色的罗盘图。用指尖顺着某位船夫在漆黑夜里只看着星星划下的线走，许久前消失的一座岛，便在陈旧的纸上重又慢慢浮现。"},"ICON-1350":{"nm":"瓶中信","de":"被海浪推来的玻璃瓶里，一张卷成卷的纸。不知是谁、何时放出的问候，终于触到了某人的手。大海只要有心，也能这样当一名缓慢的邮差。"},"ICON-1351":{"nm":"漂流箱","de":"被海水泡得发胀、盖子卡得紧紧的，打开它的那一刻才算冒险的终点。无论里面装的是宝物还是空空的沙子，随波漂来的箱子总会一同带来某个素未谋面之人的故事。"},"ICON-1352":{"nm":"小钥匙","de":"正好能握进掌心的一块旧铁。哪扇门早已忘得一干二净，可它那份温柔的分量留在指尖，让人先想起开启的方法，而非上锁。"},"ICON-1353":{"nm":"银币","de":"被摩挲得花纹都模糊了的圆形银币。它曾是某人的船费，也曾换来疲惫一夜的安眠。抚过那冰凉的表面，许久以前一桩交易的温度便隐约在指尖复苏。"},"ICON-1354":{"nm":"金币","de":"放上掌心，沉甸甸的分量先一步撼动了心。一枚迎着阳光泛起金黄的硬币，仿佛拥有它就能成为富翁——可真正闪得最亮的，其实是握住它前那一瞬的心跳。"},"ICON-1355":{"nm":"船长印章","de":"曾在红色封蜡上重重按下的船长的承诺。仅凭一个印记，命令便得以立下，险峻的航线便得以定夺。所谓权威，归根结底不过是同舟之人共同选择信赖的那一枚小而坚实的印章。"},"ICON-1356":{"nm":"手持麦克风","de":"握住的瞬间，掌心便被一种莫名安心的分量填满。无论是颤抖着说出第一句问候，还是终于飙起高音的那一刻——这根小小的棒子都悄悄为你的嗓音装上翅膀。"},"ICON-1357":{"nm":"无线麦克风","de":"线一消失，整个舞台都豁然开阔。哪怕跑到观众席的最尽头，声音也从不会中断，仿佛有谁轻轻推着你的背，让你尽情奔跑歌唱。"},"ICON-1358":{"nm":"立式麦克风","de":"稳稳立在脚边，默默等待着歌手。双手一旦自由，歌声便不再只从指尖、而是从全身蔓延开来。它静静地说：坚守一处直到最后，也自有一份分明的帅气。"},"ICON-1359":{"nm":"防喷罩","de":"在麦克风前圆圆挡上的一层薄布。它温柔地滤去粗重的呼吸，只放清亮的嗓音通过。所谓让人听得清楚，正是在始终不被看见的位置默默遮挡。"},"ICON-1360":{"nm":"入耳式耳机","de":"塞进耳中，便能在万千呐喊之外清晰复苏自己的歌声。在光与声齐齐倾泻的舞台上，它替你抓住节拍不致失误，是最小巧、最隐秘的同伴。"},"ICON-1361":{"nm":"头戴耳机","de":"戴上的瞬间，世界缩小了一寸，只剩歌声被放大。一间谁也无法闯入的圆形房间。独自戴着耳机，却奇妙地不觉孤单。"},"ICON-1362":{"nm":"乐谱","de":"黑色的音点静静落在线上，沉默的纸便含住了声音。这是不靠读、而靠听的文字。翻开的瞬间，停驻的歌声重新开始呼吸。"},"ICON-1363":{"nm":"声乐谱","de":"在每个该换气的地方画上小小的圈。在这里吸气，在那里轻轻放开。这是一张温柔的地图，为不伤嗓音而铺好道路。"},"ICON-1364":{"nm":"钢琴谱","de":"十根手指同时问路的一页。左手按住根基，右手描绘旋律。讲着不同故事的两只手，终在最后一小节合而为一。"},"ICON-1365":{"nm":"吉他和弦表","de":"手指初学的外语，那第一个单词就写在这里。六个点汇成一个圈，一个音才终于鸣响。日复一日的按压之夜，指尖渐渐长出了茧。"},"ICON-1366":{"nm":"节拍器","de":"嗒，嗒——一步不曾动摇的脚步在身旁打着拍子。当心急着抢跑时，它从背后慢慢、慢慢将你拉住。所谓节拍，归根结底是一句一起走的约定。"},"ICON-1367":{"nm":"调音器","de":"当指针滑向正中央，音才终于找回了自己的位置。不高也不低的那一点。所谓对准，原来就是这样不再颤动、静静停下的事。"},"ICON-1368":{"nm":"钢琴键卡","de":"每翻过一张，琴键便走进掌心。从do到si，七格的小宇宙。在没有真钢琴的夜晚，歌声也在这里静静生长。"},"ICON-1369":{"nm":"吉他拨片","de":"夹在拇指与食指之间的小而坚硬的一片。一旦掉落便会在椅子底下永远消失踪影，可一握进手中，六根弦便齐齐鸣响开来。"},"ICON-1370":{"nm":"鼓棒","de":"两根在半空相击，信号便落在那一处。一、二、三、四。原本四散的众人心跳，随着这四拍开始以同样的速度跳动。"},"ICON-1371":{"nm":"铃鼓","de":"敲一下，便如阳光细碎绽开般，清亮的声音向四方散开。看似轻巧，却在兴致渐凉时最先伸手去拿的一拍。谁也别因它小而小看。"},"ICON-1372":{"nm":"舞蹈运动鞋","de":"对滑行旋转的脚而言，摩擦便成了武器。磨损的每一块鞋底都刻着转了又转的旋转。最帅的动作，总是从一双结实的鞋开始。"},"ICON-1373":{"nm":"护膝","de":"唯有无数次跪下又重新站起的人才懂得，这薄薄一层布的可贵。让地板不再令人畏惧——勇气有时就这样裹在膝上。"},"ICON-1374":{"nm":"护腕","de":"提前裹好易弯折的部位，再勉强的动作也能宽容几分。手腕不会说话，疼到极限也独自忍着。那长久的沉默，便由一层布替它挡下。"},"ICON-1375":{"nm":"护踝","de":"高高跃起的尽头是落地，落地的尽头是脚踝。在最低的位置承接全身重量的所在。这条小小的束带，静静守护着明天的练习。"},"ICON-1376":{"nm":"拉伸带","de":"拉多远，它就奋力想弹回原处多远。在抵住那份阻力的过程中，身体在不知不觉间一点点变长。所谓延展，归根结底是坚持过的时间留下的痕迹。"},"ICON-1377":{"nm":"瑜伽垫","de":"铺开的瞬间，地板上便有了属于我一人的领地。趴下、躺平、调匀呼吸的小小疆土。一天的开始与结束，都在这一张垫上静静收拢。"},"ICON-1378":{"nm":"泡沫轴","de":"在僵硬处缓缓按压，起初是疼，随即便舒爽起来。化解僵结的事总伴着一点疼痛。无论身体还是心，要想松开，总得先按上一回。"},"ICON-1379":{"nm":"哑铃","de":"举起同样的重量，一遍又一遍。只比昨天多举一次，仅此而已。在毫无华丽的重复里，手臂默默变得粗壮。一块只知诚实的铁。"},"ICON-1380":{"nm":"壶铃","de":"全身被一只把手整个甩动。当圆形的重量画着圈旋转，坚持之人的平衡便被推上考验。要想不动摇，得先认清自己的重心。"},"ICON-1381":{"nm":"跳绳","de":"越过从脚下嗖地掠过的一根绳，再越过。就像在院子里与玩伴数着数的那场游戏，数字越堆越高，气息越急促，笑声也越来越多。"},"ICON-1382":{"nm":"跑鞋","de":"唯有踏上路面才懂其真价的一双鞋。划开清晨的空气，在同一条路上再跑一遍，昨日还遥远的转角，今天已近在眼前。距离，是脚记住的。"},"ICON-1383":{"nm":"运动毛巾","de":"擦去额上的汗，那里便沁着今天努力的一道痕。洗过后印迹虽会消失，可流过多少汗，便在某处一笔笔积攒。最坦诚的加油，总在身旁渐渐晾干。"},"ICON-1384":{"nm":"水瓶","de":"空了就装满，渴了便喝一口。这单纯的往返默默支撑着一天。就像井边吊桶上上下下，新的一天又从注满中开始。"},"ICON-1385":{"nm":"蛋白奶昔","de":"摇匀后咽下一口，今天耗损的肌肉便在明天重新充盈。味道虽不华丽，身体却懂得，这是恢复的语言。成长总是被静静喝下。"},"ICON-1386":{"nm":"能量棒","de":"在口袋里被压得扁扁的一条。填补正餐与正餐之间那段空荡时光的应急口粮。虽不起眼，可这小小一口，让人多撑住午后的一个动作。"},"ICON-1387":{"nm":"润喉糖","de":"含在口中打转，清凉的薄荷便悄悄抚过粗糙的嗓子。说了很多话的日子、唱了很久的夜晚——一颗小糖安抚着那条干涩的路。甜，也自有它的用处。"},"ICON-1388":{"nm":"护嗓茶","de":"温热的雾气暖着喉咙，一口下肚，肩头的紧绷便悠悠松开。像奶奶熬的姜茶那样古老的方子。歌唱之前，向嗓音递上的一句温柔问候。"},"ICON-1389":{"nm":"蜂蜜水","de":"在温水里慢慢化开一勺蜂蜜。每当喉咙发干，大人总会冲上这样一杯。它既非药也非饮料，只是从体内静静抚慰身体的一缕甜。"},"ICON-1390":{"nm":"加湿器水箱","de":"在房间里释放一团小小雾气的器皿。干燥空气抓挠喉咙的冬夜，它无声地分予一份湿润。照料一个人的事，大多便是这样无声地流淌。"},"ICON-1391":{"nm":"休息券","de":"一张写着可以歇歇的纸。接过手的瞬间，心头的负担便轻了一格。停下也是一种练习——这张小小的票替你许下了这份允许。"},"ICON-1392":{"nm":"练习日程表","de":"在一格格写满的时间上，一天稳稳地落下。清晨发声，午后编舞，傍晚休息。再茫然的明天，划上线分一分，不知不觉便变得可以走一走了。"},"ICON-1393":{"nm":"出勤印章","de":"重重按下一个今天也来了的印记。墨色微微晕开的圆圈在每格里渐渐增多，原本不起眼的勤勉，不知何时已成了一条路。每日的小小见证。"},"ICON-1394":{"nm":"表扬贴纸","de":"不说一句做得好，只是轻轻贴上一颗星。不过指甲盖大小的闪光，落在笔记本一角的瞬间，整个一天便明亮起来。表扬虽小，却奇妙地闪耀得很久。"},"ICON-1395":{"nm":"心理笔记","de":"把舞台幕后颤抖的心情，化作文字写下的那一面。再不顺的日子，老实记下来，心里也会轻松几分。心，是看进去多少，便坚韧多少。"},"ICON-1396":{"nm":"意象训练卡","de":"闭上眼握在手中，脑海里便静静铺开一座舞台。把还不曾站上的位置预先走上一圈。用想象描绘的走位，总比真正的脚尖先一步抵达。"},"ICON-1397":{"nm":"表情练习镜","de":"在镜前笑了又收，同一张脸做上不止一百次。喜悦也好悲伤也罢，都需要练习，这道理在这里学到。所谓表情，正是把心向外誊写的事。"},"ICON-1398":{"nm":"编舞笔记","de":"把脚与手将要经过的路，化作图画誊写的那一面。每八拍身体该往哪去，箭头静静指明。怎么也记不住的动作，也在这上面慢慢被驯服。"},"ICON-1399":{"nm":"编舞视频芯片","de":"一枚小小的芯片里，原原本本装下数百遍的动作。睡前再回放一次，指尖便自行顺着那条路移动。重复，是用身体誊写的又一份记录。"},"ICON-1400":{"nm":"舞台走位图","de":"从高处俯瞰舞台的一张地图。谁在哪里相遇、又往哪里散开，用线与点预先约定好。要众人共绘一幅画，得先把路分清。"},"ICON-1401":{"nm":"彩排通行证","de":"观众席空着，灯光仍在沉睡。这一张通行证将你送进那片寂静。无人观看时的舞台——于是与最诚实的你相遇的时光，便从这里开始。"},"ICON-1402":{"nm":"穿搭书","de":"今天怀着怎样的心情来穿呢。哪怕一件衬衫，也有与之相称的心绪，这本书静静地告诉你。越翻越多的页里，曾在镜前犹豫的指尖渐渐积起一点眼光。"},"ICON-1403":{"nm":"发胶","de":"嗤，喷一下，连风也无法轻易将其吹乱。一份想把舞台上短短几分钟严丝合缝抓住的小小贪心。完美的瞬间，总在这般琐碎的固执之上完成。"},"ICON-1404":{"nm":"彩妆盘","de":"十二格颜色，便是十二种心情。今天要以哪副表情歌唱，指尖先一步挑选，心随其后。每一格变空的地方，都静静沾着遗落在舞台上的那些日子。"},"ICON-1405":{"nm":"服装别针","de":"最华丽的瞬间，偏在看不见的角落，有一枚小别针撑住布料。让它不滑落、不凌乱。舞台上的闪耀，总是踏着某人的坚实而立。"},"ICON-1406":{"nm":"名牌板","de":"原本空白的板上被填上名字的瞬间，一桩模糊的约定便清晰起来。谁将站上这个位置——由一行字决定。名字，是最短也最坚定的誓言。"},"ICON-1407":{"nm":"粉丝服务卡","de":"收到的只有一个人，对那一个人却是整个世界。在简短一句问候里，把几个夜晚的感激重重压进去。心意，哪怕在巴掌大的纸上也这样满溢而出。"},"ICON-1408":{"nm":"签名练习纸","de":"起初连自己的名字都画得陌生。划上一百遍、打磨上一千遍的清晨，直到手比心先一步记住那道笔势。就这样，一个名字才终于成为签名。"},"ICON-1409":{"nm":"采访问题单","de":"「这个问题该怎么答呢。」攥着纸的指尖微微发颤。不是背诵答案，而是把真心依次立好的时光——面试也好告白也罢，归根结底都是在问心的次序。"},"ICON-1410":{"nm":"外语单词本","de":"磨损最厉害的那个边角，告诉你最久凝视过的那个单词。一个陌生发音黏上嘴的时间有多长，与那个从未去过的世界的距离，便缩短一寸。"},"ICON-1411":{"nm":"发音矫正卡","de":"打卷的'ㄹ'，漏气的'ㅅ'。有那么些清晨，一张张翻着卡片驯服舌头。话语越清晰，想用那话语触及的某张脸，也越清晰。"},"ICON-1412":{"nm":"现场检查表","de":"麦克风已开、入耳已确认、走位已检查。每填满一个方框，胸中的不安便空出一格。登台之前，细致是最安静的勇气。"},"ICON-1413":{"nm":"状态贴","de":"贴上的瞬间，便有一处温暖蔓延开来。劳损的肩、僵硬的小腿——这是巴掌大的慰藉，静静回应身体发出的小小信号。好好休息，也是练习的一部分。"},"ICON-1414":{"nm":"冰袋","de":"轻轻敷在肿胀的脚踝上。凉意慢慢渗入的过程中，才终于明白今天奔跑了多少。舞台幕后的恢复，总是这样无声地到来。"},"ICON-1415":{"nm":"急救袋","de":"创可贴、止痛药、小镜子。装满这些不起眼之物的小袋子，会迎来它最令人安心的时刻。预先备好的体贴，在意料之外的危机面前闪耀得最亮。"},"ICON-1416":{"nm":"提示卡","de":"镜头之外，有人悄悄将它举起。险些忘掉的一句话，工整地写在上面。流畅无碍的进行背后，总有这样一只镜头照不到的手。"},"ICON-1417":{"nm":"任务信封","de":"拆开信封前的那一刻最令人心跳。无论里面装着什么，在尚不知晓中雀跃的那短短一隙。综艺的妙趣，整个就活在那被封缄的一瞬之中。"},"ICON-1418":{"nm":"名牌","de":"贴在胸前的一个小小名字，替你完成了初次问候。在彼此尚不相识的人们之间，一枚名牌啪地打破了尴尬的坚冰。从呼唤名字的那一刻起，关系便开始了。"},"ICON-1419":{"nm":"惩罚贴纸","de":"啪地贴在输家额头上的一张，引得笑声哗地炸开。说是惩罚却太过亲昵，连输了都成了久久回味的回忆。这是为了一起笑而做的小而温情的标记。"},"ICON-1420":{"nm":"随机惩罚卡","de":"抽到之前谁也不知道。是转十圈大象鼻子，还是来一个撒娇。把命运整个交给一张纸的瞬间，偏偏先笑得绷不住了。"},"ICON-1421":{"nm":"提示卡","de":"像在卡壳处悄悄伸来的一只手。不会把答案全给你，却为你指明道路。好的提示不是正解，而是静静递上再想一次的勇气。"},"ICON-1422":{"nm":"机会卡","de":"能将倾斜的局面一举翻转的唯一一次机会。何时亮出这张牌，便分出了胜负。攒了又攒的好运，唯有在最关键的一刻才终于值回身价。"},"ICON-1423":{"nm":"暂停卡","de":"歇一会儿也没关系，这张卡替你说出口。需要喘口气时坦然举手——停顿也是堂堂正正的策略，好好休息同样是实力的一席之地。"},"ICON-1424":{"nm":"笑声按钮","de":"啪地一按，咯咯爽朗的笑声便满满倾泻而出。真正好笑的场面，连这样的音效也悄悄来助一臂之力。一处的暖意，便由这样一个小小玩笑捂热。"},"ICON-1425":{"nm":"音效遥控器","de":"一个按钮是掌声，另一个是嘘声。仅凭指尖便能调出气氛的魔法师，静静坐在调控室里。镜头照不到的导演手法，让那个场面活了起来。"},"ICON-1426":{"nm":"场记板","de":"啪，伴着清脆的一声，一个镜头开始了。在数十次NG与唯一一次OK之间，这块黑板把每个瞬间工整地数着。这是记录迈出的第一拍。"},"ICON-1427":{"nm":"走位胶带","de":"脚尖轻轻触到那条线的瞬间，灯光便如等候已久般轻盈落下。背得滚瓜烂熟的唯一一格——舞台，靠地上贴的一条小小色带才终于完整。"},"ICON-1428":{"nm":"灯光滤片","de":"同一张脸，也会因光的颜色整个改变。蓝色滤片栖着清晨，红色滤片含着晚霞。氛围绝不在远方——它静静折叠在一张薄薄的色纸里。"},"ICON-1429":{"nm":"相机电池","de":"红灯一开始闪烁，心便先急了起来。偏偏最好的场面，总在电量1%时到来。口袋里的一块备用，便成了喘口气的安心。"},"ICON-1430":{"nm":"存储卡","de":"一天份的笑与汗珠，密密麻麻装进指甲盖大小的芯片里。小到极易丢失，也正因此格外珍贵。所怀回忆的分量，绝不能以大小来衡量。"},"ICON-1431":{"nm":"拍立得相纸","de":"咔嚓，然后静静等待。原本雪白的一面上，面孔慢慢浮现的那几秒，奇妙地令人心动。即便握在手中的即时照片，也总要掺上整整一勺耐心。"},"ICON-1432":{"nm":"小卡相纸","de":"这一张会冲印出怎样的表情，在印出之前都是秘密。即将成为某人本命的面孔，正诞生于此。一张小小的纸，竟能怀抱那样大的心意。"},"ICON-1433":{"nm":"小卡卡套","de":"小卡是不徒手碰的。边角一旦压到，连那天的笑容都会跟着发疼。用一张透明将本命好生包裹——珍惜，也要花上这般心思。"},"ICON-1434":{"nm":"硬卡夹","de":"夹进两张硬板之间，连时间也无法随意将它揉皱。别弯了，别折了。守护珍贵之物的事，总要借来一层坚硬。"},"ICON-1435":{"nm":"贴纸包","de":"一张张撕下，贴在日记本的边角、笔记本电脑的背面。仅凭一幅小小的图，无彩的一天便被染得五彩斑斓。想要装点身边的心，本就不分年龄。"},"ICON-1436":{"nm":"签字笔","de":"墨水沙沙擦过纸面的声响里，队伍越排越长。颤抖着伸出的专辑上，短短几秒的相遇却长久留存。心意顺着笔尖渡了过去。"},"ICON-1437":{"nm":"签名专辑","de":"翻开封面，熟悉曲线的签名先来打招呼。因音乐结缘的关系，在纸上又靠近了一寸。所谓珍藏，便是把那个瞬间静静停驻。"},"ICON-1438":{"nm":"应援棒电池","de":"「灯亮起来吧，求你了。」入场前换电池的手忙个不停。在万千光点之中别让我那一束熄灭——一节小小电池，把那个偌大的夜照得通明。"},"ICON-1439":{"nm":"应援棒收纳袋","de":"不留一道划痕，妥帖收好，连同下一夜的呐喊一并珍藏。哪怕炽热的那一处都已凉透，也珍重地装好带回家。应援的器具也有它的位置，更有惦记那位置的心。"},"ICON-1440":{"nm":"应援横幅","de":"写在长布上的句子，横越观众席铺展开来。说不出口的应援豁然展开的瞬间，一个人的真心便成了所有人的呐喊。那块布原原本本化作了声音。"},"ICON-1441":{"nm":"迷你横幅","de":"正好握进掌心的小小应援。远处挂着的横幅是大家的，可这一面只在你桌角飘扬。小，不代表心也小，它静静摇曳着证明这一点。"},"ICON-1442":{"nm":"粉丝信","de":"收信人的名字改写了三遍，第一句删了七回。封口前指尖发颤，是因为心意太过坦诚。比一张邮票更重的真心，折叠在那里面。"},"ICON-1443":{"nm":"礼物包装纸","de":"拆开前那一秒最令人雀跃，包装纸比谁都清楚。明知自己即将被撕开，却也仿照赠予者的心意，以最美的纹理裹住自身。"},"ICON-1444":{"nm":"丝带","de":"系得太紧会憋闷，太松又会散开，恰好找准那中间，便是心意。指尖挑出的一个结里，盛着心的形状。礼物的最后一行，总由丝带替你写下。"},"ICON-1445":{"nm":"感谢卡","de":"口头说的谢谢会随风散去，亲手写下却能久久停留。把收到的温柔再多添一些回赠出去。一笔一画地写下的过程里，心意深了一倍。"},"ICON-1446":{"nm":"便当券","de":"凭这一张纸，午餐的担忧便悠悠化开。刚做好的米饭热气腾腾，菜格格填满的一顿饭已有约定。是守护饥饿午后的小小护身符。"},"ICON-1447":{"nm":"零食券","de":"为了在下午三点、嘴馋稍稍发来信号时取出而生。一份小甜食便让心情上扬半寸，这张券深谙此道。虽不是大奖赏，却在最需要的瞬间悄然送达。"},"ICON-1448":{"nm":"咖啡券","de":"一杯温热与一个窗边座位，这张券承诺的便是这些。看似不起眼，对某人却成了撑过一天的小小奖赏。是香气先一步抵达的温柔邀请函。"},"ICON-1449":{"nm":"宿舍清扫券","de":"敞开窗户，把被子抖得啪啪响，连一粒灰尘都逃个精光的一天。不必亲手去做竟是这般享受。房间一闪亮，连心也悄悄整理妥帖。"},"ICON-1450":{"nm":"维修工具包","de":"螺丝刀加胶带，再加几个来历不明的零件。凑齐了仿佛没什么修不好，可一打开却总缺那么一样。即便如此，握在手里仍莫名变得底气十足的自信箱。"},"ICON-1451":{"nm":"幸运票","de":"没有座位也没有数字的一张空白票。今天会有什么好事到来并未写明，这才是关键。填满那块空白，是揣它在口袋里之人的事。"},"ICON-1452":{"nm":"骰子","de":"最懂公平这个词的朋友。不偏袒任何一方，平等地爱着六个面。在离开掌心咕噜噜滚动的那一刻，连实力与人脉都暂且把位置让给了运气。"},"ICON-1453":{"nm":"移动券","de":"从这里到那里，一步便够，如此的约定。把远路小小折起放进口袋的魔法般的纸。在犹豫是否启程的日子，再没有比它更好的借口拦截器。"},"ICON-1454":{"nm":"再挑战券","de":"不是向跌倒的人伸出手，而是静静推一把背、叫他再试一次的票。它最安静地告诉你，失败不是终点，只是片刻的逗号。再来一次的勇气，便从这里充盈。"},"ICON-1455":{"nm":"快速完成券","de":"稍稍跳过等待的温柔作弊码。三分钟都等不及的心，谁又能责怪。用手指轻轻把沙漏的沙一推到底——这里有一点像犯规的乐趣。"},"ICON-1456":{"nm":"生产加速器","de":"同一双手、同样的时间，成果却翻了一倍。仿佛在说别问诀窍，它在工作台上嗡嗡欢快地转着。是为勤恳忙碌的双手轻轻装上翅膀的小装置。"},"ICON-1457":{"nm":"亲密度糖果","de":"言语难以化解的尴尬，在甜食面前也会悠悠融化。一起拆吃的一颗糖，便让彼此比昨天近了一寸。甜，竟就是变亲近的速度，这是个可爱的发现。"},"ICON-1458":{"nm":"心情恢复软糖","de":"伤心的日子，冰凉软弹的最管用。咬上一口，阴霾的表情便悄悄舒展开来。修复心情本就是稀罕的事，R级可不是白挂的。"},"ICON-1459":{"nm":"闪光粉","de":"在平凡之物上稍稍一撒，便骤然变得特别。明明只是闪亮的粉，沾上的瞬间世界却显得更雀跃几分，真是奇妙。是日常里啪地一点的幸福调料。"},"ICON-1460":{"nm":"舞台胶带","de":"一站上舞台，无数灯光便齐齐找到你。那个位置，由地上一个小小的X字无声标出。在看不见之处最精准的东西，终究撑起了最大的舞台。"},"ICON-1461":{"nm":"扎线带","de":"把缠乱的线一举理得整整齐齐的小英雄。一旦扎紧便无法复原，既是缺点也是魅力。对整洁认真的人，会悄悄备好的必需品。"},"ICON-1462":{"nm":"备用线缆","de":"有它时毫无存在感，没它时才终于令人渴求的东西。在舞台后方的包底沉睡，在关键一刻倏地醒来。它以身证明了未雨绸缪这个词。"},"ICON-1463":{"nm":"彩排检查表","de":"从走位、提示，到换装，一格格写得密密麻麻的纸。这里哪怕空了一个勾，便有谁的心倏地一沉。完美的舞台，唯有在这张表填满之后才终于拉开帷幕。"},"ICON-1464":{"nm":"片场指示牌","de":"这里是咖啡馆，那里是小巷，顺着箭头走便是截然不同的世界。明明是画在合板上的谎言，在镜头前却成了真的。是把毕生都献给指引方向的诚实向导。"},"ICON-1465":{"nm":"迷你奖杯","de":"接到手的瞬间，仿佛个头莫名长高了一寸的一块金光。它在桌上闪耀着说：不是第一名也真的没关系，今天你的努力它全都明白。小小奖赏递来的大大慰藉。"},"ICON-1466":{"nm":"背包","de":"背上的瞬间，仿佛去哪里都行。里面装的虽没什么，可能性却满满当当。冒险，总从把这肩带牢牢系紧的事开始。"},"ICON-1467":{"nm":"指南针","de":"迷了路也不慌张，是因为针尖永远指向北方。颤了好一阵才终于找回原位的模样，简直像人的心。它以颤动的针尖告诉你：迷路也没关系。"},"ICON-1468":{"nm":"笔记本","de":"第一页永远空白。要写什么，只有握笔的人知道。我只是等待着，等今天的念头化作字迹，静静落在我身上。R级，便是即将被填满的可能性的分量。"},"ICON-1469":{"nm":"铅笔","de":"写错了也没关系，这是这件工具最温柔的一面。只要橡皮朋友在旁，便能一次次重新开始。越削越短，可短了多少，便是被爱了多久的证据。"},"ICON-1470":{"nm":"胶卷","de":"光通过的瞬间，那一天的颜色便原原本本印了进去。一格过去便再也无法挽回，这是紧张也是魅力。是在飞快的时代里，刻意慢上一拍去记忆的人的选择。"},"ICON-1471":{"nm":"拍立得相机","de":"咔嚓，然后片刻等待。握在手中轻轻一晃，模糊的瞬间便渐渐清晰。把此时此地原样定格在一张纸上，是台有点像魔法的机器。"},"ICON-1472":{"nm":"旧照片","de":"颜色褪了多少，便意味着时间流过了多少。边角磨损的每一处，都曾停留过某人的手。最旧的照片怀抱着最清晰的记忆，大概正是因为那些手的缘故。"},"ICON-1473":{"nm":"剪贴簿","de":"舍不得丢的碎片聚了又聚，便成了一本。褪色的电影票、干枯的花瓣、短短一张便条。在旁人眼里是杂物，在翻开者眼里却整个复活成一段时光。"},"ICON-1474":{"nm":"航海日志","de":"今日的风与浪，还有心绪一行。再无事的日子也照例一笔不落地记下，是航海的规矩。平安抵达的证据，总写在这厚厚记录中的某处。"},"ICON-1475":{"nm":"地图碎片","de":"明明只是整体的一角，少了它却终究找不到路。撕裂的断面与另一片严丝合缝咬合时的那份快感啊。R级，便是拼图最后一格般的存在感。"},"ICON-1476":{"nm":"瓶中信","de":"在不知谁会读到中，静静将自身交付海浪。不指望回信，只盼这份心意能触及某处。是最缓慢、却也最浪漫的寄信方式。"},"ICON-1477":{"nm":"骰子","de":"仿佛说着又是你呀，圆圆笑着的六个面。明明是同样的模样，每次滚动却都给出不同的答案，这是它一成不变的善变。离手的瞬间，把选择暂且交给命运试试。"},"ICON-1478":{"nm":"风车","de":"得有风吹，才终于活了起来。静置着不过是纸做的翅膀，可一旦有谁呼地一吹，便欢快地转起来。不以受助为耻，正是这朵小花的智慧。"},"ICON-1479":{"nm":"野餐篮","de":"掀开盖子，紫菜包饭的香气先来打招呼。青青草坪、铺开的野餐垫，还有分着吃的一双双手。这只篮子装满的日子，奇妙地总是晴空万里。"},"ICON-1480":{"nm":"花瓶","de":"哪怕只插一枝，房间的空气也会不同。空着时默默等待，便是它的本分。为让花更显光彩而静静放低自己的存在，是房间里最谦逊的舞台装置。"},"ICON-1481":{"nm":"花瓣","de":"风带走一片，春便轻了那么一点。院中老树年年送上同样的问候——飘落也是绽放的一段。飘散不是终点，而是预先寄给下一个春天的信。"},"ICON-1482":{"nm":"玫瑰","de":"先竖起刺，是别随意触碰的约定。那内里藏着最赤红的心。有人将一枝静静放在脚边，不留名字、只以颜色写下心意，便离去了。"},"ICON-1483":{"nm":"百合","de":"素净的白瓷旁，总摆着这朵白花。愿香气飘远，姿态却不凌乱。在以纯洁取代华丽的那一处，百合默默守住一席的品格。"},"ICON-1484":{"nm":"郁金香","de":"微微低着头列队而立的模样，莫名地端庄。是包揽春日花坛第一排的花。一齐绽放又一齐凋零的那份诚实，把短暂的季节染得最浓。"},"ICON-1485":{"nm":"风信子","de":"一根花茎上密密挂满了小小的钟。摇也无声，香气却替它在房中回响。在初春，以一只花瓶便将房间的空气整个换新的温柔奢侈。"},"ICON-1486":{"nm":"青蛙标本","de":"在玻璃箱里时间停驻的小小身躯。标签上写着——「水田与水库，雨后第二天最为活跃。」唯有停下之后，一只生物所栖水边的温度，才以记录留存。"},"ICON-1487":{"nm":"蜥蜴标本","de":"断尾逃生的那份机敏，即便成了标本也抹不去。是只爱晒太阳的石墙的小小访客。一旁的便条上，工整地记着它常爬上的那片向阳处的方向。"},"ICON-1488":{"nm":"鼹鼠记录","de":"穿行地底者的日记，以泥土的纹理写就。在哪里挖过、又在哪里停下，是一张看不见的路的地图。背光而活的时光，对某人而言也成了无比勤恳的记录。"},"ICON-1489":{"nm":"贝壳标本","de":"海浪打磨了千百遍才送来的坚硬纹路。滩涂的人仅凭壳的纹理，便知是哪片海的产物。曾经鲜活呼吸的那片海的模样，原原本本盛在巴掌大的标本里。"},"ICON-1490":{"nm":"珊瑚标本","de":"在大海深处历经数百年，才勉强长上一寸。看似枝杈，实则是无数微小生命共同筑起的家。越缓慢的越能久留，珊瑚以沉默证明了这一点。"},"ICON-1491":{"nm":"爱动线索","de":"散落在岛上某处的故事的一截。一张小小的纸片，静静指向下一步。所有冒险归根结底都始于拾起这般细微的痕迹，年迈的向导如是说。"},"ICON-1492":{"nm":"签名碎片","de":"散落的纹样各归其位，一个标记才终于成形。是刻着某人独有纹理的碎片。拼合之前藏起意义，拼合的瞬间才终于成为名字。"},"ICON-1493":{"nm":"舞台记忆碎片","de":"一首歌唱罢，观众席仍残留余温。把那份暖意剥下凝固，便成了这样一块小碎片。四散的掌声与呐喊的碎屑，静静聚拢，那一夜便整个复活。"},"ICON-1494":{"nm":"出道印章","de":"初次被叫到自己名字的那天，盖在手背上的那道墨痕。连小心晾干生怕晕开的那份心情，都算在起跑线里。一枚小小的印，让某个日子永不被抹去。"},"ICON-1495":{"nm":"顶级偶像奖牌","de":"唯有登上最高位之人才被许可的那份沉重。然而这奖牌之所以沉，并非因为金属。是共同填满舞台的无数双手的分量，原原本本汇聚于一点之故。"},"ICON-1496":{"nm":"小钥匙","de":"宿舍的第一把钥匙，永远是最里间那屋的。是个先学会开、再学会锁的地方。离开的那天，冰冷的铁块上，掌心留下的温度久久不散。"},"ICON-1497":{"nm":"宝箱","de":"打开之前，谁也不知里面装着什么。那份不知，才正是宝箱真正的宝物。掀起盖子的短短一瞬，谁都暂时回到孩提时的那份心跳。"},"ICON-1498":{"nm":"设计图","de":"在一格格划出的线上，住着尚未建起的楼。展开图纸，便是把明天预先走上一回。一条划得好的线，撑起不会坍塌的明天。"},"ICON-1499":{"nm":"食谱卡","de":"沾满手泽的一张卡上，奶奶的手艺以分量写就。「盐一撮」这样含糊的话，才是最精准的秘诀。字迹越模糊，熬煮那道菜的厨房便越清晰浮现。"},"ICON-1500":{"nm":"设施许可证","de":"一张纸，便把空地变成「可以使用的地方」。新建筑照例先得有村里的印章。所谓许可，归根结底是一枚温暖的印——说在这里开始些什么也无妨。"},"ICON-1501":{"nm":"港口许可证","de":"船要下锚停靠，先得有这么一张纸。港湾里那枚褪色的印章，是迎接远道来客的第一声问候。在离去与抵达之间，港口总是用一纸文书敞开心扉。"},"ICON-1502":{"nm":"入岛凭证","de":"证明你已成为这座岛家人的小小文书。旧时村落每逢有新邻搬来，便添上名字、分送热腾腾的年糕。虽只是一张纸，上面却写满了\"从今往后你也是我们的人\"那般明亮的款待。"},"ICON-1503":{"nm":"宿舍门牌","de":"门旁挂上一个名字，空房才终于成了某人的家。旧时的厢房，也总先挂上刻着主人雅号的匾额。门牌虽小，里头却满是\"这里有人住\"的暖意。"},"ICON-1504":{"nm":"应援邮票","de":"用舌尖舔湿、用力按贴的那份心意，才算得上一封完整的信。把喜欢的心情贴在小小的纸上，远远寄出。即便在数字时代，仍有人偏要亲手把心意寄出去。"},"ICON-1505":{"nm":"闪光岛徽章","de":"别在衣领上，细小的光便一路相随。在街上遇见戴着同款徽章的人，不必开口也能心意相通。这点闪光不是炫耀，而是\"我们都爱着同一座岛\"的悄声暗号。"},"ICON-1506":{"nm":"工作台","de":"布满划痕的台面，正是那双制作了最多东西的手的见证。修补、拼接、打磨的地方。比起干净的书桌，凌乱的工作台其实藏着更多故事。"},"ICON-1507":{"nm":"收纳箱","de":"越珍贵的东西，越要先给它定好位置。古人也把贵重文书单独收进梧桐木匣里。所谓妥善保管，归根结底是为未来的某人，把今天端端正正地折叠收好。"},"ICON-1508":{"nm":"资源箱","de":"充裕时存起来，匮乏时取出用。这里盛着那个仓廪殷实、心也安稳的年代的智慧。储备，是提前递给未来的自己的一顿温饱。"},"ICON-1509":{"nm":"冷藏箱","de":"填满冰块的匣子，盛夏里也能留住一份清凉。仿佛把石冰库的古老智慧，缩到了手掌大小。守住低温，便是让最新鲜的那一刻多停留些时候。"},"ICON-1510":{"nm":"水泵","de":"上下摇动把手，地底深处的水便涌了上来。要先倒进一瓢引水，水才哗哗喷涌的老实机器。先付出才有回报的道理，井边人早早就懂了。"},"ICON-1511":{"nm":"净水器","de":"浑水一层层变清流出的小小奇迹。古人在缸里层层铺上沙与炭来滤水。清澈并非凭空得来，而是慢慢滤出的一份用心。"},"ICON-1512":{"nm":"洒水壶支架","de":"洒水壶有了歇脚的地方，花圃的一天便齐整起来。给工具定个挂处，是热爱劳作之人的习惯。一处归位定了，整个院子都跟着利落了几分。"},"ICON-1513":{"nm":"钓竿支架","de":"人可以离开，钓竿却替人守着位置，直到手感传来。在河边垂钓岁月的那份等待姿态，原封不动地嵌在这里。所谓支架，归根结底是暂且放下急躁的托架。"},"ICON-1514":{"nm":"采集篮","de":"盛着一把山野菜、一朵野花归来的母亲的手提物。竹篾编织的缝隙间，悄悄渗出泥土的气息。看盛什么，空篮子既能是春天，也能是秋天。"},"ICON-1515":{"nm":"石臼","de":"咚，咚，按着均匀的节拍舂谷，村庄的一天便苏醒了。逢年过节，捣糕声便会填满巷子的器具。要把坚硬之物变柔软，得有手不停歇的节奏。"},"ICON-1516":{"nm":"砧板","de":"刀划过的每道痕迹，都刻着一餐饭的历史。布满划痕的木板，是拥有最勤快双手的厨房勋章。切东西这件事，始于想要用心款待它的那份心意。"},"ICON-1517":{"nm":"锅","de":"咕嘟咕嘟的沸腾声，比任何音乐都来得亲切。嘴馋的凌晨，等面煮熟的那3分钟，是最私密的慰藉。圆圆的锅底里，热着一份想喂饱谁的暖意。"},"ICON-1518":{"nm":"平底锅","de":"在火上一瞬间煎熟的手艺，全靠这一口锅。养得越好的锅面越不粘、越油亮。用久了的铸铁锅，本身就是厨房走过的岁月的证据。"},"ICON-1519":{"nm":"烤箱","de":"关上门等待的时间里，里头正悄悄发生着魔法。面团膨起、色泽渐熟的时光。哪怕看不见，只要信任着等待，温热的成果便会推门而出。"},"ICON-1520":{"nm":"搅拌机","de":"再坚硬的东西放进去，一瞬间也成了柔滑的一杯。不同食材交融、孕育出新味道的小小漩涡。所谓相融，归根结底是各自让出一点棱角。"},"ICON-1521":{"nm":"打蛋器","de":"手腕一转便锁住空气，搅动越快，稀软之物便挺立得越坚实。泡沫像山峰般隆起时，膨胀的不只是面糊。今天想喂饱谁的那份心意，也一同涨了起来。"},"ICON-1522":{"nm":"磨豆机","de":"抓一把豆子转动手柄，齿轮间香气便先碎开。手臂酸胀之时，粉末才终于细腻，那份辛劳让第一口愈发醇厚。用心，总是从手腕开始的。"},"ICON-1523":{"nm":"磨粉机","de":"谷粒钻进石缝间，化作白粉流出。一次磨不细也没关系，再磨上两遍便是了。把粗粝磨细也是有先后次序的，磨粉机默默地这样告诉你。"},"ICON-1524":{"nm":"锯木台","de":"原木一上台，锯子便先读懂木纹。避开木节，只顺着笔直的纹路锯，板子才不会翘。锯木这件事，归根结底是把一棵树活过的时光齐整地铺展开来。"},"ICON-1525":{"nm":"缝纫机","de":"嗒嗒——针咬住布料飞驰的声响，填满了深夜。一道缝把两幅布连成一体，舞台服装内里看不见的每一道针脚里，都密密缝着某人未眠的时光。"},"ICON-1526":{"nm":"染布台","de":"把白布浸下再捞起，起初是嫩绿，遇了空气才终于转蓝。那是蓝草要泡足三回才得的颜色。等待即是颜色——这道理，我是在这染布台前头一回学会的。"},"ICON-1527":{"nm":"摄影三脚架","de":"三条腿张开踏地的瞬间，晃动的世界便停了下来。若用手端着定会抖动的那一帧，在这三点的约定上变得清晰。想要长久地凝望什么，得先懂得停下脚步。"},"ICON-1528":{"nm":"照明灯架","de":"一根立柱上托起光，房间任何角落都成了小小的舞台。角度稍一偏转，影子便拉长，表情也活了过来。它不是抹去黑暗，而是连黑暗也温柔地安放。"},"ICON-1529":{"nm":"麦克风架","de":"调好高度的瞬间，嘴与歌之间的距离便定了。松开手，声音仍停留在原处。唯有在双手自由的舞台上，用全身去唱的歌才终于开始。"},"ICON-1530":{"nm":"谱架","de":"摊开的纸斜斜靠立，音符便齐刷刷排到演奏者的视线高度。手一挥，下一小节便至，托架也纹丝不动。某人演奏的背后，总有一个默默无言的位置。"},"ICON-1531":{"nm":"菜园","de":"翻土开出垄沟，地上便生出一行小小的约定。埋下种子的几天像没动静似的，某个清晨，嫩嫩的子叶却顶开泥土钻了上来。这是只有等待过的人才看得见的风景。"},"ICON-1532":{"nm":"沃土菜园","de":"同样的种子，在这片地里叶子却大了一倍。手指插进去，乌黑松软的土便跟到了指甲缝里。长得好这件事，归根结底是看不见的脚下默默成就的。"},"ICON-1533":{"nm":"温室","de":"玻璃天顶下，季节流转得慢上一拍。外头落了霜，里头却仍是盛夏的潮湿。为了那些怕冷的生灵，有人把阳光悄悄圈进了屋顶。"},"ICON-1534":{"nm":"香草花圃","de":"指尖拂过叶片，香气便先打了招呼。罗勒、迷迭香、薄荷——每唤一个名字，指间便沾上不同的气味。一方小小的花圃，把整个厨房都变得亲切起来。"},"ICON-1535":{"nm":"果园","de":"春天枝头是花荫，秋天是被果实压弯的重量。爬上梯子摘下一颗咬下去，整整一年攒下的阳光甜味便在口中迸开。像是树写给人的回信。"},"ICON-1536":{"nm":"菌菇原木","de":"在伐下的原木上钻孔、植入菌种，枯死的树便又培育出新的生命。几天后菌伞一簇簇冒头的清晨，在以为已是终点的地方，新的生计悄然开始了。"},"ICON-1537":{"nm":"蜂箱","de":"把耳朵凑近，里头传来低沉而勤勉的振动。数千次振翅汇聚，才勉强成就一勺香甜。往返花田一整天的辛劳，黏稠而金黄地积在这里。"},"ICON-1538":{"nm":"鸡舍","de":"天亮之前，栖在架上的家伙们便先窸窸窣窣动起来。把手伸进温暖的稻草里，能摸到一颗尚有余温的蛋。最先报晓的地方，也最先备好了早餐。"},"ICON-1539":{"nm":"牧场","de":"草香与阳光气味交织的开阔原野。围栏内慢悠悠反刍的脊背上，云影缓缓掠过。在这无需匆忙的地方，连时间也像啃草般缓缓流淌。"},"ICON-1540":{"nm":"奶酪工坊","de":"刚挤出的奶经凝固与熟成，慢慢变得坚实。在洞穴般阴凉的架子上等候几个月，白色的块体便浸出深沉的风味。奶酪，是只赐给不慌不忙的牛奶的名字。"},"ICON-1541":{"nm":"豆腐工坊","de":"黄豆泡发、磨碎、煮沸，腥气的豆浆便变得香醇。一滴卤水，散开的便聚拢成嫩豆腐，轻轻压实又成了方块。这里有一双安抚散乱之心、为它定形的手。"},"ICON-1542":{"nm":"酱缸台","de":"向阳的院子一角，矮矮的缸瓮挨挨挤挤晒着太阳。揭开盖子，陈年时光的气味扑面而来。奶奶腌下的酱味，其实是把岁月一勺勺舀来吃。"},"ICON-1543":{"nm":"碾米坊","de":"石磨咣当咣当转动，谷物便松散成粉。白色的粉尘在阳光里飘游，想做一笸箩年糕的人排着队等候。村里的喜庆日，总从这道门槛开始。"},"ICON-1544":{"nm":"面包房","de":"黄油与砂糖的香气从烤箱门缝渗出。膨起的面团烤得金黄之际，路过店前的脚步便不由得慢了下来。一块刚出炉的面包，有谁都抵挡不住的亲切。"},"ICON-1545":{"nm":"小吃摊","de":"塑料篷布随风扑啦作响，辣炒年糕的汤汁咕嘟咕嘟收着浓。一串鱼糕配一纸杯热汤的傍晚，是同时融化寒冷与饥饿的地方。是巷尾那一处小小的慰藉。"},"ICON-1546":{"nm":"西餐厨房","de":"锅被烧热，橄榄油滋滋作响。仅凭火候的拿捏，酱汁或浓稠或焦糊。在这连盘中色彩平衡都要顾及的地方，一餐饭成了精心打磨的一场演出。"},"ICON-1547":{"nm":"中餐厨房","de":"猛火之上，炒锅如起舞般翻飞旋转。火苗腾起的短暂瞬间，食材的香气被原封锁住。又快又烫，迟疑便会错过的那一口气里，藏着中餐的秘密。"},"ICON-1548":{"nm":"咖啡馆","de":"推门而入，咖啡香与轻柔的音乐先来相迎。窗边的位子，一杯渐凉的拿铁与摊开的笔记本。城市把这样的小房间藏在各处，是叫你在忙碌的一天里稍稍喘口气。"},"ICON-1549":{"nm":"甜品店","de":"玻璃橱窗里，五颜六色的蛋糕排着队等候客人。叉尖划开奶油的瞬间，嘴角先翘了起来。再难过的日子，有一块也变得能熬过去，是小小而甜蜜的处方。"},"ICON-1550":{"nm":"肉铺","de":"红色灯光下，肉顺着纹理摆得齐齐整整。一句\"今天这块好\"，刀便以精准的厚度滑下。晚餐的踏实，正是从每日守着同一处的这双手悄然开始。"},"ICON-1551":{"nm":"水产处理台","de":"凌晨的腥味与冰块的寒意交织的处理台。鱼鳞飞溅、双手冻僵，挑选最新鲜之物的眼睛却不停歇。刚从海里捞上来的东西，在这里得到了通往餐桌的路。"},"ICON-1552":{"nm":"盐田","de":"把海水圈住，余下的便交给阳光与风。等上几天水分蒸干，池底便像星星般冒出白色的结晶。一把咸味，其实是海与天慢慢合作做成的礼物。"},"ICON-1553":{"nm":"海藻晾晒架","de":"长绳上裙带菜与海带并排晾着，随风摇曳。饱含海水的它们一边风干，一边变成浓郁的深绿。阳光与海风共同酿出的、大海最朴素的味道，就挂在这里。"},"ICON-1554":{"nm":"小码头","de":"半浸在水里的木板，在脚下轻轻晃荡。是拴上一只小船刚刚好的地方。无论是远行，还是平安归来，都在这一方天地里开始，又结束。"},"ICON-1555":{"nm":"港口仓库","de":"推开被海风浸蚀的木门，渔网、桶与缆绳一直堆到天花板。要启程远航的货物，与刚抵达的货物，暂在同一屋檐下停留。是离去与归来短暂交错的中转站。"},"ICON-1556":{"nm":"灯塔","de":"夜海最漆黑之时，它才终于开始干自己的活。旋转的光束划开浓雾，告诉你\"这里有路\"。为了某人的平安归航，它是那个终究不眠的高个守望者。"},"ICON-1557":{"nm":"造船工坊","de":"立起龙骨、装上肋材，一艘船的骨架便有了模样。在锤声整日回响的院子里，尚不知水味的船，梦想着它的首航。是为了离去而先要变得坚固的地方。"},"ICON-1558":{"nm":"录音棚","de":"门一关上，外头所有声音瞬间消失。耳机那头听得见的，只有自己的呼吸与节拍。在这小小房间的静谧里，那把尽可颤抖也无妨的嗓音，才终于诞生。"},"ICON-1559":{"nm":"音乐室","de":"从门缝漏出的和声，填满了走廊。有人按着音阶，有人数着节拍。生涩的声音与成熟的声音混在一起也无妨的地方，是每一首歌迈出第一步的亲切教室。"},"ICON-1560":{"nm":"钢琴房","de":"掀开琴键盖，白键上落了薄薄一层灰。指尖触上的瞬间，满室便荡开清澈的回响。倘若有哪个夜晚独处却不觉孤单，大概都是因为这一架钢琴。"},"ICON-1561":{"nm":"练舞房","de":"脚尖一踩，地板便回推上来。四面镜子把同一个动作复制四遍的同时，身体比节拍早半拍记住了编舞。汗与喘息停留最久的房间，在这里长成的动作，会走上舞台。"},"ICON-1562":{"nm":"健身房","de":"重量不会说谎。举起多少，便分毫不差地积攒到肩上，正因爱这份诚实，人们每天清晨都来找我。在镜中慢慢刻下的不是肌肉，而是没有放弃、咬牙撑过的那些时光。"},"ICON-1563":{"nm":"瑜伽室","de":"深深吸一口气，仿佛木地板也跟着一同鼓起。这是把飞奔而来的一天慢慢折叠收好的房间，一张瑜伽垫上，谁都能回到自己呼吸的节奏。再急躁的心，到了这里也暂且放下。"},"ICON-1564":{"nm":"化妆间","de":"登台之前，人们在这里短暂地成为另一个人。镜子四周的灯泡把脸均匀地烘暖，颤抖便沾在粉扑尖上，悄悄藏进了衣领后头。是变身开始、又结束的地方。"},"ICON-1565":{"nm":"服装室","de":"舞台上一身衣裳完成之前，这里挂着的衣服要被穿上脱下数十次。别着珠针打转的人台，粉笔划出的缝份线。光鲜的背面，总留着某人的针线痕迹。"},"ICON-1566":{"nm":"电视台布景","de":"只需把摄影机照到的那一面布置得像真的就够了，我早早就学会了这点。绕到胶合板后头，只剩空荡荡的骨架。默默撑起正面华丽的，向来是那些看不见的木条。"},"ICON-1567":{"nm":"摄影棚","de":"从三个方向打光、抹去阴影，是头一条诀窍。主光照亮脸庞，辅光照亮阴影，背光照亮发梢。快门落下的刹那，一张白色背景便锁住了今天最好的那个笑容。"},"ICON-1568":{"nm":"演出厅","de":"在天顶高耸的黑暗里，我总怀着同一个约定。幕一拉开，连空荡的观众席也会像一个人那样屏住呼吸。为了第一拍落下的那一瞬，我整整一年都静静空着。"},"ICON-1569":{"nm":"粉丝见面会展位","de":"手与手之间的距离，恰好一张桌子那么宽。短短的问候、颤抖的签名、终究没能说出口的一句话，排着队经过。在这小小的格子里，长久珍藏的喜欢第一次面对面相遇。"},"ICON-1570":{"nm":"床","de":"最先接住一天结束的，向来是我。把练习压沉的双腿、留在台下的颤抖全都安抚下来，清晨便又以轻盈的脚尖重新开始。我无声地拥着你，道一声晚安。"},"ICON-1571":{"nm":"上下铺","de":"上铺与下铺之间，五级梯子连起两个人。熄灯后交换的细语，贴在天花板的夜光星星。狭小的宿舍变得最宽敞，全靠每晚在梯子上来回的那些故事。"},"ICON-1572":{"nm":"搁架","de":"看一个人在我身上摆什么，便看得见这个人。收到的信、第一座奖杯、褪色的入场券并排站成一行。我不是陈列炫耀的家具，而是把舍不得丢的记忆静静摆放的地方。"},"ICON-1573":{"nm":"书桌","de":"歌词本摊开着，擦去的痕迹上又划出新的一行。通宵堆起的纸杯，与好不容易捞到的一句旋律。把心思誊成文字这件慢活，总在这平整的台面上静静发生。"},"ICON-1574":{"nm":"椅子","de":"\"坐一会儿吧\"这句话，意外地温柔。会议拖得再长、练习拉得再久，椅背都默默接住人的重量。站得越久的人越欢迎我，这一点我心里清楚。"},"ICON-1575":{"nm":"沙发","de":"深夜把宿舍变成客厅，有我一个就够了。大家挤坐在一起看综艺，不知不觉就有一个人靠着扶手睡着了。中间那塌陷的位置，证明着这个家的暖意。"},"ICON-1576":{"nm":"餐桌","de":"围坐下来，谁都不再是上座。刚煮好的炖汤、勺子相碰的声响、今天发生的种种，都朝中间汇拢。一张圆面铺展开来，散落了一天的人也重新围坐到了一处。"},"ICON-1577":{"nm":"衣柜","de":"每逢换季，内里便倾泻出陈年的故事。舞台服装与日常便服肩并着肩，紧闭的门后，衣服们等着下一个轮次。唯有打开门，今天要穿的这一天才终于定下来。"},"ICON-1578":{"nm":"镜子","de":"夸赞也好、瑕疵也罢，我都以同样的诚实奉还。这是登台前接受最后检查的地方，人们在我面前整理表情、端正姿态。最坦诚的朋友，向来一句话也不说。"},"ICON-1579":{"nm":"梳妆台","de":"每个小抽屉里都沉睡着不同的脸。舞台用一盒、日常用一盒、舍不得用的限定款一盒。坐到镜前，便从今天要变成怎样的人出门，开始慢慢拿定主意。"},"ICON-1580":{"nm":"地毯","de":"赤脚初次触到的触感，决定了那房间的温度。围坐着吃零食、打滚的痕迹，化作绒毛留了下来。把冰凉的地板再焐暖一寸的，是在最低处工作的家具。"},"ICON-1581":{"nm":"窗帘","de":"放进多少清晨，由我来定。轻轻拉开，阳光便长长地淌进来；紧紧闭上，连赖床都变得宽容。立在窗与房之间，悄悄调节光的多少，向来是交给我的差事。"},"ICON-1582":{"nm":"灯","de":"同一个房间，随光的颜色不同，便成了全然不同的时光。黄光把傍晚拉长，白光把清晨唤得清晰。一个开关便悄悄改变一天氛围的、巴掌大的魔法师。"},"ICON-1583":{"nm":"挂钟","de":"秒针的声响，只在安静的房间里听得见。练习越深入越忘了我，蓦然抬头，窗外不知何时已是凌晨。从不责怪流逝的时间，只是默默指向下一格。"},"ICON-1584":{"nm":"花瓶","de":"花凋谢了，我也不会空着那个位置。是暂且盛放收到的心意的器皿，只要有换水的手，餐桌便明亮起来。即便空着，我也以等待某人的姿态站着。"},"ICON-1585":{"nm":"海报相框","de":"把喜欢的脸挂上墙，也是要费一番心思的。阳光照不到的位置，一颗水平恰好的钉子。玻璃里端端正正躺着的一张纸，每天清晨我一进房，便最先向我道一声问候。"},"ICON-1586":{"nm":"小卡板","de":"是按字母顺序插还是按发行顺序插，光这幸福的烦恼，便是追星的开始。空着的那一格，是还没遇见的本命的位置。一张张填满，卡板便成了我专属的小小编年史。"},"ICON-1587":{"nm":"应援棒支架","de":"电池取出，手柄朝上。连斜斜立放的角度，也自有一番门道。等待着即将到来的下一阵呐喊，应援棒就在这里熄了光，端端正正地躺下身。好好歇息，才能亮得更耀眼。"},"ICON-1588":{"nm":"奖杯架","de":"最前排摆的是最旧的那座。从小赛事的铜像到大舞台的奖杯，不按高矮，而按心意的次序排列。每次擦拭，那天台上的颤抖便又沾上了指尖。"},"ICON-1589":{"nm":"野餐篮","de":"揭开盖子，春日阳光的气味先溢了出来。紫菜包饭、保温瓶、一张野餐垫层层叠好，正备着往野外去。提着我的人的脚步，不知怎的总比平时轻快一寸。"},"ICON-1590":{"nm":"小花盆","de":"一拃宽的窗台，于我便足够。常忘了浇水也宽容相待的小小绿意。在忙碌之人书桌的一角，我每天多舒展一片叶子，静静递上今日的问候。"},"ICON-1591":{"nm":"大花盆","de":"我长高的同时，人也一同成长。占据客厅一角的宽叶承着阳光、投下绿荫时，房间里也悄悄住进了季节。这是只有没忘记浇水的人才懂的欣慰。"},"ICON-1592":{"nm":"香薰蜡烛套装","de":"点燃灯芯的瞬间，房间的空气便沉静了一层。香气缓缓弥漫，把昨日残留的疲惫焐热送走。用一簇小小的火苗，像静默的仪式般为忙碌一天的尾声画上句点。"},"ICON-1593":{"nm":"迷你冰箱","de":"深夜打开门，一罐冰凉的饮料便来迎我。嗡嗡的细小振动声，让空荡的宿舍没那么孤单。做不了大家务，可论照看嘴馋的凌晨，没有比我更在行的了。"},"ICON-1594":{"nm":"捕虫网造型头饰","de":"戴到头上的瞬间，夏日的原野便跟着落到了肩上。圆圆的网兜把阳光细细滤过，每走一步草香便轻轻摇曳。一只蜻蜓没捉到也无妨，是把整个季节整个戴上头的帽子。"},"ICON-1595":{"nm":"采集网袋","de":"挂在腰间，成了采集的伙伴。把袋口稍稍束紧，捉到的东西便不会再逃走——这是在原野上学到的头一个窍门。一只轻巧的布袋，结结实实地揽住一天的收获。"},"ICON-1596":{"nm":"昆虫观察瓶","de":"对于短暂停留的客人，透气孔最要紧，这点我懂。盖上钻出的小小气路，瓶底铺的一片草叶。观察结束后再把它放回草丛，这才算凑成完整的一套。"},"ICON-1597":{"nm":"标本针盒","de":"连斜插针的角度里也藏着技艺。太深会碎，太浅会晃，得把指尖的力道精细地分匀。想长久端详一段小小生命的人的用心，静静盛在这盒里。"},"ICON-1598":{"nm":"饲养盒盖","de":"守住内与外的界线，是我的本分。盖得太严会闷，留得太松会迷路，所以总要留下斜纹般的缝隙。守护，与囚禁分明是两回事。"},"ICON-1599":{"nm":"蝴蝶喂食碟","de":"把蘸了糖水的棉花放在中间，翅膀便聚拢过来。浅而宽，盛到小脚陷不进去的深度，是诀窍。一只碟子，静静招来阳光正好的花园里、短暂逗留便要离去的客人。"},"ICON-1600":{"nm":"诱虫灯","de":"在黑暗中淡淡点着，小小的翅膀便循光聚来。亮度要柔和，位置要离人远些。把嗡嗡作响的夏夜安抚得格外宁静的、再亲切不过的揽客人。"},"ICON-1601":{"nm":"昆虫贴纸标签","de":"六条腿配一对触角，指甲盖大小的纸里沉睡着一段小小的生涯。轻轻贴在笔记本的角上，书页之间便悄悄铺开一拃宽的草地。"},"ICON-1602":{"nm":"采集许可标牌","de":"举起捕虫网之前，大人先问的话。捉到几只为止，去到哪里为止。这张小小的标牌，在雀跃的好奇与该守的约定之间，亲切地划上一道线。"},"ICON-1603":{"nm":"鱼饵盒","de":"揭开盖子，腥气而清凉的凌晨气息便升了上来。招来鱼的或许不是鱼饵，而是那颗肯静静等到浮标晃动为止的心。"},"ICON-1604":{"nm":"浮标收纳盒","de":"五颜六色的浮标一格格躺着安睡的小衣柜。有的是平静湖面的清晨，有的是湍急水流的正午。为水的每一种表情，都细细叠好相称的伴。"},"ICON-1605":{"nm":"钓线绕线器","de":"松开的线，切莫缠到手指上。在这圆形的工具上一圈圈绕回，纠结也会悄悄解开。与把松垮的一天重新理顺的手势，颇为相似。"},"ICON-1606":{"nm":"取钩器","de":"只有曾徒手取钩、被扎得生疼的人，才认得出这件工具。对小小的生命、对我的指尖，都少几分疼痛的路。体贴，总是从这样细微的末梢开始。"},"ICON-1607":{"nm":"挖贝铲套","de":"包裹刚从滩涂挖出的铲刃的一层套。为了不让泥与咸水蚀坏刃口，在大海与工具之间，轻轻垫上一段薄而柔软的歇息。"},"ICON-1608":{"nm":"潮汐表卡","de":"水何时涨、何时退，一张巴掌大的卡片静静告知。月亮与大海立下的古老约定，被人接抄下来的一页小小日历。"},"ICON-1609":{"nm":"鱼缸清洁刷","de":"把玻璃壁上附的绿苔轻轻刷去，光便又渗进水中那个小小的世界。让某人的一天变清亮这件事，大抵都这样静静流过。"},"ICON-1610":{"nm":"水族温度芯片","de":"一个数字闪了闪，停在适宜的度数上，鱼儿便终于安了心。不太冷也不太热的一格暖意。照料，连看不见的地方也能触及。"},"ICON-1611":{"nm":"海洋生物观察筒","de":"透明的筒里短暂停留的小客人。静静数一数它的背鳍，再把它送回大海。所谓观察，不是占有，而是暂且借看一回。"},"ICON-1612":{"nm":"化石刷","de":"唤醒沉睡数千万年的石头纹理的，不是锤子，而是柔软的刷尖。在一急便会碎裂的时间面前，谨慎成了最深的敬意。"},"ICON-1613":{"nm":"发掘笔帽","de":"刷尖一旦干透，泥土也落不利落。一顶小小的帽子，湿润地守护着刷子的气息。珍惜工具的手，迈出发掘的第一步。"},"ICON-1614":{"nm":"地层样本板","de":"一拃厚的泥土里，数百年层层叠着。静静舀盛到这块板上，先前看不见的时间纹路便划出线条，缓缓浮现。"},"ICON-1615":{"nm":"骨片托盘","de":"把散落的碎片一格格放好，曾随风四散的一段生涯，便慢慢摸索着找回自己的位置。所谓复原，是亲切地重新追问那遗失的次序。"},"ICON-1616":{"nm":"修复粘带","de":"连起破裂之处的一道细线。不刻意藏起伤痕，而是亲切地将它拥住、扶稳。它静静证明着：碎过的东西，也能重归完整。"},"ICON-1617":{"nm":"展品名牌罩","de":"为了让玻璃那头的名牌不褪色，轻轻盖上的一张罩。盼着\"是谁、从何处活来\"那短短一句，直到遥远的日后仍能清晰读出，这份心意藏在其中。"},"ICON-1618":{"nm":"库房标签","de":"未曾走到灯光下的珍宝沉睡的深房。里头的每一件，都挂着小小的名牌。哪怕不站在明亮处，也绝不会被遗忘。"},"ICON-1619":{"nm":"博物馆捐赠信封","de":"有人把毕生收藏的东西默默递了过来。这信封里装的不是物件，而是长久珍藏的一颗心。分享，化作留存最久的展览，照亮着某个人。"},"ICON-1620":{"nm":"标本编号芯片","de":"在采集到的那个地方，静静编上一个小小的数字。何时，在何处初次相遇。没记下的发现，转眼便像晨雾般散去。"},"ICON-1621":{"nm":"流星碎片瓶","de":"划破夜空坠落的碎片，被关进了玻璃瓶里。来不及许愿便消逝的那一缕光，如今在手中静静地重新闪烁。"},"ICON-1622":{"nm":"贝壳风铃绳","de":"把在海边一颗颗捡来的贝壳穿到线上，挂在屋檐下。每当风吹过，便叮叮当当，那年夏天的大海，便静静跟着进了屋。"},"ICON-1623":{"nm":"彩虹水珠","de":"雨过天晴后，叶尖上滴溜溜凝起的一颗水珠。那圆圆的里头，盛着整片天空与七种颜色。最小的东西，有时也能容纳最辽阔的风景。"},"ICON-1624":{"nm":"雾气采集瓶","de":"把凌晨山脚的雾装满了一瓶带回来。握在手里，凉丝丝、白蒙蒙的。是想把抓不住的东西暂留身边的、亲切而微小的一点贪心。"},"ICON-1625":{"nm":"接露杯","de":"接住草叶整夜一滴滴攒下的露水的小小杯子。虽连一口都不足，可清晨里最清澈、最干净的那一部分，正静静积在那里。"},"ICON-1626":{"nm":"风纹丝带发夹","de":"照着风掠过的纹路系成的丝带。别在头上，每走一步便有微风轻轻悠悠相随。把春日的轻盈，静静系在了一枚发夹上。"},"ICON-1627":{"nm":"海浪声胶囊","de":"静静凑到耳边，远海的浪便涌了过来。儿时收进海螺壳里的那个声音，仿佛被人珍重地封进了这小小的一颗里。"},"ICON-1628":{"nm":"沙星碎片","de":"在夜晚的海滩抓一把沙，里头便掺着星屑闪着光。是从天上落下的，还是被海浪细细磨成的，谁也不愿特意去问。"},"ICON-1629":{"nm":"海岛天气记录芯片","de":"岛上的天空，一天也要变好几次心思。把晴、雾、阵雨一一记进小小的芯片里，昨日的天空今天便又能重新翻看。"},"ICON-1630":{"nm":"悬崖阶梯套件","de":"供人上下陡坡的一级，又一级。把散落的部件拼起来，悬崖也成了悠然的散步道。所谓开路，是为某人的下一步预先铺好。"},"ICON-1631":{"nm":"土路纹理卷","de":"原样拓下柔软土路纹理的卷轴。唰地一展开，一条叫人想赤脚走的乡间小径，便静静铺到了脚下。"},"ICON-1632":{"nm":"石路纹理芯片","de":"铺满旧巷的石板纹样，原封不动地收进了小小的芯片里。每踏一步便嗒嗒作响，古老村落的脚步声，从脚尖复活。"},"ICON-1633":{"nm":"海滩栅栏段","de":"为不让浪头漫过而立在沙滩上的矮栅栏，那一段。在大海与沙地之间亲切地划一道线、站立着的、小小而默默的界守。"},"ICON-1634":{"nm":"草坪修复贴片","de":"在被踩得光秃的地方轻轻覆上的一片绿。不出几日，草便彼此牵起手，填补空缺。大自然向来懂得自我愈合之法。"},"ICON-1635":{"nm":"水路标识桩","de":"预先指明水该流往何处的木桩。为让雨水不至迷路，钉在地里的小小路标，即便雨天也默默站立着。"},"ICON-1636":{"nm":"小桥部件","de":"连起小溪两岸的小桥的一段部件。这头与那头之间，随时都能过去的约定，从这一小段部件里静静开始。"},"ICON-1637":{"nm":"瞭望台栏杆帽","de":"岛上最高处，包覆那栏杆末端的一点收尾。为眺望远方而聚来的人们最常触碰的地方，被它静静托着、守着。"},"ICON-1638":{"nm":"篝火底座","de":"在架上柴火之前，托住火星不让它四散的位置。在它之上仰望星空、絮絮谈心的那些夜晚，长久而温暖地燃烧着。"},"ICON-1639":{"nm":"墙纸样本卷","de":"房间的氛围，从一面墙开始。展开小小的卷轴挑选颜色，便是预先静静描画往后想过怎样的日子。"},"ICON-1640":{"nm":"地板材料样本芯片","de":"用指尖先掂量赤脚将触到的地板触感。是暖是凉，往后日子的那份温馨，静静系在这一小片芯片上。"},"ICON-1641":{"nm":"天花板挂钩套装","de":"在横梁上挂起一只钩子的瞬间，空荡的天花板便成了等待某物的位置。挂风铃呢，还是挂花盆呢。所挂之物的重量由这小小铁钩承住，挂什么却由住的人的心来定。"},"ICON-1642":{"nm":"窗户遮光膜","de":"正午的光太过坦诚，便给窗蒙上薄薄一层膜。阳光照旧透进来，棱角却柔和地化开，房里万物都温润成了杏色。这不是遮挡，而是让光亲切地晕染开来。"},"ICON-1643":{"nm":"门铃盖","de":"说是客人按的门铃也得有件衣裳，有人便给它扣上了圆圆的盖子。挡雨、挡尘，更重要的是，它是最先递上\"这里有人住\"那句问候的、小小圆圆的嘴。"},"ICON-1644":{"nm":"留言簿支架","de":"为让每位来客留名而立的托架。墨迹未干前，笔尖便淌出一行问候。来过的脚步一行行积起，空白的本子不知不觉便成了这个家最厚的相册。"},"ICON-1645":{"nm":"家具定位钉","de":"书桌的位置挪还是不挪，犹豫不决间，一枚钉子便咚地钉进地里替你定夺。静静扣住家具脚尖的小小钉子。位置一旦定下便会生出情分，木地板静静点头应和。"},"ICON-1646":{"nm":"收纳标签框","de":"什么放在哪里，抽屉终究开不了口。于是在方框里嵌上名牌，让它代为发声。一张标签一落定，杂乱的一格格便找回了自己的名字，沉静下来。"},"ICON-1647":{"nm":"室内香薰扩香棒","de":"棒尖蘸湿的香气缓缓向上弥漫。一会儿是薰衣草，一会儿是雨后的草地。如细线般无形的气味为房间换上新空气时，归来之人肩上一天的疲惫便缓缓松开。"},"ICON-1648":{"nm":"种子袋夹","de":"春天买下却没能种完的种子，连袋用夹子结结实实夹好。哪怕漏出一粒，下一个季节便少了一行。小小的扣合里，明年的菜园整个沉睡着。"},"ICON-1649":{"nm":"育苗盘","de":"一格格填上土，做成幼苗的第一间房。一孔一个生命，排成行一同生长的新生们。探头去看，绿意挨挨挤挤地点名的清晨，便在育苗盘上每天重新开始。"},"ICON-1650":{"nm":"浇水提示插牌","de":"\"我渴了。\"花盆不会说话，便由小小的牌子插在土里替它发信号。颜色一变，就是浇水的时候。植物与人之间最小的翻译，全在这一拃长的小棒里。"},"ICON-1651":{"nm":"作物支架绑绳","de":"怕长高的茎被自己的重量压得摇摇晃晃，便用柔软的绳子轻轻把它系在支架上。绑得太紧会喘不过气，绑得太松又会倒下，所以系绳的手需要恰到好处的温柔。连成长也需要有人相伴。"},"ICON-1652":{"nm":"防虫网","de":"对着嫩叶虎视眈眈的小嘴，被细密编织的网静静地挡在外面。让风和阳光通过，只把伤害挡开的隐形守门人。菜园之所以平和，全靠这密密网眼的体贴。"},"ICON-1653":{"nm":"光照测量卡","de":"今天晒到了多少阳光，立一张卡在花坛里静静地问它。颜色变得多深，就是今天接收的光量。喜欢向阳的孩子和习惯阴凉的孩子，各自的位置就由这张小纸片来划分。"},"ICON-1654":{"nm":"土壤酸度试纸","de":"把试纸贴到土上，从粉红到湛蓝，大地用颜色坦白自己的心事。不太酸也不太碱的地方，根才能呼吸得最舒坦。原本看不见的土壤心思，被一格格读了出来。"},"ICON-1655":{"nm":"收获篮标签","de":"今天摘来的是生菜还是圣女果，给每个篮子挂上名牌。在掺杂着泥土香与青草气的收获清晨，贴上标签的那一刻，那个篮子便成了通往餐桌之路的第一块里程碑。"},"ICON-1656":{"nm":"种子保存瓶","de":"把今年收下的种子装进玻璃瓶，寄给下一个春天。盖上盖子，时间便暂时停住，小小的颗粒在黑暗中等待属于自己的那一刻。这是一只跨越一季、传递心意的信瓶。"},"ICON-1657":{"nm":"嫁接胶带","de":"把切下的枝与新枝对齐，用胶带缠绕一圈，两者便渐渐合为一体。在断裂处重新流动的汁液，慢慢愈合的伤口。所谓拼接，归根结底是彼此接纳对方的纹理。"},"ICON-1658":{"nm":"修枝剪刀套","de":"给锋利的剪刀尖戴上一顶小帽子。在修剪枝条的手歇息的时候，让刀刃不变钝、让手不受伤。菜园说，完成工作的工具也需要睡衣，于是细心地把器具哄睡。"},"ICON-1659":{"nm":"花籽分类盒","de":"凤仙花、半枝莲、紫茉莉——名字与颜色各不相同的种子，在每一格里得到自己的房间。混在一起，春天就分不清谁是谁了。盒中的小隔板，提前画好了那座尚未绽放的花园的设计图。"},"ICON-1660":{"nm":"花盆托盘轮","de":"再重的花盆，装上四只轮子也能跟着阳光出门串门。清晨在东边窗台，正午挪到阴凉处。被重量钉在原地的那抹绿色，咕噜噜地，整日追着光寻找最好的位置。"},"ICON-1661":{"nm":"藤蔓引导绳","de":"不知去向、在空中摸索的卷须，被绳子悄悄引向正确的路。向上，再向上。只要替它定好攀附之处，植物便神奇地抓住那只手。原来连成长也需要一位引路人。"},"ICON-1662":{"nm":"花语卡夹","de":"插在花旁的卡片上，写着那朵花想要传达的话。绣球是真心，雏菊是纯洁。为了让漫步花坛成为一场读信的散步，小小的卡夹静静借给了无言之花一张嘴。"},"ICON-1663":{"nm":"花园牌套","de":"怕风雨把字迹晕开，给花园的牌子戴上一顶透明的帽子。\"这里是番茄\"、\"这里是罗勒\"。差点模糊的名字清晰地留了下来，菜园即便过了一年，也一个都不会忘记自家的成员。"},"ICON-1664":{"nm":"肥料勺","de":"给土壤添养分时，贪心反而会烫伤根。所以一勺，恰好那么多。小勺舀起适量，告诉你——会养育的心，总是来自懂得适度的指尖。"},"ICON-1665":{"nm":"水滴喷头","de":"拧动喷头，水流便如薄雾般散落而下。曾被湍急水柱冲刷的嫩叶，在露珠般的水滴下轻轻抬起头来。同样的水，因为给的方式不同，便成了截然不同的问候。"},"ICON-1666":{"nm":"喂食量杯","de":"一杯，两杯。把朋友的一餐，用心意而非目测来量。太多会剩下，太少又会失落，所以要细细斟酌出刚刚好的分量。爱，有时就这样以计量的模样到来。"},"ICON-1667":{"nm":"梳毛梳套","de":"换毛的季节，缠在梳子上柔软的绒毛被套子细心地包好。给梳完毛的梳子戴上帽子，第二天也是松软的开始。共同生活的家人那身光泽，就在这样的小小整理中悄悄生长。"},"ICON-1668":{"nm":"指甲剪套","de":"给锋利的指甲剪尖端套上小盖子。让完成护理的工具，不去划伤抽屉里的其他物件。在照料的时光结束后，把器具哄好放回——这才是关怀转完的一整圈。"},"ICON-1669":{"nm":"项圈装饰片","de":"在项圈上挂一枚闪亮的小片，平日走惯的散步路便多了几分特别。在阳光下滴溜溜发光的小装饰。虽不华丽，但用来表明这孩子是某人深爱的家人，已然足够。"},"ICON-1670":{"nm":"动物健康卡","de":"今天吃得好不好，哪里有没有不舒服。把同住朋友的一天，一行行写进卡里。不会说话的家人那身状态若以字迹留存，照料的心也会随之变得细致又踏实。"},"ICON-1671":{"nm":"睡窝垫套","de":"给睡窝的垫子换上松软的新衣。脱下因翻滚蹭磨而磨旧的布料，飘来阵阵晒过太阳的绒毛香。把躺得最勤的地方收拾得最干净，正是为同住家人付出的每日心意。"},"ICON-1672":{"nm":"小围栏插针","de":"在花坛边缘咚咚插上小针，立起一道矮矮的围栏。这不是别越界的恐吓，而是\"到这儿为止才是花的地盘\"的温柔界限。有了守护的线，里面的一切才能安心生长。"},"ICON-1673":{"nm":"亲近零食罐","de":"再怕生的孩子，听到摇晃这只罐子的声音也会竖起耳朵。里面装着一把能打开心扉的零食。比起言语，靠近彼此时小小的约定更快——叮当作响的声音先一步走了过去。"},"ICON-1674":{"nm":"散步记录牌","de":"今天走了哪条路、走了多远，像打结一样把记录系在牌子上。脚印聚起来便成地图，地图聚起来便成回忆。一同走过的每一天，都在这枚小小的标牌上一层层累积。"},"ICON-1675":{"nm":"鸟食碟","de":"在窗台放一只碟子，撒上几粒小米，便有不知名的客人接连飞来。咄咄啄食的声音，扑棱扑棱的振翅。施予的那一把，每天清晨都带来一场小小的音乐会，是一张小巧的餐桌。"},"ICON-1676":{"nm":"松鼠观察筒","de":"在透明的筒里，与松鼠圆溜溜的眼睛对上了视线。腮帮塞满橡子、歪着头打量的模样，可真是。在看一会儿就放它走的约定之上，与小小的野性互道一声短短的问候。"},"ICON-1677":{"nm":"脚印石膏模","de":"倒入软软的石膏，拓下小小的脚印。等待凝固的工夫，院子里的时间也暂时停住。那一寸长大后便会消失的脚印，被白色的模具如永恒般拓起，轻轻交到两手之中。"},"ICON-1678":{"nm":"夜视观察镜头盖","de":"给凝望黑夜的镜头尖端盖上小盖子。让看过星星与鸟巢的玻璃片，一尘不染地等待下一个夜晚。能将黑暗看清的眼睛，也需要白日里的一个逗号。"},"ICON-1679":{"nm":"鸟巢保护标识","de":"在树枝间发现鸟巢时，不是凑近，而是立起一块标识。\"这里有鸟一家，请安静。\"守望却不侵犯的距离——退后那温柔的一步，最能护鸟巢周全。"},"ICON-1680":{"nm":"动物声音录音片","de":"草丛里的歌、屋檐下的啁啾、夜里的虫鸣，不去囚禁，而是暂时借存进芯片里。重新播放，连那一刻的空气都会复苏的小小声音盒。让听过的一切，都不再消逝。"},"ICON-1681":{"nm":"观察望远镜套","de":"在一只鸟即将振翅而起的前一刻，森林暂时屏住了呼吸。在那寂静的瞬间，盖住镜头的一块布，护住了远方的那份清晰，不让一丝指痕沾上。"},"ICON-1682":{"nm":"林间相机背带","de":"每当攀上陡峭的山路，相机便一下下轻碰胸口。怦怦的心跳与快门声以同一拍子摇晃着，而这一条带子，把那些瞬间稳稳地系在胸前。"},"ICON-1683":{"nm":"自然解说卡","de":"卡片静静地告诉你，连一棵草也有自己的名字。当原本擦肩而过的事物有了称呼，山路便忽然热闹起来，挤满了一张张亲切的熟面孔。"},"ICON-1684":{"nm":"桅杆修补贴","de":"用全身承受风的帆布，也会留下伤痕。只需一块小布静静地补在撕裂处，帆便重新获得了拥抱远海的资格。"},"ICON-1685":{"nm":"绳结练习板","de":"向上，向下，再绕一圈——手记住的那道顺序便成了绳结。在风暴敲打甲板的夜里，那一道程序把人与船紧紧系在一处。"},"ICON-1686":{"nm":"锚链保护套","de":"别小看这顶套在铁链端头的小帽子。锈会在暗处悄悄滋长，而一只背对海风、挡在前头的套子，便默默延长了锚的寿命。"},"ICON-1687":{"nm":"航路标识旗","de":"雾浓得前路尽失的日子，一面旗帜替你指明了方向。在风中翻飞的那一点色彩，终于让迷途舵手僵硬的肩膀松弛下来。"},"ICON-1688":{"nm":"船舱钥匙环","de":"在摇晃的海上，狭窄的船舱门上挂着一只小小的环。只要钥匙守在原处，便总有一间可归的房，不曾为你而上锁。"},"ICON-1689":{"nm":"防水地图套","de":"在雨中，纸质地图会率先抹去路。当一张图在透明的套子里干爽地坚持着，湿透的旅程也终究不会迷失方向。"},"ICON-1690":{"nm":"船灯灯芯","de":"灯芯缓缓吸起的油，终于绽放为一簇火焰。甲板上的一点光，仅凭那小小一颤，便让夜海那遥远的距离悄悄拉近。"},"ICON-1691":{"nm":"遇险信号布","de":"在声音够不到的距离，高高挥动红布的手，比言语传得更远。这一幅布划破长风，替你呐喊：这里还有人活着。"},"ICON-1692":{"nm":"海风方向针","de":"知道风从何处吹来的人，才能定下航路。小小的针静静指向的一个方向，今日整整一天的航程命运，都悄悄倚靠了上来。"},"ICON-1693":{"nm":"折叠铲套","de":"把刃折叠盖好，勤快的铲子也得以稍稍喘口气。挖尽泥土的手最后做的事，便是照料明日的刃，使它不至变钝。"},"ICON-1694":{"nm":"便携指南针盒","de":"针总是毫不动摇地指向北方，而守护那根针的，是坚固的盒子。越是曾经迷过路的人，越懂得珍重地怀抱方向。"},"ICON-1695":{"nm":"露营餐具网","de":"把洗好的碗碟挂在网上，让晨光晒干。营地的一天，从水汽风干的声音里开始，那份琐碎将帐篷里填得满满当当、踏踏实实。"},"ICON-1696":{"nm":"露营许可卡","de":"这是允许在这座山里留宿一夜的许可。一张纸递到手中的瞬间，原本陌生的森林也暂且成了我这边的人，静静地接纳了小小的帐篷。"},"ICON-1697":{"nm":"探险路旗绳","de":"在每个岔路口系上旗子，归来的路便不会在黑暗中散失。先行者留下的一个小标记，悄悄推着后来者的背向前。"},"ICON-1698":{"nm":"防水火柴盒","de":"火柴只要沾上一滴水，便会永远沉默。在密封得滴水不进的盒子里，火种保持着干燥，静静地只为最寒冷的夜晚等待。"},"ICON-1699":{"nm":"便携净水滤芯","de":"再浑浊得令人犹豫的水，经过这只滤芯也会变得清澈。这是一个比解渴更先让人放下疑虑的小装置——\"可以喝\"的那份信任，本身便是一口安息。"},"ICON-1700":{"nm":"应急毯包","de":"折起来只有巴掌大，展开来却是一个人的暖意。为了让\"应急\"二字不那么沉重，毯子总在背包一角，随时准备着变暖。"},"ICON-1701":{"nm":"夜间标识手环","de":"夜幕降临的山路上，一只手腕静静地发着光。那条标明彼此位置的小小带子，把同行的人们用一根看不见的线温柔地连在一起。"},"ICON-1702":{"nm":"矿工头盔贴纸","de":"贴在头盔上的贴纸，是矿工的另一张名牌。在连光都稀罕的深井尽头，仅凭灯火映出的那一个小图案，便能欣喜地认出同伴。"},"ICON-1703":{"nm":"矿脉标记针","de":"在找到矿脉的地方，静静地插下一根针。在黑暗中独自闪亮的那一点，温柔地告诉下一个到来的人：就从这里挖起。"},"ICON-1704":{"nm":"裂缝测量尺","de":"测量墙上裂开的缝隙，是缓慢而执着的忍耐。比昨天又宽了一寸吗？尺子报出的小小数字，提前道破即将到来的崩塌。"},"ICON-1705":{"nm":"遗迹纹样拓本纸","de":"把纸贴在刻于石上的纹样上，轻轻地、一下下叩打墨包。千年前的手痕以黑色的纹理浮现而出的瞬间，拓本让逝去的时间暂时与你对坐。"},"ICON-1706":{"nm":"古钱币盒","de":"为免生锈而安睡的这一小块金属，怀抱着某个消失国度最后的声音。一枚钱币里盛着一个时代，在透明的盒中慢慢老去。"},"ICON-1707":{"nm":"水晶碎片底座","de":"把光囚于体内的水晶，也需要一处依靠。在小小的底座上静静安放的瞬间，易碎之物才终于得以完整地舒展开自己的晶莹。"},"ICON-1708":{"nm":"洞窟地图碎片","de":"撕裂的地图只肯透露一半的秘密。直到找出余下碎片的那一天为止，这一张图都将那剩下的路，在洞窟某处半遮半掩着。"},"ICON-1709":{"nm":"绳索下降扣","de":"要把身体托付给崖底，先得彻彻底底地信任这只扣。把全部重量挂在一块冰冷的铁上——所谓信赖，本就是这般沉甸甸的东西。"},"ICON-1710":{"nm":"发掘许可证","de":"一张清晰盖着\"准予掘地\"印章的纸。想唤醒埋藏之物，须先求得许可，发掘悄悄教人：要以礼相待为始。"},"ICON-1711":{"nm":"挡风包","de":"背对着风展开，狂野旷野的正中央便生出一坪的宁静。这一层之后，护住小小的火种，让疲惫的人暂歇片刻。"},"ICON-1712":{"nm":"沙暴护目镜套","de":"纵使沙子凶猛地席卷而来，视野也要守护到底。盖住护目镜的一片薄套，成了在风暴中也能睁眼前行的勇气。"},"ICON-1713":{"nm":"雨天来访托盘","de":"来访客人的鞋尖滴滴答答落着雨水。静静放在门前的一只托盘，无言地温暖接住了被淋湿而冰凉的脚尖。"},"ICON-1714":{"nm":"酷暑降温牌","de":"悄悄为正午的暑气降温的小小挂牌。挂在包上含着一份清凉，待汗珠快要沁出时，便悄悄递来一捧阴凉。"},"ICON-1715":{"nm":"寒潮暖手带","de":"在腰间绕上一圈的温暖带子。当暖手宝的热意顺着腰背蔓延时，凛冽的隆冬旷野，也变成稍稍可以忍受的地方。"},"ICON-1716":{"nm":"湿度吸收包","de":"潮湿无声无息地啃噬着物件。当箱中的小包默默吸去湿气时，珍爱之物便干爽地守住了自己的模样。"},"ICON-1717":{"nm":"泥地鞋套","de":"有些时候，纵使踩过泥泞，唯独鞋子要保持干净。这层挡泥的薄罩，让归来跨过门槛的脚步轻快了许多。"},"ICON-1718":{"nm":"海雾灯套","de":"当海雾想把灯火整个吞没时，这只套子静静聚拢起将散的光纹。即便是朦胧的拂晓，港口的那一盏灯也终究不会熄灭。"},"ICON-1719":{"nm":"落雷警示针","de":"乌云低低压下时，一根针先一步发出警告。在闪电劈下之前放低身子——在自然面前的谦逊，总是提前学好为妙。"},"ICON-1720":{"nm":"食谱书签","de":"夹在摊开的菜谱之间的小小书签。在炉火前重新摸索漏看的那一行时，母亲的手艺也在那一页一同苏醒。"},"ICON-1721":{"nm":"调料分装棒","de":"妈妈总只说\"一撮\"。目测明明不可能准确，那手艺却从未失手过。用这根棒子衡量盐量时便会明白，比计量熟成得更久的，不是估量，而是爱。"},"ICON-1722":{"nm":"发酵盖封带","de":"你知道坛子也会呼吸吗？当这条带子把盖子严严裹住，里外便慢慢开始攀谈。熬过那不急不躁的几天，等待才终于得了\"味道\"这个名字。"},"ICON-1723":{"nm":"熟成标签片","de":"把腌制的日期一笔一画写上贴好的小片。字迹渐渐模糊，里面的东西反倒愈发醇厚。佯装遗忘地记下，某天忽然又取出来看——熟成，便是这般守护着的约定。"},"ICON-1724":{"nm":"汤汁过滤网","de":"清澈的汤汁，是滤了又滤之后才得来的。看着那只留住残渣、只静静放走精华的网，便从指尖传来那句旧厨房的话：舀去之处，方能沉淀出深度。"},"ICON-1725":{"nm":"面团发酵布","de":"在面团上静静盖一块布。在那昏暗之下酵母勤勉膨胀的工夫里，第一次学会了那些在看不见处悄悄生长之物的温柔。"},"ICON-1726":{"nm":"食材处理针","de":"剖开大葱的纹理、稳稳夹住蒜瓣的小针。处理食材就像是向它递出的第一声问候，用心修整过多少，晚餐餐桌的光彩便明亮一个色调。"},"ICON-1727":{"nm":"摆盘夹","de":"盘上最后一点该摆在何处，终究由这把夹子决定。熟练的手在半空犹豫半拍的那短短一瞬，一餐便悄然化作一幅画。"},"ICON-1728":{"nm":"保温饭盒套","de":"在校门前接过的饭盒，得一直温到午休铃响。被囚在这只套子里的暖意，有着某个从凌晨便守在炉火前的人那份心意的厚度，不曾凉去。"},"ICON-1729":{"nm":"用餐邀请券","de":"\"来我家吃顿饭吧。\"还有比这更温情的话吗。没有什么隆重的承诺，只是请你坐到同一张桌前——用韩语能道出的最古老的邀请，盛在这一张券里。"},"ICON-1730":{"nm":"餐桌预约片","de":"写下名字，把座位先订下来。小小一枚片子，把空餐桌暂时系成某人的专属，与此同时，约好的那个时间便如脚步声般缓缓走近。"},"ICON-1731":{"nm":"试吃评价卡","de":"咬下一口，便神情认真地打起星来的那些脸庞。在这张卡上一笔一画写下的诚实一行，是把下一盘菜做得更美味的、最温暖的唠叨。"},"ICON-1732":{"nm":"饭盒致谢带","de":"在吃得干干净净的饭盒上绕一道带子再退还回去。连\"吃得很好\"都终究没说出口的人，也凭这一个结，替自己把没能道出的心意系着传了过去。"},"ICON-1733":{"nm":"过敏标识牌","de":"这一枚小小的牌子，静静守护着某人的餐桌。把里面放了什么一笔一画交代清楚，是连看不见之处都用心照拂的待客之道的另一个名字。"},"ICON-1734":{"nm":"味道记忆勺","de":"久久留在舌尖的那个味道，其实是那一天的风景。一勺便一下子把人带回童年的厨房，可见记忆并非藏在胃里，而是由心来舀着盛起的。"},"ICON-1735":{"nm":"今日菜单代币","de":"今天吃什么。在这世上最难的问题面前，我们每每败下阵来。咯哒一翻这枚代币，把菜单交给命运，心里反倒轻松又愉快。"},"ICON-1736":{"nm":"共用餐桌铃","de":"铃声一响，散在各房的家人便聚到一处。圆桌上那阵铃声，是把\"做好了，快来\"这句话译得最有人情味的一段译文。"},"ICON-1737":{"nm":"甜点顺序表","de":"甜的总在最后。这条不知由谁定下的约定，便由这张表替你守着。它是把味蕾的高潮一直留到甜点那一口的、小小而温情的餐桌主持人。"},"ICON-1738":{"nm":"讨价代币","de":"市场正中央，\"便宜点儿吧\"与\"这已经是亏本了\"亲热地碰撞着。这枚代币，是那番讨价还价最终在笑声里收场的、老主顾的一张收据。"},"ICON-1739":{"nm":"库存确认针","de":"静静扫过仓库货架，找到空位便插上一针。知道剩下什么、又缺了什么——持家这桩大事，总是从这琐碎的清点开始的。"},"ICON-1740":{"nm":"货架清扫刷","de":"集市散场的傍晚，扫过空荡货架的刷声低低弥漫在店里。预先擦净明日要重新填满的位置，那指尖上沾着把一天好好收尾的勤勉。"},"ICON-1741":{"nm":"今日推荐卡","de":"\"今天这个不错哦。\"老板悄悄递来的一张卡。在替犹豫不知挑什么的客人轻轻推一把肩的那番推荐里，端端正正盛着一天份的自豪。"},"ICON-1742":{"nm":"常客集章夹","de":"集满十次，就送一次。盖章格一格格填满的这只夹子，是\"常客\"二字的另一张脸，而常来，归根结底就是喜欢的意思。"},"ICON-1743":{"nm":"交换账册夹","de":"把交换与归还过的物件记录汇在一处夹起的夹子。来往得越多，账册便越厚，而那厚度，正是与邻里一同垒起的信任。"},"ICON-1744":{"nm":"售罄牌","de":"当最后一件贴上这张牌的瞬间，心里莫名地满了起来。这是向那即将奔赴某人餐桌、某个房间一角的物件道一声\"走好\"的、短短的送别。"},"ICON-1745":{"nm":"预订商品篮","de":"挂着你名牌的篮子守着货架上的一格。那预先留好的一个位置，向走进店里的你静静说一句：\"一直在等你呢。\""},"ICON-1746":{"nm":"包装台垫","de":"铺在包装台上的垫子，是忙碌手法的舞台。在纸张被折起、绳子被端端正正系好的那短短一段时间里，平凡的物件悄然变成了某人的礼物。"},"ICON-1747":{"nm":"到访约定便条","de":"\"明天来串门。\"写下一行，悄悄夹在门缝里的便条。即便彼此没能碰上面，约定也搭在一张纸上，比人先一步抵达，静静地等着。"},"ICON-1748":{"nm":"邻里礼物篮","de":"隔着院墙递过来的篮子，里头总附带一句\"做得有点多\"的托词。韩国的情谊就这样佯装宽裕、装作若无其事，悄悄越到这边来。"},"ICON-1749":{"nm":"村庄消息箱","de":"村里大大小小的消息，在这只箱子里一层层累积。谁新搬了来，哪家要办喜事，几张纸聚在一起，传递着村庄那平缓的脉搏。"},"ICON-1750":{"nm":"致谢到访印章","de":"把\"谢谢你来访\"的心意，用一枚印章狠狠按下。那一抹晕在纸上的墨痕，比\"我不会忘记\"这句话更长久地留在原处。"},"ICON-1751":{"nm":"善意称赞卡","de":"把今天某人递来的善意静静写下、再回赠回去的卡片。在特意把小小温情诉诸文字留存的村庄里，好事会不停地转啊转，又回到自己身边。"},"ICON-1752":{"nm":"道歉信封印","de":"就像红红熟透的苹果，对不起这句话，也得在充分熟成之后才能道出口。在信封上狠狠按下的这枚封印，是把那句没能说出的道歉怀抱到底的勇气印记。"},"ICON-1753":{"nm":"共同作业表","de":"把谁负责什么一格格分写清楚的一张表。独自难以承担的活儿，只要分摊上各人的名字便轻松许多——并肩干过活的人都懂。"},"ICON-1754":{"nm":"邻里喜好丝带","de":"用五彩的丝带静静标下邻里各自的喜好。把某人的喜好记在心里，是不必特意说出口的、最安静的一句告白：我珍视你。"},"ICON-1755":{"nm":"邀客门牌环","de":"用挂在门牌上的一只环，告知\"今天待客\"。虽只是巴掌大的标记，里头却挂着一颗迎接来人、敞开到底的心。"},"ICON-1756":{"nm":"庆典入场手环","de":"舍不得解下、原样戴了好几天的一条褪了色的带子。它被扣上手腕的那一刻，庆典才算开始。里头安睡着一段结束了却终究没能结束的一天。"},"ICON-1757":{"nm":"烟花票夹","de":"夜空炸开的前一刻，这只夹子里的票紧紧攥着那份悸动。为了第一朵烟花砰地绽放的那一瞬，它是攥到掌心沁汗的一个约定。"},"ICON-1758":{"nm":"赏月碟","de":"曾有过那样的夜晚，仿佛把一轮满月整个舀进了碟里。在这只碟上盛好时令鲜果与松饼，向月亮叩拜，一颗圆满的心便直抵天际。"},"ICON-1759":{"nm":"冬节手套别针","de":"在雪地里手冻得发僵，手套却总从手腕处滑脱。直到这枚别针牢牢扣在袖口上，才终于能在冬日庆典上尽情奔跑。"},"ICON-1760":{"nm":"迎春种子卡","de":"卡里沉睡的几粒种子，各自等待着春天。埋进土里便如约定般准时发芽，可见一切的开始，都源自一个又小又坚实的点。"},"ICON-1761":{"nm":"夏日海滩印章","de":"海浪在沙上狠狠盖下一枚印章，又缓缓退去。明知很快会被抹去，仍留下一个\"这里曾有人来过\"的小小标记。夏天总是这样清晰地盖印一回，便伴着咸味流走。"},"ICON-1762":{"nm":"秋收丝带","de":"捆扎谷粒的手，最后会把丝带漂亮地系好。这是一个把一年的汗水细心收束的结。即便田野日渐空荡，秋天也会以最绚丽的色彩，如晚霞般再道一声问候。"},"ICON-1763":{"nm":"纪念拍照对话框","de":"\"谢谢你来到这里。\"那句终究没能说出口的问候，在纸上圆圆地鼓胀起来。它是悄悄借给照片中凝固的沉默一段声音的、圆圆的一片心意。"},"ICON-1764":{"nm":"庆典场地图针","de":"怕你在宽阔的场地里迷路，有人咚地为你插下的一个标的。哪怕脚因农乐声先一步奔了出去，这一枚针也会把迷途的你，静静领回约好的位置。"},"ICON-1765":{"nm":"专辑母带钥匙","de":"上锁的不是唱片，而是封存其中的时间。初次录音的颤抖，最后混音的拂晓。慢慢转动钥匙，那间唯有创作者才知的房门，便吱呀一声打开。"},"ICON-1766":{"nm":"曲目单卡","de":"写在一张纸上的曲序，其实是心境的顺序。在哪里哽咽、在哪里调匀呼吸，纸早已尽数知晓。在听到第一个音之前，便先一步涌上的悸动。"},"ICON-1767":{"nm":"音源审听牌","de":"只有把同一段倒回大约一百遍的人，才会贴上这枚牌。再一次，就再听一次吧。在通过的印章旁，藏着某人疑心听到天明的那个夜晚。"},"ICON-1768":{"nm":"预购标签","de":"对一件还未问世之物，先一步许下等待的约定。标签贴上的瞬间，一个空位便以某人的名字静静预订下来。连令人雀跃的等待，也有自己的号码牌。"},"ICON-1769":{"nm":"初版封印贴纸","de":"它像极了在坛上覆一张韩纸、再用糨糊封住的旧时手法。一张要守住最初模样的纸。正因知道撕开的瞬间它便会消失，才越发久久地端详那份齐整。"},"ICON-1770":{"nm":"回归日历片","de":"日历上每多画一个圈，到那天为止剩下的夜便短一格。攥在手心的小片上，归来的日期清清楚楚。对等待的人而言，时间便是这样用手来数的。"},"ICON-1771":{"nm":"概念照内页套","de":"在下一个概念把上一个概念的色彩挤走之前，把那道纹理好好夹存的一张透明片。为了纵使季节流转也不被遗忘，它把昔日的色泽连同边角一并静静守住。"},"ICON-1772":{"nm":"预告公开代币","de":"揭开面纱的前一刻，攥在掌心的一枚小硬币。把它递出的瞬间，那锁住的第一个画面便朝世界敞开一寸。所谓公开，归根结底是谁先伸出手的事。"},"ICON-1773":{"nm":"唱片陈列托座","de":"当一只矮矮的托座把唱片轻轻托起的瞬间，平凡的一张便成了陈列台上的主角。它是默默在身后撑住光线最美角度的、温情的配角。"},"ICON-1774":{"nm":"出道展示会通行证","de":"印着\"首次为您呈现\"字样的一张通行券。从舞台后那条长长的走廊，到台下的第一阵掌声，这张通行证带你跨过\"出道\"那令人颤抖的门槛。"},"ICON-1775":{"nm":"首演走位片","de":"用脚尖静静探着贴在地上的片子。无须去看，身体也会先一步知晓的一格。当精准踏上记熟的位置，指尖的颤抖便终于化作清晰的动作。"},"ICON-1776":{"nm":"致辞卡","de":"\"这都多亏了大家\"这句寻常话，一旦用颤抖的手写下，便不再寻常。怕一激动就忘了词，于是预先写好的几行。真心，有时也要倚靠一张卡。"},"ICON-1777":{"nm":"形象拍摄预约表","de":"端端正正写着定好要站到镜头前那一天的一张纸。它是慢慢准备出最好那张脸的时间表。每填满一格空白，对镜停留的夜晚也随之拉长。"},"ICON-1778":{"nm":"粉丝俱乐部入会单","de":"把名字与心意写在同一行、羞涩递出的入场纸。喜欢这句话总是难以启齿，而这一张单子替你一笔一画地写了出来。这是决定相伴的第一份签名。"},"ICON-1779":{"nm":"出道礼检查表","de":"想着收礼之人，一件件细细核对的手。边角有没有磕坏，心意有没有落下。礼物在递出之前，便已先被爱了一回才出发。"},"ICON-1780":{"nm":"舞台收尾标识","de":"幕将落下的前一刻，放在最后一个定格姿势所停之处的标识。它不是宣告结束，而是把结束漂亮收束的一个小点。唯有好好闭合的舞台，才能开启下一场舞台。"},"ICON-1781":{"nm":"采访待场针","de":"静静守护着提问开始前那份寂静的针。在脑中挑选答案的短短沉默里，这枚小小的标记替你温柔地说一句：\"还没，马上就好。\""},"ICON-1782":{"nm":"出道纪念信封","de":"就像旧时把珍贵书信连封交到远行人手中的那份心意，这是一层好好盛放首场舞台记录的封套。多年后开启的那天，连那一日的颤抖也会哗啦一同涌出。"},"ICON-1783":{"nm":"声乐呼吸吸管","de":"用细细的管子尽头，把气息长长地、成一缕地送出去的练习。歌唱归根结底是调理好的呼吸——这根小小的吸管每天清晨静静地这样告诉你。声音之前，先有气息。"},"ICON-1784":{"nm":"节拍训练点击片","de":"嗒，嗒，嗒——世上最诚实的朋友。快了便拽住你，慢了便推你一把。把节拍刻进身体，就像与这块结实的片子展开的一场长谈。"},"ICON-1785":{"nm":"舞姿核对丝带","de":"指尖在哪里停、肩膀在哪里打开，用一条丝带静静勾勒动作的线条。勾勒得好的舞线，连观众席看不到的地方都笔直而端正。"},"ICON-1786":{"nm":"表情反馈卡","de":"据说连笑也是要学的。把眼角的角度与嘴角的高度一一记下的一张卡。镜子来不及告知的表情，便由这张卡替你温柔地点拨。"},"ICON-1787":{"nm":"说唱流程备忘","de":"\"这里稍歇一下，那里倾泻而出\"——预先画好话语水路的备忘。越快的段落，气口越要清晰。在随手写下的箭头里，一段词的节奏正鲜活地呼吸着。"},"ICON-1788":{"nm":"发声温度贴纸","de":"嗓音也有温暖的日子与冰冷的日子。把今日的状态选一种颜色贴上的小标记。一面回暖一面降温，声音每天都以略微不同的温度醒来。"},"ICON-1789":{"nm":"休息日常代币","de":"据说会好好休息也是一种本事，于是把一枚硬币交到你手里。递出它，便能毫无愧疚地暂歇片刻。对一路狂奔的人而言，停下是最有勇气的选择。"},"ICON-1790":{"nm":"成长目标针","de":"\"先朝这儿走一回看看\"而咚地插下的一根小针。看似近在咫尺却遥远，却每天朝那一边一步步生长。所谓目标，就像在远处向你招手的一个温柔约定。"},"ICON-1791":{"nm":"周评信封","de":"把一周的汗水与眼泪一层层装进一只信封递出。做得好的与遗憾的并排放在里头。开封这件事，是交给下周的自己的一道小小作业。"},"ICON-1792":{"nm":"舞台装饰零件盒","de":"闪亮舞台的背后，住着无名的零件。一颗螺丝、一只挂钩聚在一起，把天花板上的星星升起。打开盒子，满是默默撑起华丽的那些细碎心意。"},"ICON-1793":{"nm":"服装概念板","de":"把布片与颜色一块块贴上去，提前试穿那件世上还不存在的衣服。在板上先一步完成的舞台服。想象，总是比针线早一步走在前头。"},"ICON-1794":{"nm":"配色试装片","de":"同一件衣服，随着光线也会有截然不同的面孔。哪种颜色与那个人笑得最灿烂，便一片片比对着寻找。所谓相称，是长久比较之后的发现。"},"ICON-1795":{"nm":"鞋带样品板","de":"在舞台上稳稳的一步，意外地是由一根小小的鞋带来担当的。既不松脱，又不至于勒得发闷。把多种纹理排开来挑选，是来自最低处的、温情的斟酌。"},"ICON-1796":{"nm":"饰品检查信封","de":"越是闪亮之物，一道瑕疵越显得格外刺眼。把信封里的饰品对着光仔细端详的手。把细小之物看到底的那份心，守护着整场舞台。"},"ICON-1797":{"nm":"发色试染片","de":"提前给头发披上新季节的小小试样。一缕上悄悄染上的颜色，静静透露着下一个概念的第一印象。变化，总是从巴掌大的地方开始。"},"ICON-1798":{"nm":"美甲概念卡","de":"把要画在十指尖端的小图案预先定好的一张卡。为了让一个手势里也隐隐透出概念，连最微小的细节都用心赋予了故事。"},"ICON-1799":{"nm":"造型变更券","de":"\"今天要不要成为与昨天稍稍不同的我\"——让这一行成为可能的一张券。无论发型、衣着还是气质，这张券都为你打开通往全新模样的、令人雀跃的门。"},"ICON-1800":{"nm":"尺寸修改牌","de":"把要改到合身为止、需收放之处都用心记下的牌子。就像旧时一针一线为孩子改衣的手，这小小的调整，让舞台舒适了一寸。"},"ICON-1801":{"nm":"缩略草图卡","de":"一张尚未上色的画稿。在粗糙的铅笔线上，静静揣摩下一幕将流向何方。比起完成，更令人心动的永远是这未竟的第一行——安静的剪辑室如是告诉你。"},"ICON-1802":{"nm":"拍摄同意贴纸","de":"\"我出现在这里也没关系吗？\"不必开口，只把一枚圆圆的标记贴在胸前。一张小小的贴纸，在镜头与心之间立下温柔的约定。"},"ICON-1803":{"nm":"拍照墙站位针","de":"稳稳扎进墙角的一枚小针。这是事先约好谁站在哪里的位置。针插过的每一处，都有一份笑容停下脚步，定格成一张照片。"},"ICON-1804":{"nm":"选片筹码","de":"在数百张画面中只点出唯一一张的手指。放下这枚筹码的瞬间，那些被收起的表情，仿佛都只为这一张而活过。挑选这件事，总像一场安静的告别。"},"ICON-1805":{"nm":"幕后信封","de":"镜头背后发生的事都装进这里。封好封口，笑声、NG与困倦的哈欠便一同沉睡。比起正片更令人珍惜的，往往是这里面的东西。"},"ICON-1806":{"nm":"剪辑请求便条","de":"\"这里再多停1秒，音乐稍微调小一点。\"一张写满红字的便条。某人的挑剔，让影像的呼吸多了一分讲究。完成度，正是在这些细致的手笔上长成的。"},"ICON-1807":{"nm":"上传预约标签","de":"贴在明早7点会自行问世的影片上的一张小标。即便众人皆睡，唯有约定仍在清醒。提前设好的时间，从不知何为迟到。"},"ICON-1808":{"nm":"缩略框封套","de":"包裹最出彩的第一幕的封套。不让手垢与灰尘沾染，把四角整整齐齐地掩好。在展示之前，第一印象就这样被悉心守护着。"},"ICON-1809":{"nm":"影片时长筹码","de":"用来揣度今天拍下的时间有多少分钟的小筹码。长不一定就好，短也不一定就轻。懂得恰当长度的心，是剪辑的第一颗纽扣。"},"ICON-1810":{"nm":"应援口号校对表","de":"在放声呐喊之前再核对一遍的纸。哪怕一个字错位，千百人的声音便会散开。在呐喊背后，看不见的校对之手早已先行走过一趟。"},"ICON-1811":{"nm":"粉丝画收纳套","de":"某人彻夜画成的一幅画。为它腾出一座透明的家，不让它被揉皱。仿佛在说，用心画的东西也要用心去抱，才能长久——收纳套默默地拥它入怀。"},"ICON-1812":{"nm":"粉丝信分类绳","de":"把堆积如山的信件按寄信人整齐捆好的绳子。一个结，就理顺了一天份的思念。一封也不愿漏掉的手，就在这里——哪怕无法回信。"},"ICON-1813":{"nm":"周边交换预约表","de":"\"有人愿意和我交换吗？\"把忐忑的心写在纸上递出去。只因喜欢同一样东西，初次相见的两人便短暂地成了朋友。"},"ICON-1814":{"nm":"团体应援座位筹码","de":"为穿着同色衣服的人安排相邻座位的筹码。当四散的心聚到同一区域，看台便像一个巨人，开始齐声歌唱。"},"ICON-1815":{"nm":"生日广告收据","de":"把爱投上电子屏后，接过的一张收据。金额旁未曾写下的，是彻夜攒下的心意。这张纸，将作为只献给一个人的祝福之证留存下来。"},"ICON-1816":{"nm":"留言册封面","de":"包裹着众人手写字迹汇成之书的封皮。翻开来，各不相同的笔迹便以同一份心意层层叠合。外表虽端庄，内里却满是温暖的喧闹。"},"ICON-1817":{"nm":"粉丝俱乐部会员针","de":"只递给呼唤着同一个名字的人的小针。别在胸前的瞬间，孤身一人的喜欢便化作众人的约定。归属感，原来就是这样圆圆的形状。"},"ICON-1818":{"nm":"线上应援代币","de":"远隔两地的手隔着屏幕挥动的一点光。距离虽遥远，节拍却分毫不差。这是一份证明：即使在看不见的地方，应援也必定如期抵达。"},"ICON-1819":{"nm":"旧钥匙残片","de":"一块缺了齿的铁片。它曾开过哪扇门，如今已无人记得。比锁着的地方活得更久的，永远是这种失去用处的半截钥匙。"},"ICON-1820":{"nm":"密道地图","de":"画着藏在常春藤后那条路的一张旧纸。捷径只有知道的人才知道。展开它的瞬间，平凡的小岛便悄悄换上一副冒险舞台的面孔。"},"ICON-1821":{"nm":"密码解读卡","de":"把杂乱散落的字母送回原位的卡片。一行对上了，下一个秘密便招手相邀。看似解不开的结，终究也是从第一个字母开始的。"},"ICON-1822":{"nm":"封印箱绳","de":"仿佛在说\"别打开\"似的牢牢系紧的绳。结里沉睡着什么，只有系它的人知道。想解开的心与想守护的心，并排系在这一根绳上。"},"ICON-1823":{"nm":"遗迹拼图筹码","de":"从古老石壁上剥落的一小片。拼回原位时，千年前某人的手艺便在指尖复活。把散落之物聚拢起来，便是重新接续时间的事。"},"ICON-1824":{"nm":"海岛传说剪报","de":"把流传于海岛的旧故事亲手抄下的纸。是真是假并不那么重要。口耳相传而来的故事，本身便是海岛的年轮。"},"ICON-1825":{"nm":"隐藏标记石","de":"看似随意放在路旁的一块石头。只在知情人眼中，悄悄指明方向。越是想深埋的秘密，越是以最平凡的面孔站在那里。"},"ICON-1826":{"nm":"谜题信封","de":"信封外什么都没写。拆封前的这一瞬最令人心跳。在把答案握在手中之前，所有可能性都还活在信封里。"},"ICON-1827":{"nm":"侦探放大镜盖","de":"轻轻套在放大镜头上的小盖子。不查看时，让镜片静静歇息。想看清，先得好好守护——侦探很早就学会了这一点。"},"ICON-1828":{"nm":"环岛巴士票","de":"登上绕岛一圈的巴士的一张票。终点便是起点。在兜兜转转回到原处的路上，风景每一次都看得稍稍新鲜。"},"ICON-1829":{"nm":"自行车租借标签","de":"挂在租来的自行车车把上的一张标。在归还之前，被允许片刻的自由。乘风而行的时光结束时，这枚标签便悄悄收回那份约定。"},"ICON-1830":{"nm":"小船船票","de":"登上一艘小船的船票。在摇晃的甲板上，岛与岛之间近了起来。横渡水路这件事，总会一同带来些许心动与些许晕眩。"},"ICON-1831":{"nm":"货车车轮销","de":"牢牢扣住货车车轮的销子。这一小块铁，让沉重的货物滚动起来。最不起眼的零件，往往默默承受着最多的重量。"},"ICON-1832":{"nm":"缆车代币","de":"投进划过空中的缆车的圆代币。脚离开地面的瞬间，整座岛尽收眼底。升得越高，风景便越发宽容。"},"ICON-1833":{"nm":"热气球乘坐带","de":"登上吊篮前缠在手腕的带子。火焰膨胀、大地远去时，心也随之轻盈。所谓升空，便是暂时放下重量的意思。"},"ICON-1834":{"nm":"水上出租船呼叫筹码","de":"呼唤在水上奔驰的出租船的小筹码。一抬手，船便破浪而来。在没有路的地方开出路来的，终究是先开口呼唤者的勇气。"},"ICON-1835":{"nm":"登山口通行证","de":"在入山的第一道关卡接过的通行证。从这里起，由脚尖来决定路。山顶虽远，唯有通过入口的人才被许诺那片风景。"},"ICON-1836":{"nm":"港口储物柜钥匙","de":"打开码头储物柜的一把小钥匙。把行李寄存，以轻盈的手眺望大海。有一处可以暂时放下的地方，便是把远行的勇气借给了你。"},"ICON-1837":{"nm":"腌渍罐盖","de":"把酸味之物封存起来的罐盖。拧紧了，夏天的黄瓜便能把那份爽脆守到冬天。战胜时间的诀窍，说到底是从好好密封开始的。"},"ICON-1838":{"nm":"晾晒网标签","de":"贴在摊在筛子上晾晒之物上的名牌。记下什么时候晾了什么，等待便不会乱了次序。即使是阳光与风的时光，也需要个先来后到。"},"ICON-1839":{"nm":"熏制木屑袋","de":"装着香木碎屑的袋子。打开封口，篝火般的气味便先在鼻尖打了招呼。被烟熏得醇厚的滋味，只向懂得等待的人缓缓敞开。"},"ICON-1840":{"nm":"储藏食品贴纸","de":"为让食物熬过一整年而贴在坛子上的贴纸。腌制的日子与心意都写在上面。久放慢吃的食物，总会附上一张小小的便条，记着那一天的手艺。"},"ICON-1841":{"nm":"发酵时计标签","de":"发酵不信钟表。因为它不用分针，而用香气来计时。当酸味触到鼻尖，标签便静静点头\"现在好了\"。连等待，也各有各的刻度。"},"ICON-1842":{"nm":"冷藏格分类针","de":"冷藏格的小交警就在这里。蔬菜在上，小菜在下，昨天剩的放前排。插上一枚针，每次开门，原本乱找的手便不知不觉认得了路。"},"ICON-1843":{"nm":"便当保温带","de":"妈妈给便当系上了带子，怕暖意在午饭前逃走。解开带子，雾气朦胧的盖子下，清晨的心意还温温地躺着，等我。"},"ICON-1844":{"nm":"酱料熟成瓶","de":"好的调味从不着急。是静静给酱油与蒜彼此渗透的时间。在瓶中的幽暗里，滋味缓缓变深，酱缸台上慢悠悠的智慧，搬进了这只小瓶。"},"ICON-1845":{"nm":"时令果酱标签","de":"春天草莓，夏天杏子，秋天无花果。一张标签，把季节工工整整写在瓶上。寒冬里拧开盖子，往日的阳光便一勺一勺慢慢融出。"},"ICON-1846":{"nm":"收集率徽章板","de":"不必特意去数收集了多少。因为徽章板会替你炫耀。每填满一格空位，肩头便得意一耸——这不是数字，而是用脚尖一步步走来的足迹。"},"ICON-1847":{"nm":"未发现卡槽卡","de":"一处还未相遇的位置。卡中的剪影只以朦胧的轮廓递来约定。空着，便意味着即将被填满，所以心动总是以问号的形状等着你。"},"ICON-1848":{"nm":"图鉴完成印章","de":"印章\"砰\"地落在最后一格上的那声响。合上图鉴摊开手掌，一点红墨便像完成的勋章似的留在掌心。那份深深的畅快，只有集到最后的人才懂。"},"ICON-1849":{"nm":"稀有度涂色筹码","de":"即便形状相同，颜色不同故事便不同。一枚筹码，在平凡与珍贵之间静静画下一道线。收藏家的眼，总在那微妙的色泽之差前久久停驻。"},"ICON-1850":{"nm":"重复收集兑换券","de":"又出来了，又是它。第三次捡到已有之物的那天，这张兑换券悄悄伸出手来。仿佛温柔的安慰：重复的不舍弃而是珍藏，总有一天会化作珍宝归来。"},"ICON-1851":{"nm":"收藏箱编号牌","de":"给每只箱子都挂上编号，仓库便成了一座小图书馆。17号是春天收集的，23号是海边捡来的。我是把零散记忆一行行整理好的、安静的索引。"},"ICON-1852":{"nm":"陈列位置指南","de":"陈列，有一半是由位置成就的。高的往后，亮的居中。顺着指南挪动双手，原本杂乱的陈列架便不知不觉像一座小美术馆，静静屏息。"},"ICON-1853":{"nm":"收藏品掸尘刷","de":"越珍爱的东西，灰尘越爱落上去。用柔软的刷尖轻轻拂过，连许久未曾细看的歉意也一并扫去。擦拭之间，沉睡的回忆也短暂地，再次闪亮。"},"ICON-1854":{"nm":"收纳上限扩展券","de":"收集多了，地方不够也成了幸福的烦恼。望着多出一格的架子静静安心——这不是贪心，而是喜欢之物有那么多的证明。"},"ICON-1855":{"nm":"好友邀请码卡","de":"递出这串码，是\"一起玩吧\"最温柔的邀请函。几个数字里装着的心意，待收到的朋友第一次踏上海岛，两人专属的故事才算开始。"},"ICON-1856":{"nm":"共用仓库钥匙","de":"仓库的门绝不会独自打开。你和我，两只手凑齐了，锁才终于转动。共用的空间里，共同守护的约定，总是以钥匙的形状挂在那里。"},"ICON-1857":{"nm":"失物招领标签","de":"丢失的物件，对某人也是珍宝。写下一行\"在这里哦\"挂上去——标签是一根小小的绳，重新把暂时迷路的心与失主，静静系到一起。"},"ICON-1858":{"nm":"求助旗","de":"说出\"请帮帮我\"不是软弱，而是勇气。旗子升起，便有人从某处奔来。在这座岛上传得最快的不是流言，而是彼此伸出的手。"},"ICON-1859":{"nm":"应急联络手环","de":"缠在手腕上的一份小小安心。无论发生什么，写在这里的号码都会比谁都先赶来。平日里遗忘度日，却在最需要的瞬间最为可靠的，安静的同行者。"},"ICON-1860":{"nm":"分工筹码","de":"谁去买菜、谁来做饭，分好筹码便不会有争执。一起做一件事的第一步，是从彼此温柔地定好各自的那份开始的。"},"ICON-1861":{"nm":"协作制作表","de":"独自连想都不敢想的事，众人聚到一起便像谎言一般成了真。表上的名字一个个填满，空格便减少，笑声便增多。协作，在格与格之间悄悄生长。"},"ICON-1862":{"nm":"拜访礼仪卡","de":"踏进别人家时，连脚尖都变得小心翼翼。卡上写的不是什么大道理，只是\"鞋子摆整齐，问候要先开口\"这样小而温暖的约定罢了。"},"ICON-1863":{"nm":"派对散场铃","de":"欢乐也要有个尽头，才会令人期待下一次。铃\"叮铃\"一响，大家便带着不舍的神情手忙脚乱地收拾起来。懂得好好告别的派对，最久久留在心里。"},"ICON-1864":{"nm":"床垫边角固定带","de":"被单铺得再平整，边角也总要翘起来。多亏这条牢牢抓住四角的带子，每天清晨的床都像酒店房间一样平平整整地睁开眼。"},"ICON-1865":{"nm":"被领纽扣绳","de":"我是抓住被领的纽扣绳。整夜无论怎样翻来覆去，都紧紧攥着，不让被领逃跑。一觉醒来丝毫不乱的被子，便是我通宵执勤的成果。"},"ICON-1866":{"nm":"床垫顶垫固定夹","de":"顶垫一有机会就想悄悄滑走。每到那时，夹子便\"咔\"地咬住边角守住位置。在看不见的角落里守护睡处的，一个沉默的犟脾气。"},"ICON-1867":{"nm":"床单抚皱器","de":"夜里在床单上生出的细皱，不知怎的，像极了心里的褶子。愿凌乱的一天也能像被抚一遍便平整的布一样，被那样妥帖地熨平。"},"ICON-1868":{"nm":"床垫通风承架","de":"床垫也需要喘息的缝隙。承架在下方开出风道，潮气便排出，干爽便渗入。好的睡眠，正是从那托住后背的空气里，静静开始的。"},"ICON-1869":{"nm":"被套拉链遮盖","de":"换被套时棉花老往外冒的那场半夜兵荒马乱。用遮盖把拉链一掩，睡着也不会被脚勾到惊醒。一片小小的遮盖，带来一份大大的安宁。"},"ICON-1870":{"nm":"防棉团聚集垫","de":"枕芯的棉花不知不觉就挤到一边，堆成一座小丘。垫子在其间默默撑住，平整便保留到最后。多亏它，每个夜晚，崭新般的蓬松都如约归来。"},"ICON-1871":{"nm":"床单弹力挂钩","de":"床单总爱往一边慢慢褪开。在边角挂上挂钩绷紧拉好，整夜翻身也纹丝不动。那份绷紧，便这样悄悄成了安眠的底子。"},"ICON-1872":{"nm":"枕套更换标签","de":"今天到底洗没洗枕套，忽然犯糊涂时，一张标签便给出清楚的答案。睡了又睡而总爱忘掉的日程，由这枚小标记替你妥妥地记着。"},"ICON-1873":{"nm":"梦日记夹书签","de":"把醒来便从指间散去的梦，夹在书签夹着的那一页上。翻开来，昨夜的海与天都还在——一座轻轻搭在睡与写之间的小桥。"},"ICON-1874":{"nm":"白噪音鹅卵石","de":"太过安静的夜，反倒会唤醒睡意。鹅卵石沙沙地放出雨声般的声响，心便顺着那纹理慢慢沉静下来。一块轻轻安抚沉默的小石。"},"ICON-1875":{"nm":"温感睡眠筹码","de":"睡着时额头是热是脚尖是凉，筹码在旁静静守望。多亏这位悄悄寻找贴合体温的守夜者，睡眠一直流淌到天明也不曾中断。"},"ICON-1876":{"nm":"遮光帘夹","de":"晨光多么勤快，老往窗帘缝里挤进来。用夹子紧紧咬住两端，房间便重新黑得像深夜。一次睡懒觉的，可靠共犯。"},"ICON-1877":{"nm":"月光投影灯","de":"关灯后，月亮便升上天花板。灯投出的柔和光晕，把房间变成一片小小的夜空。把仰望明月入睡的那份心情，原样留在枕边。"},"ICON-1878":{"nm":"助眠香囊挂钩","de":"装着薰衣草与草香的香囊在枕边轻轻摇曳。循着沁入鼻尖的香气，肩膀缓缓松开，一只香囊比枕头更先把睡意请来。"},"ICON-1879":{"nm":"摇篮曲八音盒针","de":"轻轻上紧发条，一段小旋律便流泻而出。从针尖转出的摇篮曲，像极了奶奶轻拍后背的那个节拍。每一个音都慢慢地把眼皮压得沉重。"},"ICON-1880":{"nm":"湿度植物杯","de":"我是用清水而非泥土养植物的杯子。看着细根在水中悠悠漂浮，连房间里的空气也变得湿润几分。一口积在书桌上的、小小的绿色之井。"},"ICON-1881":{"nm":"梦碎片收集瓶","de":"睡梦中流露的梦没有形状，醒来便从指间漏走。用瓶盖轻轻堵住一片将逝的碎片，留到清晨——想要铭记的心，就是从这样的小处开始的。"},"ICON-1882":{"nm":"枕边眼镜托盘","de":"摘下眼镜放下的瞬间，奇妙的是，连一天份的疲惫也一同卸下了。枕边这一方小小的位置，正是为承接那一个动作而在那里。睡前，把世界静静模糊掉的托盘。"},"ICON-1883":{"nm":"床头柜杯垫环","de":"水杯留下的一圈圆痕，看似微不足道，对床头柜的木纹却是道伤。为防它而套上的小环。珍惜之心，总在这种看不见的地方静静做着事。"},"ICON-1884":{"nm":"叠被定角器","de":"把被子叠得方方正正这件事，也有它的章法。顺着这件定角的工具对齐边角，连凌乱的心也被一并抚平。整齐的床位，是开启一天最端庄的问候。"},"ICON-1885":{"nm":"充电线枕边挂钩","de":"讨厌充电线整夜往地上慢慢滑落，便在枕边挂上的钩子。趁睡着时静静蓄满了力的线，到了早晨便满满地等着指尖。"},"ICON-1886":{"nm":"枕边零食篮","de":"在伸手可及处把喜欢的零食归到一处的篮子。是预先体谅了深夜会来的小馋的、温柔准备。在黑暗中捏起一颗咬下的窸窣声，莫名地亲切。"},"ICON-1887":{"nm":"入睡书架翼","de":"睡意涌来也不丢失正读的那行，静静托住摊开书页的翼。即将合眼前盖上的那一页，明晚会在同一处等你。"},"ICON-1888":{"nm":"枕边闹钟石托","de":"唤醒清晨的闹钟，也需要一个不摇晃的固定位置。圆圆的石托沉甸甸地承着那份重量，像即使破晓也不滑动的约定，守住那个位置。"},"ICON-1889":{"nm":"睡眠眼罩挂钉","de":"把整夜遮挡光线的眼罩，在白天挂起来透气的一枚钉子。给尽了用处的布腾出一处干爽的地方——小小的关照，就这样不着痕迹地渗入。"},"ICON-1890":{"nm":"枕边手电夹","de":"把深夜所需的一点光，固定向你想要的方向的夹子。把手电咬在床沿，在黑暗中摸索的手便舒坦许多。一只为光定方向的手。"},"ICON-1891":{"nm":"隔断帘挂环绳","de":"拉住分隔公共空间之帘的挂环绳。虽只是一片薄布，其外却是某人私密的夜晚。在同住一室里彼此守护睡眠的、温柔的界线。"},"ICON-1892":{"nm":"共用插座分配木板","de":"让众人分享唯一插座而做成的木板。把电均匀分送，不让任何人的夜晚陷入黑暗。共同生活，归根结底正是从分享这样的小事开始的。"},"ICON-1893":{"nm":"灯光亮度谦让石","de":"灯光太刺眼时，不用言语而悄悄递过去的石头。\"能稍微调暗点吗？\"那句话，由这小东西代为传达。是同住一室的房间里，最柔和的请求。"},"ICON-1894":{"nm":"起床时间谦让代币","de":"递到掌心、交给要先起身者的小牌。谁多睡会儿晨觉、谁先醒来，由这枚代币不起争执地定下。用指尖来定下谦让顺序的心意。"},"ICON-1895":{"nm":"共用衣架编号环","de":"在众人合用的衣架上编好的号码环。为不弄混是谁的位置，一个小小的数字静静建起秩序。在容易混淆的日常上，划下的一道温柔的线。"},"ICON-1896":{"nm":"双层床踏板套帽","de":"套在攀上二层的踏板上的帽套。让赤脚踩上也不冰不滑，照看着一级的安全。梯子顶端这点小小的体贴，稳稳托住上层的梦。"},"ICON-1897":{"nm":"公用纸巾挂臂","de":"用来挂公用厕纸的手臂状挂架。安放得让任何人都能单手轻松扯下一段。看似微不足道，却是顺畅衔接众人清晨的一双手。"},"ICON-1898":{"nm":"香薰轮值筹码","de":"记下该由谁去新换香薰的轮值筹码。连一缕淡淡的香气，也是轮流负责的约定。好闻的气味不会白来，而是从某人的轮值里绽放。"},"ICON-1899":{"nm":"共用睡眠灯把手","de":"众人一同开关的睡眠灯的把手。醒到最晚的那只手，最后收起光亮。是分享柔和灯光的、同住一室之人安静的约定。"},"ICON-1900":{"nm":"沙发扶手杯槽","de":"沙发扶手上凹出的圆圆杯位。哪怕手暂时放下杯子，也不必担心打翻。歇脚的地方，总要有处放杯子，心才终于能舒坦地舒展开来。"},"ICON-1901":{"nm":"靠垫内胆拉链把手","de":"装在靠垫内胆拉链上的小把手。一个小环，省去换洗的辛苦。连看不见的里子都照看到——居家的温柔，总藏在那里。"},"ICON-1902":{"nm":"沙发靠背填缝垫","de":"填满靠背缝隙、托住腰的靠垫。让久坐也不硌背，把空处填补起来。倚靠的瞬间，身体便先一步察觉\"啊，就是这个\"的安适。"},"ICON-1903":{"nm":"坐垫边角固定带","de":"把每次坐下都悄悄跟过来的坐垫，在边角拽住的带子。固定在一处不让它滑走。所谓端整，正是从这种小而执拗的固定开始的。"},"ICON-1904":{"nm":"靠垫缝线护边带","de":"靠垫最先磨损的地方，永远是边角的缝线。预先把那处缠包起来、护着不让它绽开的护边带。想长久相伴的心，像缝针一样结实。"},"ICON-1905":{"nm":"沙发缝遥控器袋","de":"总爱消失在靠垫间的遥控器，终于有了自己的家。插在沙发缝里的小袋子。以为弄丢的东西总在那里，是比想象中更大的安心。"},"ICON-1906":{"nm":"膝盖毯卷扎绳","de":"把膝盖毯卷起来扎好的绳子。把摊开便散开的暖意，为下一个夜晚整齐收好。暖意这样收着，明天便又能取出来盖上。"},"ICON-1907":{"nm":"脚凳套纽扣","de":"把因脚踩而磨损最快的脚凳套，做成易于更换的扣子。\"啪\"地一扣的那个动作，延长了布的寿命。想长久使用的心，在小处也精打细算。"},"ICON-1908":{"nm":"沙发腿防滑套","de":"再重的沙发也不该刮伤地板。套在四条腿尖的柔软套子，悄悄地呵护木地板。连脚尖都小心翼翼的家具，不知怎的更惹人怜爱。"},"ICON-1909":{"nm":"遥控器收纳座","de":"把各自滚动散落的遥控器们整整齐齐立到一处的收纳座。一长一短的棒子排好队，仅此一项，房间里的空气便沉静下一个调子。"},"ICON-1910":{"nm":"游戏手柄充电挂","de":"把尽兴玩过的游戏手柄挂起来充电的钩子。悬着静静蓄力的同时，手也暂歇片刻。这一个短短的休止符，为下一局做足准备。"},"ICON-1911":{"nm":"桌游棋子袋","de":"装着五颜六色棋子的小袋子。一袋之中等待下一局的棋子，每次一摇便咯哒作响。那声响一起，\"再来一局？\"的心动便先醒来。"},"ICON-1912":{"nm":"骰子掷盘","de":"专用来掷骰子的盘子。把那从桌外蹦出去消失的运气，由边缘困在盘内。骰子骨碌碌滚停的那短短一瞬，众人的呼吸也一同屏住。"},"ICON-1913":{"nm":"牌组固定带","de":"把一副牌捆住不让它散开的带子。在洗牌之前，那顺序便是约定。解开带子摊开牌的那个手势里，一局的故事才终于开始。"},"ICON-1914":{"nm":"主机线整理夹","de":"把主机背后缠成一团的线抓住、整齐梳下的夹子。默默整理那看都看不见之处的杂乱。所谓干净，总是这样在背后悄悄完成的。"},"ICON-1915":{"nm":"计分格转盘","de":"转动以标示计分格的小转盘。\"咔哒\"，每上一格数字便引来一阵欢呼。不用脑子盘算，指尖便先记下了那天的胜负。"},"ICON-1916":{"nm":"棋盘立起支架","de":"把棋盘斜着立起，让围坐的所有人一眼便能看清全局的支架。让谁都不必探头，静静铺开一片公平的视野。"},"ICON-1917":{"nm":"游戏顺序抽签筒","de":"为定游戏顺序而把手伸进去抽的筒子。摸索捏出的一根棒子，分出谁是第一轮。在略微赖一把运气的那短短一瞬，圆筒里大家一同心跳。"},"ICON-1918":{"nm":"分享零食分格盘","de":"把零食按种类分装的分格盘。隔开位置，便能不碰到彼此的手地挑出喜欢的那样。体谅分食之人的心意，盛在一格一格里。"},"ICON-1919":{"nm":"茶壶保温罩","de":"围住茶壶肩头守护暖意的保温罩。在茶慢慢沏出的同时，包裹着不让它凉掉。是想把温热的一杯，温热地奉到最后的指尖之心。"},"ICON-1920":{"nm":"茶包捞置托","de":"把泡好的茶包捞起、让它暂歇片刻的托。连最后一滴水珠也接住不洒。是给尽了本分的茶叶，也腾出一个端整收尾的位置。"},"ICON-1921":{"nm":"公用马克杯区分环","de":"茶水间架上一模一样的六只马克杯。不必问是谁的，便套上了各色的环。一个小小的标记，把口味手艺各异的六个人，静静系到同一张餐桌旁。"},"ICON-1922":{"nm":"爆米花分享篮","de":"从手传到手的过程中，喷香的热气先打了招呼。每分出一把却奇妙地不见减少的，若有什么，那便是围坐分食的傍晚之心吧。"},"ICON-1923":{"nm":"方糖夹筒","de":"用夹子\"嗒\"地夹起一颗方糖，投进茶杯。望着白色的棱角慢慢化开消失——那是在奶奶的茶几旁初学到的、不慌不忙的甜之礼仪。"},"ICON-1924":{"nm":"托盘防滑垫","de":"托盘即便倾斜，杯子也守住原位。正如那些在底下默默扶持之物一向如此，垫子独自熬过险些滑落的瞬间，到最后也闭口不言。"},"ICON-1925":{"nm":"饮料吸管立杯","de":"把吸管直直立好，饮料也好心也好都不会散乱。仅凭这看似不值一提的直立，书桌便端整起来的午后，杯子怀抱着一根小柱，静静托起慵懒的时光。"},"ICON-1926":{"nm":"饼干屑接盘","de":"酥脆，饼干碎裂的瞬间掉落的碎屑都聚到这里。连最美味的一口留下的痕迹也一并接住——对最后的碎屑也温柔的、餐桌安静的收尾。"},"ICON-1927":{"nm":"照片夹挂绳","de":"在像晾衣绳一样垂下的绳上，用夹子把拍立得一张张夹上去。今天拍下的笑容随风轻摇晾干的同时，一面墙便成了一方小而明亮的回忆展厅。"},"ICON-1928":{"nm":"回忆线团线轴","de":"把缠乱的线解开、整齐缠好的线轴。在每一处断口打结接续起来的东西。记忆也这样一圈圈慢慢倒回，以为变短的路便又长了起来。"},"ICON-1929":{"nm":"墙饰挂钉盖","de":"遮住钉痕的小小圆盖。曾挂过什么的地方，取下后留下的小疤，静静盖上，墙便仿佛什么都没发生过似的，重新露出光滑的面孔。"},"ICON-1930":{"nm":"合影夹框","de":"六人紧紧并肩拍下的合影。嵌进夹框的瞬间，那天的笑容与温度便一同被封存。所谓相框，是把流逝的一天，最安静地停驻下来的一双手。"},"ICON-1931":{"nm":"便条钉软木板","de":"图钉痕密密麻麻的褐色板子。不可忘的约定、谁贴上的应援便条、今天要做的事，层层钉在上面。是替大脑记忆的、书桌旁可靠的一面墙。"},"ICON-1932":{"nm":"花环挂结","de":"连挂在门上的一只花环，也藏着指尖的手艺。结要打得牢，在多风的季节才不会掉下来。迎接某人的心，总是从看不见的地方开始变得结实。"},"ICON-1933":{"nm":"挂钟摆罩","de":"包住滴答摆动的钟摆、挡灰的布罩。连计量时间这件事，也受着这样的照看。轻轻守护着不让它老去，挂钟便能在我们身边多停留一阵。"},"ICON-1934":{"nm":"贴纸收集插板","de":"在各个抽屉里散落的贴纸聚到一块板上排好队。喜欢的角色、闪亮的星星、一张手写字。小小的收集之乐整齐排列开来，连心也变得端正。"},"ICON-1935":{"nm":"装饰旗连接绳","de":"把各色旗子连成一串的绳子。无论生日还是欢迎，绳子横贯天花板的瞬间，平凡的房间便变成了喜庆之家。所谓庆祝，便是把断开的心一点点接续起来的事。"},"ICON-1936":{"nm":"电热水壶软木垫","de":"垫在滚烫水壶底下的一片软木。为不让餐桌被烫伤，独自把那份热揽入怀中。是为了不让某人的温热留下印记，而默默承托的小小体贴。"},"ICON-1937":{"nm":"烤面包机屑盘","de":"烤得焦黄的面包掉落的碎屑，骨碌碌落进盘里。抽出来一抖即可。它默默承接忙乱的清晨，又把下一顿重新备得干干净净。"},"ICON-1938":{"nm":"微波炉转盘环","de":"在团团转的环上，盘子缓缓画出一圈。为求均匀加热而转动的那份旋转，把凉透的昨日之饭，重新救活成一顿热气腾腾的餐。"},"ICON-1939":{"nm":"迷你电磁炉灶盖","de":"油四处飞溅，灶面却总是干净。一片盖子，把猛烈的热气与手隔开。那些不动声色挡在前面的东西，把厨房守成了不会被烫伤的地方。"},"ICON-1940":{"nm":"电饭煲排气盖","de":"\"嗤——\"地排气的声响。多亏轻轻放走所含压力的小盖子，刚煮好的饭以最柔和的面孔掀开盖子。焖饭的时光里，没有催促。"},"ICON-1941":{"nm":"饭勺立架","de":"把搅过汤的饭勺直直立好。是不愿在台面上洒下一点污渍的小小心意。厨房的端整，总是从这样不起眼的小处开始的。"},"ICON-1942":{"nm":"锅把硅胶套","de":"在烧得滚烫的锅把上套上硅胶，手便不会被烫到。是夹在炽热与手掌之间的一层。在最近的地方，守护着煮暖饭的人。"},"ICON-1943":{"nm":"电热水壶水垢滤网","de":"每天烧的水里也会积起淡淡的痕迹。细密的滤网静静滤去水垢，只倒出清澈的一杯。是在看不见处守护着茶的第一口的、勤快的一双手。"},"ICON-1944":{"nm":"烹饪计时器夹腿","de":"\"再三分钟\"，用夹腿紧紧咬住餐桌边角的计时器。在面煮熟的同时，靠着小小的腿撑立着，滴答滴答陪你数着一天中最令人期待的瞬间。"},"ICON-1945":{"nm":"餐具沥水承杯","de":"刚冲洗过的餐具上，水珠骨碌碌滴落。承杯静静接住聚拢那些水气，餐桌便不知不觉变得干爽。所谓干净，是连一滴水也照看到的、温柔的勤快。"},"ICON-1946":{"nm":"立盘隔挡条","de":"把盘子竖起、一格格隔开。叠放便互相磨蹭的碗碟，各自得到一处位置。所谓整理，归根结底是给每一个都腾出互不碰撞的那一格。"},"ICON-1947":{"nm":"筷子配对环","de":"把失了伴、孤零零剩下的筷子穿进环里，重新凑成一双。只剩一只便会立刻失去用处，所以这把它们并排系好的小环，守护着抽屉里的秩序。"},"ICON-1948":{"nm":"杯架枝状座","de":"在像树枝般分出多杈的架座上一只只挂起杯子。倒扣的杯子各自沥干的同时，厨房一角便像一棵小而端整的树，静静伫立。"},"ICON-1949":{"nm":"餐具格托盘把手","de":"勺、筷、叉一格格并排躺着的托盘。抓住把手整个端出来，摆桌便轻快许多。抽屉里也无一例外地，住着秩序的美学。"},"ICON-1950":{"nm":"水杯倒扣沥干板","de":"把洗好的杯子倒扣，水珠便嘀嘀嗒嗒落下。在洒进阳光的窗边慢慢沥干的同时，玻璃杯为下一口，静静寻回最初的透明。"},"ICON-1951":{"nm":"叉缝防卡梳","de":"用细密的梳齿轻轻梳理，让食物不再卡进叉齿的缝隙里。正因为有这份连狭窄缝隙都顾到的细心，下一顿饭总能以洁净无瑕的第一口开始。"},"ICON-1952":{"nm":"叠碗防滑毡","de":"瓷碗叠在一起时，会发出彼此磕碰的刺耳声响。夹在中间的一片毛毡，平息了那份摩擦。能长久相处的诀窍，就在于让彼此都稍稍柔软一些。"},"ICON-1953":{"nm":"茶匙挂环绳","de":"把小巧的茶匙挂在环上，悬于墙边。不再被埋没在抽屉深处，而是始终在触手可及的地方闪闪发亮——这是小工具堂堂正正占据的专属位置。过日子，也讲究各得其所。"},"ICON-1954":{"nm":"冷藏分区托盘","de":"把冷藏室分成一格格，每样食材都有了自己的小家。曾经混在一起被遗忘的东西都各归其位，每次开门，什么在哪儿都一目了然。"},"ICON-1955":{"nm":"冷冻封口袋立夹","de":"用夹子夹住用了一半的冷冻封口袋，让它笔直立起。既不会倒下漏出，下次也好找。即便在冰冷的冷冻室里，也藏着持家人滴水不漏的精明智慧。"},"ICON-1956":{"nm":"瓶盖紧旋帽","de":"没拧紧的瓶子，不知不觉就跑了气。把盖子拧紧的那一下手腕之力，把里面的香气与气泡原封不动地锁存到第二天早晨。精明，往往在小处闪光。"},"ICON-1957":{"nm":"蛋格防滑垫","de":"为了让圆滚滚的鸡蛋不会咕噜滚落摔碎，一格格稳稳托住的垫子。想把最娇嫩的东西最小心地对待的那份心意，小小而温柔地安在冰箱门的一侧。"},"ICON-1958":{"nm":"冷藏门兜扩展带","de":"把冷藏门的口袋向旁边轻轻撑大，多出一格来。家当多了，存放的地方也得跟着多起来。把窄处拓宽来用的巧手里，映出持家人精明的心。"},"ICON-1959":{"nm":"剩菜压盖","de":"轻轻压盖在剩菜上的盖子。让它不干掉，也不串上别的气味，静静守护着。懂得珍惜的手，连一顿饭剩下的也会细心收好。"},"ICON-1960":{"nm":"冷气导向风翼","de":"冷气往哪边流，由小小的风翼悄悄决定方向。用指尖把那看不见的风路稍稍一拨，凉意便能抵达最里面最深的角落。"},"ICON-1961":{"nm":"蔬菜格吸湿垫","de":"冰箱蔬菜格最暗的角落里，我默默地吸住水汽。昨天蔫掉的叶子，到了早上又重新挺括起来的小奇迹。即便无人知晓，新鲜也总由我来守护。"},"ICON-1962":{"nm":"饮料罐防滚挡","de":"静静贴在餐桌边缘，拦住想要滚走的罐子的脚步。差点洒掉的饮料，差点擦拭的餐桌。过日子的安心，就从这样不起眼的小挡边开始。"},"ICON-1963":{"nm":"值日轮值转盘","de":"今天谁洗碗，谁分类回收。箭头一转，争执的事便圆圆地化解开。在五个人挤在一起过的家里，顺序就是一份温柔的和平。"},"ICON-1964":{"nm":"成员杯区分硅胶圈","de":"五个差不多的杯子，到底是谁的，叫人犯迷糊的清晨。套上一条手腕大小的色带，'这是我的'这个小小约定便清晰起来，温柔的秩序便悄悄落在早餐桌上。"},"ICON-1965":{"nm":"餐食碗分量环","de":"忙碌的日子里，碗里的刻度成了可靠的朋友。一格盛饭，一格盛菜。不多也不少，静静告诉你今天该吃多少的那道温柔的线。"},"ICON-1966":{"nm":"零食分享夹筒","de":"整袋递过去，手碰过的地方就剩下没人要，叫人尴尬。用夹子一个个夹出来分，这才人人份量相同。分享时，比起手的手艺，更配一份讲究的好习惯。"},"ICON-1967":{"nm":"水壶值日挂架","de":"烧水这活儿，总落在同一双手上。自从在水壶旁的挂架上轮流挂上名牌，一杯热茶便成了大家轮流泡出的情意。"},"ICON-1968":{"nm":"勿剩提醒锅铲牌","de":"'请别剩下'这一句，小小地挂在锅铲尖上。虽像唠叨，却没半点惹人厌。因为这里寄寓着昔日饭桌上珍惜一餐的心意。"},"ICON-1969":{"nm":"个人餐具袋挂钩","de":"餐具不再在抽屉里乱滚。当它们各自装进口袋挂上墙的那一刻，五口人的位置便整整齐齐排成一列。小小的整理，撑起每天的安宁。"},"ICON-1970":{"nm":"餐桌座位区分软木牌","de":"把软木片铺在餐桌上，谁坐哪儿便一清二楚。总坐的位置，总相对而望的侧脸。固定的座位，是'共同生活'这句话最安静的证明。"},"ICON-1971":{"nm":"值日围裙卷挂钩","de":"洗完碗的围裙不会被随手一扔。卷成一卷挂在钩上，明早再用时便又干爽顺手。为下一个人着想的心，就住在这个小小的结里。"},"ICON-1972":{"nm":"一次性拖鞋折叠包","de":"来客的日子，我便整包摊开。整齐放好的一次性拖鞋，软软地迎接初来的脚。款待，总是从玄关静静开始。"},"ICON-1973":{"nm":"棉签纸杆口袋","de":"棉签用完只剩纸杆时，我会把那端细心收起。给将被丢弃的东西也留个位置。我知道，整洁书桌的秘密，就是这样琐碎的温柔。"},"ICON-1974":{"nm":"针线包线轴束","de":"为了让线轴不松脱缠成一团，把各色线捆在一处。掉了的纽扣，松了的袖口，有这一束便很快恢复如初。在重要日子的夜里悄悄救场的手缝。"},"ICON-1975":{"nm":"香皂单装小块","de":"一块块精心包好的香皂，放在每间客房里。一掌大小的身躯，用一捧泡沫洗去一天的尘埃。洁净，总是从这样的小处开始。"},"ICON-1976":{"nm":"浴帽折褶囊","de":"折起褶皱便能塞进手心，展开便能把头发整个裹住。让一次淋浴梳理好的头发不被打乱。明早的整洁，由这一层守护。"},"ICON-1977":{"nm":"牙刷护套","de":"刷毛比想象中娇气。一只护套盖住那一端，连包里的灰尘也碰不到。守护看不见的地方——这是每次旅行都会学到的卫生真功夫。"},"ICON-1978":{"nm":"化妆棉单张夹","de":"化妆棉要一张张夹才能好好取出。哗啦倒一堆，浪费的反而更多。'一张张，用心地'——这是梳妆台上一条安静的规矩。"},"ICON-1979":{"nm":"迷你折叠鞋拔","de":"折起在口袋里，展开在脚后跟。我自豪能用小小的身躯干出不小的事。哪怕睡过头的清晨，让你不弄坏皮鞋穿上的，总是我。"},"ICON-1980":{"nm":"牙线单段卷盘","de":"把一段牙线漂亮地卷好，需要时正好掐断来用。虽是指甲大小的卷盘，但守护灿烂笑容的事里，它从不缺席。微笑背后，也有看不见的准备。"},"ICON-1981":{"nm":"电热壶盖把手","de":"为了不被沸水的蒸汽烫到手，把我套在壶盖上。在炽热与手掌之间的一寸距离。那小小的距离，安全地温暖着某个忙碌的清晨。"},"ICON-1982":{"nm":"熨斗搁置硅胶板","de":"熨烫途中短暂放手的那一瞬最危险。把熨斗立在硅胶板上，餐桌和衣服都不会被烫焦。抚平褶皱的活儿，要在搁板上才算真正完成。"},"ICON-1983":{"nm":"防滑落衣架弯钩","de":"为了不让挂着的衣服随意滑落，弯钩牢牢闭住了口。守在衣柜里那件心爱衣裳旁的小哨兵。守护，原来是这样安静的事。"},"ICON-1984":{"nm":"水壶水垢滤网","de":"把在沸水中漂浮的水垢静静滤掉，是我的本分。把看不见的杂质也滤净之后，一杯茶才会清澈。用心，总是在不起眼的地方酝酿出来。"},"ICON-1985":{"nm":"衣架防滑带","de":"缠了防滑带的衣架，连轻薄的真丝也不会滑落。见过衣服掉在地上皱成一团的人才懂，这细细一条带子有多可贵。"},"ICON-1986":{"nm":"熨斗线整理夹","de":"散开的电线会绊倒人，让谁踉跄一下。用夹子整齐捆在一处的一份手势。防患于未然的事，总是从这样细小琐碎的整理出发。"},"ICON-1987":{"nm":"电热壶底座杯槽","de":"为了不晃动，把壶严丝合缝地坐进我的槽里。放在该在的位置，就等于安心。每天早晨热水总在同一个地方烧开，自有它的道理。"},"ICON-1988":{"nm":"裤架夹腿","de":"夹腿稳稳咬住裤脚下摆，连一道褶子都不会留。熨好的一条裤子，从挂上衣架的那刻起便受礼遇。利落的版型，是在衣柜里完成的。"},"ICON-1989":{"nm":"吹风机挂钩","de":"吹风机随手一放，电线很快就缠在一起。往钩上一挂，洗手台也宽敞了，明天早晨也轻松了。整洁的位置，悄悄为忙碌的一天松了绑。"},"ICON-1990":{"nm":"迷你吧饮料垫","de":"静静垫在杯子底下，水珠便不会在桌上洇开。一张杯垫的体贴，让圆圆的印子无处可留。整洁，是不留痕迹的温柔。"},"ICON-1991":{"nm":"请勿打扰挂牌","de":"挂在门把上的一块牌子，静静低语着'此刻正在休息'。守护漫长一天结束时那一口小憩。逗号，也需要有人用心守护。"},"ICON-1992":{"nm":"客房服务呼叫钮盖","de":"多亏裹住按钮的盖子，衣角蹭过也不会被随便按下。只在真正需要的瞬间清晰地呼叫。一只小小的盖子，让忙碌的客房愈发整洁。"},"ICON-1993":{"nm":"迷你吧冰块夹腿","de":"光手夹冰，又冷又总打滑。这活儿就由夹腿利落地代劳。一杯清凉饮料的开始，藏着一双看不见的手。"},"ICON-1994":{"nm":"房卡插槽","de":"把卡插进插槽，房间的灯便啪地亮起。我虽只是一道小小的缝隙，却成了开启那个能卸下一天疲惫之空间的第一个手势。归来之处，重新亮起了灯。"},"ICON-1995":{"nm":"水瓶颈封环","de":"若挂在水瓶颈上的封环完好，就意味着还没有人动过。证明仍是最初模样的小小约定。信任，从未被破坏的封口开始。"},"ICON-1996":{"nm":"指南手册立架","de":"把指南手册斜斜立起，路过的目光便自然停留。等待被翻开的信息那从容的姿态。只是摆放得醒目，就让某人的路顺畅了几分。"},"ICON-1997":{"nm":"迷你吧开瓶扁片","de":"扁平身躯的一角，悄悄藏着开瓶盖的凹槽。虽小，自己的活儿却干得利落。一瓶饮料清凉的第一口，总从这小小的片子打开。"},"ICON-1998":{"nm":"灯光调节旋钮罩","de":"轻轻转动包着罩子的旋钮，房间的明暗便缓缓变化。亮一些，又柔一些。挑选入睡时分的光，是温柔地为一天收尾的仪式。"},"ICON-1999":{"nm":"行李箱轮挡楔","de":"轻轻塞进轮子底下，行李箱便不会自顾自滚走。即便在倾斜的车站站台，行李也守得住原位。出行路上的安心，由这小小的楔子稳稳撑起。"},"ICON-2000":{"nm":"旅行打包折叠板","de":"摊开把衣物放上去，衬衫裤子都棱角分明地叠得整齐。让包里不塌乱，让你抵达的城市能毫无褶皱地出门。打包得好的行李，从出发前就在助力旅行。"},"ICON-2001":{"nm":"客房保险箱锁柄","de":"转动把手，小小的门闩便向内滑去。把贵重物品托付出去，是只这一夜便彻底放下心来的约定。锁，不是不安，而是以安心的另一个名字存在于此。"},"ICON-2002":{"nm":"行李箱拉杆套","de":"每一处磨出手泽的地方，都刻着某人的出发。握住这个被拖行的距离磨损的把套，便静静懂得：离开，终究是一个包含着归来的词。"},"ICON-2003":{"nm":"旅行收纳袋挂夹","de":"把收纳袋挂在洗手台边角，狭小的客房便宽出一寸。一只小夹子，便能开启包内的秩序——远行过的手，早已深谙此道。"},"ICON-2004":{"nm":"充电器多插夹","de":"把多根线缆聚到一个插座上充电。等待充满的夜里，有这样一双小手，把散乱的线温柔地拢在一处。"},"ICON-2005":{"nm":"行李箱名牌挂绳","de":"在一色黑的箱子之间，让你认出自己那个的一根绳子。挂上名字，便是给这件行李刻下一个温柔的标记——它有一条通往某人的归途。"},"ICON-2006":{"nm":"客房墙面充电线挂板","de":"贴在床头墙上的小板，整齐地托起充电线。在陌生房间度过的第一夜，只要熟悉的一缕光亮起，那里也暂时成了家。"},"ICON-2007":{"nm":"行李架折叠腿","de":"把折起的腿撑开，包便从地板的尘埃上浮起一寸。尚未打开就搁上去的行李箱，静静怀着未竟的旅程，等候下一个清晨。"},"ICON-2008":{"nm":"房卡插槽口","de":"插上卡，客房才会亮灯。只在停留期间点亮的光——旅人的一天，便由这小小的插槽所允许的、恰好那么多的明亮所温暖。"},"ICON-2009":{"nm":"房卡挂绳环","de":"把一张卡挂在脖子上，双手便轻松了。把怕弄丢的担忧系在一根绳上的小聪明，是行李多的旅人世代相传的智慧。"},"ICON-2010":{"nm":"前台呼叫铃钮","de":"一按，前台某处便叮地响起清脆的声音。为了让人求助时不必难为情，铃总是温柔地摆在伸手就够得着的地方。"},"ICON-2011":{"nm":"入住排号夹","de":"把队尾接过的号纸夹住固定。等待也有先后——秩序，是从彼此静静珍惜对方时间的小小约定中生长出来的。"},"ICON-2012":{"nm":"客房钥匙穗","de":"挂在钥匙末端的穗子随着每一步轻轻摇晃。在实用之上悄悄添一抹风情的心意，只有懂得指尖之乐的人才会施展。"},"ICON-2013":{"nm":"前台门铃罩","de":"给门铃罩上盖子，正午的静谧便不被打破。守护某人安眠的小小体贴——宁静，也是有人用心营造出来的。"},"ICON-2014":{"nm":"房号挂牌条","de":"挂在门把上的纸条上，清楚地写着房间号码。几个数字便为今晚我归来的位置作了标记，在陌生的走廊里，它成了一座小小的灯塔。"},"ICON-2015":{"nm":"房卡磁条","de":"把黑色磁条贴近门缝，锁便悄然解开。看不见的信号开启门扉的时代——曾经如魔法般的事，如今已落入掌心成了寻常。"},"ICON-2016":{"nm":"入住盖章垫","de":"每次盖章，垫子都均匀地承接印油。为了让确认的那一笔清晰留下，有一双手在看不见的地方默默托着。"},"ICON-2017":{"nm":"行李车挂杆","de":"挂在行李车上的一根杆，毫无褶皱地托起衣袋。对那些替我们扛起沉重一天的东西，偶尔也想道一声谢。"},"ICON-2018":{"nm":"行李箱拉杆标签","de":"在行李箱拉杆上挂一个小标签。只要写名字的那一栏还空着，这只箱子的下一个目的地便尚未定下，留着一份悸动。"},"ICON-2019":{"nm":"行李车轮锁楔","de":"为了不让车在斜坡上滚走，往轮子底下垫一只楔子。守住'静止不动'，有时正是最可靠的安全的另一副面孔。"},"ICON-2020":{"nm":"行李捆带扣","de":"把塞满旅行行李、鼓胀的包紧紧勒住扣好，使它不致撑爆。路走完了，回忆的体积却不减，于是带扣把那份重量稳稳扣到最后。"},"ICON-2021":{"nm":"行李车挂钩套","de":"套在车钩上的套子，不在衣服上留下一道印子。连看不见的小擦痕都预先体察的心——好的款待，正在这样的小处完成。"},"ICON-2022":{"nm":"行李箱名牌口袋","de":"挂在包侧的小口袋，揣着名牌。写下属于谁，就如同预先刻下了即便丢失也能重逢的资格。"},"ICON-2023":{"nm":"搬运手套夹","de":"搬重物时，用夹子利落地咬住手套，使它不滑落。守护双手与把活儿干好，终究出自同一颗心。"},"ICON-2024":{"nm":"行李网罩","de":"盖上网罩，零碎的行李便不会四处散开。密密的每一个网眼，在忙碌的辗转中替你抓住，不漏掉那些小东西。"},"ICON-2025":{"nm":"行李车便签夹","de":"插在车把上的便签写着客房号码。把该去哪儿记下来的习惯——越是忙碌的手，越静静依靠那一行字。"},"ICON-2026":{"nm":"托盘餐盘罩顶","de":"掀起银色的圆顶，蒸汽便一下子升腾而起。盖着不让食物变凉的心意，正是想把温热原封不动递出去的那份用心本身。"},"ICON-2027":{"nm":"请勿打扰门把牌","de":"把这块牌挂在门把上，连走廊的脚步声也变得小心翼翼。'请勿叫醒'这一句——歇息，也要有人守护时才得以完整。"},"ICON-2028":{"nm":"客房服务纸巾环","de":"把纸巾套进圆环里，理出整洁的形状。一餐的格调便从这小小的环开始，用心，在琐碎处显得最为清晰。"},"ICON-2029":{"nm":"托盘防滑垫板","de":"在托盘上铺一块垫板，碗碟便不会滑动。在晃动中也守住原位——安静的稳定背后，也有某人的细心设计。"},"ICON-2030":{"nm":"早餐订单门把卡","de":"把早餐订单卡挂在门把上，明天的早晨便提前约定好了。今晚便把第一餐写下来，是温柔的等待所带的又一副面孔。"},"ICON-2031":{"nm":"托盘支腿架","de":"撑开托盘的腿，在床上也成了一张像样的餐桌。躺着便能享用的早餐一席——小小的支架，把平凡的房间变作奢侈的风景。"},"ICON-2032":{"nm":"水壶保温罩","de":"给水壶罩上保温罩，水的暖意便久久不散。如同围炉而坐的昔日夜晚，想守住温热的心意，从不分时代。"},"ICON-2033":{"nm":"清扫请求门把吊牌","de":"把清扫请求的吊牌挂在门把上，留下一个无声的信号。不必开口便能传达的请托——整洁房间的背后，有一份看不见的手的约定。"},"ICON-2034":{"nm":"托盘调料瓶座","de":"为了不让调料瓶倒下，托座牢牢地扶住它。即便在晃动的托盘上也守住味道的平衡，正是这小小固定默默担起的本分。"},"ICON-2035":{"nm":"预约便签立架","de":"把预约便签插好立起，先后次序便一目了然。为了让忙碌的手也不犯迷糊，把一张纸清楚立起的小小秩序之具。"},"ICON-2036":{"nm":"景点插针地图板","de":"在地图上插针，把想去的地方一处处点上。每一枚针都是一份尚未抵达的悸动——旅行，在展开地图的那一刻便已开始。"},"ICON-2037":{"nm":"招车旗夹","de":"叫出租车时，用夹子把小旗笔直立起。代替举手、由旗子替你喊出的信号——在街上，呼唤也要清晰，才终能传达。"},"ICON-2038":{"nm":"礼宾门铃把手","de":"一按把手，清脆的声音便传到礼宾台。这是'什么都尽管问'的款待信号，在陌生城市里最叫人安心的一声呼唤。"},"ICON-2039":{"nm":"预约号码夹板","de":"把预约号码纸夹在夹板上，使其清晰可见。为了不弄混约定的位置，把一行数字端正扶住的小小尽责。"},"ICON-2040":{"nm":"游览手册插架","de":"把游览手册插好，旅人的手便不由自主停下。每一张被翻开抽出的纸里，都静静折着那条尚未启程之路的风景。"},"ICON-2041":{"nm":"简图盖章座","de":"为了迎接初次踏进玄关的脚步，稳稳托住简图上盖章的一格，使它不晃动。印油不洇开，路也就不会走错。它默默压住分量，让小小的指引能端正立住。"},"ICON-2042":{"nm":"雨伞保管吊牌","de":"屋檐边雨珠滴答落下的午后，给每把伞挂上一个号码。雨停归来的人来寻自己那把时，吊牌便清清楚楚地唤回那段湿漉漉的记忆。"},"ICON-2043":{"nm":"问询台呼叫铃挂座","de":"叮地响一声，那边便有人笑盈盈地跑来。挂在台角的小铃，是连难以启齿的话也替你传达的、最温柔的传译。"},"ICON-2044":{"nm":"洗发液泵头","de":"摊开手掌轻轻一按，泡沫便噗地涌出。香气在浴室满满弥漫开的那一次出泵。把困倦的清晨最温柔唤醒的信号声，正从这里开始。"},"ICON-2045":{"nm":"皂托沥水板","de":"悄悄把香皂底下积的水放走的板子。让它不变软、不发糊。想把每天一点点磨损的东西多留在身边一寸的、小小温柔的体贴。"},"ICON-2046":{"nm":"入浴剂勺","de":"舀一勺粉末化进温水里，颜色与香气便慢慢晕染开来。用手腕搅动间，浴缸成了一座小小的湖，一天的疲惫静静沉浸其中。"},"ICON-2047":{"nm":"起泡网袋","de":"把一块香皂困进网里搓揉，手掌便满满涌起绵软的泡沫。把粗糙变作柔滑的、浴室一隅安静的炼金术士。"},"ICON-2048":{"nm":"牙刷消毒帽","de":"总希望碰到嘴的东西始终干净的心意。一只轻轻裹住刷头的小帽，连看不见的地方也顾到。洁净，正是由这样的琐碎累积而成。"},"ICON-2049":{"nm":"棉签盒盖","de":"白色小棒整齐躺着的盒子，上面圆圆扣着的盖。开时啵，合时嗒。用小小的声音为整理画上句点的、浴室里温柔的休止符。"},"ICON-2050":{"nm":"沐浴油滴瓶","de":"稍一倾斜，便一滴滴滚落出芬芳的油。在浴缸里晕开的光泽与淡淡香气。说是奢侈嫌素朴，说是日常又太温柔的、仅仅一滴。"},"ICON-2051":{"nm":"洗护用品托盘隔断","de":"在分成一格格的托盘上，小瓶子各自找到自己的位置安顿。散开便凌乱、聚起便整洁的东西。一道隔断，守住忙碌清晨的秩序。"},"ICON-2052":{"nm":"桑拿沙漏托座","de":"这是一个温柔的约定：哪怕只在沙子流尽的这段时间里，也好好把脊背暖热。当斜倚在托座上的沙漏咕噜噜数着时间，人便在弥漫的蒸汽中暂作一无所是地歇息。"},"ICON-2053":{"nm":"汗蒸羊角头巾","de":"把毛巾的两端卷起，像羊耳般竖立翘起，镜中的脸便悄悄舒展开来。在炽热的蒸汽间，谁都会短暂返回童心——这是汗蒸房里小小的仪式。"},"ICON-2054":{"nm":"桑拿浇水瓢","de":"用瓢舀满水浇在烧烫的石头上，嗤——蒸汽便直冲到天花板。那一瞬，全身浸入温热的雾气，积久的疲惫随汗珠慢慢化开。"},"ICON-2055":{"nm":"足浴桶温度棒","de":"把棒子浸进水里，刻度便悄悄开口说话。既不太烫也不太凉，恰好那个温度。在把脚尖泡进去之前，最先问候水之冷暖的指头。"},"ICON-2056":{"nm":"汗蒸石夹","de":"刚烧烫的石头总不能光手去拿。用夹子利落地咬住夹起，炽热便被移到安全的距离之外。小心翼翼也是一种本事，汗蒸房静静这样说。"},"ICON-2057":{"nm":"桑拿坐垫","de":"在热烫的地板上铺一张，脊背贴着的地方便柔软许多。默默承接被汗浸透的一天的垫子。歇息，终究来自与地板之间恰当的距离。"},"ICON-2058":{"nm":"足浴盐袋","de":"装一把粗盐化进温水里，倦意便从脚尖丝丝融去。当咸味的蒸汽缠上小腿升起，走了一整天的日子才终于停下脚步。"},"ICON-2059":{"nm":"桑拿香水石碟","de":"在烧热的石头上滴几滴香水，温热起来的香气便在桑拿里慢慢散开。闭上眼，分不清这里是森林还是花田。这是一趟由鼻尖出发的、最短的旅行。"},"ICON-2060":{"nm":"热敷袋保温套","de":"把热好的袋子整个裹住、久久留住暖意的布。如同唯恐它凉了而紧紧抱住的那份心意，搁在腹上的温热整夜守在身旁。"},"ICON-2061":{"nm":"香薰扩香藤条","de":"纤细的藤条把香气吸上来，缓缓散入房间。每一次吸气都淡淡渗入的气味。这是让所栖之地一点点染上那个人香气的方式。"},"ICON-2062":{"nm":"日光椅角度旋钮","de":"慢慢转动旋钮，靠背便缓缓倾斜。朝阳光那边一点，朝阴凉那边一点。摸索着寻找最舒适角度的事，是只属于我一个人的算计。"},"ICON-2063":{"nm":"泳池边缘防滑带","de":"沿水边一圈围起的防滑带。为了让戏水后兴冲冲跑来的小脚平安停住，它静静铺在看不见的地方，是一条安全的终点线。"},"ICON-2064":{"nm":"泳圈气塞环","de":"在封住气的小塞子上，细心系了一个环。免得从泳圈拔出的塞子顺水漂走。预先防住盛夏正午那点琐碎遗失的智慧。"},"ICON-2065":{"nm":"泳池入水台阶帽","de":"柔软包住通往水中那级台阶末端的塞帽。为了不刮伤光脚板，把入水的第一步软软地接住。无论什么，开始总该小心翼翼。"},"ICON-2066":{"nm":"日光椅坐垫绳环","de":"为了不让坐垫滑落而把绳挂住系牢的环。这是哪怕起风也要守住原位的小小约定。一个结，把午后的慵懒拴在那个位置上。"},"ICON-2067":{"nm":"泳池别墅饮料插板","de":"把饮料杯稳稳插进泳池边缘的板子。即便尽情扑腾水花也纹丝不动的一个位置。把清凉放在伸手可及处，便把盛夏正午拉得更长。"},"ICON-2068":{"nm":"湿泳衣挂夹","de":"夹住滴滴答答淌水的泳衣，静静交给风去吹。在阳光下晾干的这段时间，夹子默默咬住伫立。这是为下一次戏水而备的、安静温柔的等待。"},"ICON-2069":{"nm":"遮阳伞柱底座配重","de":"为了不让遮阳伞被风吹得晃动，垫在柱底的沉甸甸的配重。阴凉能在原地久久停留，全靠这份重量。可靠，往往藏在最低的地方。"},"ICON-2070":{"nm":"泳池水温浮标片","de":"在水面浮浮荡荡、静静告知水温的小片。太凉便泛红，正好便转柔。用一种颜色读出水之心情的、可爱的小算命师。"},"ICON-2071":{"nm":"帐篷拉链拉绳穗","de":"拽一下挂在拉链末端的小穗，帐篷门便嘶啦一声拉开。不必指尖摸索就能立刻抓住的拉手。它温柔地引导着深夜里的出入。"},"ICON-2072":{"nm":"帐篷绳固定蝶夹","de":"把绳咬成蝴蝶形状牢牢扣住的夹子。曾被风吹得猎猎作响的布，这才安静下来。野营的夜晚，正由这些小而利落的结悄悄守护。"},"ICON-2073":{"nm":"豪华露营垫气塞","de":"对着口呼、呼地吹，垫子便慢慢鼓胀起来。吹满后把塞子拧紧，地面便软乎乎的，星光下安身的一处地方这才完成。"},"ICON-2074":{"nm":"帐篷顶挂钩","de":"挂在帐篷顶上、用来悬灯笼和手帕的钩子。连头顶那点小空间也细心利用的持家智慧。等于在顶上挂了一颗代替天空的星。"},"ICON-2075":{"nm":"睡袋卷收固定带","de":"缠绕扣住卷好的睡袋、使它不散开的带子。一到早晨便再次缩小的卧处。整装待发，便是把昨夜的暖意端正地折叠收好。"},"ICON-2076":{"nm":"帐篷入口鞋托板","de":"放在帐篷入口、把鞋整齐托住的板子。泥土在外，里头干净。用一道门槛温柔地把内外分开，这是野营的小小礼仪。"},"ICON-2077":{"nm":"豪华露营灯笼挂钩","de":"挂灯笼的弯钩。往这儿一挂，光便圆圆地漫进帐篷里。在黑暗中悬起一盏灯火的那个位置，便是我们今夜的客厅。"},"ICON-2078":{"nm":"帐篷通风窗卷夹","de":"把通风窗卷起夹住的夹子。把风路稍微开一点，帐篷里的空气便清爽许多。一道小小的缝隙，静静为整夜的呼吸留出余白。"},"ICON-2079":{"nm":"帐篷地面防潮垫","de":"铺在帐篷地面、挡住泥土与湿气的垫子。在草地上也为你铺出干爽卧处的一层。让你身处自然却不被自然浸湿，静静在旁相助。"},"ICON-2080":{"nm":"杠铃刻度卡环","de":"扣在杠铃两端、使杠片不脱落的环。完全信任举起者重量的小小锁扣。当安全稳稳托底，极限才得以刷新一格。"},"ICON-2081":{"nm":"壶铃握把套","de":"钢铁磨着手掌的最后一组，靠这一只小套，痛便消失了。比起举起重量，握到最后更难——在收尾的那一刻，手比谁都先知道。"},"ICON-2082":{"nm":"杠片嵌入楔","de":"杠片只要微微一晃，还没举起姿势便先垮了。薄薄嵌进缝隙的楔子，无声地稳住重心。坚固，总是在看不见的地方悄悄开始。"},"ICON-2083":{"nm":"杠铃卡扣夹","de":"扣上卡扣的指尖不该有半分犹豫。咔哒一声那小小的上锁，撑起接下来的整个动作。把信赖押在一只夹子上的本事，身体比脑子先学会。"},"ICON-2084":{"nm":"杠片重量色标","de":"每种重量配以不同颜色的色标，就算不识数，手也先认出来。红色重、蓝色轻，用颜色来记重量。身体出乎意料地，是借眼睛来掂量力气的。"},"ICON-2085":{"nm":"壶铃底座","de":"多亏增大触地面的底座，木地板才不会被砸出坑。运动的痕迹，只留在汗水和肌肉上就够了。不想连脚下也留成伤痕的小小心意，就铺在这里。"},"ICON-2086":{"nm":"杠铃中心标","de":"刻在杠正中央的标记，是左右平衡的基准点。准确按住中央的手，能把晃动减去一半。知道哪里是中心的那一刻，才终于能安全地举起。"},"ICON-2087":{"nm":"杠片收纳挂架","de":"用过的杠片再回到原位。按重量整齐挂在架上的景象，是为下一个人着想的安静体贴。整洁的空间才是最可靠的安全装置，有人这样相信着。"},"ICON-2088":{"nm":"杠片防滚挡","de":"放在地上的杠片悄悄滚来压住脚背的事故，总在松懈的一瞬来临。防滚挡静静拦住那一刹那。大祸不从大处来，而是从小缝里滚来的。"},"ICON-2089":{"nm":"卧推凳靠背垫","de":"撑住脊背的垫子若太硬，连呼吸都先变浅。恰当地硬、恰当地软的那道分界，只有久坐过的人才能用指尖摸索找到的平衡点。"},"ICON-2090":{"nm":"深蹲架高度插销","de":"只要一根定高度的插销，无论谁的肩膀都能让杠正好合适。身高不同的人和睦地共用同一件器械——一个小小的调节孔，造就了那份温柔的平等。"},"ICON-2091":{"nm":"器械滑轮罩","de":"在裹住滑轮的罩子里，钢索无声地转了又转。把摩擦藏进里头，只把顺滑递到手上的部件。好的装置，从不把自己付出的辛劳显露出来。"},"ICON-2092":{"nm":"卧推凳腿防滑脚","de":"套在四条腿末端的防滑脚，把凳子牢牢钉在地上。唯有不晃，才能放心地把全身力气压上去。稳定，终究是从脚尖那点小小摩擦开始的。"},"ICON-2093":{"nm":"深蹲架杠铃搁钩","de":"搁杠的钩子，总该在伸手够得着的高度。疲惫的手臂最后把杠轻轻放下的那个位置——那一寸的高度，安全地为今天的训练画上句点。"},"ICON-2094":{"nm":"器械配重插销把手","de":"插销选重量的把手要光滑，指甲才不会受伤。即便在改变重量那转瞬的小动作里，也悄悄藏着一份体察人手指的收尾，叫人感受得到。"},"ICON-2095":{"nm":"卧推凳角度锁杆","de":"锁住靠背角度的锁杆若松了，姿势便悄悄垮掉。咔哒一声固定时那份笃定。运营者每天清晨开门时，总先静静检查这一声。"},"ICON-2096":{"nm":"深蹲架安全杆托","de":"在杠铃脱手的最坏一瞬，安全杆托替你接住那份重量。正因有这看不见地总在下方待命的托架，人才终能把自己推到极限。"},"ICON-2097":{"nm":"器械钢索端帽","de":"收束钢索末端的小帽，是防止松散的最后一个结。把绳股理得不散开、端正束住的事——收尾的格调，总停留在那不起眼的端点上。"},"ICON-2098":{"nm":"镁粉袋","de":"抹在手上、抹去打滑的一捧白粉。如同舞台幕后的妆容般不显眼，今天所有动作的稳定，都从这一捧才真正开始。准备，永远从指尖起步。"},"ICON-2099":{"nm":"握力练习夹","de":"默默反复着握紧又松开的小夹子，养出手掌的力量。握力比大肌肉长得更慢，所以这也是一种静静放下急躁的练习。"},"ICON-2100":{"nm":"手指张开带","de":"套在手指间、缓缓向外张开的带子。只用过握紧之肌的手，重新找回张开的力气。手说，正如紧紧握住一般，静静松开也需要练习。"},"ICON-2101":{"nm":"粉笔粉盒盖","de":"粉盒盖只要松一点，整个书包里就会染上一片白。一个能严丝合缝盖紧的小盖子，提前挡住了这桩不起眼的狼狈。能否管住，关键总在那只盖子上。"},"ICON-2102":{"nm":"护膝缠绕带","de":"缠住膝盖、托住它的带子，要恰好停在合适的压力上。太紧会阻断血流，太松又毫无用处，那微妙的分寸，老练的手凭记忆悄悄拿捏。"},"ICON-2103":{"nm":"弹力阻力环带","de":"能伸能缩的弹力带，不靠铁块也能唤醒沉睡的肌肉。所谓阻力，未必非得沉重。即便面对轻柔的拉力，身体也总会诚实地回应。"},"ICON-2104":{"nm":"脚踝负重沙袋","de":"系在脚踝上的沙袋，让每一步都沉甸甸地往下坠。稍稍添些重量，平常的走路也成了像样的训练。这是给日常悄悄添点负担的小智慧。"},"ICON-2105":{"nm":"手腕强化卷轴","de":"用手腕慢慢卷起绳上吊着的重物的卷轴。手腕是最小、最常被遗忘的关节，而这个简单的工具，悄悄唤回了那被遗忘的力气。"},"ICON-2106":{"nm":"握力强化橡胶球","de":"在手中一握一松的橡胶球，让人坐在书桌前也能不动声色地继续锻炼。零碎积攒的力气，比一次性使出的更长久。坚持总是在这些小处生长起来。"},"ICON-2107":{"nm":"心率带搭扣","de":"缠在胸前的带子，搭扣只要稍有偏差，数字就会乱跳。哪怕只是想听听自己的心跳，也得先扣得牢固。一切测量，归根结底都始于严丝合缝的贴合。"},"ICON-2108":{"nm":"脉搏夹","de":"轻轻咬住指尖的小夹子，静静测算着脉搏。夹上去、调匀呼吸，小屏幕上便清晰浮现出心脏的节拍。身体总会毫无谎言地告知自己的状态。"},"ICON-2109":{"nm":"手腕心率带收纳盒","de":"存放手腕测量器的盒子，虽小却认得自家的物件。越是容易弄丢的小设备，越需要一个可以回去的家。妥善保管，也是温柔的一种方式。"},"ICON-2110":{"nm":"配速旗别针","de":"为奔跑者点出目标地点的小旗别针。\"只到这里\"——一个预先定下的点，把沉重的双脚一直带到终点。心中的终点线，总是亲手插下的。"},"ICON-2111":{"nm":"心跳灯帽","de":"随心跳静静闪烁的小灯。凝望着它一亮一灭的节奏，会忽然心头一暖——原来活着，竟是这样规律的一件事。"},"ICON-2112":{"nm":"计圈串珠绳","de":"一次拨过一颗珠子来计数。无需用脑子去记数字，手指会替你记住。把计数交给手，心便能全然停留在动作上。"},"ICON-2113":{"nm":"血氧夹垫","de":"夹在指尖的夹垫，静静读取血中的氧含量。当看不见的呼吸深度化作数字浮现，才再次领悟——照顾身体，归根结底是好好端详它。"},"ICON-2114":{"nm":"心率区色带","de":"用颜色划分运动强度的带子，一眼就能告诉你此刻自己有多卖力。蓝是从容，红是极限。颜色成了温柔的语言，是一份静默的约定。"},"ICON-2115":{"nm":"测量胶囊","de":"测量身体状态的小胶囊，一粒里盛着一天份的信息。无论透明壳里装着什么，那份想更了解自己一点的心意，也一同装在了里头。"},"ICON-2116":{"nm":"汗巾挂钩","de":"不随手乱搭，而是必定挂回自己钩子上的一个小习惯，便守住了整个空间的整洁。就像它为毛巾预留好归处一样，整理总在细微处闪光。"},"ICON-2117":{"nm":"水壶盖系绳","de":"拴在水壶盖上的短绳，挡住了盖子骨碌碌滚走的意外。把易丢的东西悄悄系在身上的智慧——一根小绳，便静静收走了一天份的麻烦。"},"ICON-2118":{"nm":"通风扇叶板","de":"展开便能生风的扇叶。就像炎日里为人扇凉的旧扇子，最简单的工具，递来最清凉的慰藉。一缕风，总是从指尖绽放。"},"ICON-2119":{"nm":"冷感毛巾袋","de":"存放浸湿后会变凉的毛巾的小袋子。那块降温的布在里头静静安睡，待到疲惫的后颈处，便轻盈落下，悄悄带走正午的暑气。"},"ICON-2120":{"nm":"水珠承接碟","de":"预先为凝结的水珠备好落处的承接碟。不去责怪它往下淌，而是先腾出承接的位置。厨房的温柔，总是这样无声地停驻。"},"ICON-2121":{"nm":"送风机导向叶","de":"迎面扑来的风顺着小叶片稍稍偏开的那一刻，闷热的练习室空气才终于喘上一口气。改变流向的，总是这般细微的角度。"},"ICON-2122":{"nm":"额发束发带","de":"洗脸时若刘海被水打湿，一整天都会乱了套。把发丝轻轻拢上额头的这条带子，给镜前的人捧上了清爽的5分钟。少了它，才终于察觉。"},"ICON-2123":{"nm":"水杯夹座","de":"杯子在桌沿岌岌可危地晃动时，这只夹子静静扶住了一侧。一口水告诉你——没有打翻而平安度过的一天，全靠有人替你扶住了那个边角。"},"ICON-2124":{"nm":"通风窗钩把手","de":"紧闭的窗令人憋闷，大开的窗又透着寒意。这只钩把手记住了那之间恰到好处的一道缝。所谓通风，归根结底是适度敞开的心意。"},"ICON-2125":{"nm":"软木砖护角帽","de":"磕碰受伤的，总是尖锐的棱角。所以削下一块软木，给每个边角戴上。被柔软包裹的地方，如今不会再硌疼谁的膝盖了。"},"ICON-2126":{"nm":"抱枕带把手","de":"搬运长枕比想象中麻烦。系上一根带子，便能一手轻松提起。把重物拎得轻巧的诀窍，全在于把手装在哪里。"},"ICON-2127":{"nm":"腰带搭扣紧固件","de":"有要把腰多收一格的日子，也有要松开一格的日子。最诚实知晓那天状态的，是这个小小的紧固件。它是默默记录身体坦诚的金属。"},"ICON-2128":{"nm":"四分之一砖垫块","de":"切成四等份的砖块，稳稳托住地面。不高也不低，恰好那么多的平衡。它默默示范着——所谓承托，是放低自己，托起上方。"},"ICON-2129":{"nm":"蛋形抱枕套","de":"给蛋一般浑圆的枕头穿上合身的衣裳。即便沁了汗，脱下来洗了便是。越是每天肌肤相贴的，越要有一件可换洗的——这道理，过日子的人懂。"},"ICON-2130":{"nm":"砖块调高楔子","de":"地面稍一倾斜，辛苦垒起的便全都摇晃。往那道缝里塞进一块薄楔子，世界便重拾水平。要扶正一样东西，并不需要什么大动静。"},"ICON-2131":{"nm":"带子末端结珠","de":"为防带子末端散开磨损，牢牢打上结珠。把末端收拾利落的绳子才耐用。比起开头，收尾更难——这道理，一个小结便教会了你。"},"ICON-2132":{"nm":"护膝折叠垫","de":"每每把膝盖抵在硬地板上时那阵酸痛。一张可折可展的垫子，悄悄挤进膝盖与地板之间。这是替谁的膝盖承托的一份温柔。"},"ICON-2133":{"nm":"砖块防滑底板","de":"再坚固的砖块，一旦打滑也是枉然。底板上刻的细密纹路，紧紧咬住地面。稳固不动的秘密，总藏在看不见的下方。"},"ICON-2134":{"nm":"对齐杆夹","de":"把杆子摆得笔直，再用夹子轻轻一夹固定。习惯于对齐的人都懂——把错位的东西摆得整整齐齐时，那股奇异而微小的满足感。"},"ICON-2135":{"nm":"腘绳肌拉伸环","de":"大腿后侧拉扯得几乎要叫出声时，这只环替手够向了触不到的脚尖。在独自无法触及的地方，一根绳子为腿架起了桥。"},"ICON-2136":{"nm":"脚趾分隔垫","de":"整日被关在鞋里的脚趾，也需要片刻歇息。在逐一撑开的垫子上，脚难得舒展了筋骨。从最远的地方开始放松的傍晚。"},"ICON-2137":{"nm":"姿势角度量尺","de":"我的姿势歪了几度，光凭眼睛实在估不出来。量尺静静告知角度，身体这才挺正。它是把看不见的倾斜显现出来的刻度。"},"ICON-2138":{"nm":"骨盆对齐楔子","de":"骨盆偏向一侧、僵住不动的慵懒午后。垫上一块楔子，慢慢寻回中心。不是硬掰，而是重新找回那个恰当的位置。"},"ICON-2139":{"nm":"开肩带搭扣","de":"静静舒展蜷缩双肩的带子。扣紧搭扣，弓起的背便缓缓打开。挺起舒展的双肩深吸一口气，这才有了上台谢幕的姿态。"},"ICON-2140":{"nm":"脊椎支撑楔垫","de":"仰躺下去，脊椎便描出它本来的弧线。这块楔垫静静托着，不去违逆那道曲线。好好休息的诀窍，始于承认身体天生的弧度。"},"ICON-2141":{"nm":"足背拉伸楔子","de":"拉伸足背的动作，总觉得差着点什么。垫上合适的楔子，连够不到的深度都舒爽地舒展开来。这是助你够得更远一点的小斜坡。"},"ICON-2142":{"nm":"手腕对齐托架","de":"在键盘前弯折的手腕酸麻起来时，托架悄悄探进手腕下方。最先体恤久工之手的，正是这些位置低矮的物件。"},"ICON-2143":{"nm":"护腕缠带","de":"举起重物前，给手腕缠上一圈。缠多少，心里便踏实多少。受伤前先包好的习惯，是长久运动之人静默的诀窍。"},"ICON-2144":{"nm":"臂带手机袋","de":"奔跑时手机搁哪儿，一直是个烦恼。绑在前臂上的这个袋子，把烦恼带走了。把喜欢的歌夹在手臂上奔跑，路也仿佛短了几分。"},"ICON-2145":{"nm":"握力器弹簧帽","de":"套在握力器弹簧末端、防它扎到手掌的帽子。在一握一松的反复之间，这个小盖子守护着手与铁之间的和平。是看不见之处的体贴。"},"ICON-2146":{"nm":"手套指尖护顶","de":"惯于针线的奶奶手指上，总戴着顶针。套在手套指尖的这个护顶守护着指尖。爱惜久劳之手的心意，隔了世代也分毫不差。"},"ICON-2147":{"nm":"握把老茧垫","de":"手掌上磨出的老茧，是努力留下的指纹。覆在其上的垫子，让下一次得以可能。重新包住那变硬的地方，人便又一次攀了上去。"},"ICON-2148":{"nm":"掌心防滑胶带","de":"手掌老打滑，辛苦抓住的便要脱手。缠上粗糙的胶带，手与器械便成了一体。不脱手的力量，意外地来自摩擦。"},"ICON-2149":{"nm":"前臂吸汗带","de":"运动中淌下的汗水触到手腕之前，前臂上这条带子先含住了它。汗水并不可耻——湿透的布无声地作着证。"},"ICON-2150":{"nm":"手套晾干挂架","de":"随手一扔，次日清晨便要受罪；好好挂起，风便会通宵替你晾得清爽干燥。晾干的手套那股干净气息，让明天清新地拉开序幕。"},"ICON-2151":{"nm":"运动服拉链拉手","de":"湿淋淋的手，实在抓不住那细小的拉链。装上一个拉手，一下便能拉到底。这不起眼的小环，整整救回了手忙脚乱的那1分钟。"},"ICON-2152":{"nm":"排汗透气贴","de":"在身上最热的地方贴上透气贴。被困住的热气，从贴片间悄悄溜走。这是在闷得透不过气的正中央，开出一个小小气孔的事。"},"ICON-2153":{"nm":"鞋垫缓冲块","de":"从旧鞋垫上只剜下磨损的部分，嵌进新的一块。不整个丢弃，只替换疼处的手艺。脚下的小修补，把一天的步履变得轻盈。"},"ICON-2154":{"nm":"运动服号码熨烫贴","de":"用熨斗把背号牢牢压印到衣上。热气退去间，数字稳稳落定在布面。这是让佩着同一号码的人成为一队的、那起点的印章。"},"ICON-2155":{"nm":"鞋头加固帽","de":"鞋尖总要磕碰的命运，被覆在鞋头的加固帽静静挡下。最先磨损的地方，护得最坚固。越是想穿得久的鞋，越要从鞋尖处结实起来。"},"ICON-2156":{"nm":"运动服抽绳结","de":"把运动服腰绳一拉打结的那一刻，宽松的衣服便贴合上身。这个牢实不松的结，在整个激烈动作间稳住了不致散乱。"},"ICON-2157":{"nm":"船袜防滑带","de":"船袜老往鞋里卷进去的那份窘迫。一条带子按住了那滑动。小到让人无心在意的一只袜子，这才守住了自己的位置。"},"ICON-2158":{"nm":"运动服腋下汗垫","de":"预先贴在出汗最多处的汗垫。即便湿透，衣服表面也丝毫不露痕迹。在看不见处默默工作的东西，干净地守护着舞台。"},"ICON-2159":{"nm":"鞋后跟提环","de":"穿上鞋后把后跟提环轻轻一拉，脚便嗖地滑进去。那份无需蹲下的短暂便利。忙碌的清晨，这样一个环可立了大功。"},"ICON-2160":{"nm":"按摩枪头帽","de":"依据敲打的部位更换枪头。每一处僵硬的肌肉，都另有合适的形状。是为撑过一天的肩膀，挑选并递上恰当慰藉力度的傍晚。"},"ICON-2161":{"nm":"按摩枪充电座","de":"整日要替人放松身体的那只手，也得充满电才会苏醒。红灯转绿的这段时间，稍歇片刻也无妨。闪烁一停，便又到了轻抚僵肩的时候，那时刻正悄悄逼近。"},"ICON-2162":{"nm":"按摩枪力度旋钮","de":"弱一点，再多点，到那儿。指尖一边转旋钮，一边静静与自己的身体讨价还价。今天那句\"只痛到该结实起来的程度\"的约定，工工整整地写在小刻度之间。"},"ICON-2163":{"nm":"震动球承托环","de":"再好滚的球，也需要一处暂歇之地。这个圆形托座静静怀抱着那颗想骨碌碌滚走的心，守住原位直到下一回轮到它。歇息也是运动的一部分。"},"ICON-2164":{"nm":"指压棒手柄帽","de":"套在末端的一顶小帽，便让掌心的疼痛悄然消散。坚硬与肌肤之间，总需要柔软的一层。这是先把触碰之处打磨圆润的、温柔的一寸。"},"ICON-2165":{"nm":"花生滚轮袋","de":"存放花生形滚板的小袋子。它从书包一角骨碌碌滚出来时，连昨天那句\"今天也得照顾照顾身体\"的决心，也一并跟了出来。小袋子记着约定。"},"ICON-2166":{"nm":"足底滚轮支架","de":"托脚的地方一晃，放松也跟着晃。这个撑起滚板的支架稳稳咬住地面，为疲惫的双脚备下一处可安心倚靠的位置。踏实，源于不晃动。"},"ICON-2167":{"nm":"滚轮内芯塞","de":"塞住空心芯的小塞子。看不见的内里被填实，外面才不致散乱。在滚动间谁也看不见的那个位置，这个安静的部件默默支撑着。"},"ICON-2168":{"nm":"按摩棒端帽","de":"圆圆套在棒端的帽子。不磨损、不刮伤——守住末端，归根结底就是长久相伴之道。把最先碰撞的地方，包裹得最柔软的一份心意。"},"ICON-2169":{"nm":"贴扎卷切割器","de":"单手一拉，胶带便利落地切断。打结收尾也自有小窍门，这刀刃懂得整洁收尾的那份手感。干净的收尾，让下一步变得轻盈。"},"ICON-2170":{"nm":"胶带头粘贴帽","de":"为防散开、静静压住末端的帽子。开头谁都会，可一直黏到最后却总是难。这只揿住最后一寸的小手，悄悄担起了今天的收尾。"},"ICON-2171":{"nm":"手腕加压护套","de":"给劳损的手腕缠上一层，疼痛便迟来一拍。就像有谁静静扶住的一只手，加压有时成了最温柔的保护。它不是勒紧，而是托住。"},"ICON-2172":{"nm":"护踝搭扣","de":"扣上搭扣那短短一声咔哒，心便安定下来。把脚踝牢牢裹住，便悄悄涌起一股勇气——仿佛再多迈一步也无妨。一声轻响，成了踏实的出发。"},"ICON-2173":{"nm":"护膝加压带紧固件","de":"绳子拉得越紧，膝盖便越踏实。不松脱，却又不疼痛——在那之间某处，有恰好合适的一格。紧固件每次都不忘，牢牢记住那个位置。"},"ICON-2174":{"nm":"手指贴扎剪","de":"把缠在指节上的胶带精巧剪断的小剪刀。刀尖圆润，不会伤到皮肉。越是照护用的工具，越要把刀刃磨得温柔——这把剪刀静静示范着。"},"ICON-2175":{"nm":"加压带卷绕架","de":"把松开的加压带整整齐齐重新卷好的架子。用心卷好用过之物的手，下次解开时也不致散乱。层层卷起的每一圈，都浸着今日的整洁。"},"ICON-2176":{"nm":"护胫垫绑带","de":"捆住护胫前侧垫片的绑带。先去查看会磕碰之处的心，便是准备。绑紧结实地走进操场，心中的怯意便消去了一半。"},"ICON-2177":{"nm":"护肘夹","de":"为防护肘滑落而牢牢咬住的小夹子。虽琐碎得如夹一张纸，可它一松，一切便都松了。一个小小的固定，稳稳扣住一天份的安心。"},"ICON-2178":{"nm":"拉伸环手柄","de":"握住环、把身体长长舒展，便看见比昨天又远了一寸的指尖。被拉长的，不只是肌肉。僵硬的心，也在那之间一点点舒展开来。"},"ICON-2179":{"nm":"脚趾分隔器","de":"把整日困在鞋里的脚趾间撑开，风便钻进了那狭窄的缝隙。世上有些东西，非得暂时分开才终于舒坦。脚尖也需要透气的间隙。"},"ICON-2180":{"nm":"小腿放松楔板","de":"像楔子般垫在小腿下，腿便缓缓松弛下来。一个倾斜的角度，静静送走一天份的重量。微微倚靠着躺下，那有时是最舒坦的姿势。"},"ICON-2181":{"nm":"颈部放松挂托","de":"把脖颈搭上去，暂且闭上眼。这个小小的挂托总在同一处，向肩膀低声细语——沉重的头，偶尔放下片刻也无妨。倚靠这件事，也是需要勇气的。"},"ICON-2182":{"nm":"拉伸棒端帽","de":"盖住长长伸出的棒端的一只帽。末端柔软，碰到哪里都安心。无论伸向谁，都先把棱角打磨圆润——体贴，总是这样无声地开始。"},"ICON-2183":{"nm":"指压垫凸点板","de":"把身体躺在凹凸的凸点上，每一处被戳到的地方，一天便随之抽离而去。在那似痛似爽的边界上，整日僵着的肩膀，仿佛缴械般缓缓松开。"},"ICON-2184":{"nm":"放松呼吸沙漏","de":"直到沙子落尽最后一粒，请一直把气息拉长——这是一个安静的约定。细细的沙流，静静数着吸气与呼气的节拍。忙乱的心，也在那之间暂且沉静下来。"},"ICON-2185":{"nm":"足底指压球托","de":"把球垫在脚心正中，缓缓压下去。给整日撑起全身的脚——这小小的托座静静腾出位置说：如今轮到来托住你了。撑托之物，也有歇息的时候。"},"ICON-2186":{"nm":"肩部放松环绳","de":"挂在肩上往下拉的环绳。朝着僵硬之处把绳延展开，结成团的关节便一格格松弛开来。它告诉你——想要获得自由，也需要有什么伸手来牵你一把。"},"ICON-2187":{"nm":"泳道绳圆盘","de":"划分水路的泳道绳，那一颗圆圆的节。是为了不让人与邻者相撞，而在水面上画下的温柔界线。守护各自路线的小隔板，让所有人并肩一路向前。"},"ICON-2188":{"nm":"泳道绳张力钩","de":"把泳道绳绷紧挂住的钩子。太松会被水波弯折，太紧又会绷断。寻找恰当张力的事，与收束心神的事相似，总要在那之间某处摸索着寻找。"},"ICON-2189":{"nm":"泳道颜色帽","de":"给每条泳道涂上不同颜色的小帽。是为了让人远远便能一眼认出自己的路而涂的标记。用一种颜色让人不致迷茫——指引，本就始于这般细微的善意。"},"ICON-2190":{"nm":"泳道绳挂板","de":"不用时把泳道绳整整齐齐挂起的板。为下一次出发而把绳子细心整理的手上，静静盛着想把今天好好收尾的那份从容心意。"},"ICON-2191":{"nm":"泳道绳卷收手柄","de":"把手柄一圈圈转动，将长长松开的绳卷收进来。把散开之物收拢的事，总需要耐心。一圈，又一圈——收尾就这样不慌不忙地缓缓完成。"},"ICON-2192":{"nm":"泳道端打结夹","de":"牢牢咬住绳端结、防它散开的夹子。连一截零余的节也不肯放过。要有一只管到最后的手，长长的绳子才不致散乱，好好守住自己的模样。"},"ICON-2193":{"nm":"泳道绳浮标珠","de":"浮在水面上的泳道绳浮标珠。为了不沉下去，它在自身体内满满怀了一口气。有些轻盈，源于刻意填满的一颗空心——荡漾的水波，每每将它托起示人。"},"ICON-2194":{"nm":"泳道号码旗","de":"告知泳道号码的小旗。在风中飘扬的一块布，清楚地告诉你\"这里是你的位置\"。它让人不致迷失、径直走入自己的路，是个小巧却分明的路标。"},"ICON-2195":{"nm":"泳道绳连接钩","de":"把泳道绳一根根连挂起来的钩。一只重接断路的挂钩，让水路终于得以完整。所谓连接，归根结底是在断开之物间悄悄伸出手的、小小金属的活计。"},"ICON-2196":{"nm":"出发台踏板","de":"起跑线上的踏板，原原本本承下第一跃的重量。奋力蹬出的0.1秒，脚尖踏住的那份坚实，推动着一场比赛的开始。一切腾飞，都从坚实可踏之处出发。"},"ICON-2197":{"nm":"出发握把杆","de":"出发信号前的一刻，手紧紧攥住的杆。颤抖的心要扶住在某处，出发才不致晃动。仅仅是有处可抓这一点，便让下一个动作格外清晰而坚定。"},"ICON-2198":{"nm":"仰泳旗绳","de":"向仰望天花板游泳的人告知墙已临近的旗绳。是预先告知看不见之处的一份温柔。一个细心顾着身后的信号，便让最后一下也安全起来。"},"ICON-2199":{"nm":"转身墙垫","de":"贴在转向之墙上的柔软垫子。哪怕用力撞上也不疼，把折返之处包裹得软软的。返程的路口，总是先铺好了某人静默的体贴。"},"ICON-2200":{"nm":"终点触摸板","de":"指尖触到的那一瞬，一切便结束了。漫长而喘息的路途，终点竟是这轻轻一叩。所谓抵达并非什么大事，而是精准点中自己位置的事——触摸板静静作答。"},"ICON-2201":{"nm":"出发台滑道带","de":"站在斜坡尽头，谁都会有一回屏住呼吸。越过那短暂的害怕滑下去，便扑通一声——伴着水花，笑声炸开。出发，总是从一格小小的恐惧那头开始的。"},"ICON-2202":{"nm":"转向距离标志锥","de":"在岔路口犹疑时，这个小点先开了口。在这儿转身就好，别迷路。有人看着这一抹颜色，便重新寻回自己的方向走下去。"},"ICON-2203":{"nm":"出发台角度楔","de":"腾跃前，身体压到最低的那半拍。那儿有一处小小的踏垫，撑着角度好让脚尖不打滑。每一个高高跃起的瞬间，都诞生于这道倾斜。"},"ICON-2204":{"nm":"墙角缓冲帽","de":"为了让人嬉闹撞上也不疼，棱角把自己的锋利圆圆地让了出来。别受伤的心意，被一削再削，贴附在墙上。最温柔的保护，大多这般安静。"},"ICON-2205":{"nm":"救生圈挂钩","de":"平日只是挂着而已的位置。可一旦有人落水，最先伸手去够的，正是这里。有些踏实，是不被用上反倒更好的——这世上也有这样的存在。"},"ICON-2206":{"nm":"救援抓钩长杆","de":"一举缩短那触不可及之距离的长臂。当手不够长时，这只抓钩便代手伸去。所谓救援，归根结底是把自己的指尖，递向远处某人的事。"},"ICON-2207":{"nm":"池边淋浴头","de":"\"下水前一定要冲洗干净再来。\"如同泳道引导员的口头禅，水流从头顶倾泻而下。冰凉的一冲，一天的尘埃便哗啦啦地洗落而去。"},"ICON-2208":{"nm":"防滑踏脚瓷砖","de":"为防赤脚打滑而细细凸起的纹理。在看不见的地方，静静抓住脚底。最坚实的安全，总藏在并不华丽的地方。"},"ICON-2209":{"nm":"水深标志牌","de":"踏入之前，数字先告知深浅。不知情便踏入会令人害怕的地方，读过一遍，心里便有了估量。这块牌子做的，是助人做一点小小的准备。"},"ICON-2210":{"nm":"安全线浮标绳","de":"浮在水面上、划分区域的彩色绳子。\"到这里都是安全的\"——浮标们手拉着手作下约定。正因有了界线，人才得以安心地尽情畅游。"},"ICON-2211":{"nm":"浸脚消毒池","de":"入水之前，赤脚短暂驻留的小池。从脚尖开始变得洁净的短短仪式，便盛在那里。洁净，总始于这般一步的用心。"},"ICON-2212":{"nm":"湿地警示锥","de":"一只黄色尖帽，悄悄放缓了脚步。\"这儿湿了，当心。\"以颜色代言语递出的体贴。这小小的警示，静静守住了某个差点摔倒之人的一天。"},"ICON-2213":{"nm":"急救包壁柜","de":"墙边的白色柜子轻易不会打开。可一旦打开的那一刻，便成了某人的安心。所谓紧急，总在最近的位置静静等候着。"},"ICON-2214":{"nm":"水面过滤捞网","de":"把漂在水面的叶子与尘埃静静捞起。清澈不会自来，每天都得有谁的手捞上一回。宁静的水背后，有一把勤劳的捞网。"},"ICON-2215":{"nm":"池底清洁机器人软管","de":"在众人皆眠的夜里，它也摸索着池底缓缓游走。在无人观看的时刻，是最勤勉的工人。清晨那份清澈，是这根软管整夜描下的轨迹。"},"ICON-2216":{"nm":"氯投放药桶","de":"把水守得清澈这件事，也有恰当的分量。多则变毒，少则浑浊，那之间的平衡。看不见的手，每天静静校准着那道刻度。"},"ICON-2217":{"nm":"水质检测瓶","de":"用小瓶盛一口水，问候今天的安否。眼睛看来虽一模一样，数字却不说谎。所谓安心，便是这样每天确认一回的东西。"},"ICON-2218":{"nm":"戏水板打捞耙","de":"把漂在水面的板子和浮物聚拢一处的长耙。把散乱之物归拢的手，不知怎的竟像极了人心。再纷乱，扫上一回也就齐整了。"},"ICON-2219":{"nm":"排水口盖网","de":"守着排水通道的细密网。静静甄别该放走的与该留下的。放走某物也需要过滤——这张小网无声地告知着。"},"ICON-2220":{"nm":"水温计浮标","de":"浮在水面上读取温度的小哨兵。凉还是恰好，在身体触到之前先行告知的那份温柔。入水的第一份安心，总始于这只浮标。"},"ICON-2221":{"nm":"泳池盖卷收杆","de":"把宽大的盖子团团卷起、收在一旁的把手。懂得何时展开、何时收起的工具，不知怎的格外可靠。歇息时分，等于也给水盖上一床被子。"},"ICON-2222":{"nm":"撇沫器篮桶","de":"漂在水面的浮物最终汇聚而来的篮子。有一只在看不见处接住渣滓的容器，上层的水才总是清亮。洁净的背后，堆着辛劳。"},"ICON-2223":{"nm":"泳帽晾干挂架","de":"把含着水汽的泳帽倒挂起来。一滴滴往下淌的间隙，帽子缓缓调匀呼吸。所谓晾干，归根结底是等待的别名。"},"ICON-2224":{"nm":"泳衣肩带环","de":"为防从肩头滑落而扶住带子的小环。在看不见的地方，静静守着仪态。整洁，总在这般细微的支撑之上得以成全。"},"ICON-2225":{"nm":"泳帽收纳袋","de":"湿泳帽一只只各归其位的袋子。把易散之物拢进一怀的小居所。整理，是不愿丢失的一份温柔习惯。"},"ICON-2226":{"nm":"泳衣胸垫","de":"悄然安在衣服内侧的一片垫子。表面虽看不见，却悄悄替穿者挺起了双肩。有些踏实，不在外头，而是从内里静静填满。"},"ICON-2227":{"nm":"泳帽名牌夹","de":"在泳帽末端夹住名牌的小夹子。在一模一样的物件之间，清楚地说出\"这是我的\"。一个标记，便让混淆当下了结。"},"ICON-2228":{"nm":"泳衣拉链环","de":"\"帮我把后背拉链拉上好吗？\"独自够不到的那个位置，这个小环代手拉了上去。它是帮着搭上最后一格的、温柔的一段距离。"},"ICON-2229":{"nm":"泳帽防卷板","de":"把卷得成了习惯的泳帽展平托住。静静帮着让弯曲之物重拾本来形状的承托。有伸展的手在，什么都能重新挺括起来。"},"ICON-2230":{"nm":"泳衣腰绳收束件","de":"恰当裹住腰际、扶住它不致滑落的收束件。不太紧也不太松，恰好那么多的合宜。舒适，总住在那之间的某处。"},"ICON-2231":{"nm":"泳帽翻面夹","de":"抓住里外翻反的泳帽、一下扳正的夹子。把翻面之物归正的那份手感，颇为畅快。整顿的小小快意，便来自这般细微之处。"},"ICON-2232":{"nm":"踢水板手柄绳","de":"为防踢水板脱手而缠在手上的绳子。即便被水流推搡，有处可抓便是莫大的安心。初学打水那天的颤栗，至今仍留在这根绳上。"},"ICON-2233":{"nm":"夹腿浮标束绳","de":"牢牢扶住夹在两腿间浮标的绳子。不松脱，才终于能专注于姿势。在被妥妥扶住之物上，那天的练习一寸寸深入下去。"},"ICON-2234":{"nm":"脚蹼壁挂","de":"脚蹼并排挂在墙上时，活像在水边歇息的一群鸭子。游罢的脚们抖落水珠，等待着明天。连歇息的标点，都透着几分圆乎乎的可爱。"},"ICON-2235":{"nm":"踢水板边角帽","de":"轻轻套在踢水板边角的一只小帽。让它磕碰也不疼、磨损也不坏地包住边端。久伴身旁的诀窍，在于从边角处开始爱惜。"},"ICON-2236":{"nm":"脚蹼收纳网","de":"形似蹼足的脚蹼们在网中晒着太阳。如刚出水的鸭子晾着羽毛，在网里慢慢晾干。这是为下一次畅游而悠然小憩的午睡。"},"ICON-2237":{"nm":"夹腿浮标整理标","de":"给每个浮标贴上名牌，清楚标明主人。越是众人分用之处，越要\"谁的\"分明，心里才踏实。一张小标签，立起了秩序。"},"ICON-2238":{"nm":"踢水板沥水托","de":"让积在踢水板上的水骨碌碌淌下、斜斜承住的位置。它默默告知你——倒空所含之物，才会轻盈。晾干的第一步，是好好承托。"},"ICON-2239":{"nm":"脚蹼束带收紧件","de":"把脚蹼带收紧得正合脚的小部件。松了会脱落，紧了又疼，那微妙的一格。要像戴蹼的鸭子般轻快前行，就需要这一分一毫。"},"ICON-2240":{"nm":"踢水节奏片","de":"每蹬一下脚便告知节拍的小片。一、二、三——节奏入了身，水也不知不觉成了歌。游泳也有节拍这件事，这枚小片悄悄教会了你。"},"ICON-2241":{"nm":"湿泳衣袋","de":"走出泳池的包里，最先占好位置的总是我。哪怕别的行李给脸色看也没办法——湿的东西得另装着，大伙才都能干干爽爽。湿气的隔离室，便是我担下的温柔职务。"},"ICON-2242":{"nm":"拧水压板","de":"水汽这东西，一压便悄悄逃开。压一下，再压一下——得搁在板上施以重量，它才终于缴械。对那些手腕力气无处可使的人来说，这般舞台也实属难得。"},"ICON-2243":{"nm":"泳包隔板","de":"全装进一个袋里，湿的与干的便要互相沾染。悄悄挤进那之间、静静划下一道线的活计。若一块隔板便能带来和平，那和解或许出乎意料地简单。"},"ICON-2244":{"nm":"防水鞋袋","de":"把沾满沙的鞋整只吞下，也面不改色。无论里头闹腾出什么，外面照旧干爽——这就是防水恪守的礼数。守口如瓶的袋子，到哪儿都受欢迎。"},"ICON-2245":{"nm":"泳包排水帽","de":"拧开塞子，积在包底的一天便哗啦啦流走。尽兴玩耍后的善后，总系于这一个小孔。懂得放流，也自有一番设计。"},"ICON-2246":{"nm":"吸水踏垫","de":"在玄关前静静趴着，把进门的每只脚的水汽都接住。哪怕无人知晓，地板却懂——今天又没人滑倒。默默之位，栖着默默的欣慰。"},"ICON-2247":{"nm":"湿泳帽承接碟","de":"脱下随手一扔的泳帽若无处可去，便由我来承接。虽名为碟，却盛着水珠而非食物，可若是替谁腾出位置的事，承托者也算颇为坦然。"},"ICON-2248":{"nm":"毛巾晾晒夹","de":"在晾衣绳上紧紧咬住一条毛巾的活计。任风怎样使坏，绝不松口的倔强是我的骄傲。直到在阳光下晾得清爽，一旦抓住的手，绝不先松开。"},"ICON-2249":{"nm":"防水包挂架","de":"挂上钩子的那一刻，漂泊的包终于有了住址。哪怕只是借墙上一格悬着，可还有什么比这无需担心丢失的位置更踏实呢。"},"ICON-2250":{"nm":"滑梯入场手腕带","de":"静静等候轮次的那份雀跃，全系在这一条小带上。直到戴上手腕，滑梯的队伍才开始荡漾——所谓入场，或许就是把一个约定缠上手腕。"},"ICON-2251":{"nm":"防滑垫碎片","de":"脚下早已破损，人们却浑然不觉地欢快奔跑。这块铺来防滑的垫子，要等它缺了一角，才终于被人注意到它的存在。世上有许多东西，都是靠空缺才被人记住的。"},"ICON-2252":{"nm":"更衣柜钥匙防水腕带","de":"把更衣柜钥匙护在水里，是我一辈子的工作。缠在手腕上一起扑通戏水，也要让那把钥匙保持干爽。弄丢了连衣服都找不回来，这么说来我也算个责任重大的看守人。"},"ICON-2253":{"nm":"滑道出发信号灯牌","de":"从红灯切换到绿灯的那一瞬，滑道上所有人的心都一起怦怦直跳。一块小小的信号牌，竟掌握着允许出发的大权，也藏着这么大的雀跃。"},"ICON-2254":{"nm":"漂流池救生衣扣","de":"把漂在漂流池上的人牢牢扣住的卡扣。只有听见那声咔嗒，才能安心地把身子交给水流。所谓安心，有时就是从这样一个小小的锁扣开始的。"},"ICON-2255":{"nm":"造浪池提示旗","de":"提前告诉大家海浪什么时候涌来。旗子升起便是欢呼，落下便是稍歇喘息。在波涛起伏的池边掌控节奏的，竟是一块布。"},"ICON-2256":{"nm":"滑道号码挂牌","de":"把排在第几号挂在脖子上，就再也不会搞混了。一张号码牌就排定了先后——秩序，往往就是从这样一个小小的挂牌开始的。"},"ICON-2257":{"nm":"水上腕带充值代币","de":"往手腕带上轻轻一碰，充值就完成了。在不带现金也不带卡就能畅游水中的时代，这枚小小的代币顶起了整个钱包的活。手腕轻了，心情也跟着轻快起来。"},"ICON-2258":{"nm":"水枪握把端盖","de":"握得紧才够味的水枪握把。少了一个端盖，瞄准什么的都顾不上了，整把枪在手里直打转——盛夏水仗的胜负，就系在这个小小的封口上。"},"ICON-2259":{"nm":"沙堡塔尖模具杯","de":"把湿沙用力压实再倒扣过来，一座小塔便拔地而起。明知会塌却还要再堆，最懂这份心情的就是我。对沙的建筑师来说，模具就是图纸。"},"ICON-2260":{"nm":"沙耙齿","de":"像梳头一样拖过沙地，便留下整齐的纹路。明知是海浪转眼就会抹去的花纹，耙齿仍勤勤恳恳地梳出沟壑。为转瞬即逝之物精心营造，也别有一番韵味。"},"ICON-2261":{"nm":"遮阳伞底座配重","de":"为了不让遮阳伞被风吹跑，它在伞脚下默默撑着。守护这片阴凉的，不是那华丽的伞布，而是沉沉压着的配重。看不见的重量，往往最让人安心。"},"ICON-2262":{"nm":"筛沙网手柄","de":"晃一晃筛去沙子，手里就只剩下贝壳和小小的珍宝。攥着手柄一颠一颠——海边寻宝的成败，一半就靠这张网定夺。"},"ICON-2263":{"nm":"贝壳造型沙模","de":"填满湿沙轻轻拍打，巴掌大的贝壳便在沙滩上一个接一个绽放。真贝壳虽吃不到，但这个形状谁都做得出来。这是夏天朴素的魔法。"},"ICON-2264":{"nm":"遮阳伞角度调节销","de":"太阳每挪一步，遮阳伞也得跟着转头。拔出销子再插回去，阴凉便悄悄换了个位置。躲避阳光这门技艺的关键，就藏在这小小的角度里。"},"ICON-2265":{"nm":"沙铲刃端盖","de":"套在锋利的铲刃尖端，包里就安全了。挖沙时的勇猛暂且收起，戴上一个盖子，它就成了温顺的玩具。懂得藏起锋芒，也是一种体贴。"},"ICON-2266":{"nm":"沙滩垫边角夹","de":"风一掀起垫子的边角，我就狠狠咬住。守住铺在沙地上的这一方天地，靠的终究是四角的执拗。没有翻飞作响的午后，是这些小夹子的功劳。"},"ICON-2267":{"nm":"遮阳伞下衣物挂钩","de":"往遮阳伞杆上随手一挂，湿衣物便在阴凉里晾干。避开烈日又迎着清风，一个挂钩支起了临时的晾衣绳。海边也透着过日子的智慧。"},"ICON-2268":{"nm":"防水手机挂脖袋","de":"把手机揣进怀里挂在脖上，水中也生出了拍照的勇气。把想多留一张照片的心愿用防水护住，作为回忆的保镖，它还真够能干。"},"ICON-2269":{"nm":"湿衣防水收纳袋","de":"换下的湿衣服，它二话不说整件收下抱住。不让一滴水沾到外面的行李是它的自尊，于是闭紧袋口守在包的一角。利落的收尾，从我这儿开始。"},"ICON-2270":{"nm":"戏水凉鞋脚背带","de":"为了不让赤脚的凉鞋滑脱，它轻轻裹住脚背。在沙地上蹦蹦跳跳，有一根带子就放心了。脚步可靠的同伴，虽不显眼，却始终相伴左右。"},"ICON-2271":{"nm":"防水卡挂脖套","de":"怀揣门票和卡片挂在脖上，陪你一起戏水。让你不必担心遗落、尽情扑腾，它以自身为盾守护着卡片。这正是可靠保镖的姿态。"},"ICON-2272":{"nm":"泳镜防雾布套","de":"把雾蒙蒙的泳镜内侧用布擦上一遍，水下的世界便重新变得清晰。一个小小的布套，就是打开模糊视野的钥匙。"},"ICON-2273":{"nm":"湿沙清扫刷","de":"连脚趾缝里的沙子都轻轻柔柔地刷净。把畅游大海的痕迹在家门口做最后一番整理。刷子扫过一遍，一天份的沙子才算正式道别。"},"ICON-2274":{"nm":"防水硬币拉链袋","de":"把几枚硬币紧紧关进拉链里。就算被水浸湿，叮当声依旧响亮，去小卖部的应急钱总算守到了最后。袋子虽小，却是过日子的好帮手。"},"ICON-2275":{"nm":"戏水毛巾捆扎带","de":"把卷好的毛巾用一根带子一系，便利落地挂上了背包带。双手自由，毛巾上肩。轻装戏水的窍门，就藏在这小小的捆扎里。"},"ICON-2276":{"nm":"防水腕带钥匙扣盖","de":"守护钥匙不进水的腕带，由它来收尾扣合。盖子咔哒一声合上，才能安心跳进泳池。它负责锁扣的最后一道，是个小巧却毫无破绽的句点。"},"ICON-2277":{"nm":"浮潜入水咬嘴塞","de":"含在嘴里呼吸的通道便打开，海底的景致顿时近在眼前。让你在水下也能呼吸的小小咬嘴。把呼吸借给别人，竟会如此令人雀跃。"},"ICON-2278":{"nm":"面镜防雾垫","de":"面镜内侧一起雾，水下观光也跟着泄了气。一张垫子挡住了那层模糊，清晰的视野，正是这看不见的一层的功劳。"},"ICON-2279":{"nm":"脚蹼末端收紧夹","de":"把脚蹼末端贴合脚型收紧，毫不松垮地划水。为了不让每一蹬的力气白白流失，夹子在脚尖默默打下结实的一结。"},"ICON-2280":{"nm":"面镜带保护套","de":"为了不让面镜带子扯到头发，它柔柔地裹住带子。消除了每次摘下时那一阵刺痛的一层体贴。小小的套子守护的，竟是一份温柔。"},"ICON-2281":{"nm":"浮潜排水阀盖","de":"连含住呼吸这件事，也悄悄存在着渗漏的缝隙。一个小小的阀门把那条水路悄然引回，守住可以吸气的余地直到最后。大海最感念这份细微的把关。"},"ICON-2282":{"nm":"脚蹼收纳挂钩","de":"脚蹼整整齐齐挂在墙上钉着的一个钩子上，凌乱的装备室也落下一份井然的心境。把东西归位，是面向下一次潜水最安静的承诺。"},"ICON-2283":{"nm":"面镜捏鼻垫","de":"轻轻按住鼻子的一片垫子。多亏这小小的温柔挡住灌进来的水，脸庞在冰冷的海里也不会失了自己的表情。"},"ICON-2284":{"nm":"浮潜顶端护罩","de":"圆圆地裹住浮潜管顶端的护罩，在浪头漫过时静静地把水挡开。越是默默工作的零件，越是深深托起一口呼吸的安全。"},"ICON-2285":{"nm":"脚蹼鞋底防滑条","de":"贴在脚蹼鞋底的一道细带。是脚尖在湿滑甲板上为了不打滑而抓住的一线摩擦。安全，总是从这样细微的纹理中悄然开始。"},"ICON-2286":{"nm":"氧气瓶阀门罩","de":"为盛满空气的瓶子阀门盖上的一顶帽子。不让灰尘落上，不让呼吸的通道被弄脏。盖好它，就是连下一个人的第一口呼吸都提前照料好了。"},"ICON-2287":{"nm":"呼吸器咬嘴盖","de":"接触嘴唇的地方，永远得是最干净的。罩在咬嘴上的这一片盖子，默默守护着呼吸的入口，挡住咸风与沙粒。"},"ICON-2288":{"nm":"潜水服拉链绳环","de":"系在潜水服拉链上的一个短绳环。是为了让冻僵的手也能一把拉起而特意挂上的体贴。连系好衣襟这件事里，都渗着某个人的巧思。"},"ICON-2289":{"nm":"气压表保护罩","de":"告知余气的仪表，那块玻璃由保护罩裹着。因为数字绝不能模糊。越是关乎性命的刻度，越要精心擦净再盖好。"},"ICON-2290":{"nm":"配重带卡扣","de":"把重量绕在腰上，向深处下潜的人们。卡扣松开与扣合的一瞬间，上浮与下沉的抉择，便静静汇聚于指尖。"},"ICON-2291":{"nm":"潜水灯腕带","de":"漆黑的水中，系在手腕上的一根带子牢牢攥住手电。哪怕松开手，光也跟随着你。在黑暗之中不丢失那一点微光，所以才令人安心。"},"ICON-2292":{"nm":"呼吸软管整理夹","de":"把散乱的软管归拢到一处的小夹子。提前防住缠绕，紧急关头手才不会乱摸。整理，是为未来的自己准备的一份悄悄的善意。"},"ICON-2293":{"nm":"潜水手套指尖加固","de":"每根指尖都加缝的一层加固布。拉绳子、撑岩石的地方总是最先磨损，为了提前拥住那份磨损，便多叠上了一层。"},"ICON-2294":{"nm":"氧气瓶底托环","de":"让沉重的瓶子稳稳立直的一个底托环。把险些倾倒的重量圆圆地拥住，撑出一份平衡。所谓承托，就是腾出身旁的一方，好让它不至跌倒。"},"ICON-2295":{"nm":"冲浪板尾鳍盖","de":"包住板底尾鳍锋利尖端的盖子。让你走在沙地上也不会受伤，把劈波斩浪的刀尖暂且哄睡。歇息的时候，谁迟钝一点都无妨。"},"ICON-2296":{"nm":"桨叶端保护盖","de":"守护桨叶尖端的保护盖。挡住撞上岩石的磕痕，免得它搅乱水路。爱惜了尖端，每一桨便能划得更远。"},"ICON-2297":{"nm":"皮划艇桨握把套","de":"缠在手掌与桨相遇之处的握把套。柔柔地垫住那个起水泡的地方，让你在逆流而上的途中，手也不会怨恨起桨来。"},"ICON-2298":{"nm":"冲浪蜡收纳铁盒","de":"用来盛放一块蜡的小小铁罐。把脚黏在板上的那份魔法，总是从这巴掌大的盒里取出。从一个整洁的罐子开始，今天的准备便就绪了。"},"ICON-2299":{"nm":"脚绳脚踝收紧环","de":"把连着脚踝与冲浪板的脚绳收紧的扣环。是哪怕被大浪卷走也绝不放开你的一个结。所谓连接，就是不让你漂远的一份约定。"},"ICON-2300":{"nm":"桨板充气塞","de":"含住气便变得坚挺的板子，由它封住那口气。打开便扁扁折起，合上便立于水上。一个小小的塞子，装下了一天的鼓胀与瘪沉。"},"ICON-2301":{"nm":"皮划艇座椅坐垫带","de":"把坐垫绑在座椅上的带子。为了长时间端坐划桨的腰背，让那份柔软不致滑落，把它牢牢系在原位。连舒适也需要一个结实的结。"},"ICON-2302":{"nm":"冲浪板鼻头保险杠","de":"包住冲浪板船头的保险杠。越是常常磕碰的鼻尖，越要垫上让它先变钝的一层肉。把柔软安放在打头阵的位置，是想要长久使用的决心。"},"ICON-2303":{"nm":"防水包封口扣","de":"为了不进一滴水而折上两三道再扣紧的卡扣。把珍贵之物干爽地守护好这件事，总要多动一次手。牢牢封住的那一下，就成了安心。"},"ICON-2304":{"nm":"五人制足球门网碎片","de":"曾撼动球门的那张网的一角。它一丝一缕地记着皮球破网时的欢呼。每个结里都进过球，每处破损里，那天的比赛都还鲜活着。"},"ICON-2305":{"nm":"足球打气筒嘴","de":"为没气的球吹入气息的打气筒嘴。蔫蔫滚来滚去的皮球又重新弹跳起来。所谓充气，就是把停下的游戏重新扶立起来。"},"ICON-2306":{"nm":"角旗底座","de":"在运动场角落把旗子稳稳立直的底座。虽只是标示边界的小小记号，但有了这一点，泥地才终于有了赛场的模样。"},"ICON-2307":{"nm":"护胫绑带","de":"把护胫缠在小腿上的绑带。牢牢护住常受撞击的部位，让你在激烈的身体对抗中，每一步都不再胆怯。"},"ICON-2308":{"nm":"鞋钉更换销","de":"把磨损的鞋钉换成新的所用的销。是抓住草皮的脚尖那一颗颗小牙。要想不打滑，有时得从脚底重新立起。"},"ICON-2309":{"nm":"足球气门盖","de":"堵住球的气孔的小小气门盖。看管入口，不让灌进的气漏出去。守住那份饱满，就如同直到下一场比赛都不松懈那份紧张。"},"ICON-2310":{"nm":"划线标记锥","de":"在地上划线、分出场地的锥筒。到这儿是我方，从那儿起是对方。一个小小的锥筒，就把杂乱的空地变成了有规则的游乐场。"},"ICON-2311":{"nm":"球鞋除尘刷","de":"扫去球鞋缝里夹着的尘土的刷子。比赛一结束，鞋上也积起一天份的泥土。掸去尘土的手，是向跑得卖力的双脚道一声安静的辛苦。"},"ICON-2312":{"nm":"守门员手套挂架","de":"把守门员的手套晾着挂起的挂架。是被汗水浸透的手——它扑出过多少射门——稍作歇息的地方。为了下一场比赛，湿的渐干，紧绷的心也慢慢松开。"},"ICON-2313":{"nm":"篮筐挂网钩","de":"把网挂在篮筐上的一个个小钩子。有了它们，球穿出时才会发出唰的一声。那清脆的得分声，其实就始于这些小钩。"},"ICON-2314":{"nm":"篮球放气器","de":"给太硬的球稍稍放气的工具。太过饱满，弹跳就变得粗暴。恰到好处地减一点。手感好的球，总是诞生于那份恰如其分。"},"ICON-2315":{"nm":"篮板传感垫","de":"贴在篮板背后的传感垫。把球触碰的那一瞬，清清楚楚地读成数字。连肉眼错过的瞬间，这小小的感官也记得住，判罚便更公平了一分。"},"ICON-2316":{"nm":"运球障碍锥","de":"排成一列立在运球练习路上的障碍锥。在左躲右闪的缝隙间，脚下的功夫渐渐长进。横在路上，也是教你更好地穿过去的一份好意。"},"ICON-2317":{"nm":"篮球气门刷","de":"擦净球的气门孔的小刷子。灰尘一堵，针就插不进去，于是从看不见的入口先清理干净。充气之前，总要先排空、擦净。"},"ICON-2318":{"nm":"手指缠绕胶带卷","de":"缠在手指上的一卷胶带。把扭伤的关节牢牢护住，递上再次握球的勇气。把伤处包扎起来，是一句不会停下的小小宣言。"},"ICON-2319":{"nm":"号码布夹","de":"把号码布夹在衣服上的夹子。是数字代替你的名字驰骋球场。在牢牢夹住、不让它脱落的那一下里，今天谁上场便写得清清楚楚。"},"ICON-2320":{"nm":"投篮练习靶环","de":"嵌进篮筐里、把靶心收窄的靶环。把入球的余地缩小，逼你忍住偏离。朝着窄门一次次投出，不知不觉指尖便学会了精准。"},"ICON-2321":{"nm":"篮球鞋底清洁器","de":"踏进球场之前，弯下膝盖先擦鞋底。是不想在木地板上留下一丝打滑。用洁净的脚尖踏出第一步，今天的我便比昨天更坚实了几分。"},"ICON-2322":{"nm":"排球网张力环","de":"紧绷是看不见的。只是当环把绳子拉到尽头停住的那一刻，球网便以一拃的张力把球场一分为二。那只看不见的手所托起的平衡，唤醒了整场比赛。"},"ICON-2323":{"nm":"天线固定夹","de":"总在风里摇晃的天线，一夹之下便笔直立起。是小小之物去拢住大大的晃动。在舞台幕后悄悄固定一根线缆的手，也正是怀着这般心意而动的。"},"ICON-2324":{"nm":"自由人背心挂架","de":"防守专职那件异色背心挂在墙上，等候着下一场比赛。即便不华丽，也是支撑起整片球场的名字——自由人。在最低的位置，藏着望得最远的那双眼。"},"ICON-2325":{"nm":"护膝收纳袋","de":"越是在地上翻滚，膝盖就磕得越频。把护膝细心收好的这个小袋子明白：唯有先学会好好摔倒的人，最终才能飞得更远。"},"ICON-2326":{"nm":"排球气压表","de":"光用指尖弹一弹是测不准的。表针细细颤动指向的那一格刻度。丈量一只球的气息，是比赛的第一颗扣子。诚实的气压里，才生出诚实的轨迹。"},"ICON-2327":{"nm":"躲避球边线胶带","de":"在运动场泥地上用胶带划出的一个圆圈。圈内圈外，分开了半日捉迷藏的整个宇宙。划线的手明白，规则正是游戏的开端。"},"ICON-2328":{"nm":"裁判哨座","de":"尖锐的哨声一停，便又静静放回座上的原位。是离裁判呼吸最近的地方。公正，总是始于安守本位的小事。"},"ICON-2329":{"nm":"传球练习墙靶","de":"无人接应的清晨，朝着贴在墙上的靶子把指尖托起千百次。墙是最宽容的队友。弹回的球，把疲惫的我又一次扶立起来。"},"ICON-2330":{"nm":"球网高度测量杆","de":"球网哪怕只低了一根手指，比赛便会走样。举起测量杆的那一刻，公正便不再是数字，而成了每日的习惯。看不见的精准守护着球场。"},"ICON-2331":{"nm":"起跑器角度销","de":"俯身姿势下脚尖触及的角度，那1度便决定了起跑。用一枚销固定住起跑器，调匀呼吸。起步的姿态，会一路悄悄跟到终点线。"},"ICON-2332":{"nm":"跑道分道号码旗","de":"插在每条道上的小旗在风中摇着号码。都朝同一个方向奔跑，却各有各的路。跑道把并肩与不同一同揽入怀中。"},"ICON-2333":{"nm":"接力棒端帽","de":"为了触及末棒选手之手的那一刻，端帽把棱角圆圆地裹起。接力赛中最珍贵的，不是速度，而是递向下一个人的那只手。"},"ICON-2334":{"nm":"成绩测量卷尺挂架","de":"把记录成绩的卷尺挂在墙上，免得它缠成一团。是把昨天的距离与今天的距离并排挂起的地方。成长，总是先以微小的数字之差悄然来临。"},"ICON-2335":{"nm":"跑道弯道标记锥","de":"放在弯道内侧的小锥告诉跑者路的心意。别太往里钻，也别往外散。会过弯的人，终将跑在最前。"},"ICON-2336":{"nm":"终点线彩带夹","de":"那条最先触及胸口的彩带，由夹子绷紧着等候。是一条为了被扯断而存在的带子。为了某人那短短的1秒，它整日抵着风。"},"ICON-2337":{"nm":"发令枪罩","de":"在砰的信号响起之前，枪口在罩下沉睡。是盛着出发的声音之器。寂静越深，第一发的回响便传得越远。"},"ICON-2338":{"nm":"跨栏高度调节销","de":"每把要跨的高度往上提一格，销的位置也跟着挪。恐惧也正好随之长一分。可双脚每一次都揣度着更高一点的地方，向前奔去。"},"ICON-2339":{"nm":"圈数计数转盘","de":"记不清还剩几圈时，便把转盘拨过一格。数字减少的那声轻响，又给双腿添了力气。计算剩余距离的手，守护着配速。"},"ICON-2340":{"nm":"撑竿存放立架","de":"又长又晃的撑竿，需要另设一处倚靠之地。正因是要弯曲才能腾跃的器具，才更要小心立放。妥善存放的柔韧，孕育着最高的腾跃。"},"ICON-2341":{"nm":"沙坑整平耙","de":"用耙子慢慢梳平前一位选手留下的脚印。沙坑每一次都如初次般重归平整。为了某个人的腾跃而抹去痕迹的手，就在那里，默默守候。"},"ICON-2342":{"nm":"助跑距离标记带","de":"少一步不行，多一步也不成。地上的距离标记带诚实地指出该起跳的位置。好的助跑不是一味的贪心，而是源于沉着的计算。"},"ICON-2343":{"nm":"铁饼握把握套","de":"手指一滑，掷出之前便已经掷出去了。裹住铁饼的握套那粗糙的触感拢住了旋转。松手的时机，总是始于握持的手感。"},"ICON-2344":{"nm":"铅球底托环","de":"为了不让沉重的铁球滚走，底托环静静地把它拥住。是守护掷前那份宁静的小小巢窝。越是要爆发的力量，停驻之处就越要稳固。"},"ICON-2345":{"nm":"标枪尖保护盖","de":"罩在锋利标枪尖上的盖子，覆上了一层柔软的沉默。当要远飞的器具静静躺卧时，危险便被体贴所驯服。保管之中也住着安全。"},"ICON-2346":{"nm":"跳高横杆托扣","de":"为了让横杆稍被碰到也不掉落，托扣以绝妙的平衡承着它。过与不过，那颤抖的边界由它负责。公正，寓于细微的细节之中。"},"ICON-2347":{"nm":"落地垫边角固定夹","de":"落地垫的边角一旦翘起就会受伤。固定夹把四个角牢牢压住。让飞得最高的身体最安全地落下，它在看不见处默默承托着。"},"ICON-2348":{"nm":"投掷圈边界胶带","de":"投掷之处的边界，由一条胶带划出。踩没踩到那条线，成绩便随之或生或死。这是自由与规则相遇之处、一条细细的约定。"},"ICON-2349":{"nm":"平衡木橡胶脚垫","de":"为了让窄窄的平衡木不晃动，橡胶脚垫紧紧咬住地面。在它之上将要展开的、毫无颤抖的平衡，其实是看不见的下方那份稳固所造就的。"},"ICON-2350":{"nm":"单杠握把缠绕带","de":"为了不让手掌打滑，在单杠握把上缠上缠绕带。旋转翻飞的秘密不在华丽，而在攥紧的手上。落在垫子上的汗，最懂这一点。"},"ICON-2351":{"nm":"吊环绳高度固定扣","de":"两根绳的高度哪怕只差一个手掌宽，动作便会崩塌。固定扣默默拢住那份平衡。唯有在精准对齐的高度之上，自由的飞行才得以开始。"},"ICON-2352":{"nm":"鞍马握把套","de":"裹住握把的套子，护住手掌不起水泡。在那旋转不停的动作之下，是一双反复磨破又愈合无数次的手。所谓保护，是面向下一次练习的温柔约定。"},"ICON-2353":{"nm":"高低杠间距销","de":"用销把两杠之间的间距精准对齐。身体往返的那片空隙，便成了舞台。在精准的距离之上才诞生最大胆的腾跃——指尖比谁都先知道。"},"ICON-2354":{"nm":"跳马踏板弹簧盖","de":"踏板被一蹬，弹簧便把身体推向天空。盖子牢牢裹住那份弹起之力。最短的助跑，造就最长的滞空。"},"ICON-2355":{"nm":"镁粉袋","de":"抹在手上的白粉，是抹去打滑的一道小小护符。把手伸进袋里再抽出的那短短一礼，便让恐惧沉静下来。紧张，终究也是在指尖被驯服的。"},"ICON-2356":{"nm":"体操绷带护腕缠带","de":"把绷带缠上手腕，连心里的那根弦也一起收紧。是提前抓住将要晃动的关节。一只缠得妥帖的手腕，便静静地许下更果敢的旋转。"},"ICON-2357":{"nm":"空中飞人安全环","de":"把身体抛向空中的前一刻，安全环成了那只看不见的手。当坠落的担忧消失，才终于能飞得最远。信任成全了飞行。"},"ICON-2358":{"nm":"网球桶收纳盖","de":"在堵住桶口的盖子之下，新球们含着气压沉睡。开启一罐时那一声小小的噗，唤醒了比赛的雀跃。封存，是守护新鲜的约定。"},"ICON-2359":{"nm":"球拍线张力夹","de":"线的紧绷，由夹子牢牢咬住直到最后绝不松开。因为一根线的张力决定了球的回弹。那看不见的手感，就始于这个小小的夹子。"},"ICON-2360":{"nm":"网球场线清扫器","de":"比赛一结束，便沿着球场的白线缓缓清扫。掸去泥尘，线便重新清晰起来。为下一场比赛而清出道路，那最后一份用心，让球场重获生机。"},"ICON-2361":{"nm":"球拍头护边条","de":"把球拍边框绕上一圈，再粗暴的碰撞也圆圆地接住化开。我知道边角是最先磨损的地方。代人承受磨损本就是我的本分，所以今天也站在最外圈。"},"ICON-2362":{"nm":"馆内气温芯片","de":"门一开灌进来的清晨寒风，巴掌大的芯片比人更先读到。在鼻尖发凉之前就察觉——这是为空荡的体育馆开启一天、最安静的一声问候。"},"ICON-2363":{"nm":"底线踏板","de":"对犹豫该把脚尖往哪儿放的选手来说，地上划出的一道线就足够了。不可越过的线，恰恰成了跳得最远的起跑线——踏板默默如此相告。"},"ICON-2364":{"nm":"网球篮挂架","de":"一口含住数十个球，却连一个也不漏下。把散落在球场上的东西收拢，递向下一次练习——在角落里默默忙碌的手，今天也挂在这儿。"},"ICON-2365":{"nm":"球拍握把端帽","de":"往握把末端轻轻一嵌的那一瞬，球拍才终于妥帖地落进手掌。一个小小的端帽，分隔开了打滑与安心。把末端封得牢靠，第一记挥拍才坚实。"},"ICON-2366":{"nm":"场边毛巾夹","de":"哪怕风刮得再猛，也不让费心拧好的毛巾飞走，它在球场旁紧闭着嘴坚守。守护那片刻喘息的休憩，也有某人利落的指尖触及其间。"},"ICON-2367":{"nm":"羽毛球理毛夹","de":"哪怕只有一根羽毛凌乱，飞行便会晃动。小心地把皱起的翅膀理平，羽毛球便重新备好笔直起飞的姿态。飞得远，总是始于这样细微的整妆。"},"ICON-2368":{"nm":"羽毛球筒盖","de":"为了让排列装好的羽毛球不致受潮变软，把筒口牢牢塞紧。久看便知，一点湿气就能压垮羽毛。妥善收存，本就已是比赛的一部分。"},"ICON-2369":{"nm":"乒乓球滚动托","de":"滴溜溜滚动的小球在我身上稍稍歇息调息。为了不让它咕噜噜掉落而静静托住——这是乒乓球台旁递出的、最圆的一份体贴。"},"ICON-2370":{"nm":"乒乓球拍胶皮滚轮","de":"把滚轮在胶面上轻轻一滚，陈年的灰尘便扬起，黏性也随之复苏。旋转活了球才会拐弯。球拍今天的状态，就在这一次温柔的打理中苏醒。"},"ICON-2371":{"nm":"球网测高棒","de":"球网哪怕只高一拃，比赛的纹理便会不同。终究不肯信目测的人，便把我拿来比一比。所谓公正，正是从这样用尺一板一眼量出的高度而来。"},"ICON-2372":{"nm":"羽毛球速度测量芯片","de":"划破半空的羽毛球有多快，由我静静掂量。当看不见的速度落成清晰的数字，教练接下来的一句话便分明了许多。这是把感觉化作事实的活儿。"},"ICON-2373":{"nm":"乒乓球收纳胶囊","de":"把一只圆圆的球轻轻卧进胶囊，磕痕与灰尘便退到一旁。愿你到下一场比赛都平安无事，这是整整腾出一间小屋相让的心意。"},"ICON-2374":{"nm":"羽毛球拍线挂架","de":"把松弛的线整整齐齐挂好，下一位接手的人便不会乱摸。整理，终究是给明天的自己提前写好的一张温柔便条。今天让明天轻松。"},"ICON-2375":{"nm":"乒乓球拍边缘护条","de":"胶皮易翘起的边缘，由我用一条静静拥住。边缘一裂开，连球的纹理都会乱掉。守住边角这件事，终将成为守住一分的事。"},"ICON-2376":{"nm":"壁球温度袋","de":"冰凉的球总是难以弹起。比赛前，把它像手掌般暖热揣怀的袋子。传到手里的那一点点暖意，提前定下了一轮的呼吸与节奏。"},"ICON-2377":{"nm":"长曲棍球网兜夹","de":"当网眼悄悄要松开时，我默默咬住那一个网眼。网紧实球才停得住。在看不见的地方撑住整场比赛的手，就在这儿。"},"ICON-2378":{"nm":"壁球拍尖护条","de":"越是朝着墙用力挥，球拍便越从尖端先哭起来。把那哭着的尖端静静裹住，便能多陪打一个赛季。懂得珍惜尖端的人，终究能握拍更久。"},"ICON-2379":{"nm":"曲棍球杆刃罩","de":"在锋利的刃上罩上罩子，包里也好、指尖也好，这才终于安下心来。把危险之物静静哄睡——这是收拾球杆时最先做到的、由来已久的礼数。"},"ICON-2380":{"nm":"板球擦光布","de":"把红球在布上一擦，一面便如镜子般含住了光。光泽活了球才会拐弯，投手凭指尖的感觉便知道。在用心擦拭里，也藏着一份安静的策略。"},"ICON-2381":{"nm":"长曲棍球收纳筒盖","de":"为了不让坚硬的球随意滚出去，把筒口牢牢塞紧。把易散之物在一处安抚拢齐——运营的根本，总是这般细微。"},"ICON-2382":{"nm":"壁球墙靶片","de":"钉在墙上的一个小小靶子，把摇摆不定的选手目光聚到一点。指明该瞄向何处的唯一一点——那面宽阔的墙，在这一片靶前也收窄成了分明的靶心。"},"ICON-2383":{"nm":"曲棍球杆握把套筒","de":"把用惯的握把移装到陌生的新杆上，那一刻器具便顿时成了我的。把熟悉原样换装上去的小小套筒——这正是通往适应的捷径。"},"ICON-2384":{"nm":"场地球门挂网钩","de":"得把网挂上球门，进球才终于有了进球的样子。把皮球扑进网窝那短短一瞬死死兜住的，向来都是那张网。在承接喷涌而出的欢呼之形的位置，有我在。"},"ICON-2385":{"nm":"冰刀刃罩","de":"刀刃立着，在冰面之外连一步都不敢安心。一旦离开冰，就请把我罩上吧。把锋利静静哄睡，也是冰上人长久守着的礼法。"},"ICON-2386":{"nm":"冰鞋鞋带挂架","de":"把脱下的靴子那长长的鞋带，一根一根整齐挂好。理顺不缠的鞋带，让下一次上冰更顺滑地开启。今天的收尾，便直接成了为明天所做的准备。"},"ICON-2387":{"nm":"冰刀刃擦布","de":"刚离开冰面的刀刃上，会凝起细密的小水珠。把那份湿气细细擦去，锈便绕道而行。把寒冷留下的痕迹静静收起，便是我的一天。"},"ICON-2388":{"nm":"冰鞋脚踝护垫","de":"脚踝一旦晃动，整段滑行便会崩塌。牢牢护住、稳住落点的护垫。冰上那份优雅的平衡，总是在看不见的地方最先开始。"},"ICON-2389":{"nm":"冰刀刃罩收纳袋","de":"包的一角有一个小袋，专门收好刀刃罩。不漏掉该带的东西的习惯，让装备长久不坏。整洁的包，就是一场好滑行的第一幕。"},"ICON-2390":{"nm":"冰鞋鞋垫夹","de":"为了不让靴内的鞋垫悄悄滑移，在脚下牢牢固定住。踏脚之处一旦错位，跳跃也跟着错位。抓住最低处的手，终究助成了最高的腾跃。"},"ICON-2391":{"nm":"冰刀刃套挂环","de":"为了不让刀套滑溜溜地脱落，用挂环牢牢扣锁。我知道松垮的保护终究算不上保护。一个扣好的挂环，便守护那道刃直到最后。"},"ICON-2392":{"nm":"冰鞋鞋带收紧盖","de":"把鞋带用力拉紧再用盖子锁住，从此便再也不会松开。从脚尖起就毫无缝隙地利落系紧——在踏上冰面之前，这是最稳妥系好的一结。"},"ICON-2393":{"nm":"冰刀刃水渍布","de":"从滑过一阵的刀刃上，静静收去凝结的水渍。我知道湿着不擦，刀刃便会哭。唯有干爽的刀刃，才能在冰面上清晰描出下一道弧线。"},"ICON-2394":{"nm":"滑雪杖握把盖","de":"把雪杖握把末端柔柔裹住，握着的手掌便舒服许多。划破雪原的力气，终究出自那紧握之处。一个小小的盖子，把长长的滑降一路撑到最后。"},"ICON-2395":{"nm":"单板固定器销","de":"连着板与脚的小小的销一旦脱落，眼前的整座山便停了下来。即便不起眼，也是最该先检查的一块——这份牢固的连接，便成了雪原上的自由。"},"ICON-2396":{"nm":"滑雪板刃端保护夹","de":"为了不让锋利的边刃刮到包里，把端头静静咬住。把锋利安抚哄睡——这是痛快地滑下整座山后，递上的一份温柔收尾。"},"ICON-2397":{"nm":"单板鼻头护罩","de":"把单板的前端整个裹住，迎面而来的撞击也柔柔地化开。默默守住最先撞上的位置——奔向陡坡的勇气，正是从这里开始。"},"ICON-2398":{"nm":"雪靴卡扣罩","de":"为了不让卡扣与冰冷的雪相撞而受损，静静地把它盖住。守护锁扣的又一重锁——这一个小小的罩子，悄悄延长了雪靴的一个赛季。"},"ICON-2399":{"nm":"单板脚绳环","de":"哪怕单板脱手，也不让它跑远，我把脚踝与板用一根绳连在一起。即便失手，终究不至丢失——是垂在长绳尽头、安静安心的一个环。"},"ICON-2400":{"nm":"滑雪板底刮蜡刀尖","de":"把板底凝固黏着的陈蜡，顺滑地一刮而去。唯有把旧物清得干净，新的滑行才会活起来。精心打理过的板底，把下一片雪原开启得更快了几分。"},"ICON-2401":{"nm":"滑雪板缓冲头","de":"在板子划破雪原之前，最先触碰世界的是它的鼻尖。每一次撞击，总由这块小小的橡胶率先承受。它在最前方默默磨损却从不张扬——某人的飞驰，正滑行在这份钝拙的奉献之上。"},"ICON-2402":{"nm":"雪杖底篮环","de":"雪杖即将深陷雪中的那一刻，这圈圆环替它探到了地面。它悄悄托住那一步险些落空的脚步。即便看不见，它也像一只防止滑倒、始终相伴的手。"},"ICON-2403":{"nm":"刃蜡刷盖","de":"保养结束后，趁粉末未干轻轻盖上。不让一丝纹理散乱，把今日的柔软封存起来。等下次再打开时，昨日的用心仍原封不动地等候着。"},"ICON-2404":{"nm":"防寒耳罩挂","de":"还记得吗？春天一来，耳罩就被搁在包旁短暂遗忘。可一到初雪传来消息的夜晚，它总是最先被唤起。挂起季节有专属的位置，而这只挂环从不忘记那个约定。"},"ICON-2405":{"nm":"磨刃磨石盒","de":"要让刀刃锋利，先得把石头浸湿——像奶奶的手艺般渗入的次序。连驯服钝口的工具也需要自己的栖身处，于是这小小的盒子怀抱磨石，等待下一次保养。"},"ICON-2406":{"nm":"蜡块袋","de":"造就闪亮飞驰的材料，在自己体内却凝结成块沉沉睡去。怀抱凝固块的沉甸甸。滑行总是从这份静默的重量里解开，铺展到雪原之上。"},"ICON-2407":{"nm":"暖手宝袋挂","de":"冬日散步路上，手指在口袋里最先摸索寻找的地方。它为温暖冻手的那点小暖意备下专属的家。越是寒冷的日子，这只小挂环越显得温柔。"},"ICON-2408":{"nm":"刃尖研磨石座","de":"一晃动刀刃就会歪，所以它先把自身牢牢固定。为了对别人的精准负责，自己却纹丝不动。某人笔直的刀尖，正立在这份沉默之上。"},"ICON-2409":{"nm":"防寒围脖夹","de":"寒风呼啸的上学路上，围脖即将滑落的瞬间，咔嗒一声夹住衣领。温暖也要守住位置，才真正温暖。一声小小的咔嗒，把清晨的暖意牢牢留住。"},"ICON-2410":{"nm":"打蜡熨斗罩","de":"炽热工作过的底面渐渐冷却时，一块布悄悄替它挡住灰尘。为飞驰做好准备的工具，由另一件工具来照料。关怀就这样静静地传递。"},"ICON-2411":{"nm":"刃油笔帽","de":"一旦打开干涸，下一道线就画不出来。所以盖上即是开启下一次——封住笔尖的润泽，为明日的一笔预先许下约定，这就是这枚小小的笔帽。"},"ICON-2412":{"nm":"应援花球头","de":"数百根流苏从这一点出发，随着节拍齐齐飞扬。摇曳的绚烂，总是始于牢牢绑住的那一处。舞台之下，让观众席掀起波浪的第一个结。"},"ICON-2413":{"nm":"应援棒手带","de":"欢呼了两个小时险些失手的瞬间，这根带子又把应援棒带回掌心。即使掉落也不愿失去的心意。那份温柔的焦急，在手腕上系成了一只环。"},"ICON-2414":{"nm":"观众坐垫折扣","de":"应援时猛地起身又落座，反复几十次。其间把坐垫利落折好、替你守住座位的小小金属。喧腾的观众席里，也夹着一份替人照看座位的心思。"},"ICON-2415":{"nm":"应援头巾环","de":"同样的花纹铺满整个观众席的那天，一块布把数万颗心系成同一种颜色。那波浪开始的第一个点，就是这只小环——独自的应援，在这里汇成了我们。"},"ICON-2416":{"nm":"应援拍掌板片","de":"独自拍声音很小，汇聚在观众席便化作浪潮。它最诚实地懂得：唯有相碰，才会响起。当你的掌心遇上我的掌心，应援便壮大起来。"},"ICON-2417":{"nm":"应援牌角盖","de":"把尖锐的边角圆圆包住，免得邻座的人受伤。热烈挥舞的心意里，也夹着对彼此的体贴。应援，就这样在圆润处变得更暖。"},"ICON-2418":{"nm":"应援丝带旗杆座","de":"即便飘扬停下，旗杆仍挺直地立着，等待下一声呐喊。为了挥动而暂时静静停留的位置。呐喊与呐喊之间，丝带调息的短暂静默。"},"ICON-2419":{"nm":"应援传声扇","de":"为了让一个人的喊声传到舞台尽头，扇形收窄了声音的去路。比起心意的大小，嘴边总在琢磨传递的方法。这是想传得更远的恳切所塑成的形状。"},"ICON-2420":{"nm":"应援徽章背针盒","de":"戴上胸前之前与取下之后，徽章的歇息从这里开始又在这里结束。把尖锐的背针安稳安置的小盒子。曾闪耀过的一点，也需要一处躺下歇息的地方。"},"ICON-2421":{"nm":"记分牌数字片","de":"每进一球便用手换上的年代，那份用心仍渗在其中。数字尚未到来之前，胜负曾由人的指尖一格格刻下。连一个数字里，也曾承载某人的雀跃。"},"ICON-2422":{"nm":"战术板磁子","de":"随着教练的指尖，防守与进攻交换位置。赛前脑海里所有的图景，都先从这些小点的移动里绘出。胜负，先在板上预演一遍。"},"ICON-2423":{"nm":"电子屏遮光檐","de":"为了让刺眼的数字不晃花选手的视线，这道檐切走了光。明亮有时也得被适度遮挡，才能尽到本分。在最亮的地方，最安静工作的那片阴影。"},"ICON-2424":{"nm":"翻分环","de":"一张张翻过，数字随之变换，呐喊也跟着升起。用手感刷新记录的模拟年代的痕迹。比分翻过的声响里，心脏也一同翻动的那些时光。"},"ICON-2425":{"nm":"战术绘线笔盒","de":"更衣室白板上画的所有跑位线，都出自这支笔。怀抱胜负底稿的、小而结实的收纳盒。决战前的沉默里，含着最多话语的那个位置。"},"ICON-2426":{"nm":"计分咔嗒器","de":"每按一下涨一格，伴着清脆的咔嗒声计数上升。把数字交给手指，心便能全然朝向比赛。这是替你卸下计数重担的小小节奏。"},"ICON-2427":{"nm":"电子屏电线罩","de":"绚烂的光背后，总缠着未经整理的线。它把那份杂乱齐整地盖好。唯有把看不见的地方收拾妥帖，看得见的地方才真正闪耀。"},"ICON-2428":{"nm":"战术板擦刷","de":"一局结束，便为下一幅图把面擦得干干净净。新的战略，总只能在空出的位置上才得以开始。擦拭的刷子，其实是下一个战术的第一支笔。"},"ICON-2429":{"nm":"计分旗夹","de":"把欲随风飞走的旗子利落咬住，绝不松开。让飘动的布守住原位。把记录昭告天下这件事，也得先有一只稳稳抓牢的手。"},"ICON-2430":{"nm":"裁判哨绳夹","de":"一声哨响，比赛停下又重新流动。把那份权威牢牢系在颈上的小小结扣。在哨声响起之前，把沉默齐整地系好，也是这只夹子的份内事。"},"ICON-2431":{"nm":"测量卷尺收线器","de":"把展开量过的长度，重新收回自己体内。所谓测量，终究是展开又收拢的反复。默默协助这单纯往返的把手，在精准的背后每每旋转。"},"ICON-2432":{"nm":"判定旗折盒","de":"曾果断划分界内界外的旗子，比赛结束后便齐整折好歇息。那分明的信号，也为下一次暂且调息。果断的背后，也有静静的休憩。"},"ICON-2433":{"nm":"秒表挂环","de":"把流逝的时间不挂在手腕，而挂在一处。计时前静止不动，一被呼唤便即刻奔出的时间车站。屏息等待出发信号的，秒针的小小的家。"},"ICON-2434":{"nm":"划线机轮","de":"每滚过一处，便清晰留下一道白色的路。规则的边界就这样一圈一圈、工工整整地刻在地上。比赛开始之前，最先在运动场留下足迹的轮子。"},"ICON-2435":{"nm":"裁判牌袋","de":"决断的瞬间从胸前掏出的那一张，正在这里沉睡。亮出之前始终沉默的判罚候命室。盼着别被掏出，却总是备好等候的口袋。"},"ICON-2436":{"nm":"测量砝码座","de":"称量这件事，唯有在毫不晃动的底面上才诚实。托着砝码、把自身平平展开的底座。精准测量的第一步，总是始于一处静谧之地。"},"ICON-2437":{"nm":"出发信号响杆","de":"一声响起，所有脚同时蹬地。开始无比短促，可造就这短促的手却比谁都沉着。把起跑线上的颤动，用一声咔嗒解开的手。"},"ICON-2438":{"nm":"赛用桩座","de":"名字虽陌生，做的事却分明——沉沉托起如舞台般的赛场正中央。在众人闪耀的中心，总有一根看不见的腿，默默支撑着。"},"ICON-2439":{"nm":"腹式呼吸腰带扣","de":"好声音不来自喉咙，而来自深沉的气息，腰最先懂得。让手掌感受腹部鼓起又收下的扣子。歌声的起点，总在这一口呼吸之下。"},"ICON-2440":{"nm":"呼吸练习羽毛板","de":"气息一吹羽毛轻轻摇曳，便是呼吸均匀的信号。给看不见的气息悄悄披上形状，教会歌唱的底子。这是在第一个音之前，用眼睛学习呼吸的练习。"},"ICON-2441":{"nm":"吸气沙漏","de":"玻璃里沙子如气息般缓缓流下。吸进、稍停、慢慢吐出的节拍，由沙粒替你数着。静静望着无声落下的沙，原本紊乱的呼吸不知不觉便齐整了。"},"ICON-2442":{"nm":"烛火练习托座","de":"点燃烛芯，嗓音也随着摇曳的火苗一同颤动。有人为了暂搁那点小小的颤动，用心削出了这个座。烛泪凝固堆叠的厚度里，积着一个个独自歌唱的夜晚。"},"ICON-2443":{"nm":"压腹垫带","de":"不必把手按在腹上，一根带子静静替它压着那处。气息涌上便绷紧，吐尽便悄悄松开。它陪在身旁帮身体先记住节拍，是个无言的小伙伴。"},"ICON-2444":{"nm":"呼吸续航气球帽","de":"别一口气把气球吹尽。长长地、慢慢地、推到最后试试。含着帽口吐气的时候，空气会抵达肺最深处。歌声，终究能飞得多远，取决于你忍住的那口气有多长。"},"ICON-2445":{"nm":"调息把手","de":"心越是动摇，手越想紧紧握住点什么。握住这只把手，肩膀便缓缓落下，吸气也长了一寸。学会握的方法，就是修整自己的方法，手掌最先懂得。"},"ICON-2446":{"nm":"腹肌震动带环","de":"把弹力带挂上环，细微的震动便朝腹部正中扩散。力量悄悄汇聚在大笑时颤动的那个地方。结实的中心总是这样，在谁也看不见的地方慢慢生长。"},"ICON-2447":{"nm":"吸气计数转盘","de":"一、二、三——转盘每翻过一格，吸进气息的深度便被刻下。数字多一格，歌也多撑一小节。这小小的刻度盘上，悄悄记下今日练出的肺活量。"},"ICON-2448":{"nm":"舌操匙板","de":"把舌尖该触及的位置，工工整整刻在板上。卷起、弹动、稍停的方法。流畅吐出的发音背后，藏着舌头如此记熟道路的无数个清晨。"},"ICON-2449":{"nm":"口型镜夹","de":"镜中映出的口型，被夹子轻轻固定下来。「啊」要圆圆的，「咿」要向两侧拉长。直直地面对自己的脸、打磨声音形状的，只有镜子和我的安静的二人课。"},"ICON-2450":{"nm":"发音软木海豹","de":"软木削成的小海豹坐在书桌一角听着发音。「ㄹ」的收音总打滑、灰心丧气的夜里，海豹圆圆的眼睛静静说道。没关系，再来一次吧。"},"ICON-2451":{"nm":"歌词呼吸标记针","de":"歌词在哪里换气，这枚针先告诉你。在一行末尾轻轻一插，那里便成了歌中温柔的休止符。要尽情歌唱，句子里也需要一个调息的空格。"},"ICON-2452":{"nm":"咬字练习托颌","de":"只要稍稍托住下巴，原本散乱的发音便归了位。清晰的话语不只是嘴的事，而是下巴、喉咙与气息共同造就的。这小小的托座，默默协助那微妙的平衡。"},"ICON-2453":{"nm":"元音口型支架","de":"把啊·诶·咿·喔·呜五个元音离口而出的路径原样立起的支架。静静放在镜子旁，每天搭建声音的骨架。无论哪首歌，骨干终究都始于这五个元音。"},"ICON-2454":{"nm":"绕口令卡","de":"酱油厂厂长——念着念着舌头打结、终于笑出声的一张卡。说错也真的没关系，说错本就是练习。每次跨过这调皮的句子，便有一个发音清醒过来。"},"ICON-2455":{"nm":"唇颤放松塞","de":"嘴唇噗噜噜颤动、唤醒僵硬嘴角的热身。含着塞子长长吐气，沉睡的双唇便软软舒展开来。这是为柔和开启第一句，最小巧也最温柔的准备运动。"},"ICON-2456":{"nm":"歌词段落橡皮筋","de":"在总卡住的那一段绕上橡皮筋做记号。每次看到手腕上那一圈，今天要翻越的那座山便浮上心头。越是难的小节，越要常常端详，越要久久记在心上。"},"ICON-2457":{"nm":"护颈围巾挂","de":"为了不让换季清晨的空气把嗓子冻哑，把围巾牢牢挂在挂环上。唯有温暖裹住的脖颈，才得以舒展出清亮的声音。守护嗓音，总是从先呵护脖颈开始。"},"ICON-2458":{"nm":"声带震动滚轮头","de":"滚轮的头沿着脖颈侧缓缓滚过，整夜沉睡的声带便悄悄苏醒。轻微的震动解开僵硬的紧张，迟疑的第一个音也柔和了几分。歌唱之前，替身体热身的手。"},"ICON-2459":{"nm":"哼鸣热身杯垫","de":"闭着嘴哼哼唧唧，双手捧住冒着热气的暖杯，脖颈也一同暖了。低低的哼鸣在杯垫上圆圆扩散。歌声，就这样从一口温热的暖意里开始。"},"ICON-2460":{"nm":"护嗓糖收纳盒","de":"为了喉咙嘶哑沉下的日子，把糖果静静收进盒里。登台前一刻含一颗在口中滚动，清凉的薄荷便把堵塞的嗓子畅快疏通。小盒里装着，只属于我的应急安慰。"},"ICON-2461":{"nm":"蒸汽护颈敷袋","de":"把细细蒸汽渗入的敷袋围在脖上，长时间练习而僵硬的地方便缓缓融化。如同刚加热的毛巾那般温软，递给疲惫沉下的声带一拍的休憩。"},"ICON-2462":{"nm":"声带休息沙漏","de":"今天决定不开口，那个静静许下的约定，由细细的沙粒悄悄计量。暂且闭口、爱惜嗓音。这段也是最好呵护的静谧时光，正在这里缓缓流淌。"},"ICON-2463":{"nm":"热身唇颤塞","de":"轻轻颤动嘴唇、随音高上下游走的唇颤。稍稍含住塞子，原本随意晃动的颤动便整齐了许多。把发声的第一颗纽扣温柔扣好，这是巴掌大的小工具。"},"ICON-2464":{"nm":"护嗓保湿喷帽","de":"为了在干燥的舞台上嗓子不至干裂，按下帽子喷出一缕细细的水雾。深深吸一口湿润的空气，干涸的嗓音便重新含住清亮的润泽。"},"ICON-2465":{"nm":"发声放松震动球","de":"把手掌上细细颤动的球静静握住，那震动便顺着手臂柔和地传上脖颈。轻轻摇晃唤醒因紧张而僵硬的发声器官，是个圆圆的、温柔的热身伙伴。"},"ICON-2466":{"nm":"队形顶点标记","de":"钉在舞台地板上的一个小标记。这是你的位置，那边是我的位置。众人聚在一起绘出一幅图时，它静静拉住每个人不致散开，是看不见的约定。"},"ICON-2467":{"nm":"走位箭头片","de":"箭头形状的片，清晰指出下一步的方向。在哪里转、在哪里停，地板先告知你别迷路。所谓走位，是脚尖踩过无数次记熟的地图。"},"ICON-2468":{"nm":"队形中心点针","de":"众人聚拢时静静成为基准的唯一一点。以这枚针为中心，圆圆地画出圆，队形也舒展开来。各自散落的动作，只要有正中那一点，不知不觉便寻回了秩序。"},"ICON-2469":{"nm":"交叉点楔","de":"在两条岔路相会的地方，牢牢钉上楔子。让彼此不相撞、不错位交错。在气喘吁吁擦身而过的那短短一瞬，也不让任何一人迷路。"},"ICON-2470":{"nm":"退场方向旗","de":"最后一个音的余韵消散，便朝旗子所指的方向静静退出。出场时如何，退场时也不能散乱。舞台的收尾，也有预先约定好的方向。"},"ICON-2471":{"nm":"测距卷尺夹","de":"用夹子把卷尺头牢牢咬住，一拃、又一拃便丝毫不差地精准。连人与人之间的间距，也像用尺量过般齐整对齐。一幕好看的画面，总诞生于这般细致的指尖。"},"ICON-2472":{"nm":"对齐基准绳环","de":"把绳挂上环、绷成一条直线，那根细线便成了众人并立的基准。排齐站立的模样之所以那般端正，全靠这一条看不见的笔直直线。"},"ICON-2473":{"nm":"移动路线虚线片","de":"在地板上用虚线静静画出道路的片片。沿着这淡淡的痕迹走，即便在黑暗中也不会迷路。把点与点一一相连之间，散落的脚步连成了一道流向。"},"ICON-2474":{"nm":"站位地板钉","de":"为了不忘记原位，咚地按钉在地板上的图钉。即便在漆黑的暗中，脚尖也摸索着那个小小的突起，终究找到。当准确地停在那一点上，灯光才倾泻到头顶。"},"ICON-2475":{"nm":"颈部分离专注带","de":"下巴跟着晃，嗓音也随之颤抖散乱。为了练就头静止、只让脖颈单独活动的本事，缠上了这条带。看似无比自由的动作背后，藏着这般默默的分离练习。"},"ICON-2476":{"nm":"固肩垫夹","de":"为了不让肩膀随意耸动，用夹子把垫子静静固定。让身体清楚分辨该摇动之处与该静止之处。克制的线条，总在这般小小的稳住中才得以诞生。"},"ICON-2477":{"nm":"肋骨感知腰带扣","de":"肋骨张开又重新收拢的细微纹路，由腰带静静读取。扣上扣子，呼吸的动静便清晰传到指尖。深沉而结实的发声，源自这看不见的骨头的运动。"},"ICON-2478":{"nm":"骨盆摇摆锤","de":"锤子左右缓缓摆动，静静告知骨盆所绘出的韵律。身体的中心如何移转承载重量，巴掌大的小小重量无言地教导。原来摇摆之中也有纹理。"},"ICON-2479":{"nm":"手腕旋转环","de":"把环挂上手腕，向内、向外缓缓转动，整夜僵硬的关节便柔和地舒展开来。为了让动作活到指尖，先得让手腕变得柔软。这小小的旋转，开启更大的表现。"},"ICON-2480":{"nm":"脚踝阻力环带","de":"把环套上脚踝、拉动带子，每迈一步脚尖便挂上细细的阻力。踏得越沉，腿上便悄悄添了力。羽毛般轻盈的跳跃，总是立在这般沉重的练习之上。"},"ICON-2481":{"nm":"核心专注沙袋","de":"围在腹上之后才终于明白，我身体的正中央在哪里。重量拉扯肩膀之时，原本摇晃的中心慢慢寻回原位，解下之处便留下一个挺直的姿势。"},"ICON-2482":{"nm":"脊柱对齐棒帽","de":"整天低头度日的背上一触到小小的帽，仿佛有人悄悄替你舒展了肩膀。弯着也能活下去，可挺直地站立，却是要慢慢重新学习的温柔本领。"},"ICON-2483":{"nm":"肌肉放松指压珠","de":"用力按住结块的地方，起初酸涩、随即舒爽。如同小时候奶奶手背揉过脊背的那份暖意，所谓放松，是暂且陪你多疼一会儿、守在身旁。"},"ICON-2484":{"nm":"镜面角度调节螺丝","de":"哪怕只偏巴掌大，镜子映出的便是全然不同的脸。一圈螺丝间世界倾斜又扶正，原来面对自己这件事，也需要静静的瞄准。"},"ICON-2485":{"nm":"镜面除雾擦垫","de":"在被热气蒙住的镜前，人暂时失去自己的脸。轻轻一抹便归来的脸。多亏这双拨开模糊的手，每个清晨我才重新遇见自己。"},"ICON-2486":{"nm":"三脚架脚胶","de":"三脚架脚尖、指甲大的一点橡胶，左右画面的命运。咬紧地面的力按下晃动，无颤的画面总是从看不见的摩擦里悄悄开始。"},"ICON-2487":{"nm":"角度参考网格膜","de":"膜上细细的格子线，像给眼睛用的辅助轮。构图越熟练于手，线便悄悄消失，只留下感觉。学习的痕迹，越熟练越变得看不见。"},"ICON-2488":{"nm":"录制启动踏板","de":"双手满载行李的人，最后一根手指总是脚尖。轻轻一踩录制便开始，幕后的杂务就这样连脚尖也利落地尽了本分。"},"ICON-2489":{"nm":"灯光方向夹","de":"光落向何处，全系在这指甲大的夹子的指尖。把阴影挪开一拃、衬出轮廓，为那点小小的差异，有人会出神地犹豫许久。"},"ICON-2490":{"nm":"影像对比遮帘","de":"把昨日与今日并排放着，变化才终于开口。遮帘缓缓落下的瞬间，跨越其间的时间距离便诚实地显现在画面上。"},"ICON-2491":{"nm":"遥控器手腕绳","de":"在手腕缠上一根绳，怕摔落而提着的心便松了下来。小小的保险反倒让手自由，原来被系住的，竟是放下心的温柔悖论。"},"ICON-2492":{"nm":"镜头遮盖罩","de":"相机歇息的时候，镜头也静静闭上了眼。在一粒灰尘都会在画面留下疤痕的世界里，悄悄盖上，正是想长久珍惜的心。"},"ICON-2493":{"nm":"嘴角上提带","de":"把嘴角稍稍提起，僵硬的表情便缓缓舒展。笑容终究也是肌肉，起初借工具的力，某个清晨便能凭自己的力灿烂地笑了。"},"ICON-2494":{"nm":"脸颊肌肉按摩滚","de":"缓缓滚动放松脸颊内侧，话语便流淌得顺畅许多。歌唱之前，轻轻唤醒脸庞的安静准备。表情暖过之后，也变得更温暖。"},"ICON-2495":{"nm":"微笑角度量规","de":"相机知道，笑容也有恰当的角度。拿量规反复量过，终究明白：最美的微笑，绽放于怎么也量不出的真心。"},"ICON-2496":{"nm":"眉毛活动夹","de":"眉毛哪怕动一毫米，心绪的纹理便整个改变。静静抓住表情最小部件的夹子，演技正是驾驭这般细微的指尖之事。"},"ICON-2497":{"nm":"颧骨上提贴","de":"把颧骨稍稍提起贴上，脸上便生出一处光停留的地方。指甲大的一张贴造就的立体感，舞台妆里藏着这般看不见的秘密。"},"ICON-2498":{"nm":"眨眼遮眼罩","de":"遮住一只眼，心便完整地汇聚到剩下那只眼上。眨眼练习，终究是学会把一半巧妙藏起的本事。遮住多少，便有多少表情更清晰，确是如此。"},"ICON-2499":{"nm":"口型模具夹","de":"嘎、嘉、噶……把口型对着模具比一比，模糊的发音便清晰了。每一个元音都是脸的姿势，在镜前慢慢刻进身体。"},"ICON-2500":{"nm":"表情热身袋","de":"登台前一刻，轻轻暖热脸庞的暖袋。手冷了演奏会僵，表情也是如此。微笑也需要预热，这是幕后的小小真相。"},"ICON-2501":{"nm":"额纹舒展带","de":"在额头绕上带子，深陷的皱眉便悄悄舒展。让被忧虑刻下的皱纹暂且歇息的物件。舒展的额头之下，人显得年轻了些。"},"ICON-2502":{"nm":"剧本翻页顶针","de":"套在翻纸指尖的小小顶针。把厚厚的剧本一页页翻过的那份节奏，不知不觉成了故事的节拍。读这件事里，也栖着温柔的手部习惯。"},"ICON-2503":{"nm":"情绪涂色旗","de":"喜悦是黄，悲伤是蓝。给心情涂上颜色立起旗子，看不见的情绪便随风飘扬、有了形状。感受，也能这样用手描画出来。"},"ICON-2504":{"nm":"台词重音夹","de":"把力放在这个词上，夹子静静这样告知。同样的台词，一个重音便意思全变，它便是抓住话语重心的小小标记。"},"ICON-2505":{"nm":"朗读逗号块","de":"为了告诉你在这里歇一拍而摆下的块。台词里的逗号不是停止，而是为下一句吸进的气。会好好歇息的人，终究说得最好。"},"ICON-2506":{"nm":"呼吸标示夹带","de":"带子顺着夹子上下移动，把气息的长短描在眼前。看着模仿吸气与吐气的节拍，歌的开头总是从驾驭呼吸开启。"},"ICON-2507":{"nm":"情绪骰子袋","de":"从袋里咕噜噜滚出的骰子，定下今日的情绪。掷出喜悦便高兴看看，掷出愤怒便生气看看。演技练习成了把心交给偶然的游戏。"},"ICON-2508":{"nm":"剧本支撑斜架","de":"把剧本放上斜斜倾着的支架，便不必低头。守护视线高度的这点小小斜度，静静照料因长时间练习而酸胀的颈背。"},"ICON-2509":{"nm":"低语遮挡板","de":"从这里起请低语的标记。在遮挡板后压低嗓音，观众席反倒屏息侧耳倾听。说得越小越传得越大，是舞台温柔的悖论。"},"ICON-2510":{"nm":"换角令牌盒","de":"把令牌轻轻翻过，担当的角色便变换。今天是主角，明天是守在身旁的朋友。在一同成长的岛上，谁都轮流轮到站上舞台正中央的那一回。"},"ICON-2511":{"nm":"视线固定点贴","de":"把目光静静落在相机旁的一个小点上。摇晃的视线触及一处的瞬间，画面里的眼神便清晰地活了过来。所谓凝视，终究始于停驻。"},"ICON-2512":{"nm":"取景三角尺","de":"画面一角莫名显得倾斜时，悄悄靠上三角尺便有了答案。把歪斜的扶正。在相信眼睛之前，先试着相信一下尺。"},"ICON-2513":{"nm":"镜头平视座","de":"把镜头对准人的视线高度，画面便少说几分谎。不在上也不在下，用同样的眼睛相对而望时，才拍下不加修饰的真实表情。"},"ICON-2514":{"nm":"视线引导箭羽","de":"目光顺着箭羽所指的方向悄悄跟去。悄悄牵引观者视线的小小箭。好的画面，会亲切地招手告诉你该看向哪里。"},"ICON-2515":{"nm":"拍摄走位地板片","de":"踩上熟记到磨损的走位的一点，下一个位置便立刻到手。穿行舞台的脚步，是把地板上咚咚钉下的这些小标记连起来、造出的看不见的路。"},"ICON-2516":{"nm":"镜机距离卷尺带","de":"用带子量好被摄物与相机之间的距离。在一拃之差便分远近的世界里，卷尺成了守护模糊与清晰之界的安静哨兵。"},"ICON-2517":{"nm":"歪头引导器","de":"头要歪到多少，才显得最温柔呢。顺着引导走，便悄悄明白。歪斜的角度，终究与敞开心扉的程度极为相似。"},"ICON-2518":{"nm":"对视手镜夹","de":"用夹子把手镜放在相机旁，便能看着自己的眼，同时与你对视。在镜中的我与画面里的你之间，悄悄架起一座视线之桥的小装置。"},"ICON-2519":{"nm":"拍摄标示亮灯器","de":"灯一亮，便是此刻正在拍摄的信号。一盏小灯把喧腾现场的紧张聚到一处。从光亮起的那一刻起，所有人的呼吸便齐整成同一节拍。"},"ICON-2520":{"nm":"反应铃按钮","de":"一按下按钮，清亮的铃声便清脆响起。如同好场面之后哗地爆出的掌声，某人「做得好」的一句温暖话语，就装在这只小铃里。"},"ICON-2521":{"nm":"急智抽签筒","de":"一摇，木签便哗啦作响，先把气氛炒热。谁来开场，全凭手腕一抖间分晓——被抽中的人尴尬地笑，剩下的人松了口气。连分配运气，也有温柔的规则。"},"ICON-2522":{"nm":"音效摇铃","de":"手腕轻轻一抖，叮铃一声，帮腔便插了进来。这只小铃抢先填满静默将要尴尬的空隙。数着笑的节拍，总是这边快上一步。"},"ICON-2523":{"nm":"惊喜盒盖","de":"打开之前谁也猜不到里面。那便是这盖子唯一的本职。在它微微掀起的一瞬，让尖叫与笑声一同炸开，把雀跃挂在一只铰链上。"},"ICON-2524":{"nm":"反应折扇","de":"啪地展开的声音，便是回答。把还没来得及说出口的赞叹，由扇骨替它扇送出去。折与开的手势间兴致来往，一缕心意也随风一同摇曳。"},"ICON-2525":{"nm":"惩罚轮盘","de":"指针会停在哪一格，谁也无从预知。轮盘越转越慢，心跳却越来越快——咔嗒，停下处写着今日滑稽的命运。连那份颤动都教人欢喜的几秒。"},"ICON-2526":{"nm":"感叹气泡板","de":"往头顶猛地一举，「哇」便化作字浮现出来。嘴还没来得及跟上的心意，由一张纸抢先喊了出来。反应也是需要舞台演出的。"},"ICON-2527":{"nm":"瞬停手旗","de":"旗子升起的瞬间，所有人就那样在原地僵住。连呼吸声都囚进定格画面的信号。再落下时，被停住的笑声便哗地一齐倾泻而出。"},"ICON-2528":{"nm":"怪答夹筒","de":"越是离谱的答案，越要利落地夹起挂上。当晾衣绳上挂着的错答随风摇曳时，比起正确答案，那份偏差更受宠爱的舞台。这是说错也没关系的一天的风景。"},"ICON-2529":{"nm":"姿势矫正靠背楔","de":"靠上背的瞬间，弯曲的脊柱便悄悄摸索寻回自己的路。无言托撑的小小楔子。所谓正确的姿势，唯有人扶撑时才得以安适，它在背后静静这样告知。"},"ICON-2530":{"nm":"骨盆对齐支撑块","de":"重心摇晃时垫在脚下的小小坚实。身体的平衡，终究是从脚底慢慢往上升起的。在看不见的地方托起姿势，是个无名的配角。"},"ICON-2531":{"nm":"收腹平衡球","de":"夹在腹上静静收紧，散开的中心便聚成一点。气息调得越深，球便越结实，身体一口气一口气地寻回遗忘已久的自身的轴。"},"ICON-2532":{"nm":"脊柱曲线检查尺","de":"沿着背靠上尺，看不见的弯曲便显现在刻度上。所谓挺直地站，不是抹去曲线，而是连那细微的弯曲也温柔地读出。"},"ICON-2533":{"nm":"展肩弹力环","de":"挂在肩上缓缓拉动，蜷缩的胸膛便豁然敞开。弹力总在低语着回到原位，一整天弯着的背，便随那柔和的呼唤一点点舒展。"},"ICON-2534":{"nm":"核心刺激沙袋","de":"围在腰上，沉甸甸的沙粒便唤醒沉睡的核心。再轻的动作，在这重量面前也一瞬间变得认真。撑得越久便越结实，每一粒沙都静静这样告知。"},"ICON-2535":{"nm":"尾骨支撑垫标","de":"在尾骨下静静托着的垫，那末端挂着的小小标签。给久坐疲惫的一天写上「在这里靠一会儿也可以」、贴上去的、像温柔便条般的工具。"},"ICON-2536":{"nm":"腰部支撑角度三脚架","de":"用三条腿撑住，静静拿捏腰可倚靠的角度。悄悄插进即将崩塌的姿势里的支撑。要扶住摇晃的东西，意外地三个点就够了。"},"ICON-2537":{"nm":"收颌姿势夹","de":"把下巴稍稍收住托着，散乱的颈线便寻回原位。手指大的夹子的唠叨，不知怎么有几分温柔。把头端正抬起的方法，由这小小的工具来教导。"},"ICON-2538":{"nm":"步法梯带","de":"铺在地上的带子，依次画出脚该踏的格。一格一格诚实地踩着，不知不觉步法便刻进了身体。所谓路，是越踩越清晰的。"},"ICON-2539":{"nm":"转向圆锥片","de":"立起来便「在这里转」地告知方向的小小标记。给只会笔直奔跑的脚，赠予一个转角。绕进去的路上，也藏着自有的韵律。"},"ICON-2540":{"nm":"单脚站立摇板","de":"单脚踏上去的瞬间，板便悄悄倾斜。为了战胜晃动而拼命撑住的那几秒，正是平衡最诚实的一课。不愿摔倒的脚尖道尽了一切。"},"ICON-2541":{"nm":"反应速度闪灯","de":"信号亮起的刹那，比的是手先还是眼先。闪烁的灯光不给犹豫的余地。快的手，总比想法早动半拍。"},"ICON-2542":{"nm":"之字踏点标记","de":"斜斜贴在地上、引脚之字形起舞的小小的点。比直线更难的，永远是交错。顺着点一路摸索，碎步便利落地长成了。"},"ICON-2543":{"nm":"平衡走绳扁杆","de":"把脚踏上细细的杆，世界便如一根独绳般收窄。如同走在半空的走绳艺人，把全身的专注托在一拃宽上。平衡越是收窄，反倒越清晰。"},"ICON-2544":{"nm":"敏捷反弹球手环","de":"戴在手腕上，小球便借反弹咚地弹回。在掷出与接住的刹那，反应的速度刻进指尖。所谓快，终究是不漏接回弹之物的本事。"},"ICON-2545":{"nm":"快脚环呼啦体","de":"套在脚上骨碌一转，呼啦体便不停撩拨小腿。一停下便会掉，于是脚不停地颠动。在仿佛玩耍般的活动间，脚下功夫便麻利地练熟了。"},"ICON-2546":{"nm":"足尖中心木陀螺","de":"在手掌上旋转的陀螺，失去中心的瞬间便就此停下。如同在院子里抽陀螺的儿时，所谓平衡，是唯有不停旋转才得以立住的东西。"},"ICON-2547":{"nm":"护踝紧束带","de":"裹住脚踝收紧，摇晃的踏步便利落了许多。越是易伤之处，越要温柔地扶住。一根带子，成了一步的安心。"},"ICON-2548":{"nm":"暖膝缠带","de":"缠在冰凉的膝盖上，暖意便渗进关节缝隙。僵硬的关节唯有暖过才终于变软。活动之前，递给身体的、最温暖的清晨问候。"},"ICON-2549":{"nm":"肌肉放松指压球珠","de":"在结块的地方轻轻一按，颗粒便静静抚过那个结。疼多少便松多少的奇妙安慰。连手够不到的酸痛，也由这小小的球替你拍抚。"},"ICON-2550":{"nm":"热身顺序转盘","de":"从转盘停下的那格开始唤醒身体。脖子、肩膀、脚踝——顺序交给运气，心便轻松搁下。准备运动里掺进游戏，僵硬的身体便先悄悄笑了。"},"ICON-2551":{"nm":"暖关节热敷包","de":"把热乎乎的热敷包搭在关节上，便有种冬日暖炕般的安心漾开。这是僵硬的关节慵懒舒展的时刻。被暖透的身子，这才慢慢做好了活动的准备。"},"ICON-2552":{"nm":"拉伸牵引手环","de":"握住环往回拉，僵硬的肌肉便被长长地拉伸开。在撑住的手与舒展的身体之间，进行着一场紧绷的对话。拉伸了多少，明日的动作便会轻盈多少。"},"ICON-2553":{"nm":"足底刺激凸点板","de":"赤脚站上凸点，沉睡的脚掌便猛地一惊醒来。像赤脚走过碎石路时那股微麻的刺激，踏地的感觉从脚尖一点点涌上来。"},"ICON-2554":{"nm":"伤情备忘磁扣","de":"写下\"别勉强\"，啪地贴在铁板上。疼痛的记忆容易被淡忘，便用磁铁挂在眼前。爱惜身体的心，归根结底也是从一行备忘开始的。"},"ICON-2555":{"nm":"松筋膜棱节棒","de":"缓缓滚动带棱节的棒，黏连的筋膜便一格格松解开来。是轻轻推开结节的手。攒了一整天的疲惫，这样一节节舒展开，也会轻松许多。"},"ICON-2556":{"nm":"步行线垫带","de":"笔直铺在地上，便有了一条供脚跟着走的线。再凌乱的步子，踏上这条线也不知不觉变得端正。只要画出路，脚便不再迷茫。"},"ICON-2557":{"nm":"肩部水平棒","de":"横搭在肩上，偏向一侧的失衡便悄然显露出来。所谓水平，向来是把一边压低、把另一边抬高的事。一根棒，静静点出了歪斜的习惯。"},"ICON-2558":{"nm":"头顶平衡锤","de":"想让头顶的锤不掉下来，全身就得挺成一条直线。如同从前头顶水罐行走的身影，重心是从最高处开始往下立住的。"},"ICON-2559":{"nm":"下巴角度支托","de":"轻轻托住下巴，总爱低垂的头便寻回了应有的角度。是倚着一个支托的片刻歇息。所谓端正的线条，要在有人于下方撑住时，才终于成形。"},"ICON-2560":{"nm":"步幅间距木桩","de":"钉在地上的木桩，预先量好了脚要落下的间距。不宽不窄的一个步幅，那诚实的距离。步伐的平衡，便从这小小的标记静静开始。"},"ICON-2561":{"nm":"脚尖方向楔","de":"踌躇不前的第一步，该往哪里去，脚尖先犹豫了起来。这小小的楔子替你定好方向，心也悄悄朝那边倾去。决定去路的，不是什么宏大的决心，而是脚尖所指的一拃之地。"},"ICON-2562":{"nm":"挺腰直立带","de":"\"挺直背、挺直背\"——那叮嘱的声音仿佛活在这条带子里。把佝偻了一天的身子静静挺直，压在肩头的重量竟也神奇地轻了几分。一个姿势，连心都一并扶了起来。"},"ICON-2563":{"nm":"体重分配踏板","de":"左脚七分，右脚三分。重心多压在哪边，平衡便随之而变。踏板静静地问——此刻你正往哪一边倾斜地站着？原来站直这件事，也是不断的调整。"},"ICON-2564":{"nm":"视线高度标的棒","de":"目光总往脚尖坠去。这时，远处立起的一根棒，会缓缓把视线牵引向上。望远的练习便是走远的练习，抬头的瞬间，那些看似够不着的地方也近了。"},"ICON-2565":{"nm":"行礼角度卡夹","de":"十五度、三十度、四十五度。腰弯下多深，心也随之低多少。卡上写的角度不只是数字，更是丈量对对方那份诚意的小小刻度。"},"ICON-2566":{"nm":"并手礼仪环","de":"把双手端正地合拢，雀跃的心也安稳地落定一处。这小小的环温柔地接住那不知所措、慌乱的指尖，悄悄定下行礼的第一个姿势。"},"ICON-2567":{"nm":"动线箭头磁贴","de":"迷了路的脚最先东张西望寻找的，就是箭头。啪地吸在磁铁上的一个方向，斩断犹豫，把脚步悄悄牵向该去的地方。徘徊的心，也终于有了一个方向。"},"ICON-2568":{"nm":"退场方向标识针","de":"出去的路，往往比进来的路更难。即便在熄了灯的黑暗里也清晰发亮的这枚针，静静指明最后的动线。好好离场也是舞台的一部分，到了尽头才明白。"},"ICON-2569":{"nm":"敬礼次序卡带","de":"曾有过那样的年月——先行礼的人与后行礼的人，次序分明。依照带上写的顺序俯下身，恭敬里便生出层次，礼数里也有了流动。这是守住心意先后的事。"},"ICON-2570":{"nm":"齐步对齐磁片","de":"一人错位，整列便会晃动。如同对齐脚尖咔哒吸住的磁片，所谓一同站立，是把自己的步幅悄悄让给身旁的人。以同一节拍迈出的脚步声，最为踏实可靠。"},"ICON-2571":{"nm":"舞台谢礼站位马蹄标","de":"哪怕只是舞台上行一次礼，也有该站的位置。把脚踏上如马蹄般圆圆铺开的印记，那因紧张而总是错乱的初次行礼，这才寻回了应有的模样。知道了站位，颤抖也平息了几分。"},"ICON-2572":{"nm":"谢意手势卡","de":"话里实在道不尽的感激，从指尖流淌出来。比一个心、把手放在胸口——卡上写的每一个手势，都成了把心意誊写过去的翻译。想要传达的真心，向来都有它的模样。"},"ICON-2573":{"nm":"排队间距卡桩","de":"排队这件事里也有温柔的礼数。如同与前人恰好保持一拃距离的桩，等待，是从不想推挤彼此的小小体贴开始的。稍稍隔开站着，也是一种用心。"},"ICON-2574":{"nm":"台词提示卡翻页环","de":"下一句台词总在嘴边打转时，手指悄悄翻过一张。串在环上的小纸片静静按下那阵心跳，从容地为你摊开下一句要说的话。即便紧张，流程也不会中断。"},"ICON-2575":{"nm":"流程顺序沙漏","de":"静静望着簌簌流下的沙粒，下一个环节便在心里从容地理顺。在最后一粒落下之前，不慌不忙、用眼睛去读时间的本领，是这只小沙漏教会你的。"},"ICON-2576":{"nm":"握麦练习棒","de":"在手熟之前，一根空空的棒子也重如千斤。握的角度、与嘴的距离、给手腕的力——握起又放下，无数次反复的练习，某天忽然绽放成一个自然的动作。"},"ICON-2577":{"nm":"吐字清晰舌棒","de":"嘎、纳、哒、拉。含着棒滚动发音，直到舌尖变得清晰。一字一句清楚地走过来的那一声，是在数百次含糊、模糊的时光之上，静静绽放的花。"},"ICON-2578":{"nm":"提示信号手旗","de":"开始、停止、停一拍。一面不发一言的旗，指挥着舞台的呼吸。在观众席看不见的位置静静挥动的手，把每一个节拍都严丝合缝地攥在掌心。"},"ICON-2579":{"nm":"转场铃铛","de":"叮当一声清脆响起，场景便切换了。如同黄昏集市上四散的铃声，这小小的一响，把踌躇的心轻盈地送往下一个环节。转换，向来都从声音开始。"},"ICON-2580":{"nm":"台词呼吸节拍锤","de":"吸一口气——一、二——再缓缓呼出。跟着左右摇摆的锤调匀呼吸，急促涌出的话语也不知不觉寻回了自己的节拍。话语的速度，归根结底就是呼吸的速度。"},"ICON-2581":{"nm":"主持稿折叠板","de":"折起又展开，仅此一个动作，便完整盛着今日的流程。展开那块浸满手泽的板的瞬间，先拿出什么而纷乱的心，便从容地排起了队。一次展开，便理顺了一天。"},"ICON-2582":{"nm":"呼吸节拍沙漏","de":"吸气三、屏息四、呼气六。沙流淌的时候，我的气息也静静随之流动。把呼吸一下下数过去，是慢慢照看忙碌的自己、最古老也最温柔的方式。"},"ICON-2583":{"nm":"冥想坐垫流苏饰","de":"系在坐垫边的流苏，无风也静静摇曳。盘腿坐下，便有古人坐在廊缘上调心的那份静谧，悄悄来到身旁，稍作停留又离去。"},"ICON-2584":{"nm":"调息手风铃","de":"一缕风掠过，清亮的声音便静静地鸣响。像悬在屋檐下的风铃，这东西在纷乱沸腾的心上，啪地滴下一滴清凉。原来声音也有抚平的力量。"},"ICON-2585":{"nm":"香烟承接盘","de":"香燃尽后留下的烟，缓缓落在盘上。如同节日清晨供桌前袅袅升起的香气，一缕烟轻轻地让纷扰的空气沉静下来，把满室填满了寂静。"},"ICON-2586":{"nm":"吸气呼气摆锤","de":"缓缓升起又再落下的一只锤，载着我的气息。吸气时浮起、呼气时沉落——在身体忘了如何呼吸的日子里，这只小小的计时器从头开始重新教你。"},"ICON-2587":{"nm":"冥想钟敲击槌","de":"静静敲钟一下，余韵便长长地荡漾开去。如同回响在山寺的风铃声，单是静静聆听那回响彻底消散于空气之中，心的一角便被清亮地涤净了。"},"ICON-2588":{"nm":"呼吸引导羽毛","de":"把羽毛静静放在鼻前，看不见的气息之路这才显现。微微飘动，便是呼吸得好；停住，便是憋得太久。最轻的东西，有时成了最诚实的向导。"},"ICON-2589":{"nm":"静心鹅卵石","de":"握在掌心的鹅卵石冰凉光滑。像在江边滚磨许久、把棱角都交付出去的石头，用指尖不停摩挲着，沸腾的心那些尖利的部分也一点点被磨圆。"},"ICON-2590":{"nm":"鼻息温度夹","de":"鼻尖的温度静静告诉你呼吸的深浅。凉凉进来、暖暖出去的空气，被夹子悄悄读出，把平日里全然感觉不到的呼吸清晰地呈在眼前。原来气息也有表情。"},"ICON-2591":{"nm":"心情天气贴纸板","de":"今天我的心是晴还是阴呢。挑一张小贴纸啪地贴上板的瞬间，那难以用言语说出口的心情，也化作一种天气，有了清晰的模样。原来心也需要天气预报。"},"ICON-2592":{"nm":"情绪色彩手印章","de":"喜悦是黄，悲伤是蓝。挑一种颜色用力按在纸上，心的颜色便留作印记。那连命名都茫然的情绪，也是颜色先一步靠近，静静地懂了它。"},"ICON-2593":{"nm":"今日心情花瓣片","de":"在一片花瓣上，轻轻搁下今天一整天的心情。如同春日纷飞的金达莱般轻盈娇嫩的一枚片，在日暮的尽头，低声问你今天过得可好。"},"ICON-2594":{"nm":"加油话语气泡磁贴","de":"想说的话总在嘴边打转。啪地贴上话语气泡磁贴的瞬间，那未能出声送出的一句鼓励，静静落在某人疲惫的一天之上。心意，便是这样传递的。"},"ICON-2595":{"nm":"心里话信封封缄","de":"来不及说出口的话，便妥帖地装进信封封好。如同古人用指尖抹上糨糊封缄书信，一枚封缄安全地守护着心里话。静静等着将来某日取出展读。"},"ICON-2596":{"nm":"情绪温度花苞","de":"紧闭的花苞触到暖意，一层层小心翼翼地绽开。心的温度一升便随之绽放——今天我被暖了多少，这花比言语先知道。原来心里也住进了春天。"},"ICON-2597":{"nm":"自夸手镜绳","de":"举起镜子，与镜中的我静静对视。系在绳上的小小镜面映出的，不是脸庞，而是昨天那个该被道一句\"你撑得真好\"的我。原来安慰，并不在远方。"},"ICON-2598":{"nm":"心情表情印章组","de":"灿烂的笑、盈盈的泪、撅起的赌气嘴。用力盖下表情印章，写下心的日记。在难以诉诸文字的日子，一张小小的脸替我静静说出那天的心情。"},"ICON-2599":{"nm":"情绪线团整理环","de":"再缠乱的线团，一缕缕循序解开，终究会归成一股。把交织得令人憋闷的情绪一个个挂上环，那连自己都摸不透的心，也抓住了一缕细细的头绪。"},"ICON-2600":{"nm":"安眠香囊绳","de":"悬在枕边的香囊里，隐隐的草香静静漫开。如同奶奶往衣柜深处放香的那股气味，摩挲绳子之间，整日紧绷的神经便悄然睡去。"},"ICON-2601":{"nm":"睡姿翻面板","de":"辗转反侧、到天明才好不容易入睡的夜。把躺着的姿势静静翻一面，昨夜的辗转便悄悄过渡为今晨的清爽。歇息也是一种练习，这小小的板默默地搭把手。"},"ICON-2602":{"nm":"枕边月光挂","de":"把从窗帘缝隙透进的光，挂一片在枕边。一条隐隐的河流淌过熟睡的脸庞，那个怕黑的练习生之夜，这才变得柔和。这是初次有过的小小慰藉。"},"ICON-2603":{"nm":"状态花苞片","de":"今天的状态像花苞一样闭合着。啪地按一下片，它便缓缓绽放，睡得好不好，身体先知道。连绽放前那份犹豫，都静静地惹人怜爱。"},"ICON-2604":{"nm":"睡灯灯芯罩","de":"\"别关灯。\"为了怕黑的老幺，有人在灯芯上轻轻罩上了罩子。不太亮也不太暗，只守在身旁直到入睡——是个小小而温柔的约定。"},"ICON-2605":{"nm":"晨起向日葵针","de":"插在枕边，它便像向日葵一样，悄悄朝第一缕晨光的方向转过头。即便在不想起床的日子，光召唤的地方自有它的道理，把清晨领向同一个方向。"},"ICON-2606":{"nm":"助眠香草枕刷","de":"把薰衣草和洋甘菊蘸在刷尖，往枕头上轻拂一遍。香气沁入枕套之间，一天份的紧张便从肩头缓缓松落。好眠，便从这小小的香气开始。"},"ICON-2607":{"nm":"床被一角夹","de":"一到凌晨，脚尖总爱往被子外逃。把被角用夹子牢牢夹住，整夜的暖意便逃不掉。是替\"睡个好觉\"这句话填上的一份小小看管。"},"ICON-2608":{"nm":"状态鹅卵石收纳篮","de":"一天一件好事，一颗手掌大的鹅卵石。篮里攒的石头越沉，心也悄悄越踏实。把不起眼的瞬间握在手里收进来，幸福本就是这样数的。"},"ICON-2609":{"nm":"决心集星罐","de":"每天夜里，把今日的决心捏成星星的形状，啪地落进罐里。装满之时，罐子便成了一小片夜空。空荡的罐口知道——约定，要攒起来才会发光。"},"ICON-2610":{"nm":"小奖糖果挂","de":"在疲惫一天的尽头，递给自己的一颗糖。从挂架上取一颗含进嘴里的瞬间，即便无人知晓也没关系了。因为小小的奖赏，是最诚实的鼓励。"},"ICON-2611":{"nm":"今日做到印章模","de":"蘸上墨在本子上用力一盖。\"今天做到了。\"做得好的日子，也只是撑过来的日子，都一格格同样地被填满。每一天不必完美，只要别停下盖章就好。"},"ICON-2612":{"nm":"加油旗插底座","de":"牢牢插在地上，风越烈，旗便挥舞得越有力。摇晃的东西也需要一只撑住它的手。为某人加油的心，便是这样在下方撑着。"},"ICON-2613":{"nm":"目标种子种植盆","de":"目标不是用嘴背诵，而是埋进土里的。种下一粒种子、浇着水等待的期间，焦急便慢慢化作根。在盆里生长的，不只是新芽。"},"ICON-2614":{"nm":"夸奖贴纸张贴板","de":"做得好的事就贴一张贴纸。板被五彩斑斓填满得越多，那些无心溜走的日子便以色彩复苏。年幼时的我们便懂得——夸奖，越贴越鲜明。"},"ICON-2615":{"nm":"决心丝带系结环","de":"把丝带穿过环打结的手。牢牢地不让它松开，却又不太用力。所谓决心恰似这结，系得太紧便断，太松便悄悄滑落。"},"ICON-2616":{"nm":"小成就贝壳片","de":"在海边捡的贝壳上，写下小小的成就。如同被浪削了又磨、一路走到这里的一片，你的每一天也滚动了许久，闪着光润的光。经住了时间的，都会闪耀。"},"ICON-2617":{"nm":"奖牌悬挂钩","de":"费力赢来的奖牌，不挂进抽屉，而挂在视线高度。挂在钩上的那份重量，每天清晨让人挺直了肩。奖赏不是用来藏的，而是挂在那里、好让你凝望的。"},"ICON-2618":{"nm":"梅雨伞接水杯","de":"梅雨顺着伞尖滴答滚落。垫上一只杯子，玄关便不会被淋湿。挡不住倾泻而下的东西，却能为它指定一个落下的位置。"},"ICON-2619":{"nm":"降温冷敷袋","de":"盛夏的后台，往脖颈悄悄一贴的一只冰凉袋子。烘烘升腾的热气，一拍间沉静下来。\"喘口气吧。\"比暑热先一步照看我的那只手，叫人安心。"},"ICON-2620":{"nm":"风扇叶片固定夹","de":"猛烈旋转的叶片，也被一个夹子静静停住。风越猛，越需要有个能牢牢抓住它的东西。飞速旋转的东西，终究是看有谁帮着抓住，才变得安全。"},"ICON-2621":{"nm":"湿鞋烘干棒","de":"淋了雨的鞋，一夜之间连心情都变得潮乎乎的。把棒插进鞋里，到早晨便干爽得能再穿上了。湿了的东西不是用来丢的，而是好好晾干的。"},"ICON-2622":{"nm":"雨靴除泥踏板","de":"沾了满满田埂泥的雨靴。在踏板上蹭蹭擦掉，这才踏上地板。把外头的泥泞留在门前再进屋，是把家保持洁净的古老礼数。"},"ICON-2623":{"nm":"夏日踏脚冷瓷片","de":"赤脚先知道。把脚掌贴上铺在夏日地板上的瓷片，正午的热气便在一掬清凉里悄悄退去。单凭一点小小的冰凉，漫长的季节也变得能熬过去。"},"ICON-2624":{"nm":"防雨水门槛带","de":"只不过在门槛上围了一条带，雨水便再也越不进里头。是分隔内外的一条细细的线。该守护的地方，比起宏大的墙，更适合一道结实的边界。"},"ICON-2625":{"nm":"蚊香承接盘","de":"夏夜，把蚊香搁在承盘上，便升起一缕呛人又亲切的烟。如同圆圆地烧尽的香，夜也慢慢深了。是躺在凉床上数星星的那个年月的气味。"},"ICON-2626":{"nm":"防暑凉袖套环","de":"用袖套遮住被太阳晒得刺痛的手臂。用环牢牢扣在衣袖上，正午的活计也变得能熬。所谓清凉，是把贴身的一处遮上一拃的小小心意。"},"ICON-2627":{"nm":"扫落叶手扫帚","de":"用手扫帚把满院飘落的落叶刷刷扫拢。一个季节在脚下沙沙作响。所谓整理某样东西，有时也是为将要送走的，妥帖地送上一程。"},"ICON-2628":{"nm":"换气窗支撑棒","de":"在憋闷的房里插一根棒，把窗稍稍支开。秋风悄悄进来，带走积了许久的浊气。换气，是把里头积存的与外头静静交换的一个小小气口。"},"ICON-2629":{"nm":"橡子袋塞","de":"像松鼠一样把橡子塞满口袋，再用塞子堵住袋口。生怕滚出去，堵得严严实实。想守住攒下之物的心，是过冬的小生灵们由来已久的本能。"},"ICON-2630":{"nm":"秋被掸尘拍","de":"把整个夏天盖的被子晾在院里，用拍子啪啪地拍。尘土之间漫开阳光的气味。要把陈旧的季节掸净，才能盖上新的季节——手腕先记住了这个道理。"},"ICON-2631":{"nm":"窗缝挡风绳","de":"用一根绳，把从窗缝渗入的冷风牢牢挡住。一条细细的线，把房里的暖意守到最后。大寒总是从小缝隙开始的——备冬之事，对此心知肚明。"},"ICON-2632":{"nm":"落叶滤网罩","de":"罩在雨水槽上的滤网。把落叶妥帖地滤下，只让水流过去。想要畅通无阻地流，就得定好让什么通过、把什么留住——秋日的屋檐如是说。"},"ICON-2633":{"nm":"干草捆束夹","de":"用夹子把晒得干透的草捆牢牢扎住。是把要四散的东西拢成一处的手。在夏日的青绿尽数褪去之处，只要攒着，用处便原原本本地留着。"},"ICON-2634":{"nm":"秋风温度摆","de":"风一吹，摆便轻轻摇曳。凭那摇摆的幅度，揣度今天的秋有多深。温度不是数字，而是借由某样轻轻摇曳的东西，最先触到手心。"},"ICON-2635":{"nm":"外套口袋暖手宝套","de":"\"手冻着了吧。\"放在外套口袋里的暖手宝套，悄悄暖着冻凉的手指。先一步体谅他人寒冷的心，向来都静静装在口袋里。"},"ICON-2636":{"nm":"窗结露接水台","de":"冬窗整夜流下的泪，被台静静地接住。是内外温差造就的一道小小水路。温差越大的地方，流淌的东西越多——清晨的窗每天都展示着这一点。"},"ICON-2637":{"nm":"火炉挡火安全网","de":"在熊熊燃烧的火炉前立起安全网。暖意靠近，危险恰好隔开一拃。把火放在身旁却不致灼伤，是照看某人的最基本的距离。"},"ICON-2638":{"nm":"冬被压实夹","de":"厚厚的冬被总往下滑时，用夹子压住、静静帮它定住位置。沉甸甸的暖意，要牢牢攥住才不负其值。冬夜的安稳，便是这样结结实实地守住的。"},"ICON-2639":{"nm":"刮霜铲","de":"清晨车窗上白白结起的霜，用铲子刷刷刮掉。模糊的视野一道道透了开来。再冻结的东西终究也能刮下来——冬日清晨的指尖如此告诉你。"},"ICON-2640":{"nm":"热水桶盖保温套","de":"给盛着热水的桶套上保温套。生怕它整夜凉掉，多裹上一层暖意。让温暖久留的法子，归根结底就是用某样东西精心地抱住它。"},"ICON-2641":{"nm":"门缝纸压条棒","de":"钻过门缝的刀风，在遇见你的瞬间猛地一顿。是把窗户纸下摆紧紧压住的一根棒。房里的暖意这才守住了自家人——冬天，便是凭这般小小的执拗暖暖地过的。"},"ICON-2642":{"nm":"脚炉承接盘","de":"垫在脚炉下的圆盘。独自全数承下灼热，却在底面不留一点烟灰。当某人的脚尖被慵懒地暖热时，我那份的一天，便静静地结束了。"},"ICON-2643":{"nm":"擦露吸水布环","de":"为了让擦过清晨窗上水珠的布不至于无处可去，一只环挂在墙上等着。比起饱饱地吸饱，重新干爽地等待明日清晨，才是吸水真正的心意。"},"ICON-2644":{"nm":"冬手套烘干挂","de":"打完一场雪仗的手套，在暖气片旁张开了手指。挂在架上、袅袅冒着热气的景象。是在鼻尖冻红的午后尽头到来的、冬日里最平和的一场晾晒。"},"ICON-2645":{"nm":"掸尘羽毛替换","de":"羽毛磨秃了，便换上新羽毛。驱赶灰尘的那端重新变得蓬松的瞬间。清洁工具也有它的换季——这小小的替换，在掌心上悄悄告诉你。"},"ICON-2646":{"nm":"拧抹布手柄","de":"为了帮你省点手腕力气而装上的手柄。一拧，抹布便自己吐出水来。在搓衣板前哼哧使劲的年月，再见了。在持家中，一把窍门便成了温柔。"},"ICON-2647":{"nm":"地刷更换刷板","de":"地刷磨秃了，便只把刷头嗖地换掉。柄还是原来的，手熟的重量也还是原来的。在长用的物件里，住着一份不愿整个丢弃、小而坚实的温柔。"},"ICON-2648":{"nm":"黏尘滚筒替芯","de":"撕完黏尘滚筒最后一张，总觉得空落落的。这时换上的一卷新芯。是要把毛衣上沾的一根毛球都彻底负责到底的、执着又温柔的替换之约。"},"ICON-2649":{"nm":"角落除尘刮","de":"扫帚够不到的边角，灰尘也悄悄安起了家。用细细的尖端在角落咯地一刮。连看不见的地方都打理周到的心，正是持家的自尊。"},"ICON-2650":{"nm":"扫帚清理梳","de":"扫地的扫帚也需要一份歇手的照料。用这把梳子把卡在刷毛间的头发刷刷梳出来，干完一场活的扫帚，这才备好了下一次扫地。"},"ICON-2651":{"nm":"地板纹理打蜡垫","de":"顺着地板纹理上一层蜡，木头便慢慢想起久违的光泽。脚掌似滑非滑，全屋都亮晶晶、心情舒畅地微笑着的午后。"},"ICON-2652":{"nm":"门缝除尘扫","de":"我盯上了住在门缝里的灰尘。门每开合一次便悄悄积起的那些，用扁薄的身子扫拢收起。缝越窄越深，便越是轮到我出场。"},"ICON-2653":{"nm":"踏垫滤尘帽","de":"为了不让玄关踏垫吞下的灰尘又漏到外面，一只网帽作为最后的门卫立着。沾泥的鞋从外头世界带来的灰尘，就只准放进到这里为止。"},"ICON-2654":{"nm":"水龙头水垢刷","de":"悄悄盘踞在水龙头脖颈上的水垢，被小刷子绕着圈刮下来。每天手都拂过的地方，越该闪亮——那便是这把小刷子守护的浴室礼数。"},"ICON-2655":{"nm":"排水口发网帽","de":"顺着排水口冲走的头发，被我静静地拦住。用一只帽子挡下\"堵塞\"这场小灾难。圆圆又结实的英雄的一天，向来在脚下静静流淌。"},"ICON-2656":{"nm":"瓷砖缝刮","de":"白瓷砖之间黑乎乎漫开的缝隙，那积年的岁月被尖端轻轻刮下。窄窄的缝隙一干净，整间浴室便如新的一般，轻快地舒了口气。"},"ICON-2657":{"nm":"花洒清洗针","de":"把堵住的花洒孔用针尖咯地一通，半天只滴答作响的水便又痛快地倾泻而下。一处小堵塞被疏通的、那痛快淋漓的清晨水声。"},"ICON-2658":{"nm":"马桶刷收纳杯","de":"马桶刷也要在干处歇着才真正卫生。端端正正插在接住水汽的小杯里，等着下一次轮到自己。器具的品格，不在使用，而在收纳里显露。"},"ICON-2659":{"nm":"霉斑清洁海绵","de":"在瓷砖边角黑黑漫开的霉斑，海绵郑重地请这位执拗的客人退场。轻轻一擦过后，浴室便又敞亮地回到本来的洁白。"},"ICON-2660":{"nm":"镜面除雾刮","de":"淋浴完雾蒙蒙的镜子前，刮片划过一道，清晰的我便回来了。与方才躲在雾后片刻的、今日的表情重逢的瞬间。"},"ICON-2661":{"nm":"浴室拖鞋挂","de":"把湿拖鞋倒挂起来，水便滴答流下，里头干爽地晾干。是为了不让下一个人的脚冰凉。小小挂钩的体贴，总是早一步迎候在前。"},"ICON-2662":{"nm":"指甲刷收纳盒","de":"刷指甲缝污垢的小刷子，也有自己的家。嗖地收进盒里，不沾水汽、干爽地晾着，等着下一个洗手台。整洁，向来从整理静静开始。"},"ICON-2663":{"nm":"牙刷消毒杯盖","de":"一天两次与口相对的牙刷，也需要一处小小的栖息地。消毒杯盖啪地盖上的瞬间，便从浴室里飘荡的湿气中，静静守住了一格清洁。"},"ICON-2664":{"nm":"棉签便携胶囊","de":"为了不让旅行包里的棉签折断或散落，一只胶囊温温柔柔地揽进怀里。越是小东西，越要提前备好，才能在陌生的路上不慌不忙。"},"ICON-2665":{"nm":"哈气检测迷你板","de":"往掌心呵口气，再轻轻贴上迷你板，哈气一触便白白地蒙起来。寒冷的日子里\"我活在这里\"最可爱的证据，被这小小的板默默记下。"},"ICON-2666":{"nm":"挖耳勺收纳盒","de":"挖耳勺搭着包出门，尖端容易钝掉。于是备下的一处小小的家。即便带着走，尖端也不会受损，纤细的器具在里头安然入睡。"},"ICON-2667":{"nm":"手帕折叠夹","de":"把四角折得整整齐齐的手帕，夹子轻轻一咬，防住它在包里散乱。叠得端正的一张，无论在哪个时刻取出，都递上一份静静的体面。"},"ICON-2668":{"nm":"创可贴收纳盒","de":"膝盖擦破的日子，打开盒子，各式创可贴排成一列等着你。连小伤口都懂得大惊小怪的那份温柔。急救盒，总该放在伸手可及的近处。"},"ICON-2669":{"nm":"掌心指纹擦","de":"把玻璃上残留的指纹擦一擦，那踌躇的手留下的痕迹便消失了。每一处碰过的地方都曾模糊的窗外世界，重新变得透明——是手掌大小的小小魔法。"},"ICON-2670":{"nm":"垃圾分类投入隔板","de":"纸在这边，罐在那边。一块隔板，分开了险些混作一团的命运。所谓分类回收，归根结底是精心区分的心，而那第一道线，由这结实的隔格一笔一画地划下。"},"ICON-2671":{"nm":"撕贴纸铲","de":"黏得牢牢的贴纸，到我面前也悄悄投降。把扁平的铲刃轻轻探进边角，便干干净净、不留一丝痕迹地剥落——好一场痛快的告别。"},"ICON-2672":{"nm":"美纹胶带切割锯齿","de":"想用美纹胶带，不必再到处翻找剪刀。对着锯齿一拉，便顺着纹理咔地断开。是做手帐的指尖最珍爱的、小巧又麻利的搭档。"},"ICON-2673":{"nm":"边角粘合护角铁","de":"从内侧牢牢撑住翘起边角的小铁。在看不见的地方默默守住棱角。外表端正的东西背后，大多有这样一根隐藏的支柱。"},"ICON-2674":{"nm":"贴纸纸保护膜筒","de":"为了不让珍贵的贴纸纸皱掉或受潮，与保护膜并排着在筒里安睡。收集的喜悦旁边，向来都跟着一份想把它妥帖守护的用心。"},"ICON-2675":{"nm":"印台印章清洁刷","de":"饱蘸墨水的印章缝隙，刷子顺着纹理轻轻一拂，褪去陈旧的颜色。为了让下一次盖下的一点清晰，预先擦净——是小巧又勤快的手。"},"ICON-2676":{"nm":"透明内页固定翼","de":"为了不让活页夹的内页滑落，翼从两侧紧紧夹住。多亏每一张都停在原位，翻页的指尖才不会乱了分寸。"},"ICON-2677":{"nm":"装饰碎片收纳铲","de":"把零零散散的装饰碎片，用小铲一下子嗖地铲拢起来。一根根用手指捡拾的麻烦消失后，精心制作某样东西的时光便更添一分愉快。"},"ICON-2678":{"nm":"书签流苏固定夹","de":"为了不让书签末端的流苏松脱，固定夹结结实实地系住。回到读了一半那页的向导，也要自己仪容端正，心里才安。"},"ICON-2679":{"nm":"装饰笔尖盖夹","de":"为了不让装饰笔尖干掉，把盖子牢牢夹住的夹子。挡下笔忘了盖、不小心凝固的窘事，颜色便总像初时一样湿润地流出。"},"ICON-2680":{"nm":"螺丝刀批头插芯","de":"螺丝刀手柄不动，只把头上的批芯嗖地换掉。十字也好、一字也好，样样应手。用一件就把好几样活儿轻松干完的机灵，结结实实地藏在这小小的批头里。"},"ICON-2681":{"nm":"砂纸边角缠卷器","de":"把粗糙的那面圆圆地缠握住，手掌便成了工具。刷、刷，顺着纹理推一回，毛糙的边角便圆润起来，最后那份光滑，向来由人的指尖辨出。"},"ICON-2682":{"nm":"螺丝分类漏斗","de":"四散的螺丝穿过窄窄的颈口，咕噜噜聚到一处。在桌上滚来滚去的小东西寻到归处的声响，连纷乱的心都觉得被整整齐齐理顺了。"},"ICON-2683":{"nm":"卷尺端钩铁","de":"卷尺端头的钩铁，是独自干活的人的第二只手。往边角啪地一挂，尺便不晃，量出的长度有多少，手与心也随之多一分诚实。"},"ICON-2684":{"nm":"扳手手柄套","de":"套在冰凉铁手柄上的一层。握住的瞬间，触到的不是冷冽，而是柔软的暖意。工具在先体谅握它的人时，才会更久地留在身旁。"},"ICON-2685":{"nm":"锥尖保护帽","de":"每一个尖端都各套上一只小帽。即便在抽屉里摸索也不会被扎到的那份安心——越是锐利的东西，越精心地包好，谁都不会受伤。"},"ICON-2686":{"nm":"电线绝缘剥皮刃","de":"只薄薄剥下绝缘皮，不伤里头的芯线。轻轻松开一层、铜色的线芯一闪而出的瞬间，好的刀刃精准地知道该在哪里停手。"},"ICON-2687":{"nm":"水平仪气泡窗擦","de":"气泡恰好停在正中央，这才算水平。把小窗擦得透亮这件事，恰似画线之前先把呼吸匀好的、静静的准备。"},"ICON-2688":{"nm":"钉钉手指护套","de":"把握钉的手指紧紧裹住的小套。即便锤子打偏也不要紧，尽管放心、毫无畏惧地敲下去吧——它已结结实实备好替手指挨这一下。"},"ICON-2689":{"nm":"食盆防滑垫","de":"撑住饭盆、不让它在地上打滑的一层橡胶。让你尽情吃也不会闹出盆子逃跑的事，一餐的安稳，便从不晃动的位置开始。"},"ICON-2690":{"nm":"饲料勺挂","de":"把舀饲料的勺挂在墙上轻轻晾干。每一餐都在同一处迎接手的小小秩序——有一张需要照看的嘴，原来是这般温柔的事。"},"ICON-2691":{"nm":"水盆接溢盘","de":"把沿着水盆边缘晃荡溢出的那一口，静静接住。多亏这只宽大的盘子生怕地板被打湿、预先揽住，脚下便总是干干爽爽。"},"ICON-2692":{"nm":"零食分发夹","de":"精准夹起一块零食递过去的夹子。在凑着鼻子等待的小嘴跟前，分享里也有一份不乱分寸的温柔指尖。"},"ICON-2693":{"nm":"饲料袋口卷封夹","de":"把拆开用过的饲料袋口卷起来咬住的小夹子。啪地一合，便挡住了潮气，明早那酥脆的一把便原原本本守住了。"},"ICON-2694":{"nm":"水壶嘴塞","de":"与水壶嘴严丝合缝的一只塞子。滴答漏着的水珠止住了，周围也干了。封得好的东西不会渗漏，长久地清亮蓄着。"},"ICON-2695":{"nm":"喂食量刻度杯","de":"顺着刻度精准舀出一杯。不多也不少——以公平地揣度今日这一餐的手，把小家伙的一天恰如其分地盛了进去。"},"ICON-2696":{"nm":"撒食垫边缘","de":"挡住撒落的食物不越出垫外的边沿。一道稍稍立起的边，把险些四散的碎屑结结实实地拢了回来。"},"ICON-2697":{"nm":"双盆分离环","de":"把叠在一起的两个盆轻轻分开的小环。死死黏住、让手哼哧使劲的窘境一扫而空。好好把它们分开，说到底也是一份温柔的照料。"},"ICON-2698":{"nm":"院子球归拢漏斗","de":"把咕噜噜滚到院子里的球归拢到一处的漏斗。畅快撒欢的傍晚，把散落四处的东西收拢回来的那双手，便自然而然浮上心头。"},"ICON-2699":{"nm":"围栏木桩帽","de":"给每一根围栏木桩戴上圆圆的帽子。生怕风雨把端头裂开，连小小的一处都照看着盖上，那份心意溢满了整个院子。"},"ICON-2700":{"nm":"游乐隧道折叠挂","de":"把玩够了的游乐隧道一层层折好挂上的挂钩。把沾了泥的一天妥帖收拾好挂起来，整理利落的玩耍，便如约定般带来明天。"},"ICON-2701":{"nm":"拉绳手柄软垫","de":"把拉绳手柄软软包裹起来的垫子。就算用力拉扯,掌心也不会被磨疼。握得越久手越舒服,全靠某人那一点小小的体贴。"},"ICON-2702":{"nm":"庭院遮阳布扣钩","de":"把庭院里张开的遮阳布牢牢固定住的扣钩。连正午的凉爽也得拴住才肯停留。在扣钩撑起的阴凉下,慵懒的午后久久地歇息着。"},"ICON-2703":{"nm":"挖土铲刃护套","de":"轻轻套在挖土铲刃上的护套。让忙活了一整天的它好好歇息,刀刃便不会变钝,来年春天还能再次翻起新土。"},"ICON-2704":{"nm":"滚球斜坡板","de":"让球咕噜噜滚下来的一块斜坡板。沿着微微倾斜的坡面,球儿欢快地一路奔跑。小小一个坡度,就造就了一整天的快乐。"},"ICON-2705":{"nm":"围栏门插销环","de":"锁住围栏门的插销环。咔嗒一声轻响落锁,心也跟着安定下来。一扇牢牢关好的门,把小小的庭院守成了一个完整的世界。"},"ICON-2706":{"nm":"玩耍铃铛系绳","de":"轻轻摇动系着铃铛的绳子,清脆的声音便荡漾开来。叮铃,叮铃——原本静谧的房间苏醒过来,一声小小的回响就让全部心神都竖起了耳朵。"},"ICON-2707":{"nm":"花盆接水托盘","de":"静静接住从花盆底渗流下来的水的托盘。把溢出的水收纳起来,不让窗台被打湿。心意太满溢出时,也得有个地方接着才行。"},"ICON-2708":{"nm":"幼苗移栽插铲","de":"把娇嫩的幼苗轻轻插进土里的小铲子。指尖一株株小心翼翼地为它们安置位置,巴掌大的菜园里也探出了一片青翠的春天。"},"ICON-2709":{"nm":"菜园垄标记牌","de":"插在每条垄上、写明种了什么的标记牌。在还没冒芽的泥土上,一个小小的名牌静静记下这里将要长出什么。"},"ICON-2710":{"nm":"洒水壶嘴滤网","de":"套在洒水壶嘴上的细密滤网。原本一股倾泻而下的水,被分散成蒙蒙细雨般的好几道。只有柔和的水流,才不会伤到娇嫩的叶子。"},"ICON-2711":{"nm":"支架固定夹","de":"把摇晃的茎干轻轻固定到支架上的夹子。在尚且柔弱的它能够挺直之前,暂时借给它一份依靠——成长，正需要这样的支撑。"},"ICON-2712":{"nm":"种子袋密封夹","de":"把剩下的种子袋牢牢夹紧封口的夹子。啪地一夹,一粒也不会漏出。一份对来年春天的约定，就藏在这一次的夹合里。"},"ICON-2713":{"nm":"土肥计量小勺","de":"把土和肥料舀得恰到好处的小勺子。不多不少正好一勺——在精准量好的分量之上,土壤才终于能各司其职。"},"ICON-2714":{"nm":"花盆悬挂吊钩","de":"把花盆轻盈地悬在空中的吊钩。被举高的那抹翠绿,把阳光与微风都拉近了一寸。一座小小的花园,在窗边悠悠浮起。"},"ICON-2715":{"nm":"嫩芽遮护网","de":"轻柔遮护刚冒出的嫩芽的护网。在尚且稚嫩的叶子能熬过初寒与烈日之前,最娇弱的总是最先得到照拂。"},"ICON-2716":{"nm":"梳理梳子挂架","de":"把脱落的毛轻轻拍净、再把梳子整齐挂好的地方。清空后蓬松的梳子等待着下一次抚触。整洁,总是始于爱惜工具的小小习惯。"},"ICON-2717":{"nm":"洗脚盆防滑环","de":"托住洗脚盆、让它不打滑的环。在扑腾的小脚丫下盆子稳稳不动,洗的手和被洗的心都不会晃动。"},"ICON-2718":{"nm":"牵引绳挂钩","de":"把散步牵引绳挂在玄关的一只钩子。在门边的固定位置,出门的准备总在等待。取下绳子的那一刻,一串雀跃的脚步也跟着一同出发。"},"ICON-2719":{"nm":"修甲护套帽","de":"修剪指甲时保护娇嫩肉垫的护套帽。正因为有一道画好的安全边界说着\"就到这里\",握着剪刀的手才不会发抖,才能从容沉稳。"},"ICON-2720":{"nm":"洗澡水温度带","de":"悠悠浮在洗澡水上、告知水温的带子。从前把手背浸进去揣度合适暖意的那份心意,如今化作一道颜色清晰地翻译出来,浮在水面上。"},"ICON-2721":{"nm":"黏毛滚筒刷","de":"黑衣服上的一根白毛,在登台前一刻看起来格外刺眼。随着滚动的沙沙声,一天的碎屑被一点点黏到带胶的纸上。整洁就这样一格一格、撕下多少便完成多少。"},"ICON-2722":{"nm":"散步便袋夹","de":"散步的尽头,总有一个弯腰的温柔瞬间。把便袋夹在夹子末端,手就干净,心也轻松。一起散步这件事里,也包含着照看身后的小小礼貌——这把夹子最先懂得。"},"ICON-2723":{"nm":"擦脚垫边","de":"门前垫子的边缘,是脚最先触到的欢迎致意。湿漉漉的脚尖在这里停一停,里面的地板便能保持干爽。它无声地为每一个进来的人擦净脚步,守在最低的位置。"},"ICON-2724":{"nm":"梳理铃铛结绳","de":"就连系一颗铃铛也有顺序。绳子绕两圈、穿过一次,每一步都有清脆的声音咕噜噜跟随。所谓打扮,终究是不漏掉这小小收尾的那份心意。"},"ICON-2725":{"nm":"便携伞接水袋","de":"雨停后的大厅,折好的伞尖在地上点点洇出水珠。一只小袋子静静接住它,某人的脚下便不再湿滑。体贴大多是这样,无声地守在身旁。"},"ICON-2726":{"nm":"外出包固定夹","de":"挂在椅子上的包总是悄悄滑落下来。用固定夹夹住一下,就不必担心掉落,双手也轻松。外出的从容,始于可以暂时忘掉行李的时候。"},"ICON-2727":{"nm":"暖手布袋","de":"寒风吹过的小巷里,口袋中的布袋把暖意悄悄传到掌心。柔柔地裹住滚烫之物,恰到好处地温热。冬日的温情,总是经过一层布才传递过来。"},"ICON-2728":{"nm":"便携镜展开支架","de":"一展开,小镜子便斜斜地摆好自己的角度。不用手拿也能照见自己的脸,有支架替你立着。整理仪容的那短短一隙里,也有一位可靠的配角守在身边。"},"ICON-2729":{"nm":"外出湿巾盖帽","de":"湿巾的第一张总是正在变干。啪地盖上盖帽,直到最后一张都还保持着湿润。守护它被用到最后——耐用持家的秘密,就藏在这些细微之处。"},"ICON-2730":{"nm":"钱包硬币隔板","de":"硬币散落到纸币之间,收银台前总会变得手忙脚乱。一块隔板把圆圆的家伙们归拢到一边,指尖便不再摸索。整理,就是给每样东西取一个位置的名字。"},"ICON-2731":{"nm":"外出口罩折叠盒","de":"折好放进去,口罩在包里也不会被压皱。把暂时摘下的一只干干净净地收纳起来的盒子。为了再次使用而妥帖保存,一份温柔的习惯就盛在这里。"},"ICON-2732":{"nm":"便携梳齿罩","de":"包里的梳齿常常会划伤别的物件。套上齿罩,梳子安全,同放的东西也无恙。薄薄一层保护就能护住彼此——细心收纳过的人都懂。"},"ICON-2733":{"nm":"抽屉分格夹","de":"每次拉开抽屉,混作一团的东西都像叹息般倾泻出来。用一个夹子把格子分开,小物件们才终于找到各自的地盘。整齐的抽屉,悄悄改变着每天清晨的心情。"},"ICON-2734":{"nm":"硬币立放底座","de":"把一枚旧硬币立起来,它本身就成了一场小小的展览。底座斜斜托着它,把正面的纹样清晰地展示出来。把沾着手泽的时光摆到视线高度——收藏的乐趣,便在这里更深一层。"},"ICON-2735":{"nm":"耳机绕线钩","de":"曾因解开缠成一团的耳机线而虚度了半个早晨。在绕线钩上一圈圈整齐缠好,下次取出时就顺顺溜溜。小小的整理,是悄悄递给明天的自己的礼物。"},"ICON-2736":{"nm":"充电线壁挂钩","de":"垂在地上的充电线总是被脚踩到。在墙上贴一只钩子挂起来,桌面顿时宽敞许多。驯服杂乱并不需要什么大动作,只要一枚钉子大小的位置。"},"ICON-2737":{"nm":"遥控器立放架","de":"总往沙发缝里消失的遥控器,终于有了可以回去的家。立放在架上,既不必到处翻找,也不会被压在身下。有个固定的位置,对物件来说也是一份小小的安歇。"},"ICON-2738":{"nm":"眼镜腿挂夹","de":"摘下的眼镜总是悄悄滑到不知哪里去。把镜腿轻轻挂在夹子上,镜片就不会触到桌面。想让它毫无划痕地迎接明天的那份心意,就盛在这小小的挂夹里。"},"ICON-2739":{"nm":"钥匙分类夹","de":"钥匙串越来越沉，哪把对哪扇门就越来越模糊。用分类夹捆好，只凭指尖就能认出各自的搭档。为每天开合的门悄悄理出秩序的，无言的向导。"},"ICON-2740":{"nm":"便签立放夹","de":"写好的便签在桌上常常倒伏下来。夹子把纸立着夹住,字迹便端端正正地与眼睛对视。把不可遗忘的那一句,安顿在总能看见的地方的法子。"},"ICON-2741":{"nm":"笔尖立放座","de":"为了捡滚落的笔，弯了多少回腰啊。把笔尖插进座里立着，到下一行字的距离就短了一寸。永远清醒地守在书写者身边的，小小待命所。"},"ICON-2742":{"nm":"沙漏翻转底座","de":"沙漏流尽之后,得有人翻转一下才能重新复活。底座接住最后一粒落下的瞬间,顺顺地把它转立过来。把时间拨回最初的那只手,就停留在这一小块木头上。"},"ICON-2743":{"nm":"黄油烤土豆","de":"黄油在带皮烤好的土豆上慢慢融化。金黄的纹理随着热气渗入,绵软的内里静静裹住那份香醇。带着泥土气息的根茎,正是在此刻变得最温暖。"},"ICON-2744":{"nm":"黄油烤玉米","de":"颗颗饱满的黄色玉米粒在烤盘上噼啪作响。一块黄油从上面滑过,甜香便扑鼻而来。夏日田野的甘甜,就这样原封不动地搬进了一口之中。"},"ICON-2745":{"nm":"华夫饼","de":"静静等着糖浆在格子状的一格格里聚拢。外脆里软——咬一口,温热的气息便丝丝透出。方方的格子,像是分装着小小幸福的器皿。"},"ICON-2746":{"nm":"松饼","de":"还记得面糊在平底锅上烤得金黄、慢慢鼓起的那股香味。层层叠起的圆饼上,黄油缓缓地融化坍塌。只在悠闲的早晨才被悄悄允许的,一碟柔软。"},"ICON-2747":{"nm":"巧克力","de":"含一块在嘴里,触到体温便慢慢化开。微苦尽头漾出的甜味,悄悄松开了心头的紧绷。疲惫的日子里从口袋掏出来吃的,小小慰藉的褐色一块。"},"ICON-2748":{"nm":"草莓蛋糕","de":"红草莓坐在洁白的鲜奶油上,先一步报告春天到来。叉子划开柔软的切面,酸甜的香气便悄悄绽放。有喜事的日子里,摆在餐桌正中的温柔主角。"},"ICON-2749":{"nm":"芝士蛋糕","de":"厚实的一块在舌尖浓郁地化开。咸味的尾韵牵住甜味的手,让人忍不住再咬一口。喜欢那份绵密浓厚的人,会静静珍惜着吃的甜点。"},"ICON-2750":{"nm":"香蕉饼干","de":"捣碎的香蕉香在烤箱里渐渐烤得金黄。咬一口,柔软的甜味便满满漾在嘴里。一根熟透的水果重新化作饼干——温暖蜕变的一刻。"},"ICON-2751":{"nm":"巧克力饼干","de":"面团里的巧克力豆随着烘烤浓稠地化开。趁热掰开,浓郁的褐色便沾在指尖。若配上一杯牛奶,午后便会变得格外温柔的那一块。"},"ICON-2752":{"nm":"可可碎饼干","de":"碾碎的可可粒在面团间噼噼啪啪地嚼着。不甜而深沉的苦味,静静熨帖着大人的口味。原封保留着加工前本真香气的,有点严肃的饼干。"},"ICON-2753":{"nm":"芝士吐司","de":"金黄烤好的面包上,芝士拉出长长的丝。外层的酥脆与内里的香醇在一口中交叠。把迟来的早晨喂得饱饱的,最简单也最温柔的一餐。"},"ICON-2754":{"nm":"三明治","de":"两片面包之间,塞满了一整天的用心。咬一口,层层叠起的滋味便一齐前来问好。无论去哪儿都能带上的,掌心上的小小餐桌。"},"ICON-2755":{"nm":"法式吐司","de":"在蛋液里浸得透透的面包,在平底锅上渐渐烤成金黄。随着黄油香鼓起的边角最先变得酥脆。淋上一道糖浆,平凡的面包也成了假日的奢享。"},"ICON-2756":{"nm":"蘑菇拉面","de":"沸腾的汤上,蘑菇的醇厚香气随热气升腾。夹起一片爽滑的菌伞,带着泥土气息的甘甜便在嘴里散开。比起面条更先用香气填饱肚子的,有点特别的一碗。"},"ICON-2757":{"nm":"炒拉面","de":"无汤拌出的面被辣味酱汁裹出油亮的光泽。用筷子挑起,热气间便弥漫开香喷喷的镬气。想念又快又浓的一餐时,最可靠的朋友。"},"ICON-2758":{"nm":"芝士拉面","de":"在滚烫的面上铺一片芝士,它便慢慢坍塌融化进去。辛辣的汤与柔和的香醇相遇,棱角变得圆润起来。最适合想稍稍抚平刺激的夜晚的一碗。"},"ICON-2759":{"nm":"咖喱拉面","de":"浓郁的咖喱香缠绕着面条,腾起黄色的热气。呼噜一口吸进去,温暖的辛辣便暖了肚子。在熟悉的汤里添上一缕陌生香气的,愉快变奏之面。"},"ICON-2760":{"nm":"海鲜拉面","de":"满是海洋气息的汤上,虾和贝胖乎乎地浮起。清爽而醇厚的鲜味,渗入面条的缝隙之间。不必远行就把海的气息盛进一碗的,小小魔法。"},"ICON-2761":{"nm":"腌萝卜紫菜包饭","de":"黄色的腌萝卜居于正中,饭粒圆圆地环坐四周,一张紫菜便把这一切温柔地裹成一卷。去远足的清晨,在砧板上诞生的最朴实的一餐。"},"ICON-2762":{"nm":"金枪鱼紫菜包饭","de":"拌了蛋黄酱的金枪鱼一勺渗进饭间的瞬间,即便在深夜便利店的灯光下,一餐也足够温暖。忙碌的手最常拿起的那份慰藉。"},"ICON-2763":{"nm":"水果沙拉","de":"汇集了当季的色彩,在一只碗里初次相遇。红与绿与黄如何不争不抢地融洽相处,水果只有被切开、盛在一处之后才终于展示出来。"},"ICON-2764":{"nm":"鸡肉沙拉","de":"把清淡烤好的鸡胸肉整齐地摆在青翠的叶菜上。准备明日舞台的人的餐桌上,总摆着这样端正的一碟。"},"ICON-2765":{"nm":"番茄黄瓜凉拌","de":"把熟透的番茄和爽脆的黄瓜酸甜地拌出来。蝉声浓重的正午,一筷子放进嘴里,夏天便在其中清凉地降了一个节拍。"},"ICON-2766":{"nm":"生菜沙拉","de":"把刚从菜园摘来的叶子用凉水冲洗,指尖凉凉地醒来。最寻常的蔬菜,在餐桌上占据最青翠、最鲜爽位置的一刻。"},"ICON-2767":{"nm":"玉米沙拉","de":"每当甘甜的颗粒噗噗爆开,阳光满满的盛夏田野便浮现眼前。黄色的玉米,即使在沙拉碗里也始终不忘自己那份阳光。"},"ICON-2768":{"nm":"凉拌卷心菜","de":"切丝的卷心菜含住酸甜的酱汁,爽脆便变得柔和许多。无论摆在哪道主菜旁都不争光芒、尽好本分的配菜美德。"},"ICON-2769":{"nm":"青柠鲜虾沙拉","de":"轻轻挤入青柠,虾的甜味便愈发鲜明地醒来。酸酸的一滴为整盘注入生气,虽小却决定性的最后一笔。"},"ICON-2770":{"nm":"汉堡肉排","de":"厚厚捏好的肉饼在烧热的铁板上渐渐烤成金黄。刀尖触到的瞬间溢出的肉汁——在家常菜与西餐之间最受长久喜爱的一餐。"},"ICON-2771":{"nm":"披萨","de":"芝士长长拉丝的那一口,众人围坐着从手传到手。一同把圆圆的一整张分成块时,聚会才终于成为真正的聚会。"},"ICON-2772":{"nm":"蘑菇奶油意面","de":"蘑菇深沉的泥土气息与奶油的柔滑,把面条一根一根拥入怀中。雨声轻柔的夜晚,浓郁的香气慢慢漫到盘底。"},"ICON-2773":{"nm":"鲜虾意面","de":"把饱满的虾用橄榄油略炒,再与面条拌在一起。海的咸鲜与面的清淡相遇,平淡无奇的傍晚也变得有些特别。"},"ICON-2774":{"nm":"橄榄油意面","de":"只有蒜、油和面这三样。有些味道越是减去反而越是清晰——蒜香橄榄油意面毫无赘余地静静证明着这一点。"},"ICON-2775":{"nm":"蛤蜊意面","de":"蛤蜊张口时释出的汤汁,深深渗入每一根面条。一口白葡萄酒的香气在盘上如春日般久久不散。"},"ICON-2776":{"nm":"奶油意面","de":"浓郁的奶油静静裹住面条,从第一口起心头一角便温暖起来。越是风寒的日子越发深沉的,柔滑所递来的慰藉。"},"ICON-2777":{"nm":"番茄意面","de":"久煮的番茄酱红红地漫上面条。甜味与酸味慢慢熬出、终于找到平衡时,最基础的一碟也最是踏实。"},"ICON-2778":{"nm":"蛋包饭","de":"柔嫩的鸡蛋像被子般轻轻盖住热腾腾的米饭。若用番茄酱写上哪怕一个名字,那天的餐桌便成了某人递来的一封小信。"},"ICON-2779":{"nm":"烤三文鱼","de":"在火前慢慢烤,直到鱼皮变得酥脆。粉色的鱼肉顺着纹理裂开,升腾起一缕热气——等待,总会被三文鱼诚实地回报。"},"ICON-2780":{"nm":"意式烤面包","de":"在烤得酥脆的面包上,满满堆起切碎的番茄和罗勒。用手指拈起咬一口的那份轻盈,温柔地拉开了聚会的第一声问候。"},"ICON-2781":{"nm":"芒果思慕雪","de":"把熟透的芒果细细打碎,与冰块清凉地混在一起。黄色的一杯凝起细密水珠时,慵懒的盛夏午后便一直涨到吸管尖。"},"ICON-2782":{"nm":"柠檬汽水","de":"放入现榨柠檬、糖和凉水,连杯一起摇匀。黄色的酸味顺着喉咙清凉地滑下,逞威的暑气也暂时举手投降。"},"ICON-2783":{"nm":"草莓牛奶","de":"把草莓捣碎拌进牛奶,粉色的云朵便在杯中慢慢沉下。儿时一把推开冰箱门时指尖的雀跃,原原本本地盛在这一杯里。"},"ICON-2784":{"nm":"香蕉牛奶","de":"单凭那圆鼓鼓的坛子模样,就已是一个时代的回忆。在澡堂歇台上插吸管的黄色记忆,每一口都温柔地复苏。"},"ICON-2785":{"nm":"蓝莓牛奶","de":"把紫色的果粒噗噗捣碎放进去,洁白的牛奶便染上淡淡的天蓝色。那一小把小小的果实,把一整杯都换上了崭新的颜色。"},"ICON-2786":{"nm":"果汁","de":"把好几种水果一同榨进去,便成了无法只用任何一个名字称呼的味道。彼此交融、愈发丰盈地鼓涨起来的,甜味们的小小合唱。"},"ICON-2787":{"nm":"可可","de":"在飘雪的窗边,用双手静静捧住温暖的马克杯。热气袅袅升起的褐色一杯,从指尖到心底慢慢温热起来。"},"ICON-2788":{"nm":"咖啡","de":"点亮凌晨练习室的灯的,永远是这一杯。微苦的香气静静推开睡意,新的一天的舞台便又这样悄悄拉开序幕。"},"ICON-2789":{"nm":"三文鱼寿司","de":"把饭握在手中,揣度着软硬之间那微妙的纹理。薄切的一片三文鱼轻轻躺上去的瞬间,一口便成了小小用心的完成。"},"ICON-2790":{"nm":"南瓜粥","de":"把黄南瓜煮得软烂,再细细捣碎熬下来。每舀一勺送进嘴里,秋日的阳光便温暖地化在口中。生病时最先想起的那碗粥。"},"ICON-2791":{"nm":"鱼肉咖喱","de":"用香料略煮的鱼肉在咖喱中柔嫩地散开。在熟悉的一碗里添上海洋的纹理,平凡的傍晚便往远方旅行了一寸。"},"ICON-2792":{"nm":"炸虾","de":"捏住虾尾裹上面糊、放进滚油的那短短一瞬便是胜负。披上金黄外衣的虾,要趁酥脆未凉时吃才最是熠熠生辉。"},"ICON-2793":{"nm":"炸鱿鱼","de":"圆圆的鱿鱼圈在滚烫的油里胖乎乎地鼓起。酥脆裹着弹牙的那一口,在大排档昏黄的灯光下最是相配。"},"ICON-2794":{"nm":"烤鸡肉","de":"抹上酱料在火前慢慢烤,鸡皮便泛起油亮的光。火候稍有不同味道便会两样,正因最简单,反倒最是诚实的料理。"},"ICON-2795":{"nm":"猪肉炒泡菜","de":"把熟透的泡菜和猪肉一同翻炒,酸味便熟成了甜味。让人不由得添一碗白饭的,韩国餐桌上最踏实的搭档。"},"ICON-2796":{"nm":"炒猪肉","de":"用大火快速翻炒,把外层煎得焦香。香喷喷的油气充满厨房时,今晚的菜单不必再问,早已定下。"},"ICON-2797":{"nm":"牛肉炒蘑菇","de":"把香气怡人的蘑菇和牛肉一同翻炒,彼此的滋味便愈发深厚。泥土与田野在一盘中静静握手,秋天端正的一餐。"},"ICON-2798":{"nm":"芝士炒鸡排","de":"在辣味鸡排上厚厚铺融芝士,长长地拉出丝来。众人围着滚烫的铁板坐下,火辣的辣味也化作笑声散开。"},"ICON-2799":{"nm":"泡菜汤","de":"越是陈年的泡菜,越能熬出更深更浓的汤。在咕嘟咕嘟翻滚的砂锅前相对而坐,\"家人\"这个词便又一次温暖地回温。"},"ICON-2800":{"nm":"大酱汤","de":"化开醇香的大酱,放入豆腐和西葫芦慢慢炖煮。砂锅里咕嘟到最后的那声响,是回到家最确切的信号。"},"ICON-2801":{"nm":"牛肉萝卜汤","de":"在小火前静静守候半日,直到萝卜变得透明。清澈的汤一勺触到嘴边,便想起那段毫不华丽的岁月里的饭桌。淡然的,才最是久久留存。"},"ICON-2802":{"nm":"蛤蜊汤","de":"蛤蜊张口的瞬间,锅里春意渐深。一缕海的气息随热气升起,海边村落清晨的厨房便浮现出来。每一道张开的缝里,都积着咸鲜的海。"},"ICON-2803":{"nm":"拔丝红薯","de":"放学路上,装在纸杯里像暖手宝般被攥在手心的黄色块块。咬开金黄的外壳,里面热气便呼地冒出。甜甜熬过的外层与滚烫的内里,是冬天最温柔的味道。"},"ICON-2804":{"nm":"炒茄子","de":"紫色遇上油、缓缓化开的那一瞬。被嫌弃软塌的蔬菜,其实比谁都更善于含住调味。咬一口,柔柔渗入的那份手艺便先一步传来。"},"ICON-2805":{"nm":"酱烧土豆","de":"酱油收汁时满厨房弥漫甜香的傍晚。把油亮的褐色一块装进饭盒格子的那双手。没写进食谱的用心,渗进了这小小的每一块里。"},"ICON-2806":{"nm":"腌苏子叶","de":"把整个夏天的香气腌起来,一路带到冬天的餐桌。揭下一片放到饭上,逝去的季节便在口中再次绽放。层层叠起的叶子之间,沉睡着那一年的阳光。"},"ICON-2807":{"nm":"白菜辣拌","de":"等不及做泡菜的手,当天就揉拌了起来。只有在爽脆的叶子刚开始入味的那一刻才能享受到的鲜爽。发酵前的清新,是只属于今天的奢侈。"},"ICON-2808":{"nm":"炒蘑菇","de":"雨过之后在林荫下悄悄冒出的那些家伙。在紫苏油里翻炒时,泥土味便转成了香醇。越是在暗处默默生长的,香气越深越浓。"},"ICON-2809":{"nm":"凉拌菠菜","de":"焯一下便缩成一小把的叶菜,用指尖轻轻揉拌。那份谦逊的体积正是春日野菜的美德。一碟青翠,餐桌上便多了一寸春光。"},"ICON-2810":{"nm":"凉拌海藻","de":"刚从海里捞起的滑溜溜的丝丝缕缕,与酸甜的醋酱融在一起。每一次咀嚼噗噗爆开的咸味。把波涛荡漾的口感原样移进碗里的一碟。"},"ICON-2811":{"nm":"炒南瓜","de":"有些蔬菜越老甜味越足。切薄片用虾酱翻炒,平淡的南瓜也悄悄拿出自己的甜。在口中柔柔化到最后的那抹黄色。"},"ICON-2812":{"nm":"泡菜炒饭","de":"陈泡菜熟成之时,与冷饭在同一只锅里相遇。剩余与剩余相合,成了最踏实的一碗。深夜独居小屋的灯光下,最温柔的救赎。"},"ICON-2813":{"nm":"鸡肉咖喱","de":"黄色的汤汁盖住白饭时,餐桌便明亮起来。香料还陌生的年月里,最先亲近的外面世界的味道。鸡肉绵软散开的某个周日午餐。"},"ICON-2814":{"nm":"炒饭","de":"冰箱角落剩下的边边角角,在一只锅里和睦地融洽相处。什么都宽容收纳的那份大度。把散落的归拢到一处,正是过日子的开端。"},"ICON-2815":{"nm":"烤肉盖饭","de":"用甜香酱料腌好的肉,顺着热气腾腾的饭面滑滑落下。当待客餐桌的主角降落成平日的一碗,那份特别便愈发温柔。"},"ICON-2816":{"nm":"拌饭","de":"热腾腾的饭上,五色野菜圆圆地环坐。配着颜色装盘的指尖,流淌着细细打量的古老审美。要拌到一处才终于完成的,交融之味。"},"ICON-2817":{"nm":"鲜虾炒饭","de":"饱满的虾在饭粒间泛着粉色格外显眼。把一把海洋炒进去,平凡的一餐也学起了宴席的样子。一咬便漾开的甜味令人欢喜。"},"ICON-2818":{"nm":"辣炒猪肉盖饭","de":"入味浓厚的辣炒猪肉,与热气腾腾的饭相遇。一到午饭时间便最先见底的那碗。轻轻抚慰忙碌一天的,一餐的慰藉。"},"ICON-2819":{"nm":"金枪鱼蛋黄酱饭","de":"一个罐头、一道蛋黄酱,再加一碗温热的饭。食材简单,慰藉却丰盈。上完晚自习在教室课桌上偷偷拌起来的,那个夜晚的味道。"},"ICON-2820":{"nm":"咖喱饭","de":"浓稠的金黄铺满整个盘子。把土豆和胡萝卜炖到软烂、久久搅动的那份用心。一家人盯着同一只锅的那个傍晚的团圆,浮上心头。"},"ICON-2821":{"nm":"海藻拌饭","de":"带着海洋气息的丝丝缕缕与辣椒酱相遇,刷刷地拌在一起。滑溜酸爽的口感裹住饭粒时,海女屏息打捞上来的大海便在一碗中铺展开来。"},"ICON-2822":{"nm":"烤鲭鱼","de":"银色的鱼背在烤盘上渐渐烤得金黄。剔去鱼刺、把鱼肉夹到饭上的那双手。一段青背鱼里,就这样浸着喂养长大的默默之爱。"},"ICON-2823":{"nm":"土豆煎饼","de":"下雨天就在江原道山村厨房里磨碎来煎的东西。糯弹的边缘与酥脆的边角并肩住在一张里。最配敲打窗户的雨声的那一团面糊。"},"ICON-2824":{"nm":"泡菜煎饼","de":"酸泡菜接触到刷了油的平底锅的瞬间,整间屋子便充满滋啦滋啦的声响。让人不由得想来一碗马格利酒的金黄圆饼。与檐下雨声成双的常客菜。"},"ICON-2825":{"nm":"葱煎饼","de":"把小葱整齐铺好,浇上面糊慢慢煎。在酥脆与柔软之间往返的一张。正如集市摊位上热气腾腾升起的那番亲切光景。"},"ICON-2826":{"nm":"西葫芦煎饼","de":"给薄切的西葫芦裹上衣,煎得金黄。端正守在祭桌一角的嫩绿圆片。要费许多功夫才终于成形的,那份用心的格调。"},"ICON-2827":{"nm":"辣炒鱿鱼","de":"裹着红酱的须足泛着油亮的光。即便辣得额头沁出细密汗珠,筷子也停不下来。汗水与快乐交缠在一起的那一盘。"},"ICON-2828":{"nm":"炒年糕","de":"红红收汁的辣椒酱汤里,年糕和鱼糕浸得满满。攒硬币两人分着吃的小吃店午后,被整个盛在了里面。光听名字就让人流口水的回忆之味。"},"ICON-2829":{"nm":"鱼糕汤","de":"鱼糕在汤里晃荡的大排档,热气把玻璃窗熏得白蒙蒙。握一串、用纸杯接上汤呼噜喝下,刺骨的冬夜便温暖了许多。"},"ICON-2830":{"nm":"豆腐泡菜","de":"柔嫩的豆腐旁,辣辣翻炒的泡菜并肩而坐。冰凉与滚烫、温顺与浓烈在一盘中交融。长久守护大人之夜的搭档。"},"ICON-2831":{"nm":"香肠炒蔬菜","de":"红香肠与蔬菜在番茄酱色里滋啦滋啦地融洽相处。打开运动会便当盖时最先被清空的那一格。那天的色彩,无论过去多久都始终鲜明。"},"ICON-2832":{"nm":"红薯拿铁","de":"细细捣碎的红薯在温热的牛奶里柔柔化开。菜单上用韩文写着的本土甜味。指尖发凉的日子,双手捧住便有暖意慢慢漾开的一杯。"}};
